    def make_town_map(self) -> List[List[str]]:
        """Create a block-based town exterior aligned to the road grid."""
        width, height = TOWN_WIDTH, TOWN_HEIGHT
        grid = [["." for _ in range(width)] for _ in range(height)]

        for x in range(width):
            grid[0][x] = "#"
            grid[height - 1][x] = "#"
        for y in range(height):
            grid[y][0] = "#"
            grid[y][width - 1] = "#"

        def set_tile(x: int, y: int, ch: str):
            if 0 <= x < width and 0 <= y < height:
                grid[y][x] = ch

        def fill_rect(x0: int, y0: int, w: int, h: int, ch: str, only: Optional[List[str]] = None):
            for yy in range(y0, y0 + h):
                for xx in range(x0, x0 + w):
                    if 0 <= xx < width and 0 <= yy < height:
                        if only is None or grid[yy][xx] in only:
                            grid[yy][xx] = ch

        def path_rect(x0: int, y0: int, w: int, h: int, ch: str = "="):
            fill_rect(x0, y0, w, h, ch, only=[".", ",", ":"])

        def plaza_rect(x0: int, y0: int, w: int, h: int):
            fill_rect(x0, y0, w, h, ":", only=[".", ",", "="])

        def green_rect(x0: int, y0: int, w: int, h: int):
            fill_rect(x0, y0, w, h, ",", only=["."])

        def place_building(x0: int, y0: int, w: int, h: int, wall: str, door_x: int):
            for yy in range(y0, y0 + h):
                for xx in range(x0, x0 + w):
                    set_tile(xx, yy, wall)
            door_y = y0 + h - 1
            set_tile(door_x, door_y, "D")
            if door_y + 1 < height:
                set_tile(door_x, door_y + 1, ":")

        # Main navigation grid. Streets occupy lanes; buildings stay inside blocks.
        for y in [10, 11, 22, 23, 34, 35, 44]:
            path_rect(1, y, width - 2, 1, "=")
        for x in [16, 17, 32, 33, 48, 49, 64, 65, 80, 81, 96, 97, 104, 105]:
            path_rect(x, 1, 1, height - 2, "=")

        # Farm boulevard runs from the grid to the east edge.
        path_rect(96, 18, width - 2 - 96, 5, "=")
        for y in range(18, 23):
            set_tile(width - 1, y, ":")
            set_tile(width - 2, y, "=")
            set_tile(width - 3, y, "=")

        # North wilderness road.
        path_rect(56, 1, 4, 10, "=")
        for x in range(56, 60):
            set_tile(x, 0, ":")

        # Service buildings sit inside grid blocks and open onto frontage paths.
        place_building(5, 3, 11, 6, "G", TOWN_DOORS["general_store"][0])
        place_building(20, 3, 11, 6, "X", TOWN_DOORS["blacksmith"][0])
        place_building(36, 3, 11, 6, "L", TOWN_DOORS["library"][0])
        place_building(68, 3, 11, 6, "U", TOWN_DOORS["museum"][0])

        place_building(5, 15, 11, 6, "M", TOWN_DOORS["mayor_house"][0])
        place_building(20, 15, 11, 6, "I", TOWN_DOORS["inn"][0])
        place_building(36, 13, 11, 8, "R", TOWN_DOORS["town_hall"][0])
        place_building(52, 15, 11, 6, "Y", TOWN_DOORS["furniture_store"][0])
        place_building(68, 15, 11, 6, "C", TOWN_DOORS["carpenter"][0])
        place_building(84, 15, 11, 6, "A", TOWN_DOORS["animal_store"][0])

        place_building(5, 27, 11, 6, "H", TOWN_DOORS["clinic"][0])
        place_building(68, 27, 11, 6, "P", TOWN_DOORS["market_row"][0])

        # Residential row: six small households front the south road above
        # the canal. Their interiors are selected by the exact entered door.
        for residence in AUTHORED_TOWN_RESIDENCE_DATA.values():
            door_x, door_y = residence["door"]
            place_building(
                int(door_x) - 5,
                int(door_y) - 5,
                11,
                6,
                str(residence.get("symbol", "h")),
                int(door_x),
            )

        # Plazas and district surfaces.
        plaza_rect(3, 8, 46, 5)       # North market/service court.
        plaza_rect(3, 20, 96, 5)      # Civic frontage and boulevard.
        plaza_rect(34, 20, 30, 9)     # Town Hall square.
        plaza_rect(3, 32, 96, 5)      # South civic/market walk.
        plaza_rect(66, 27, 30, 13)    # Market promenade.

        # Central park: larger, easier to navigate, and crossed by clear paths.
        green_rect(36, 24, 28, 10)
        for x in range(36, 64):
            set_tile(x, 29, ":")
            set_tile(x, 33, ":")
        for y in range(24, 34):
            set_tile(48, y, ":")
            set_tile(49, y, ":")
            set_tile(58, y, ":")
        set_tile(49, 29, "F")
        for x, y in [(39, 25), (43, 27), (53, 25), (61, 26), (40, 32), (55, 32), (62, 33)]:
            set_tile(x, y, "T")
        for x, y in [(40, 29), (45, 33), (53, 29), (58, 26), (58, 32), (62, 29)]:
            set_tile(x, y, "b")

        # Expanded east commons and orchard approach near the farm road.
        green_rect(92, 24, 17, 19)
        for y in range(24, 43):
            set_tile(104, y, "=")
            set_tile(105, y, "=")
        for x, y in [(95, 26), (99, 28), (108, 30), (94, 34), (100, 37), (108, 40)]:
            set_tile(x, y, "T")
        for x, y in [(96, 31), (101, 35), (106, 34), (99, 41)]:
            set_tile(x, y, "b")

        # South canal gives the expanded town a bottom edge without blocking main routes.
        for x in range(8, width - 8):
            set_tile(x, 46, "~")
        for x in [16, 17, 32, 33, 48, 49, 64, 65, 80, 81, 96, 97, 104, 105]:
            set_tile(x, 46, "=")
            set_tile(x, 45, "=")
            set_tile(x, 47, "=")

        # Boards, directories, and easy orientation points.
        set_tile(46, 11, "B")
        notice_x, notice_y = TOWN_NOTICE_BOARD_POS
        set_tile(notice_x, notice_y, "N")
        for ox, oy in [(notice_x - 1, notice_y), (notice_x + 1, notice_y), (notice_x, notice_y + 1), (notice_x, notice_y - 1)]:
            if 0 <= ox < width and 0 <= oy < height and grid[oy][ox] in [".", "=", ","]:
                set_tile(ox, oy, ":")
        for x, y in TOWN_DIRECTORY_TILES:
            set_tile(x, y, "D")

        # Market stalls sit on the promenade instead of interrupting travel lanes.
        for x, y in [(82, 28), (86, 28), (90, 28), (94, 28), (82, 32), (86, 32), (90, 32)]:
            set_tile(x, y, "m")
        for x, y in [(84, 30), (88, 30), (92, 30), (84, 36), (88, 36), (92, 36)]:
            if grid[y][x] != "D":
                set_tile(x, y, "$")

        # Benches, lamps, and trees should help orientation without creating mazes.
        for x, y in [(7, 10), (22, 10), (38, 10), (55, 10), (7, 22), (24, 22), (55, 22), (72, 22), (88, 22), (100, 22), (18, 36), (73, 36), (86, 36)]:
            set_tile(x, y, "b")
        for x, y in [(8, 11), (40, 11), (57, 10), (44, 22), (76, 22), (103, 22), (13, 34), (92, 34)]:
            set_tile(x, y, "!")
        for x, y in [(3, 4), (18, 5), (34, 4), (52, 5), (3, 16), (18, 16), (66, 15), (82, 15), (98, 18), (25, 34), (91, 34), (96, 12), (103, 12), (98, 44)]:
            set_tile(x, y, "T")

        sign_positions = [
            (13, 9), (28, 9), (44, 9), (76, 9),
            (13, 21), (44, 21), (76, 21),
            (13, 33), (76, 33),
            (57, 3), (104, 23), (98, 34)
        ]
        for x, y in sign_positions:
            if 0 <= x < width and 0 <= y < height and grid[y][x] in [".", ":", "=", ","]:
                grid[y][x] = "?"

        self.apply_town_development_visuals(grid)
        return self.apply_visible_town_projects(grid)


    def make_mine_map(self, floor: int = 1) -> List[List[str]]:
        """Create a procedural mine floor. Floor 1 has the main exit back to farm."""
        floor = max(1, min(MINE_MAX_FLOOR, int(floor)))
        rng = random.Random(int(self.state.mine_seed) + floor * 991)
        grid = [[" " for _ in range(WIDTH)] for _ in range(HEIGHT)]

        for x in range(WIDTH):
            grid[0][x] = "#"
            grid[HEIGHT - 1][x] = "#"
        for y in range(HEIGHT):
            grid[y][0] = "#"
            grid[y][WIDTH - 1] = "#"

        for y in range(2, HEIGHT - 2):
            for x in range(3, WIDTH - 3):
                grid[y][x] = "."

        # Rock-wall blobs for layout variety.
        for _ in range(5 + min(8, floor // 4)):
            cx = rng.randint(7, WIDTH - 8)
            cy = rng.randint(4, HEIGHT - 6)
            rx = rng.randint(2, 6)
            ry = rng.randint(1, 3)
            for yy in range(cy - ry, cy + ry + 1):
                for xx in range(cx - rx, cx + rx + 1):
                    if 2 <= yy < HEIGHT - 2 and 3 <= xx < WIDTH - 3:
                        if ((xx - cx) ** 2) / max(1, rx ** 2) + ((yy - cy) ** 2) / max(1, ry ** 2) <= rng.uniform(0.85, 1.35):
                            grid[yy][xx] = "#"

        # Guaranteed cross-path so floors are navigable.
        mid_x = WIDTH // 2
        mid_y = HEIGHT // 2
        for x in range(2, WIDTH - 2):
            grid[mid_y][x] = "."
            if rng.random() < 0.70 and mid_y - 1 > 1:
                grid[mid_y - 1][x] = "."
        for y in range(1, HEIGHT - 1):
            grid[y][mid_x] = "."
            if rng.random() < 0.70 and mid_x + 1 < WIDTH - 1:
                grid[y][mid_x + 1] = "."

        # Up/exit stairs.
        if floor == 1:
            for x in range(25, 30):
                grid[HEIGHT - 1][x] = "N"
                grid[HEIGHT - 2][x] = "."
            grid[HEIGHT - 3][mid_x] = "<"
        else:
            grid[HEIGHT - 3][mid_x] = "<"
            for dy in range(-1, 2):
                for dx in range(-2, 3):
                    if 1 <= mid_y + dy < HEIGHT - 1 and 1 <= mid_x + dx < WIDTH - 1:
                        grid[mid_y + dy][mid_x + dx] = "."

        # Down stairs.
        down_stairs_pos = None
        if floor < MINE_MAX_FLOOR:
            down_x = rng.randint(8, WIDTH - 9)
            down_y = rng.randint(4, HEIGHT - 8)
            down_stairs_pos = (down_x, down_y)
            grid[down_y][down_x] = ">"
            for dy in range(-1, 2):
                for dx in range(-1, 2):
                    if 1 <= down_y + dy < HEIGHT - 1 and 1 <= down_x + dx < WIDTH - 1 and grid[down_y + dy][down_x + dx] == "#":
                        grid[down_y + dy][down_x + dx] = "."
        else:
            grid[4][mid_x] = "?"

        # Resource nodes.
        resources = mine_floor_resource_weights(floor)
        open_tiles = [(x, y) for y in range(2, HEIGHT - 2) for x in range(3, WIDTH - 3) if grid[y][x] == "."]
        rng.shuffle(open_tiles)
        for x, y in open_tiles[:min(58, 18 + floor)]:
            grid[y][x] = rng.choice(resources)

        # Special landmark floors override part of the layout with a clear feature.
        if floor in MINE_SPECIAL_FLOORS:
            self.decorate_special_mine_floor(grid, floor, rng)

        # Breakable barrels.
        open_tiles = [(x, y) for y in range(2, HEIGHT - 2) for x in range(3, WIDTH - 3) if grid[y][x] == "."]
        rng.shuffle(open_tiles)
        for x, y in open_tiles[:2 + floor // 10]:
            if grid[y][x] == ".":
                grid[y][x] = "B"

        # Elevator/checkpoint platform. Floors unlock when reached.
        if floor == 1 or floor % 5 == 0:
            grid[HEIGHT - 3][mid_x + 4] = "A"
            grid[HEIGHT - 2][mid_x + 4] = "."
            grid[HEIGHT - 3][mid_x + 5] = "."

        if floor in [1, 5, 10, 15, 20, 30, 40]:
            grid[3][6] = "?"

        # Reassert critical navigation tiles after resources/special floors/barrels.
        # This prevents special floor decorations from accidentally trapping progression.
        if floor == 1:
            for x in range(25, 30):
                grid[HEIGHT - 1][x] = "N"
                grid[HEIGHT - 2][x] = "."
        up_x, up_y = mid_x, HEIGHT - 3
        grid[up_y][up_x] = "<"
        if up_y - 1 > 0 and grid[up_y - 1][up_x] in MINE_BREAKABLE_SYMBOLS:
            grid[up_y - 1][up_x] = "."
        if down_stairs_pos is not None:
            dx, dy = down_stairs_pos
            grid[dy][dx] = ">"
            for ox, oy in [(dx, dy + 1), (dx, dy - 1), (dx + 1, dy), (dx - 1, dy)]:
                if 1 <= oy < HEIGHT - 1 and 1 <= ox < WIDTH - 1 and grid[oy][ox] in (set(["#", " ", "?"]) | MINE_BREAKABLE_SYMBOLS):
                    grid[oy][ox] = "."
        if floor == 1 or floor % 5 == 0:
            grid[HEIGHT - 3][mid_x + 4] = "A"
            grid[HEIGHT - 2][mid_x + 4] = "."
            grid[HEIGHT - 3][mid_x + 5] = "."
        if floor in [1, 5, 10, 15, 20, 30, 40]:
            grid[3][6] = "?"
        return grid

    def decorate_special_mine_floor(self, grid: List[List[str]], floor: int, rng: random.Random):
        """Add a distinct landmark to important mine floors."""
        mid_x = WIDTH // 2
        mid_y = HEIGHT // 2
        info = MINE_SPECIAL_FLOORS.get(floor)
        if not info:
            return

        # Clear central area.
        for y in range(max(2, mid_y - 3), min(HEIGHT - 2, mid_y + 4)):
            for x in range(max(3, mid_x - 10), min(WIDTH - 3, mid_x + 11)):
                grid[y][x] = "."

        grid[mid_y - 3][mid_x] = "P"

        if floor == 5:  # miner camp
            for x in range(mid_x - 4, mid_x + 5):
                grid[mid_y][x] = "."
            grid[mid_y][mid_x - 2] = "B"
            grid[mid_y][mid_x + 2] = "B"
            grid[mid_y + 1][mid_x] = "q"
        elif floor == 10:  # lake
            for y in range(mid_y - 2, mid_y + 3):
                for x in range(mid_x - 6, mid_x + 7):
                    if ((x - mid_x) ** 2) / 36 + ((y - mid_y) ** 2) / 4 <= 1.2:
                        grid[y][x] = "~"
            grid[mid_y + 3][mid_x] = "."
        elif floor == 15:  # mushrooms
            for _ in range(18):
                x = rng.randint(mid_x - 9, mid_x + 9)
                y = rng.randint(mid_y - 2, mid_y + 3)
                if grid[y][x] == ".":
                    grid[y][x] = "m"
        elif floor == 20:  # crystals
            for _ in range(18):
                x = rng.randint(mid_x - 9, mid_x + 9)
                y = rng.randint(mid_y - 2, mid_y + 3)
                if grid[y][x] == ".":
                    grid[y][x] = rng.choice(["c", "g", "c"])
        elif floor == 30:  # ruins
            for x in range(mid_x - 8, mid_x + 9):
                grid[mid_y - 2][x] = "#"
                grid[mid_y + 2][x] = "#"
            for y in range(mid_y - 2, mid_y + 3):
                grid[y][mid_x - 8] = "#"
                grid[y][mid_x + 8] = "#"
            grid[mid_y][mid_x - 8] = "."
            grid[mid_y][mid_x + 8] = "."
            grid[mid_y][mid_x] = "g"
        elif floor == 40:  # shrine
            for y in range(mid_y - 2, mid_y + 3):
                for x in range(mid_x - 4, mid_x + 5):
                    grid[y][x] = "."
            grid[mid_y][mid_x] = "S"
            grid[mid_y + 1][mid_x - 1] = "G"
            grid[mid_y + 1][mid_x + 1] = "G"

    def get_mine_floor_map(self, floor: Optional[int] = None) -> List[List[str]]:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        key = str(floor)
        if not hasattr(self, "mine_maps") or not isinstance(self.mine_maps, dict):
            self.mine_maps = {}
        if key not in self.mine_maps:
            self.mine_maps[key] = self.make_mine_map(floor)
        if floor == self.state.mine_floor:
            self.mine_map = self.mine_maps[key]
        return self.mine_maps[key]

    def mine_enemy_floor_key(self, floor: Optional[int] = None) -> str:
        return str(max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor))))

    def is_mine_floor_cleared(self, floor: Optional[int] = None) -> bool:
        return is_mine_floor_cleared(self.state, floor or self.state.mine_floor)

    def mine_floor_stairs_available(self, floor: Optional[int] = None) -> bool:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        if floor >= MINE_MAX_FLOOR:
            return False
        return self.is_mine_floor_cleared(floor) or mine_floor_down_stairs_unlocked(self.state, floor)

    def mine_floor_enemy_remaining_count(self, floor: Optional[int] = None) -> int:
        enemies = self.get_mine_enemies(floor, create=False)
        return sum(1 for enemy in enemies if not bool(enemy.get("defeated", False)))

    def mine_floor_status_label(self, floor: Optional[int] = None) -> str:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        if self.is_mine_floor_cleared(floor):
            return "Cleared"
        remaining = self.mine_floor_enemy_remaining_count(floor)
        if remaining <= 0:
            return "Uncharted"
        return f"{remaining} hostile{'s' if remaining != 1 else ''}"

    def mine_floor_status_sentence(self, floor: Optional[int] = None) -> str:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        if self.is_mine_floor_cleared(floor):
            if floor < MINE_MAX_FLOOR:
                return "Floor cleared; the stairs down are open."
            return "The deepest floor is cleared."
        remaining = self.mine_floor_enemy_remaining_count(floor)
        if remaining == 1:
            return "1 hostile remains before the stairs down open."
        if remaining > 1:
            return f"{remaining} hostiles remain before the stairs down open."
        return "The floor is quiet."

    def locked_mine_down_stairs_message(self, floor: Optional[int] = None) -> str:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        remaining = self.mine_floor_enemy_remaining_count(floor)
        if remaining == 1:
            return "The way down is sealed. Defeat the last hostile on this floor first."
        if remaining > 1:
            return f"The way down is sealed. Defeat {remaining} hostiles on this floor first."
        return "The way down is sealed until this floor is secured."

    def grant_mine_floor_first_clear_reward(self, floor: int) -> List[str]:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor)))
        if mine_floor_clear_reward_claimed(self.state, floor):
            return []
        mark_mine_floor_clear_reward_claimed(self.state, floor)
        money = 20 + floor * 8
        exp_gain = max(4, 3 + floor)
        item_rewards: Dict[str, int] = {}
        if floor % 10 == 0:
            item_rewards["Crystal Shard"] = 1 + floor // 20
        elif floor % 5 == 0:
            item_rewards["Coal"] = 2
        self.state.money += money
        if item_rewards:
            add_inventory_items(self.state.inventory, item_rewards)
        _amount, level_lines = grant_combat_exp(self.state, exp_gain)
        reward_bits = [f"${money}", f"{exp_gain} combat EXP"]
        if item_rewards:
            reward_bits.append(format_drops(item_rewards))
        lines = [f"First clear bonus: {', '.join(reward_bits)}."]
        lines.extend(level_lines)
        return lines

    def clear_mine_floor_if_empty(self, floor: Optional[int] = None, award: bool = True) -> List[str]:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        self.ensure_mine_enemies()
        key = self.mine_enemy_floor_key(floor)
        self.mine_enemies[key] = [
            enemy for enemy in self.mine_enemies.get(key, [])
            if not bool(enemy.get("defeated", False))
        ]
        if self.mine_floor_enemy_remaining_count(floor) > 0:
            return []

        changed = mark_mine_floor_cleared(self.state, floor)
        unlocked = unlock_mine_floor_down_stairs(self.state, floor)
        self.mine_enemies[key] = []
        lines: List[str] = []
        if changed or unlocked:
            if floor < MINE_MAX_FLOOR:
                lines.append(f"Mine floor {floor} is clear. The stairs down are now open.")
            else:
                lines.append("The deepest mine floor is clear.")
        if award:
            lines.extend(self.grant_mine_floor_first_clear_reward(floor))
        return lines

    def can_descend_mine_floor(self, floor: Optional[int] = None) -> bool:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        if floor >= MINE_MAX_FLOOR:
            return False
        if self.mine_floor_stairs_available(floor):
            return True
        self.get_mine_enemies(floor)
        if self.mine_floor_enemy_remaining_count(floor) <= 0:
            self.clear_mine_floor_if_empty(floor)
        return self.mine_floor_stairs_available(floor)

    def ensure_mine_enemies(self):
        if not hasattr(self, "mine_enemies") or not isinstance(self.mine_enemies, dict):
            self.mine_enemies = {}

    def clean_mine_enemy_record(self, floor_key: str, index: int, enemy: Dict[str, object]) -> Optional[Dict[str, object]]:
        if not isinstance(enemy, dict):
            return None
        try:
            floor = max(1, min(MINE_MAX_FLOOR, int(enemy.get("floor", floor_key))))
            x = int(enemy.get("x", 0))
            y = int(enemy.get("y", 0))
        except Exception:
            return None
        species = str(enemy.get("species", "Slime")).replace("Elite ", "").strip()
        if not self.mine_enemy_passable_tile(x, y, floor=floor, ignore_enemy_id=str(enemy.get("id", ""))):
            x, y = self.nearest_mine_enemy_spawn_tile(floor, x, y)
        return {
            "id": str(enemy.get("id", f"mine:{floor}:{index}:{species}")),
            "species": species,
            "floor": floor,
            "x": x,
            "y": y,
            "alert": bool(enemy.get("alert", False)),
            "defeated": bool(enemy.get("defeated", False)),
        }

    def normalize_mine_enemies(self):
        self.ensure_mine_enemies()
        cleaned: Dict[str, List[Dict[str, object]]] = {}
        for floor_key, enemies in list(self.mine_enemies.items()):
            if not str(floor_key).isdigit() or not isinstance(enemies, list):
                continue
            if self.is_mine_floor_cleared(int(floor_key)):
                cleaned[str(int(floor_key))] = []
                continue
            clean_floor: List[Dict[str, object]] = []
            for index, enemy in enumerate(enemies):
                record = self.clean_mine_enemy_record(str(floor_key), index, enemy)
                if record is not None and not bool(record.get("defeated", False)):
                    clean_floor.append(record)
            cleaned[str(int(floor_key))] = clean_floor
        self.mine_enemies = cleaned

    def mine_enemy_passable_tile(
        self,
        x: int,
        y: int,
        floor: Optional[int] = None,
        ignore_enemy_id: str = "",
    ) -> bool:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        grid = self.get_mine_floor_map(floor)
        if y < 0 or y >= len(grid) or x < 0 or (grid and x >= len(grid[0])):
            return False
        if self.on_mine() and floor == self.state.mine_floor and x == self.state.player_x and y == self.state.player_y:
            return False
        tile = grid[y][x]
        if tile != ".":
            return False
        for enemy in self.get_mine_enemies(floor, create=False):
            if ignore_enemy_id and str(enemy.get("id", "")) == ignore_enemy_id:
                continue
            try:
                if int(enemy.get("x", -1)) == x and int(enemy.get("y", -1)) == y:
                    return False
            except Exception:
                continue
        return True

    def nearest_mine_enemy_spawn_tile(self, floor: int, x: int, y: int) -> Tuple[int, int]:
        grid = self.get_mine_floor_map(floor)
        h = len(grid)
        w = len(grid[0]) if h else WIDTH
        for radius in range(1, 12):
            candidates = []
            for yy in range(max(1, y - radius), min(h - 1, y + radius + 1)):
                for xx in range(max(1, x - radius), min(w - 1, x + radius + 1)):
                    if self.mine_enemy_passable_tile(xx, yy, floor=floor):
                        candidates.append((xx, yy))
            if candidates:
                return min(candidates, key=lambda pos: abs(pos[0] - x) + abs(pos[1] - y))
        return WIDTH // 2, HEIGHT // 2

    def generate_mine_enemies_for_floor(self, floor: int) -> List[Dict[str, object]]:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor)))
        if self.is_mine_floor_cleared(floor):
            return []
        rng = random.Random(int(self.state.mine_seed) + floor * 7331 + 40617)
        grid = self.get_mine_floor_map(floor)
        h = len(grid)
        w = len(grid[0]) if h else 0
        if not h or not w:
            return []

        critical_tiles = set()
        for yy, row in enumerate(grid):
            for xx, ch in enumerate(row):
                if ch in ["N", "U", ">", "A", "P", "S", "?"]:
                    critical_tiles.add((xx, yy))

        candidates = []
        for y in range(2, h - 2):
            for x in range(3, w - 3):
                if grid[y][x] != ".":
                    continue
                if any(abs(x - cx) + abs(y - cy) <= 6 for cx, cy in critical_tiles):
                    continue
                if floor == self.state.mine_floor and abs(x - self.state.player_x) + abs(y - self.state.player_y) <= 8:
                    continue
                candidates.append((x, y))
        rng.shuffle(candidates)

        enemies: List[Dict[str, object]] = []
        used = set()
        target_count = mine_enemy_count_for_floor(floor)
        if self.mine_hazard_label_for_date(self.state.month, self.state.day, self.state.year):
            target_count = min(7, target_count + 1)
        for x, y in candidates:
            if len(enemies) >= target_count:
                break
            if any(abs(x - ux) + abs(y - uy) < 7 for ux, uy in used):
                continue
            species = weighted_mine_enemy_name(floor, rng)
            enemies.append({
                "id": f"mine:{floor}:{len(enemies)}:{species}",
                "species": species,
                "floor": floor,
                "x": int(x),
                "y": int(y),
                "alert": False,
                "defeated": False,
            })
            used.add((x, y))

        if len(enemies) < target_count:
            fallback_candidates = []
            for y in range(2, h - 2):
                for x in range(3, w - 3):
                    if grid[y][x] != "." or (x, y) in used:
                        continue
                    if floor == self.state.mine_floor and abs(x - self.state.player_x) + abs(y - self.state.player_y) <= 3:
                        continue
                    fallback_candidates.append((x, y))
            rng.shuffle(fallback_candidates)
            for x, y in fallback_candidates:
                if len(enemies) >= target_count:
                    break
                if any(abs(x - ux) + abs(y - uy) < 4 for ux, uy in used):
                    continue
                species = weighted_mine_enemy_name(floor, rng)
                enemies.append({
                    "id": f"mine:{floor}:{len(enemies)}:{species}",
                    "species": species,
                    "floor": floor,
                    "x": int(x),
                    "y": int(y),
                    "alert": False,
                    "defeated": False,
                })
                used.add((x, y))
        return enemies

    def get_mine_enemies(self, floor: Optional[int] = None, create: bool = True) -> List[Dict[str, object]]:
        self.ensure_mine_enemies()
        key = self.mine_enemy_floor_key(floor)
        if self.is_mine_floor_cleared(int(key)):
            self.mine_enemies[key] = []
            return []
        if create and key not in self.mine_enemies:
            self.mine_enemies[key] = self.generate_mine_enemies_for_floor(int(key))
            if not self.mine_enemies[key]:
                mark_mine_floor_cleared(self.state, int(key))
                unlock_mine_floor_down_stairs(self.state, int(key))
        return self.mine_enemies.get(key, [])

    def mine_enemy_at(self, x: int, y: int, floor: Optional[int] = None) -> Optional[Dict[str, object]]:
        floor = max(1, min(MINE_MAX_FLOOR, int(floor or self.state.mine_floor)))
        if floor == self.state.mine_floor and not self.on_mine():
            return None
        for enemy in self.get_mine_enemies(floor):
            if bool(enemy.get("defeated", False)):
                continue
            try:
                if int(enemy.get("x", -1)) == int(x) and int(enemy.get("y", -1)) == int(y):
                    return enemy
            except Exception:
                continue
        return None

    def render_mine_enemy(self, enemy: Dict[str, object]) -> str:
        species = str(enemy.get("species", "Slime")).replace("Elite ", "").strip()
        profile = mine_enemy_profile(species)
        symbol = str(profile.get("symbol", "s"))[:1] or "s"
        glyph, color = actor_style(
            "hostile",
            symbol,
            elite=bool(str(enemy.get("species", "")).startswith("Elite ") or enemy.get("boss")),
            bounty=bool(enemy.get("bounty_id")),
            detailed=bool(getattr(self.state, "detailed_glyphs_enabled", True)),
            high_contrast=bool(getattr(self.state, "high_contrast_enabled", False)),
        )
        return colorize(glyph, color)

    def mine_enemy_description(self, enemy: Dict[str, object]) -> str:
        species = str(enemy.get("species", "Slime"))
        base_species = species.replace("Elite ", "").strip()
        profile = mine_enemy_profile(base_species)
        prefix = "An elite " if species.startswith("Elite ") else "A "
        fallback_name = base_species or species
        return str(profile.get("description", f"{prefix}{fallback_name} prowls this mine floor."))

    def nearest_engaging_mine_enemy(self) -> Optional[Dict[str, object]]:
        if not self.on_mine():
            return None
        px, py = self.state.player_x, self.state.player_y
        enemies = []
        for enemy in self.get_mine_enemies():
            try:
                ex, ey = int(enemy.get("x", -1)), int(enemy.get("y", -1))
            except Exception:
                continue
            if max(abs(ex - px), abs(ey - py)) <= 1:
                enemies.append((abs(ex - px) + abs(ey - py), enemy))
        if not enemies:
            return None
        return sorted(enemies, key=lambda pair: pair[0])[0][1]

    def move_mine_enemy(self, enemy: Dict[str, object]):
        try:
            ex, ey = int(enemy.get("x", 0)), int(enemy.get("y", 0))
            floor = int(enemy.get("floor", self.state.mine_floor))
        except Exception:
            return
        species = str(enemy.get("species", "Slime"))
        distance = abs(ex - self.state.player_x) + abs(ey - self.state.player_y)
        chase = distance <= 7
        enemy["alert"] = bool(chase or enemy.get("alert", False))

        options = [(1, 0), (-1, 0), (0, 1), (0, -1)]
        if chase:
            options.sort(key=lambda step: abs((ex + step[0]) - self.state.player_x) + abs((ey + step[1]) - self.state.player_y))
        else:
            random.shuffle(options)

        move_chance = 0.42
        if species in ["Wisp", "Frost Moth", "Burrower", "Razor Hare", "Cave Lynx", "Crystal Spider"]:
            move_chance = 0.58
        elif species in ["Rockback", "Thornback", "Gloomcap"]:
            move_chance = 0.30
        if random.random() > move_chance:
            return

        for ox, oy in options:
            nx, ny = ex + ox, ey + oy
            if self.mine_enemy_passable_tile(nx, ny, floor=floor, ignore_enemy_id=str(enemy.get("id", ""))):
                enemy["x"] = nx
                enemy["y"] = ny
                return

    def update_mine_enemies(self):
        if not self.on_mine():
            return
        for enemy in list(self.get_mine_enemies()):
            self.move_mine_enemy(enemy)

    def remove_mine_enemy(self, enemy: Dict[str, object]):
        enemy_id = str(enemy.get("id", ""))
        key = self.mine_enemy_floor_key(enemy.get("floor", self.state.mine_floor))
        survivors = []
        for current in self.get_mine_enemies(int(key), create=False):
            if str(current.get("id", "")) != enemy_id:
                survivors.append(current)
        self.mine_enemies[key] = survivors

    def startle_mine_enemy(self, enemy: Dict[str, object]):
        try:
            ex, ey = int(enemy.get("x", 0)), int(enemy.get("y", 0))
            floor = int(enemy.get("floor", self.state.mine_floor))
        except Exception:
            return
        dx = 1 if ex >= self.state.player_x else -1
        dy = 1 if ey >= self.state.player_y else -1
        options = [(dx, 0), (0, dy), (dx, dy), (-dy, dx), (dy, -dx), (-dx, 0), (0, -dy)]
        for ox, oy in options:
            nx, ny = ex + ox, ey + oy
            if self.mine_enemy_passable_tile(nx, ny, floor=floor, ignore_enemy_id=str(enemy.get("id", ""))):
                enemy["x"] = nx
                enemy["y"] = ny
                return

    def check_mine_enemy_engagement(self, reason: str = "nearby") -> bool:
        enemy = self.nearest_engaging_mine_enemy()
        if not enemy:
            return False
        self.start_mine_combat_encounter(enemy, reason=reason)
        return True

    def apply_mine_battle_result(self, enemy: Dict[str, object], result: object):
        outcome = combat_result_outcome(result)
        species = str(enemy.get("species", "enemy"))
        defeated = list(getattr(result, "defeated_enemies", []) or [])
        remaining_items = apply_party_status_to_combat_state(self.state, result)
        result_context = getattr(result, "return_context", {}) or {}
        record_mine_encounter_history(self.state, result_context)
        starting_items = result_context.get("farm_player_items", {}) if isinstance(result_context, dict) else {}
        used_items = consumed_combat_items(starting_items, remaining_items)
        for item_name, qty in used_items.items():
            self.state.inventory[item_name] = max(0, int(self.state.inventory.get(item_name, 0)) - int(qty))
        tactical_lines = self.apply_tactical_progression_result(result)

        if outcome == "victory":
            loot = self.combat_loot_for_result(result)
            money, items = self.grant_farm_combat_loot(loot)
            floor = max(1, min(MINE_MAX_FLOOR, int(enemy.get("floor", self.state.mine_floor))))
            exp_gain = mine_combat_exp_for_defeated(defeated or [species], floor)
            _amount, level_lines = grant_combat_exp(self.state, exp_gain)
            self.remove_mine_enemy(enemy)
            clear_lines = self.clear_mine_floor_if_empty(floor)
            self.state.mine_combat_victories += 1
            self.state.mine_enemies_defeated += max(1, len(defeated))
            minutes = self.apply_combat_time_cost(result, "mine")
            profile = farmstead_combat_profile(self.state)
            progress_lines = list(level_lines)
            progress_lines.extend(tactical_lines)
            progress_lines.extend(clear_lines)
            progress_lines.extend(self.grant_party_relationship_after_battle("victory"))
            progress_lines.extend(self.companion_after_battle_lines("victory"))
            level_text = " " + " ".join(progress_lines) if progress_lines else ""
            summary = self.combat_summary_text(
                f"Victory: {species}",
                exp_gain,
                money,
                items,
                used_items,
                minutes,
                f"HP {profile['current_hp']}/{profile['max_hp']}",
            )
            self.autosave_with_message(
                f"{summary}.{level_text}"
            )
            return

        if outcome == "defeat":
            self.state.mine_combat_defeats += 1
            self.state.combat_current_hp = max(1, int(getattr(self.state, "combat_current_hp", 1)))
            self.state.mine_floor = 1
            self.mine_map = self.get_mine_floor_map(1)
            self.state.location = "Mine"
            self.state.player_x = WIDTH // 2
            self.state.player_y = HEIGHT - 4
            self.state.facing = "DOWN"
            minutes = self.apply_combat_time_cost(result, "mine")
            profile = farmstead_combat_profile(self.state)
            party_lines = self.companion_after_battle_lines("defeat")
            party_text = " " + " ".join(party_lines) if party_lines else ""
            summary = self.combat_summary_text(
                f"Defeat: {species}",
                0,
                0,
                {},
                used_items,
                minutes,
                f"HP {profile['current_hp']}/{profile['max_hp']}",
            )
            self.autosave_with_message(f"{summary}. You were driven back to the mine entrance.{party_text}")
            return

        self.state.mine_combat_flees += 1
        self.startle_mine_enemy(enemy)
        minutes = self.apply_combat_time_cost(result, "mine")
        profile = farmstead_combat_profile(self.state)
        party_lines = self.companion_after_battle_lines("fled")
        party_text = " " + " ".join(party_lines) if party_lines else ""
        summary = self.combat_summary_text(
            f"Retreat: {species}",
            0,
            0,
            {},
            used_items,
            minutes,
            f"HP {profile['current_hp']}/{profile['max_hp']}",
        )
        self.autosave_with_message(f"{summary}. It is still prowling this floor.{party_text}")

    def start_mine_combat_encounter(self, enemy: Dict[str, object], reason: str = "nearby"):
        species = str(enemy.get("species", "enemy"))
        self.set_message(f"{species} engages you. Entering combat...")
        self.invalidate_draw_cache()
        request = mine_battle_request_for_enemy(
            self.state.mine_floor,
            enemy,
            self.state,
            self.active_farmstead_companion_profiles(),
            self.party_total_limit(),
        )
        try:
            result = run_mine_battle(request)
        except Exception as exc:
            append_debug_log(f"Combat handoff error: {type(exc).__name__}: {exc}")
            write_debug_report(self, exc, f"combat_handoff floor={self.state.mine_floor} enemy={species} reason={reason}")
            self.set_message(f"Combat could not start. Error logged to {CRASH_REPORT_PATH.name}: {exc}")
            self.invalidate_draw_cache()
            return
        self.invalidate_draw_cache()
        self.apply_mine_battle_result(enemy, result)

    def respawn_mine_enemies(self) -> int:
        self.ensure_mine_enemies()
        for floor_key in list(self.mine_enemies.keys()):
            if str(floor_key).isdigit() and self.is_mine_floor_cleared(int(floor_key)):
                self.mine_enemies[str(int(floor_key))] = []
        return 0

    def set_mine_floor(self, floor: int, from_stairs: str = "down"):
        floor = max(1, min(MINE_MAX_FLOOR, int(floor)))
        self.state.mine_floor = floor
        self.state.deepest_mine_floor = max(self.state.deepest_mine_floor, floor)
        if not self.state.unlocked_mine_elevators:
            self.state.unlocked_mine_elevators = [1]
        if floor == 1 or floor % 5 == 0:
            if floor not in self.state.unlocked_mine_elevators:
                self.state.unlocked_mine_elevators.append(floor)
                self.state.unlocked_mine_elevators = sorted(set(self.state.unlocked_mine_elevators))
                unlock_msg = f" Elevator checkpoint unlocked: floor {floor}."
            else:
                unlock_msg = ""
        else:
            unlock_msg = ""

        mine_map = self.get_mine_floor_map(floor)
        self.mine_map = mine_map
        self.get_mine_enemies(floor)

        if from_stairs == "up":
            found = [(x, y) for y, row in enumerate(mine_map) for x, ch in enumerate(row) if ch == ">"]
            if found:
                self.state.player_x, self.state.player_y = found[0][0], min(HEIGHT - 2, found[0][1] + 1)
            else:
                self.state.player_x, self.state.player_y = WIDTH // 2, HEIGHT - 4
            self.state.facing = "DOWN"
        elif from_stairs == "elevator":
            found = [(x, y) for y, row in enumerate(mine_map) for x, ch in enumerate(row) if ch == "A"]
            if found:
                self.state.player_x, self.state.player_y = found[0][0], min(HEIGHT - 2, found[0][1] + 1)
            else:
                self.state.player_x, self.state.player_y = WIDTH // 2, HEIGHT - 4
            self.state.facing = "DOWN"
        else:
            found = [(x, y) for y, row in enumerate(mine_map) for x, ch in enumerate(row) if ch in {"<", "U"}]
            if found:
                self.state.player_x, self.state.player_y = found[0][0], max(1, found[0][1] - 1)
            else:
                self.state.player_x, self.state.player_y = WIDTH // 2, HEIGHT - 4
            self.state.facing = "UP"

        special = MINE_SPECIAL_FLOORS.get(floor)
        special_msg = f" Special floor: {special['name']}." if special else ""
        status_msg = f" {self.mine_floor_status_sentence(floor)}"
        self.autosave_with_message(f"Entered mine floor {floor}: {mine_theme_for_floor(floor)}.{special_msg}{unlock_msg}{status_msg}")

    def make_house_map(self) -> List[List[str]]:
        """Create the farmhouse interior shell. Furniture is placed separately so it can be moved."""
        upgrades = getattr(self.state, "house_upgrades", []) if hasattr(self, "state") else []

        if "Deluxe Farmhouse" in upgrades:
            x0, y0, w, h = 7, 2, 40, 18
        elif "Bedroom Expansion" in upgrades:
            x0, y0, w, h = 9, 3, 36, 16
        elif "Kitchen Addition" in upgrades:
            x0, y0, w, h = 11, 3, 32, 15
        else:
            x0, y0, w, h = 13, 4, 30, 14

        grid = [[" " for _ in range(WIDTH)] for _ in range(HEIGHT)]

        for y in range(y0, y0 + h):
            for x in range(x0, x0 + w):
                if y in [y0, y0 + h - 1] or x in [x0, x0 + w - 1]:
                    grid[y][x] = "#"
                else:
                    grid[y][x] = "."

        min_x, min_y = x0 + 1, y0 + 1
        max_x, max_y = x0 + w - 2, y0 + h - 2
        center_x = (min_x + max_x) // 2

        # Soft floor bands make the house readable without becoming hard walls.
        for x in range(min_x, max_x + 1):
            if x % 2 == 0:
                grid[max_y][x] = ":"
            if x % 4 == 0 and min_y + 1 <= max_y:
                grid[min_y + 1][x] = ":"
        for y in range(min_y, max_y + 1):
            if y % 3 == 0:
                grid[y][min_x] = ":"
                grid[y][max_x] = ":"

        if "Kitchen Addition" in upgrades or "Bedroom Expansion" in upgrades or "Deluxe Farmhouse" in upgrades:
            kitchen_start = max(min_x + 1, max_x - 11)
            for y in range(min_y + 1, min(max_y, min_y + 7) + 1):
                for x in range(kitchen_start, max_x):
                    grid[y][x] = "," if (x + y) % 2 == 0 else "."
            for y in range(min_y + 1, max_y):
                if y not in [min_y + 4, min_y + 5, max_y - 2]:
                    grid[y][kitchen_start - 1] = ":"

        if "Bedroom Expansion" in upgrades or "Deluxe Farmhouse" in upgrades:
            bedroom_end = min(max_x - 1, min_x + 12)
            for y in range(min_y + 1, min(max_y, min_y + 6) + 1):
                for x in range(min_x + 1, bedroom_end + 1):
                    grid[y][x] = "," if y in [min_y + 2, min_y + 5] else "."
            for x in range(min_x + 2, bedroom_end):
                grid[min_y + 7][x] = ":"

        if "Deluxe Farmhouse" in upgrades:
            living_y = max(min_y + 8, max_y - 6)
            for y in range(living_y, max_y):
                for x in range(center_x - 7, center_x + 8):
                    if min_x < x < max_x and min_y < y < max_y:
                        grid[y][x] = "," if (x + y) % 3 == 0 else "."
            for x in range(center_x - 8, center_x + 9):
                if min_x < x < max_x:
                    grid[living_y - 1][x] = ":"

        door_x = x0 + w // 2
        door_y = y0 + h - 1
        grid[door_y][door_x] = "D"
        grid[door_y - 1][door_x] = "."
        for x in range(max(min_x, door_x - 2), min(max_x, door_x + 2) + 1):
            grid[door_y - 1][x] = "."

        custom_rows = getattr(self.state, "custom_house_map_rows", []) if hasattr(self, "state") else []
        if isinstance(custom_rows, list) and custom_rows:
            return self.normalize_house_layout_rows(custom_rows, fallback=grid)
        return grid

    def normalize_house_layout_rows(
        self,
        raw_rows: List[str],
        fallback: Optional[List[List[str]]] = None,
    ) -> List[List[str]]:
        allowed = {" ", "#", ".", ":", ",", "D"}
        fallback_grid = (
            [list(row) for row in fallback]
            if fallback
            else [[" " for _ in range(WIDTH)] for _ in range(HEIGHT)]
        )
        if not isinstance(raw_rows, list):
            return fallback_grid
        grid: List[List[str]] = []
        for y in range(HEIGHT):
            raw = str(raw_rows[y]) if y < len(raw_rows) else ""
            row = []
            for x in range(WIDTH):
                ch = raw[x] if x < len(raw) else " "
                row.append(ch if ch in allowed else ".")
            grid.append(row)
        floor_tiles = {".", ":", ","}
        floor_positions = [
            (x, y)
            for y, row in enumerate(grid)
            for x, ch in enumerate(row)
            if ch in floor_tiles
        ]
        if len(floor_positions) < 12:
            return fallback_grid
        door_positions = [
            (x, y)
            for y, row in enumerate(grid)
            for x, ch in enumerate(row)
            if ch == "D"
        ]
        if not door_positions:
            xs = [x for x, _y in floor_positions]
            max_y = max(y for _x, y in floor_positions)
            door_x = (min(xs) + max(xs)) // 2
            door_y = min(HEIGHT - 1, max_y + 1)
            grid[door_y][door_x] = "D"
            if door_y > 0:
                grid[door_y - 1][door_x] = "."
        else:
            # Keep one main exterior door and turn accidental extras into floor.
            main_door = max(door_positions, key=lambda pos: (pos[1], -abs(pos[0] - WIDTH // 2)))
            for x, y in door_positions:
                if (x, y) != main_door:
                    grid[y][x] = "."
            door_x, door_y = main_door
            if door_y > 0 and grid[door_y - 1][door_x] in {" ", "#"}:
                grid[door_y - 1][door_x] = "."
        return grid

    def house_floor_tiles(self) -> set:
        return {".", ":", ","}

    def house_layout_brushes(self) -> List[Tuple[str, str, str]]:
        return [
            ("Floor", ".", "walkable wood floor"),
            ("Inlaid Floor", ":", "walkable accent floor"),
            ("Rug Floor", ",", "walkable soft/decorative floor"),
            ("Wall", "#", "solid interior/exterior wall"),
            ("Exterior Void", " ", "empty outside the house shell"),
            ("Exit Door", "D", "the farmhouse exit; only one is kept"),
        ]

    def house_layout_palette(self, current_brush: str) -> Optional[str]:
        items = [
            MenuItem(
                label=f"{label} ({symbol if symbol != ' ' else 'space'})",
                value=symbol,
                enabled=True,
                hint=f"{hint}{' | current' if symbol == current_brush else ''}",
            )
            for label, symbol, hint in self.house_layout_brushes()
        ]
        items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
        choice = self.vertical_panel_select(
            "House Layout Brush",
            items,
            LEFT_PANEL_WIDTH,
            LEFT_PANEL_HEIGHT,
            return_back=True,
        )
        if choice is None or choice.value == MENU_BACK:
            return None
        return str(choice.value)

    def draw_house_layout_editor(self, grid: List[List[str]], cursor_x: int, cursor_y: int, brush: str):
        self.invalidate_draw_cache()
        clear_screen()
        for line in self.header_lines():
            print(line)
        cam_x, cam_y = self.camera_origin_for_cursor(cursor_x, cursor_y)
        colors = {
            ".": C.WOOD,
            ":": C.DIM,
            ",": C.HOUSE,
            "#": C.WALL,
            "D": C.WOOD,
            " ": C.WALL,
        }
        for screen_y in range(VIEW_HEIGHT):
            world_y = cam_y + screen_y
            line = []
            for screen_x in range(VIEW_WIDTH):
                world_x = cam_x + screen_x
                if world_y >= len(grid) or world_x >= len(grid[world_y]):
                    line.append(" ")
                elif world_x == cursor_x and world_y == cursor_y:
                    line.append(colorize("@", C.PLACEMENT))
                elif world_x == self.state.player_x and world_y == self.state.player_y:
                    line.append(self.render_player())
                else:
                    placed = self.get_placed_object(world_x, world_y)
                    if placed and grid[world_y][world_x] in self.house_floor_tiles():
                        key, obj_name, ax, ay = self.placed_object_at(world_x, world_y)
                        line.append(self.render_placed_object(obj_name or placed, world_x, world_y, ax, ay))
                    else:
                        tile = grid[world_y][world_x]
                        line.append(colorize(tile, colors.get(tile, C.WOOD)))
            print("".join(line))
        for line in self.footer_lines():
            print(line)
        symbol = brush if brush != " " else "space"
        print(f"House Layout Editor | Cursor {cursor_x},{cursor_y} | Brush: {symbol}")
        print("WASD/Arrows move | Z paint | P palette | I inspect | R reset preview")
        print("Q/Esc/Tab save and exit | C cancel without saving")

    def house_layout_tile_label(self, tile: str) -> str:
        return {
            ".": "Floor",
            ":": "Inlaid floor",
            ",": "Rug/accent floor",
            "#": "Wall",
            "D": "Exit door",
            " ": "Exterior void",
        }.get(tile, f"Tile '{tile}'")

    def default_house_layout_grid_for_editor(self) -> List[List[str]]:
        old_rows = list(getattr(self.state, "custom_house_map_rows", []) or [])
        self.state.custom_house_map_rows = []
        try:
            return self.make_house_map()
        finally:
            self.state.custom_house_map_rows = old_rows

    def house_layout_editor(self):
        if not self.on_house():
            self.set_message("Enter the farmhouse to edit its layout.")
            return MENU_BACK
        grid = [list(row) for row in self.house_map]
        cursor_x, cursor_y = self.state.player_x, self.state.player_y
        brush = "."
        while True:
            self.draw_house_layout_editor(grid, cursor_x, cursor_y, brush)
            key = normalize_key(read_key())
            if len(key) == 1 and key.isalpha():
                key = key.lower()
            if key in ["\t", "\x1b", "q", "b"]:
                normalized = self.normalize_house_layout_rows(["".join(row) for row in grid], fallback=self.house_map)
                self.house_map = normalized
                self.state.custom_house_map_rows = ["".join(row) for row in normalized]
                self.autosave_with_message("Saved farmhouse layout edits.")
                return "saved"
            if key == "c":
                self.set_message("Cancelled farmhouse layout edits.")
                return MENU_BACK
            if key == "p":
                selected = self.house_layout_palette(brush)
                if selected is not None:
                    brush = selected
                continue
            if key == "i":
                tile = grid[cursor_y][cursor_x]
                placed = self.get_placed_object(cursor_x, cursor_y)
                lines = [
                    f"Cursor: {cursor_x},{cursor_y}",
                    f"Shell tile: {self.house_layout_tile_label(tile)}",
                    f"Furniture: {placed or 'none'}",
                    "",
                    "Walls and exterior void block movement and furniture placement.",
                    "Floor, inlaid floor, and rug floor are walkable and furniture-safe.",
                ]
                self.vertical_panel_view("House Layout Tile", lines, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if key == "r":
                confirm = self.vertical_panel_select(
                    "Reset Layout Preview",
                    [
                        MenuItem(label="Reset to current upgrade default", value="reset", enabled=True),
                        MenuItem(label="Back", value=MENU_BACK, enabled=True),
                    ],
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )
                if confirm is not None and confirm.value == "reset":
                    grid = self.default_house_layout_grid_for_editor()
                    self.set_message("Preview reset to the default farmhouse shell. Save to keep it.")
                continue
            dx, dy = 0, 0
            if key in ["w", "UP"]:
                dy = -1
            elif key in ["s", "DOWN"]:
                dy = 1
            elif key in ["a", "LEFT"]:
                dx = -1
            elif key in ["d", "RIGHT"]:
                dx = 1
            if dx or dy:
                cursor_x = max(0, min(WIDTH - 1, cursor_x + dx))
                cursor_y = max(0, min(HEIGHT - 1, cursor_y + dy))
                continue
            if key in MENU_CONFIRM_KEYS:
                if brush in {"#", " ", "D"} and self.get_placed_object(cursor_x, cursor_y):
                    self.set_message("Move the furniture before turning this tile into wall, void, or door.")
                    continue
                if brush in {"#", " "} and (cursor_x, cursor_y) == (self.state.player_x, self.state.player_y):
                    self.set_message("Do not wall yourself in. Move first, then paint that tile.")
                    continue
                if brush == "D":
                    for yy, row in enumerate(grid):
                        for xx, ch in enumerate(row):
                            if ch == "D":
                                grid[yy][xx] = "."
                    grid[cursor_y][cursor_x] = "D"
                    if cursor_y > 0 and grid[cursor_y - 1][cursor_x] in {" ", "#"}:
                        grid[cursor_y - 1][cursor_x] = "."
                else:
                    grid[cursor_y][cursor_x] = brush
                continue
            self.set_message("House Layout Editor: move, choose a brush, paint, then save.")

    def house_floor_bounds(self) -> Tuple[int, int, int, int]:
        """Return the interior floor rectangle: min_x, min_y, max_x, max_y."""
        floor_tiles = self.house_floor_tiles()
        floor_positions = [
            (x, y)
            for y, row in enumerate(self.house_map)
            for x, ch in enumerate(row)
            if ch in floor_tiles
        ]
        if not floor_positions:
            return 15, 5, 40, 16
        xs = [p[0] for p in floor_positions]
        ys = [p[1] for p in floor_positions]
        return min(xs), min(ys), max(xs), max(ys)

    def default_house_furniture_layout(self) -> Dict[str, Tuple[int, int]]:
        """Logical starting furniture layout for the current house size."""
        min_x, min_y, max_x, max_y = self.house_floor_bounds()
        center_x = (min_x + max_x) // 2

        layout = {
            "Bed": (min_x + 2, min_y + 1),
            "Nightstand": (min_x + 5, min_y + 1),
            "Dresser": (min_x + 7, min_y + 1),
            "Wall Calendar": (min_x + 11, min_y),
            "Bookshelf": (min_x + 2, max_y - 4),
            "Writing Desk": (min_x + 4, max_y - 4),
            "Wooden Table": (center_x - 1, min_y + 6),
            "Wooden Chair": (center_x, min_y + 7),
            "Flower Vase": (center_x + 2, min_y + 6),
            "Decorative Rug": (center_x + 4, max_y - 4),
            "Television": (max_x - 4, min_y + 3),
            "Shelf": (max_x - 6, min_y + 1),
            "Standing Lamp": (max_x - 2, max_y - 3),
        }

        if "Kitchen Addition" in self.state.house_upgrades or "Bedroom Expansion" in self.state.house_upgrades or "Deluxe Farmhouse" in self.state.house_upgrades:
            layout["Television"] = (max_x - 4, max_y - 5)
            layout["Kitchen Counter"] = (max_x - 10, min_y + 2)
            layout["Pantry"] = (max_x - 5, min_y + 2)
            layout["Wash Basin"] = (max_x - 10, min_y + 4)
            layout["House Plant"] = (max_x - 2, max_y - 2)
            layout["Tea Table"] = (center_x + 2, max_y - 5)

        if "Bedroom Expansion" in self.state.house_upgrades or "Deluxe Farmhouse" in self.state.house_upgrades:
            layout["Wardrobe"] = (min_x + 10, min_y + 1)
            layout["Wall Mirror"] = (min_x + 13, min_y + 1)
            layout["Fireplace"] = (center_x - 1, min_y + 2)
            layout["Armchair"] = (center_x + 4, min_y + 3)

        if "Deluxe Farmhouse" in self.state.house_upgrades:
            layout["Room Divider"] = (min_x + 14, min_y + 5)
            layout["Couch"] = (center_x - 2, max_y - 6)
            layout["Large Rug"] = (center_x - 8, max_y - 4)
            layout["Wall Art"] = (center_x + 7, min_y)

        if getattr(self.state, "spouse_moved_to_farm", False):
            layout["Couch"] = (center_x - 3, max(min_y + 4, max_y - 5))
            layout["Tea Table"] = (center_x + 1, max(min_y + 4, max_y - 5))
            layout["Wall Art"] = (min(max_x - 7, center_x + 7), min_y)
            layout["Family Table"] = (center_x - 1, min(max_y - 2, min_y + 8))
            layout["Keepsake Chest"] = (max_x - 5, max_y - 2)

        if getattr(self.state, "children", []):
            youngest_stage = "Child"
            try:
                youngest = min(self.state.children, key=lambda child: self.household_child_age_months(child))
                youngest_stage = self.household_child_stage(youngest)
            except Exception:
                youngest_stage = "Child"
            layout["Crib" if youngest_stage in ["Newborn", "Infant"] else "Child Bed"] = (min_x + 2, min_y + 4)
            layout["Toy Shelf"] = (min_x + 6, min_y + 4)
            layout["Study Desk"] = (min_x + 9, max_y - 5)
            layout["Large Rug"] = (max(min_x + 2, center_x - 8), max_y - 3)
            layout["Bookshelf"] = (min_x + 2, max_y - 5)
            layout["Wooden Chair"] = (min_x + 6, max_y - 3)
            layout["Shelf"] = (min_x + 12, max_y - 5)

        return layout


    def make_town_room_shell(self, x0: int = 7, y0: int = 2, w: int = 40, h: int = 18, door_x: int = 27) -> Tuple[List[List[str]], int, int, int, int, int, int]:
        grid = [[" " for _ in range(WIDTH)] for _ in range(HEIGHT)]
        for y in range(y0, y0 + h):
            for x in range(x0, x0 + w):
                grid[y][x] = "#" if y in [y0, y0 + h - 1] or x in [x0, x0 + w - 1] else "."
        for y in range(y0 + 2, y0 + h - 2, 4):
            for x in range(x0 + 2, x0 + w - 2):
                if grid[y][x] == ".":
                    grid[y][x] = ":"
        for x in range(x0 + 4, x0 + w - 4, 8):
            for y in range(y0 + 2, y0 + h - 2):
                if grid[y][x] == ".":
                    grid[y][x] = ":"
        door_y = y0 + h - 1
        grid[door_y][door_x] = "D"
        grid[door_y - 1][door_x] = "."
        return grid, x0, y0, w, h, door_x, door_y

    def draw_hline(self, grid: List[List[str]], x1: int, x2: int, y: int, ch: str):
        for x in range(x1, x2 + 1):
            if 0 <= y < len(grid) and 0 <= x < len(grid[y]):
                grid[y][x] = ch

    def draw_vline(self, grid: List[List[str]], x: int, y1: int, y2: int, ch: str):
        for y in range(y1, y2 + 1):
            if 0 <= y < len(grid) and 0 <= x < len(grid[y]):
                grid[y][x] = ch

    def draw_rect_tiles(self, grid: List[List[str]], x1: int, y1: int, x2: int, y2: int, ch: str):
        for y in range(y1, y2 + 1):
            for x in range(x1, x2 + 1):
                if 0 <= y < len(grid) and 0 <= x < len(grid[y]):
                    grid[y][x] = ch

    def stamp_tiles(self, grid: List[List[str]], x0: int, y0: int, rows: List[str], transparent: str = " "):
        for dy, row in enumerate(rows):
            for dx, ch in enumerate(row):
                if ch == transparent:
                    continue
                y = y0 + dy
                x = x0 + dx
                if 0 <= y < len(grid) and 0 <= x < len(grid[y]):
                    grid[y][x] = ch

    def town_interior_spoke_rows(self, door_y: int) -> Tuple[int, ...]:
        return tuple(y for y in (8, 11, 14, 16) if 3 <= y < door_y)

    def restore_town_interior_spoke_walls(self, grid: List[List[str]], door_x: int, door_y: int):
        """Lightly divide public interiors into side rooms around a central hall."""
        clear_rows = set(self.town_interior_spoke_rows(door_y))
        for y in range(3, door_y):
            if y in clear_rows or not (0 <= y < len(grid)):
                continue
            for x in (door_x - 4, door_x + 4):
                if 0 <= x < len(grid[y]) and grid[y][x] in {".", ":", ","}:
                    grid[y][x] = "#"

    def clear_town_interior_walkways(self, grid: List[List[str]], door_x: int, door_y: int):
        """Guarantee the center plus-shaped hall remains open and non-colliding."""
        self.restore_town_interior_spoke_walls(grid, door_x, door_y)
        min_x = max(0, door_x - 19)
        max_x = min(len(grid[0]) - 1 if grid else 0, door_x + 18)
        for y in range(3, door_y):
            # The front-door column is the natural approach. Keep a three-tile
            # center lane clear from the entrance to the back rooms.
            if not (0 <= y < len(grid)):
                continue
            for x in range(door_x - 1, door_x + 2):
                if 0 <= x < len(grid[y]):
                    grid[y][x] = "."
        for y in self.town_interior_spoke_rows(door_y):
            if not (0 <= y < len(grid)):
                continue
            for x in range(min_x, max_x + 1):
                if 0 <= x < len(grid[y]):
                    grid[y][x] = "."
        if 0 <= door_y < len(grid) and 0 <= door_x < len(grid[door_y]):
            grid[door_y][door_x] = "D"
        if 0 <= door_y - 1 < len(grid) and 0 <= door_x < len(grid[door_y - 1]):
            grid[door_y - 1][door_x] = "."

    def add_town_interior_living_quarters(self, grid: List[List[str]], *, left_bed: bool = True, right_bed: bool = False):
        """Add readable private rooms without blocking the main shop approach."""
        floor_tiles = {".", ":", ","}

        def in_bounds(x: int, y: int) -> bool:
            return 0 <= y < len(grid) and 0 <= x < len(grid[y])

        def set_floor(x: int, y: int, ch: str):
            if in_bounds(x, y) and grid[y][x] in floor_tiles:
                grid[y][x] = ch

        def clear_room_path(x: int):
            for y in range(3, 10):
                if in_bounds(x, y) and grid[y][x] not in {"#", "D", "$", "&", "g", "x", "n", "d"}:
                    grid[y][x] = "."

        # Back-room partitions. Openings at x=15 and x=39 keep both side rooms
        # reachable while the center aisle remains clear for counter access.
        for x in range(8, 23):
            if x != 15:
                set_floor(x, 8, "#")
        for x in range(32, 46):
            if x != 39:
                set_floor(x, 8, "#")
        for y in range(3, 8):
            set_floor(22, y, "#")
            set_floor(32, y, "#")
        clear_room_path(15)
        clear_room_path(39)

        for y in range(3, 8):
            for x in range(8, 22):
                if grid[y][x] in floor_tiles:
                    grid[y][x] = ","
            for x in range(33, 46):
                if grid[y][x] in floor_tiles:
                    grid[y][x] = ","

        if left_bed:
            self.draw_hline(grid, 9, 12, 3, "B")
            grid[3][16] = "u"
            grid[5][14] = "c"
            grid[6][16] = "t"
        if right_bed:
            self.draw_hline(grid, 41, 44, 3, "B")
            grid[3][37] = "u"
            grid[5][40] = "c"
            grid[6][38] = "t"

    def draw_town_room_outline(
        self,
        grid: List[List[str]],
        x1: int,
        y1: int,
        x2: int,
        y2: int,
        openings: Optional[List[Tuple[int, int]]] = None,
    ):
        """Draw an interior room boundary, then cut explicit door openings."""
        self.draw_hline(grid, x1, x2, y1, "#")
        self.draw_hline(grid, x1, x2, y2, "#")
        self.draw_vline(grid, x1, y1, y2, "#")
        self.draw_vline(grid, x2, y1, y2, "#")
        for ox, oy in openings or []:
            if 0 <= oy < len(grid) and 0 <= ox < len(grid[oy]):
                grid[oy][ox] = "."

    def open_town_interior_path(self, grid: List[List[str]], points: List[Tuple[int, int]]):
        """Clear a simple orthogonal path through a hand-authored interior."""
        if len(points) < 2:
            return

        def open_cell(x: int, y: int):
            if 0 <= y < len(grid) and 0 <= x < len(grid[y]) and grid[y][x] not in {"D", "&"}:
                grid[y][x] = "."

        for (x1, y1), (x2, y2) in zip(points, points[1:]):
            if x1 != x2:
                step = 1 if x2 >= x1 else -1
                for x in range(x1, x2 + step, step):
                    open_cell(x, y1)
            if y1 != y2:
                step = 1 if y2 >= y1 else -1
                for y in range(y1, y2 + step, step):
                    open_cell(x2, y)

    def finish_town_interior_layout(
        self,
        grid: List[List[str]],
        door_x: int,
        door_y: int,
        service: Tuple[int, int],
        resident_anchors: Optional[List[Tuple[int, int]]] = None,
        extra_paths: Optional[List[List[Tuple[int, int]]]] = None,
    ):
        """Keep bespoke authored interiors usable without forcing identical spokes."""
        if 0 <= door_y < len(grid) and 0 <= door_x < len(grid[door_y]):
            grid[door_y][door_x] = "D"
        if 0 <= door_y - 1 < len(grid) and 0 <= door_x < len(grid[door_y - 1]):
            grid[door_y - 1][door_x] = "."
        service_x, service_y = service
        approach_y = min(door_y - 1, service_y + 1)
        self.open_town_interior_path(
            grid,
            [(door_x, door_y - 1), (door_x, approach_y), (service_x, approach_y)],
        )
        for anchor in resident_anchors or []:
            self.open_town_interior_path(grid, [(door_x, door_y - 1), anchor])
        for path in extra_paths or []:
            self.open_town_interior_path(grid, path)

    def make_practical_town_interior(
        self,
        rooms: List[Tuple[int, int, int, int, List[Tuple[int, int]]]],
        halls: List[List[Tuple[int, int]]],
        fixtures: List[Tuple[int, int, str]],
        *,
        door_x: int = 27,
        door_y: int = 19,
    ) -> List[List[str]]:
        """Create a small authored interior from real rooms and hall paths.

        Unlike the old spoke template, this starts with empty space, draws only
        the rooms each building actually needs, then adds sparse functional
        fixtures. Decorative furniture remains passive.
        """
        grid = [[" " for _ in range(WIDTH)] for _ in range(HEIGHT)]
        floor_cells: set = set()

        def mark_floor(x: int, y: int):
            if 1 <= x < WIDTH - 1 and 1 <= y < HEIGHT - 1:
                floor_cells.add((x, y))
                grid[y][x] = "."

        def room(x1: int, y1: int, x2: int, y2: int, openings: List[Tuple[int, int]]):
            openings_set = set(openings)
            for y in range(max(1, y1), min(HEIGHT - 2, y2) + 1):
                for x in range(max(1, x1), min(WIDTH - 2, x2) + 1):
                    edge = x in {x1, x2} or y in {y1, y2}
                    if edge and (x, y) not in openings_set:
                        grid[y][x] = "#"
                    else:
                        mark_floor(x, y)

        def hall(points: List[Tuple[int, int]]):
            if len(points) < 2:
                return
            for (x1, y1), (x2, y2) in zip(points, points[1:]):
                x, y = x1, y1
                while True:
                    mark_floor(x, y)
                    if (x, y) == (x2, y2):
                        break
                    if x != x2:
                        x += 1 if x2 > x else -1
                    elif y != y2:
                        y += 1 if y2 > y else -1

        for spec in rooms:
            room(*spec)
        for path in halls:
            hall(path)
        mark_floor(door_x, door_y - 1)
        for x, y in list(floor_cells):
            for dy in (-1, 0, 1):
                for dx in (-1, 0, 1):
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < WIDTH and 0 <= ny < HEIGHT and (nx, ny) not in floor_cells and grid[ny][nx] == " ":
                        grid[ny][nx] = "#"
        for x, y, ch in fixtures:
            if 0 <= y < HEIGHT and 0 <= x < WIDTH and grid[y][x] in {".", ",", ":"}:
                grid[y][x] = ch
        grid[door_y][door_x] = "D"
        grid[door_y - 1][door_x] = "."
        return grid

    def make_town_counter_fixtures(self, cx: int, y: int) -> List[Tuple[int, int, str]]:
        """Return a complete readable counter: stock/forms, counter, clerk."""
        return [
            (cx - 3, y, "$"),
            (cx - 2, y, "-"),
            (cx - 1, y, "-"),
            (cx, y, "&"),
            (cx + 1, y, "-"),
            (cx + 2, y, "-"),
        ]

