    def make_wilderness_map(self, seed: int = 1337) -> List[List[str]]:
        """Create a deterministic, readable wilderness chunk with rivers, trails, biomes, and clustered resources."""
        width, height = 86, 38
        rng = random.Random(seed)
        grid = [["." for _ in range(width)] for _ in range(height)]
        season_symbols = self.wilderness_seasonal_forage_symbols()
        gate_x = width // 2

        # Outer forest edge.
        for x in range(width):
            grid[0][x] = "#"
            grid[height - 1][x] = "#"
        for y in range(height):
            grid[y][0] = "#"
            grid[y][width - 1] = "#"

        # South exit/entry marker. Non-origin chunks replace S later.
        for x in range(gate_x - 2, gate_x + 3):
            grid[height - 1][x] = "S"
            grid[height - 2][x] = ":"
            grid[height - 3][x] = ":"

        # Primary vertical river. More coherent and less jittery.
        river_path = []
        river_x = rng.choice([width // 3, width // 2 + 11, width // 2 - 13])
        river_momentum = 0
        for y in range(2, height - 2):
            if rng.random() < 0.28:
                river_momentum = rng.choice([-1, 0, 1])
            if rng.random() < 0.40:
                river_x += river_momentum
            river_x = max(7, min(width - 8, river_x))
            river_path.append((river_x, y))
            river_width = 1 if rng.random() < 0.84 else 2
            for dx in range(-river_width, river_width + 1):
                xx = river_x + dx
                if 1 <= xx < width - 1:
                    grid[y][xx] = "~"

        # Smaller tributary, with a bridgeable crossing.
        trib_y = rng.randint(8, height - 12)
        main_at_trib = min(river_path, key=lambda p: abs(p[1] - trib_y))[0]
        trib_start = rng.choice([3, width - 4])
        step = 1 if trib_start < main_at_trib else -1
        trib_x = trib_start
        while (step > 0 and trib_x <= main_at_trib) or (step < 0 and trib_x >= main_at_trib):
            if 1 <= trib_x < width - 1 and 2 <= trib_y < height - 2:
                grid[trib_y][trib_x] = "~"
                if rng.random() < 0.18:
                    trib_y += rng.choice([-1, 1])
                    trib_y = max(3, min(height - 4, trib_y))
            trib_x += step

        # A few ponds/lakes, smaller and more intentional.
        for _ in range(3):
            cx = rng.randint(10, width - 11)
            cy = rng.randint(6, height - 9)
            rx = rng.randint(2, 4)
            ry = rng.randint(1, 3)
            for yy in range(cy - ry, cy + ry + 1):
                for xx in range(cx - rx, cx + rx + 1):
                    if 1 <= xx < width - 1 and 1 <= yy < height - 1:
                        if grid[yy][xx] in ["S", "="]:
                            continue
                        if ((xx - cx) ** 2) / max(1, rx ** 2) + ((yy - cy) ** 2) / max(1, ry ** 2) <= 1.10:
                            grid[yy][xx] = "~"

        # Paint broad biome terrain before trails/resources.
        self.assign_wilderness_biome_tiles(grid, rng)
        self.wilderness_dress_shorelines(grid, 0, 0, rng)
        self.wilderness_add_biome_landforms(grid, 0, 0, rng)

        # Light local trails and bridge crossings.
        self.wilderness_improve_traversability(grid, rng)

        # Resource clusters by biome, instead of uniform random noise.
        # Deep woods: tree groves.
        for _ in range(5):
            self.wilderness_resource_cluster(grid, rng, rng.randint(6, width // 2), rng.randint(4, height - 5), rng.randint(4, 8), rng.randint(2, 4), ["T", "T", "*"], 0.26)

        # Rocky ridge: stones.
        for _ in range(4):
            self.wilderness_resource_cluster(grid, rng, rng.randint(width // 2, width - 8), rng.randint(height // 2, height - 5), rng.randint(4, 8), rng.randint(2, 4), ["o", "o", "o", "^"], 0.28)

        # Meadows and clearings: grass/herbs/forage.
        for _ in range(5):
            symbols = ["^", "^", self.choose_biome_forage_symbol(";", rng), rng.choice(season_symbols)]
            self.wilderness_resource_cluster(grid, rng, rng.randint(width // 2, width - 8), rng.randint(4, height - 8), rng.randint(5, 9), rng.randint(2, 4), symbols, 0.14)

        # Mushroom hollow and riverbank clusters.
        for _ in range(3):
            self.wilderness_resource_cluster(grid, rng, rng.randint(7, width // 2), rng.randint(height // 2, height - 5), rng.randint(4, 7), rng.randint(2, 4), [self.choose_biome_forage_symbol("l", rng), "l", "^"], 0.13)
        for _ in range(4):
            # Find a water tile and place riverbank forage around it.
            waters = [(x, y) for y, row in enumerate(grid) for x, ch in enumerate(row) if ch == "~"]
            if waters:
                wx, wy = rng.choice(waters)
                self.wilderness_resource_cluster(grid, rng, wx + rng.randint(-3, 3), wy + rng.randint(-2, 2), 4, 2, [self.choose_biome_forage_symbol("r", rng), "h", "^", "r"], 0.16)

        # Sparse ambient clutter, kept low so paths/biomes remain readable.
        for y in range(1, height - 1):
            for x in range(1, width - 1):
                if grid[y][x] not in [".", ";", "%", "l", "r", "x"]:
                    continue
                roll = rng.random()
                tile = grid[y][x]
                if roll < 0.035:
                    grid[y][x] = "T" if tile in ["%", "l"] else "^"
                elif roll < 0.055:
                    grid[y][x] = "o" if tile == "x" else "*"
                elif roll < 0.085:
                    grid[y][x] = self.choose_biome_forage_symbol(tile, rng) if tile in WILDERNESS_BIOME_TILES else rng.choice(season_symbols)

        # Named wilderness points of interest / clearings.
        self.decorate_wilderness_points_of_interest(grid, rng)

        # Ensure generated POIs are reachable before returning this new map.
        blocking_poi = set(["#", "~", "T", "o", "*", "?", "R", "J", "P", "K", "Q", "Y", "u", "W", "N", "F"])
        for yy, row in enumerate(list(grid)):
            for xx, ch in enumerate(list(row)):
                if ch not in ["R", "J", "P", "K", "Q", "Y", "u", "B"]:
                    continue
                approaches = [
                    (ax, ay)
                    for ax, ay in [(xx, yy + 1), (xx, yy - 1), (xx + 1, yy), (xx - 1, yy)]
                    if 1 <= ax < width - 1 and 1 <= ay < height - 1
                ]
                if any(grid[ay][ax] not in blocking_poi for ax, ay in approaches):
                    continue
                for ax, ay in approaches:
                    if grid[ay][ax] not in ["~", "=", "S"]:
                        grid[ay][ax] = "."
                        break

        # Safe entry area and town exit.
        for yy in range(height - 5, height - 1):
            for xx in range(gate_x - 4, gate_x + 5):
                if 0 <= xx < width and 0 <= yy < height and grid[yy][xx] != "S":
                    grid[yy][xx] = ":" if yy >= height - 3 else "."
        for x in range(gate_x - 2, gate_x + 3):
            grid[height - 1][x] = "S"

        # Final polish: open entries, reduce clutter near paths, and add bridges where needed.
        self.limit_wilderness_valuable_spawns(grid, 0, 0, random.Random(int(seed) + 30600))
        self.wilderness_polish_noise(grid, rng)
        self.wilderness_bridge_near_trails(grid, rng, fallback=True)
        self.clear_wilderness_chunk_entry_lanes(grid)
        self.ensure_origin_wilderness_poi_markers(grid)
        self.ensure_wilderness_interactable_accessibility(grid)

        return grid

    def decorate_wilderness_points_of_interest(self, grid: List[List[str]], rng: random.Random):
        """Build the authored home-region collection as complete landmark sites."""
        height = len(grid)
        width = len(grid[0]) if height else 0
        if width <= 0:
            return
        bridges = [(x, y) for y, row in enumerate(grid) for x, ch in enumerate(row) if ch == "="]
        if bridges:
            ox, oy = bridges[len(bridges) // 2]
            overlook_x = max(10, min(width - 11, ox + 8))
            overlook_y = max(7, min(height - 8, oy))
        else:
            overlook_x, overlook_y = width // 2, height // 2
        sites = [
            (width // 2 + 10, height - 9, "ranger_camp"),
            (13, 9, "stone_ruin"),
            (38, 7, "spring_garden"),
            (27, 19, "fungal_garden"),
            (overlook_x, overlook_y, "overlook"),
            (width - 11, height - 11, "trail_shelter"),
        ]
        for x, y, kind in sites:
            self.stamp_wilderness_landmark_site(grid, x, y, kind, rng)

    def ensure_wilderness_poi_accessibility(self):
        """Ensure generated/backfilled wilderness POIs have at least one adjacent walkable approach."""
        if not hasattr(self, "wilderness_map") or not self.wilderness_map:
            return
        grid = self.wilderness_map
        height = len(grid)
        width = len(grid[0]) if height else 0
        blocking = set(["#", "~", "T", "o", "*", "?", "R", "J", "P", "K", "Q", "Y", "u"])
        for y, row in enumerate(list(grid)):
            for x, ch in enumerate(list(row)):
                if ch not in ["R", "J", "P", "K", "Q", "Y", "u", "B"]:
                    continue
                approaches = []
                for ax, ay in [(x, y + 1), (x, y - 1), (x + 1, y), (x - 1, y)]:
                    if 1 <= ax < width - 1 and 1 <= ay < height - 1:
                        approaches.append((ax, ay))
                if any(grid[ay][ax] not in blocking for ax, ay in approaches):
                    continue
                for ax, ay in approaches:
                    if grid[ay][ax] not in ["~", "=", "S"]:
                        grid[ay][ax] = "."
                        break

    def ensure_wilderness_points_of_interest(self):
        """Backfill v93 wilderness POIs into old persistent wilderness maps if missing."""
        # Backfill v94 biome terrain if this is an older wilderness map.
        existing_tiles = {ch for row in self.wilderness_map for ch in row} if hasattr(self, "wilderness_map") and self.wilderness_map else set()
        if self.wilderness_map and not (existing_tiles & WILDERNESS_BIOME_TILES):
            rng_biome = random.Random(int(self.state.wilderness_seed) + 9400)
            self.assign_wilderness_biome_tiles(self.wilderness_map, rng_biome)

        if not hasattr(self, "wilderness_map") or not self.wilderness_map:
            self.wilderness_map = self.make_wilderness_map(self.state.wilderness_seed)
            return
        existing = {ch for row in self.wilderness_map for ch in row}
        required = {"R", "J", "Y", "u", "K", "Q"}
        if required.issubset(existing):
            return
        rng = random.Random(int(self.state.wilderness_seed) + 9300)
        self.decorate_wilderness_points_of_interest(self.wilderness_map, rng)
        self.ensure_wilderness_poi_accessibility()

    def ensure_origin_wilderness_poi_markers(self, grid: List[List[str]]):
        """Reassert non-loot origin POI anchors that late trail cleanup can erase."""
        h = len(grid)
        w = len(grid[0]) if h else 0
        if not h or not w:
            return

        existing = {ch for row in grid for ch in row}
        if "K" not in existing:
            x, y = min(w - 8, w // 2 + 8), max(6, h // 2 - 2)
            self.stamp_wilderness_landmark_site(grid, x, y, "overlook", random.Random(int(self.state.wilderness_seed) + 9301))
        if "R" not in existing:
            x, y = min(w - 8, w // 2 + 10), h - 9
            self.stamp_wilderness_landmark_site(grid, x, y, "ranger_camp", random.Random(int(self.state.wilderness_seed) + 9302))
        if "Q" not in existing:
            x, y = w - 9, h - 11
            self.stamp_wilderness_landmark_site(grid, x, y, "trail_shelter", random.Random(int(self.state.wilderness_seed) + 9303))

    def origin_world_gateway_positions(self) -> Dict[str, Tuple[int, int]]:
        """Stable entrances linking the authored home maps to the continuous world."""
        return {"town": (27, 29), "farm": (66, 18), "mine": (48, 14)}

    def origin_world_sign_positions(self) -> Dict[str, Tuple[int, int]]:
        return {
            "town_approach": (29, 34),
            "crossroads": (50, 35),
            "mine_approach": (49, 16),
            "farm_approach": (65, 21),
        }

    def origin_world_sign_kind(self, chunk_x: int, chunk_y: int, x: int, y: int) -> str:
        if (int(chunk_x), int(chunk_y)) != (0, 0):
            return ""
        point = (int(x), int(y))
        return next((kind for kind, position in self.origin_world_sign_positions().items() if position == point), "")

    def origin_world_sign_at(self, x: int, y: int) -> str:
        if not self.on_wilderness():
            return ""
        return self.origin_world_sign_kind(
            self.state.wilderness_chunk_x, self.state.wilderness_chunk_y, x, y
        )

    def origin_world_home_road_at(self, x: int, y: int) -> bool:
        """Recognize the hand-authored road as real network infrastructure."""
        town_x, town_y = self.origin_world_gateway_positions()["town"]
        farm_x, farm_y = self.origin_world_gateway_positions()["farm"]
        mine_x, mine_y = self.origin_world_gateway_positions()["mine"]
        px, py = int(x), int(y)
        return bool(
            (px == town_x and town_y <= py <= 36)
            or (py == 36 and town_x <= px <= farm_x)
            or (px == farm_x and farm_y <= py <= 36)
            or (px == mine_x and mine_y <= py <= 36)
        )

    def origin_world_sign_lines(self, sign_kind: str) -> List[str]:
        season_note = (
            "Winter: inland ice may provide temporary foot crossings."
            if self.state.season == "Winter"
            else "Open water and seasonal terrain may alter side routes."
        )
        headings = {
            "town_approach": ("TOWN APPROACH", "The lower spur reaches Elsewhere's civic streets."),
            "crossroads": ("HOME ROAD CROSSROADS", "The maintained home road joins all three local destinations."),
            "mine_approach": ("MINE APPROACH", "The stone building ahead is the permanent regional mine entrance."),
            "farm_approach": ("FARM APPROACH", "The fenced working farm lies at the end of this maintained lane."),
        }
        title, description = headings.get(str(sign_kind), ("HOME ROAD SIGN", "A maintained route marker."))
        return [
            title, "", description, "",
            "Town: lower road, then the western spur.",
            "Farm: lower road, then the eastern spur.",
            "Mine: take the northern stone-building branch.",
            "Regional routes: continue beyond the home district.",
            "", season_note,
        ]

    def read_origin_world_sign(self, sign_kind: str) -> None:
        lines = self.origin_world_sign_lines(sign_kind)
        self.vertical_panel_view(lines[0].title(), lines, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        self.set_message("Read the home-road wayfinding sign.")

    def origin_world_gateway_kind(self, chunk_x: int, chunk_y: int, x: int, y: int) -> str:
        if (int(chunk_x), int(chunk_y)) != (0, 0):
            return ""
        point = (int(x), int(y))
        for gateway, position in self.origin_world_gateway_positions().items():
            if point == position:
                return gateway
        return ""

    def origin_world_gateway_at(self, x: int, y: int) -> str:
        if not self.on_wilderness():
            return ""
        return self.origin_world_gateway_kind(
            self.state.wilderness_chunk_x, self.state.wilderness_chunk_y, x, y
        )

    def apply_origin_world_hub(self, grid: List[List[str]]) -> None:
        """Reserve a compact physical home district inside the origin world chunk."""
        if not grid or len(grid) < 36 or len(grid[0]) < 82:
            return

        def fill(x0: int, y0: int, x1: int, y1: int, tile: str) -> None:
            for yy in range(max(1, y0), min(len(grid) - 1, y1 + 1)):
                for xx in range(max(1, x0), min(len(grid[0]) - 1, x1 + 1)):
                    grid[yy][xx] = tile

        def border(x0: int, y0: int, x1: int, y1: int, tile: str = "#") -> None:
            for xx in range(x0, x1 + 1):
                grid[y0][xx] = tile
                grid[y1][xx] = tile
            for yy in range(y0, y1 + 1):
                grid[yy][x0] = tile
                grid[yy][x1] = tile

        fill(8, 23, 38, 35, ";")
        for yy in range(25, 35):
            for xx in range(12, 35):
                if yy in {28, 29, 30} or xx in {20, 21, 27, 28}:
                    grid[yy][xx] = ":"
        for x0, y0, x1, y1 in ((11, 24, 18, 27), (23, 24, 31, 27), (11, 31, 18, 34), (30, 31, 36, 34)):
            fill(x0, y0, x1, y1, "#")
        town_x, town_y = self.origin_world_gateway_positions()["town"]
        grid[town_y][town_x] = "S"
        grid[town_y - 1][town_x] = ":"
        for yy in range(town_y + 1, len(grid)):
            grid[yy][town_x] = ":"

        fill(57, 4, 81, 19, ";")
        border(58, 5, 80, 18)
        fill(60, 6, 67, 9, "#")
        grid[9][63] = ":"
        fill(60, 12, 68, 17, ",")
        fill(72, 12, 77, 17, "~")
        for xx in range(63, 81):
            grid[11][xx] = ":"
        for yy in range(11, 18):
            grid[yy][66] = ":"
        farm_x, farm_y = self.origin_world_gateway_positions()["farm"]
        grid[farm_y][farm_x] = "F"

        # A real mine building now stands between town and farm. Its door uses
        # the existing cave silhouette, but origin-gateway dispatch sends it to
        # the authored mine progression rather than a procedural cave.
        fill(42, 5, 54, 14, ";")
        border(43, 6, 53, 14)
        fill(44, 7, 52, 13, "#")
        mine_x, mine_y = self.origin_world_gateway_positions()["mine"]
        grid[mine_y][mine_x] = "V"

        # One continuous home road visibly links all three destinations while
        # routing around the town blocks instead of cutting through them.
        for yy in range(town_y, 37):
            grid[yy][town_x] = ":"
        for xx in range(town_x, farm_x + 1):
            grid[36][xx] = ":"
        for yy in range(farm_y, 37):
            grid[yy][farm_x] = ":"
        for yy in range(mine_y, 37):
            grid[yy][mine_x] = ":"
        for sign_x, sign_y in self.origin_world_sign_positions().values():
            grid[sign_y][sign_x] = "?"
        grid[town_y][town_x] = "S"
        grid[farm_y][farm_x] = "F"
        grid[mine_y][mine_x] = "V"

    def enter_origin_world_gateway(self, gateway: str) -> None:
        if gateway == "mine":
            self.transition_to_mine(return_location="WildernessOrigin")
            return
        if gateway == "farm":
            self.state.location = "Farm"
            self.state.player_x = max(2, self.farm_width() - 3)
            self.state.player_y = min(10, self.farm_height() - 2)
            self.state.facing = "LEFT"
            self.update_farm_animal_actors(force=True)
            self.autosave_with_message("You follow the home lane onto your farm.")
            return
        self.return_from_wilderness_to_town(emergency=False)

    def transition_from_farm_to_origin_world(self) -> None:
        self.state.location = "Wilderness"
        self.set_wilderness_chunk(0, 0, entry_side="center")
        gate_x, gate_y = self.origin_world_gateway_positions()["farm"]
        self.state.player_x = gate_x
        self.state.player_y = min(self.active_map_height() - 1, gate_y + 1)
        self.state.facing = "UP"
        self.autosave_with_message("You leave the farm by the east lane and rejoin the open world.")

    def wilderness_chunk_key(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> str:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        return f"{cx},{cy}"

    def claim_scope_key(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> str:
        return f"Claim:{self.wilderness_chunk_key(chunk_x, chunk_y)}"

    def current_object_location_key(self) -> str:
        if (
            hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
            and hasattr(self, "procedural_property_object_location_key")
        ):
            property_record = self.current_procedural_residence_property()
            if property_record:
                return self.procedural_property_object_location_key(
                    str(property_record.get("id", ""))
                )
        if self.on_house():
            return "HouseInterior"
        if self.on_farm():
            return "Farm"
        if self.on_owned_wilderness_claim():
            return self.claim_scope_key()
        return self.state.location

    def owned_wilderness_claim(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> Optional[Dict[str, object]]:
        claims = self.state.owned_wilderness_claims if isinstance(self.state.owned_wilderness_claims, dict) else {}
        key = self.wilderness_chunk_key(chunk_x, chunk_y)
        claim = claims.get(key)
        if isinstance(claim, dict):
            return self.ensure_wilderness_claim_identity(key, claim)
        return None

    def on_owned_wilderness_claim(self) -> bool:
        return self.on_wilderness() and self.owned_wilderness_claim() is not None

    def on_farm_work_land(self) -> bool:
        return self.on_farm() or self.on_owned_wilderness_claim()

    def active_farm_work_map(self) -> List[List[str]]:
        return self.base_map if self.on_farm() else self.active_map()

    def land_map_for_object_scope(self, scope: str) -> Optional[List[List[str]]]:
        if scope == "Farm":
            return self.base_map
        if scope.startswith("Claim:"):
            try:
                cx_s, cy_s = scope.split(":", 1)[1].split(",", 1)
                return self.get_wilderness_chunk_map(int(cx_s), int(cy_s))
            except Exception:
                return None
        return None

    def owned_farm_land_maps(self) -> List[Tuple[str, List[List[str]]]]:
        maps: List[Tuple[str, List[List[str]]]] = [("Farm", self.base_map)]
        claims = self.state.owned_wilderness_claims if isinstance(self.state.owned_wilderness_claims, dict) else {}
        for claim_key in sorted(claims):
            try:
                cx_s, cy_s = str(claim_key).split(",", 1)
                maps.append((self.claim_scope_key(int(cx_s), int(cy_s)), self.get_wilderness_chunk_map(int(cx_s), int(cy_s))))
            except Exception:
                continue
        return maps

    def is_claimable_wilderness_chunk(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> bool:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        if cx == 0 and cy == 0:
            return False
        # One surveyed deed post per 7x7 chunk region. This keeps claims rare
        # without allowing long unlucky wilderness stretches with no land for sale.
        grid_size = WILDERNESS_CLAIM_GRID_SIZE
        cell_x = (cx // grid_size) * grid_size
        cell_y = (cy // grid_size) * grid_size
        local_x = int(self.wilderness_hash01(cell_x, cell_y, 1410) * grid_size) % grid_size
        local_y = int(self.wilderness_hash01(cell_x, cell_y, 1411) * grid_size) % grid_size
        claim_x = cell_x + local_x
        claim_y = cell_y + local_y
        if claim_x == 0 and claim_y == 0:
            claim_x = cell_x + ((local_x + 3) % grid_size)
            claim_y = cell_y + ((local_y + 5) % grid_size)
        return cx == claim_x and cy == claim_y

    def wilderness_chunk_has_stronghold(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> bool:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        if cx == 0 and cy == 0:
            return False
        if abs(cx) + abs(cy) < 2:
            return False
        if self.is_claimable_wilderness_chunk(cx, cy):
            return False
        try:
            if self.wilderness_chunk_has_dungeon_site(cx, cy):
                return False
        except Exception:
            pass
        return self.wilderness_hash01(cx, cy, 18101) > 0.976

    def wilderness_stronghold_key(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> str:
        return self.wilderness_chunk_key(chunk_x, chunk_y)

    def ensure_wilderness_strongholds(self):
        if not isinstance(getattr(self.state, "wilderness_stronghold_state", None), dict):
            self.state.wilderness_stronghold_state = {}
        if not hasattr(self, "wilderness_stronghold_enemies") or not isinstance(self.wilderness_stronghold_enemies, dict):
            self.wilderness_stronghold_enemies = {}

    def wilderness_stronghold_record(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None, create: bool = True) -> Dict[str, object]:
        self.ensure_wilderness_strongholds()
        key = self.wilderness_stronghold_key(chunk_x, chunk_y)
        record = self.state.wilderness_stronghold_state.get(key)
        if not isinstance(record, dict):
            if not create:
                return {}
            record = {}
            self.state.wilderness_stronghold_state[key] = record
        try:
            cx_s, cy_s = key.split(",", 1)
            cx, cy = int(cx_s), int(cy_s)
        except Exception:
            cx, cy = int(chunk_x or 0), int(chunk_y or 0)
        record.setdefault("discovered", False)
        record.setdefault("cleared", False)
        record.setdefault("reward_claimed", False)
        record.setdefault("chunk_x", cx)
        record.setdefault("chunk_y", cy)
        record.setdefault("marker_x", 0)
        record.setdefault("marker_y", 0)
        record.setdefault("name", self.wilderness_stronghold_name(cx, cy))
        record.setdefault("theme", self.wilderness_stronghold_theme(cx, cy))
        return record

    def wilderness_stronghold_theme(self, chunk_x: int, chunk_y: int) -> str:
        biome = self.wilderness_world_biome_tile(chunk_x * 86 + 43, chunk_y * 38 + 19)
        roll = self.wilderness_hash01(chunk_x, chunk_y, 18112)
        if biome == "x":
            return "watch"
        if biome == "r":
            return "flood"
        if biome in ["%", "l"]:
            return "thorn"
        if roll > 0.72:
            return "ember"
        if roll > 0.42:
            return "camp"
        return "watch"

    def wilderness_stronghold_name(self, chunk_x: int, chunk_y: int) -> str:
        theme = self.wilderness_stronghold_theme(chunk_x, chunk_y)
        rng = random.Random(self.wilderness_chunk_seed(chunk_x, chunk_y) + 18120)
        first = {
            "camp": ["Red", "Broken", "Ash", "Torn", "Blackroot"],
            "watch": ["Hollow", "Stone", "Old", "Iron", "Fallen"],
            "thorn": ["Briar", "Moss", "Green", "Tangle", "Root"],
            "ember": ["Ember", "Cinder", "Smoke", "Char", "Redglass"],
            "flood": ["Reed", "Mud", "Lowwater", "Flood", "Silt"],
        }.get(theme, ["Broken"])
        second = {
            "camp": ["Camp", "Hideout", "Outpost"],
            "watch": ["Watch", "Lookout", "Redoubt"],
            "thorn": ["Hold", "Nest", "Barricade"],
            "ember": ["Watchfire", "Camp", "Stockade"],
            "flood": ["Causeway", "Camp", "Dock"],
        }.get(theme, ["Stronghold"])
        return f"{rng.choice(first)} {rng.choice(second)}"

    def place_wilderness_stronghold_in_chunk(self, grid: List[List[str]], chunk_x: int, chunk_y: int):
        if not self.wilderness_chunk_has_stronghold(chunk_x, chunk_y):
            return
        record = self.wilderness_stronghold_record(chunk_x, chunk_y)
        if any("!" in row for row in grid):
            return
        h = len(grid)
        w = len(grid[0]) if h else 0
        if not h or not w:
            return
        rng = random.Random(self.wilderness_chunk_seed(chunk_x, chunk_y) + 18150)
        cx = int(record.get("marker_x", 0) or 0)
        cy = int(record.get("marker_y", 0) or 0)
        if not (8 <= cx < w - 8 and 6 <= cy < h - 6):
            cx = rng.randint(16, max(17, w - 17))
            cy = rng.randint(8, max(9, h - 9))
        record["marker_x"] = cx
        record["marker_y"] = cy

        cleared = bool(record.get("cleared", False))
        for yy in range(max(2, cy - 5), min(h - 2, cy + 6)):
            for xx in range(max(2, cx - 8), min(w - 2, cx + 9)):
                dx = abs(xx - cx)
                dy = abs(yy - cy)
                if dx + dy > 12 and rng.random() < 0.45:
                    continue
                if grid[yy][xx] in ["S", "V", "X", WILDERNESS_CLAIM_SYMBOL]:
                    continue
                if cleared:
                    grid[yy][xx] = "." if rng.random() < 0.82 else ":"
                else:
                    grid[yy][xx] = ":" if rng.random() < 0.62 else "."

        if not cleared:
            for xx in range(max(2, cx - 7), min(w - 2, cx + 8)):
                if rng.random() < 0.62:
                    grid[max(2, cy - 5)][xx] = "#"
                if rng.random() < 0.48:
                    grid[min(h - 3, cy + 5)][xx] = "#"
            for yy in range(max(2, cy - 4), min(h - 2, cy + 5)):
                if rng.random() < 0.55:
                    grid[yy][max(2, cx - 8)] = "#"
                if rng.random() < 0.40:
                    grid[yy][min(w - 3, cx + 8)] = "#"
            for _ in range(14):
                xx = rng.randint(max(2, cx - 6), min(w - 3, cx + 6))
                yy = rng.randint(max(2, cy - 4), min(h - 3, cy + 4))
                if (xx, yy) == (cx, cy):
                    continue
                grid[yy][xx] = rng.choice(["B", "^", ":", "."])
        else:
            self.dress_reclaimed_stronghold_site(grid, cx, cy, record)
            self.apply_reclaimed_stronghold_features_to_grid(chunk_x, chunk_y, grid)

        grid[cy][cx] = "!"
        self.wilderness_force_travel_corridor(grid, (w // 2, h // 2), (cx, cy), rng, width=0)
        grid[cy][cx] = "!"

    def wilderness_claim_traits(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> Dict[str, str]:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        wx = cx * 86 + 43
        wy = cy * 38 + 19
        biome = self.wilderness_world_biome_tile(wx, wy)
        trait_data = {
            ";": ("Meadow Claim", "open sun, wildflowers, easy pasture"),
            "%": ("Woodland Claim", "trees, mushrooms, shade, timber"),
            "l": ("Mushroom Claim", "damp shade, spores, forage logs"),
            "r": ("Wetland Claim", "watercress, reeds, rich mud"),
            "x": ("Ridge Claim", "stone, ore pockets, hardy soil"),
            ".": ("Mixed Claim", "balanced soil and flexible space"),
        }
        name, traits = trait_data.get(biome, trait_data["."])
        return {"type": name, "traits": traits, "biome": biome}

    def wilderness_claim_identity(self, chunk_x: int, chunk_y: int, farm_type_id: str) -> Dict[str, str]:
        cx = int(chunk_x)
        cy = int(chunk_y)
        farm_type_id = farm_type_id if farm_type_id in FARM_CLAIM_TYPE_DATA else self.recommended_wilderness_claim_farm_type_id(cx, cy)
        farm_type = farm_claim_type_data(farm_type_id)
        rng = random.Random(self.wilderness_chunk_seed(cx, cy) + 27000 + FARM_CLAIM_TYPE_ORDER.index(farm_type_id) * 359)
        name_parts = {
            "meadow": (["Sunwake", "Brightmere", "Windmere", "Goldgrass", "Southglade"], ["Meadow", "Field", "Green"]),
            "woodland": (["Cedar", "Alder", "Juniper", "Greenfall", "Pinerest"], ["Hollow", "Wood", "Shade"]),
            "riverbend": (["Reedbend", "Bluebank", "Silverbank", "Rainford", "Clearwater"], ["Bend", "Reach", "Run"]),
            "stonebreak": (["Ironroot", "Slatefall", "Graymark", "Ridgewell", "Ashstone"], ["Ridge", "Yard", "Break"]),
            "wetland": (["Reedglass", "Mirelight", "Lowmere", "Stillwater", "Mudrose"], ["Fen", "Marsh", "Moor"]),
            "orchard": (["Amber", "Briarcrest", "Oldsun", "Sweetbough", "Highbranch"], ["Orchard", "Grove", "Acre"]),
            "mushroom": (["Duskcap", "Hollowcap", "Deepmoss", "Sporelight", "Shadecap"], ["Grove", "Hollow", "Dell"]),
            "prairie": (["Openmark", "Eastwind", "Longgrass", "Clearreach", "Highsun"], ["Prairie", "Range", "Plain"]),
        }
        first_options, second_options = name_parts.get(farm_type_id, name_parts["meadow"])
        claim_name = f"{rng.choice(first_options)} {rng.choice(second_options)}"
        if rng.random() < 0.22:
            claim_name = f"{claim_name} Claim"

        landmark_options = {
            "meadow": [
                ("split rail corner", "An old split rail corner marks where someone once tried to tame the grass."),
                ("sunken flower bed", "A sunken flower bed hints at an abandoned garden line."),
                ("flat survey stone", "A flat survey stone sits half-buried near the workable center."),
            ],
            "woodland": [
                ("cedar stump ring", "A ring of old cedar stumps shows where a small clearing used to be."),
                ("mossy work stump", "A mossy work stump still has tool marks under the green."),
                ("leaning trail post", "A leaning trail post points toward a path the woods almost reclaimed."),
            ],
            "riverbend": [
                ("washed stone ford", "A washed stone ford gives the water crossing a natural work point."),
                ("reed-lined bank", "A reed-lined bank holds firm enough for careful paths and pond work."),
                ("old plank landing", "An old plank landing rests above the mud where supplies once came through."),
            ],
            "stonebreak": [
                ("broken cairn", "A broken cairn marks a seam of stubborn stone under the soil."),
                ("iron-stained shelf", "An iron-stained shelf catches rainwater along the rough ground."),
                ("quarry scar", "A shallow quarry scar gives the claim a useful but demanding center."),
            ],
            "wetland": [
                ("reed pool", "A reed pool gathers water and rich mud near the middle of the claim."),
                ("soft plank path", "A soft plank path shows where careful feet found a dry line."),
                ("sedge hollow", "A sedge hollow holds damp soil that will need patient planning."),
            ],
            "orchard": [
                ("old graft row", "An old graft row still stands where the orchard tried to keep order."),
                ("fallen trellis", "A fallen trellis marks a place where fruit once had support."),
                ("stone fruit curb", "A low stone curb outlines a former fruit bed."),
            ],
            "mushroom": [
                ("damp log circle", "A damp log circle gives the shade a useful shape for forage work."),
                ("spore shelf", "A pale spore shelf grows where the ground stays cool and wet."),
                ("moss cellar dip", "A mossy dip in the ground stays cool enough for strange crops."),
            ],
            "prairie": [
                ("clear survey line", "A clear survey line runs straight enough for future machines and paths."),
                ("wind-polished stone", "A wind-polished stone makes the open land easy to find again."),
                ("old boundary stake", "An old boundary stake gives the blank ground one firm reference point."),
            ],
        }
        landmark_name, landmark_description = rng.choice(landmark_options.get(farm_type_id, landmark_options["meadow"]))
        identity_options = {
            "meadow": ["open, forgiving, and easy to reshape", "bright, grassy, and made for flexible layouts"],
            "woodland": ["sheltered, timber-rich, and slow to open", "quiet, shaded, and full of clearing work"],
            "riverbend": ["divided by water, but generous to careful planners", "good for ponds, bridges, and compact fields"],
            "stonebreak": ["rugged, mineral-heavy, and stubborn underfoot", "hard to clear, but excellent for machines and furnaces"],
            "wetland": ["damp, odd, and rich with awkward potential", "slow to tame, but strong for water-focused farms"],
            "orchard": ["overgrown, established, and full of old shape", "best for preserves, paths, and patient fruit plans"],
            "mushroom": ["cool, shaded, and built around forage work", "strange, damp, and suited to specialty production"],
            "prairie": ["open, blank, and ready for player-made order", "wide, simple, and friendly to automation layouts"],
        }
        identity = rng.choice(identity_options.get(farm_type_id, identity_options["meadow"]))
        terrain = self.wilderness_claim_traits(cx, cy)
        deed_code = f"LC-{abs(cx):02d}{'E' if cx >= 0 else 'W'}-{abs(cy):02d}{'S' if cy >= 0 else 'N'}-{rng.randint(100, 999)}"
        survey_note = (
            f"The survey names this {farm_type.get('name', 'Farm Claim')} {identity}. "
            f"Notable feature: {landmark_description}"
        )
        return {
            "name": claim_name,
            "deed_code": deed_code,
            "identity": identity,
            "landmark": landmark_name,
            "landmark_description": landmark_description,
            "survey_note": survey_note,
            "survey_terrain": terrain.get("type", "Mixed Claim"),
        }

    def ensure_wilderness_claim_identity(self, claim_key: str, claim: Dict[str, object]) -> Dict[str, object]:
        if not isinstance(claim, dict):
            return {}
        try:
            cx_s, cy_s = str(claim_key).split(",", 1)
            cx, cy = int(claim.get("chunk_x", cx_s)), int(claim.get("chunk_y", cy_s))
        except Exception:
            cx, cy = int(claim.get("chunk_x", 0) or 0), int(claim.get("chunk_y", 0) or 0)
        farm_type_id = claim_farm_type_id_for_record(claim)
        identity = self.wilderness_claim_identity(cx, cy, farm_type_id)
        farm_type = farm_claim_type_data(farm_type_id)
        old_default_names = {
            f"{farm_type.get('name', 'Farm Claim')} ({cx},{cy})",
            f"{claim.get('farm_type', farm_type.get('name', 'Farm Claim'))} ({cx},{cy})",
        }
        current_name = str(claim.get("name", "") or "")
        if not current_name or current_name in old_default_names:
            claim["name"] = identity["name"]
        for key in ["deed_code", "identity", "landmark", "landmark_description", "survey_note", "survey_terrain"]:
            if not str(claim.get(key, "") or "").strip():
                claim[key] = identity[key]
        claim["farm_type_id"] = farm_type_id
        claim["farm_type"] = str(farm_type.get("name", "Farm Claim"))
        claim["type"] = str(claim.get("type") or claim["farm_type"])
        claim["traits"] = str(claim.get("traits") or farm_type.get("focus", "raw land"))
        return claim

    def wilderness_claim_name(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None, farm_type_id: Optional[str] = None) -> str:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        if farm_type_id:
            return self.wilderness_claim_identity(cx, cy, farm_type_id)["name"]
        traits = self.wilderness_claim_traits(cx, cy)
        return f"{traits['type']} ({cx},{cy})"

    def recommended_wilderness_claim_farm_type_id(self, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> str:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        biome = self.wilderness_claim_traits(cx, cy).get("biome", ".")
        roll = self.wilderness_hash01(cx, cy, 1420)
        if biome == ";":
            if roll > 0.86:
                return "prairie"
            if roll > 0.58:
                return "orchard"
            return "meadow"
        if biome == "%":
            return "woodland" if roll < 0.72 else "orchard"
        if biome == "l":
            return "mushroom"
        if biome == "r":
            return "wetland" if roll < 0.58 else "riverbend"
        if biome == "x":
            return "stonebreak"
        return "prairie" if roll > 0.78 else "meadow"

    def claim_plan_description_lines(self, farm_type_id: str, chunk_x: Optional[int] = None, chunk_y: Optional[int] = None) -> List[str]:
        cx = self.state.wilderness_chunk_x if chunk_x is None else int(chunk_x)
        cy = self.state.wilderness_chunk_y if chunk_y is None else int(chunk_y)
        data = farm_claim_type_data(farm_type_id)
        identity = self.wilderness_claim_identity(cx, cy, farm_type_id)
        recommended_id = self.recommended_wilderness_claim_farm_type_id(cx, cy)
        rows = [
            str(data.get("name", "Farm Claim")),
            "",
            f"Chunk: {cx},{cy}",
            f"Survey name: {identity['name']}",
            f"Price: ${WILDERNESS_CLAIM_PRICE}",
            f"Focus: {data.get('focus', 'raw land')}",
            f"Identity: {identity['identity']}",
            f"Landmark: {identity['landmark']}",
            "",
        ]
        rows.extend(str(line) for line in data.get("description", []))
        rows.extend([
            "",
            "Buying this deed reshapes the raw chunk into this farm type.",
            "It still starts wild: you clear, till, build, and automate it yourself.",
        ])
        if farm_type_id == recommended_id:
            rows.extend(["", "Surveyor note: recommended for this chunk's terrain."])
        else:
            rows.extend(["", f"Surveyor note: recommended here is {farm_claim_type_data(recommended_id)['name']}."])
        return rows

    def claim_plan_protected_tiles(self, grid: List[List[str]], marker_x: int, marker_y: int, shipping_x: int, shipping_y: int) -> set:
        h = len(grid)
        w = len(grid[0]) if h else 0
        protected = set()

        def add_radius(cx: int, cy: int, rx: int, ry: int):
            for yy in range(max(1, cy - ry), min(h - 1, cy + ry + 1)):
                for xx in range(max(1, cx - rx), min(w - 1, cx + rx + 1)):
                    protected.add((xx, yy))

        add_radius(marker_x, marker_y, 4, 3)
        for tx, ty in self.object_footprint_tiles("Shipping Bin", shipping_x, shipping_y):
            add_radius(tx, ty, 2, 2)

        mid_x = w // 2
        mid_y = h // 2
        for x in range(max(1, mid_x - 5), min(w - 1, mid_x + 6)):
            for y in [1, 2, h - 3, h - 2]:
                protected.add((x, y))
        for y in range(max(1, mid_y - 5), min(h - 1, mid_y + 6)):
            for x in [1, 2, w - 3, w - 2]:
                protected.add((x, y))

        for yy, row in enumerate(grid):
            for xx, tile in enumerate(row):
                if tile == "V":
                    add_radius(xx, yy, 2, 2)
        return protected

    def clear_claim_yard(self, grid: List[List[str]], marker_x: int, marker_y: int, shipping_x: int, shipping_y: int):
        h = len(grid)
        w = len(grid[0]) if h else 0
        for yy in range(max(1, marker_y - 3), min(h - 1, marker_y + 4)):
            for xx in range(max(1, marker_x - 4), min(w - 1, marker_x + 5)):
                if grid[yy][xx] not in ["S", "V"]:
                    grid[yy][xx] = "."
        for tx, ty in self.object_footprint_tiles("Shipping Bin", shipping_x, shipping_y):
            for yy in range(max(1, ty - 1), min(h - 1, ty + 2)):
                for xx in range(max(1, tx - 1), min(w - 1, tx + 2)):
                    if grid[yy][xx] not in ["S", "V"]:
                        grid[yy][xx] = "."
        if 0 <= marker_y < h and 0 <= marker_x < w:
            grid[marker_y][marker_x] = WILDERNESS_CLAIM_SYMBOL

    def apply_wilderness_claim_plan(self, grid: List[List[str]], chunk_x: int, chunk_y: int, marker_x: int, marker_y: int, shipping_x: int, shipping_y: int, farm_type_id: str):
        h = len(grid)
        w = len(grid[0]) if h else 0
        if not h or not w:
            return
        farm_type_id = farm_type_id if farm_type_id in FARM_CLAIM_TYPE_DATA else self.recommended_wilderness_claim_farm_type_id(chunk_x, chunk_y)
        plan_index = FARM_CLAIM_TYPE_ORDER.index(farm_type_id)
        rng = random.Random(self.wilderness_chunk_seed(chunk_x, chunk_y) + 24000 + plan_index * 997)
        protected = self.claim_plan_protected_tiles(grid, marker_x, marker_y, shipping_x, shipping_y)
        cave_positions = [(x, y) for y, row in enumerate(grid) for x, tile in enumerate(row) if tile == "V"]
        season_symbols = forage_symbols_for_season(self.state.season)

        def base_tile_for(x: int, y: int) -> str:
            wx, wy = self.wilderness_world_coords(chunk_x, chunk_y, x, y)
            n = self.wilderness_value_noise(wx + plan_index * 13, wy - plan_index * 17, 23.0, 2421)
            detail = self.wilderness_hash01(wx, wy, 2422 + plan_index)
            if farm_type_id == "woodland":
                return "%" if n < 0.78 else "."
            if farm_type_id == "mushroom":
                return "l" if n < 0.62 else "%"
            if farm_type_id == "stonebreak":
                return "x" if n < 0.72 else "."
            if farm_type_id == "riverbend":
                river_x = w // 2 + int(9 * math.sin((y + chunk_y * 11 + plan_index) / 5.4))
                if abs(x - river_x) <= 1:
                    return "~"
                if abs(x - river_x) <= 3:
                    return "r"
                return ";" if detail > 0.28 else "."
            if farm_type_id == "wetland":
                pond = self.wilderness_value_noise(wx, wy, 18.0, 2425)
                if pond > 0.76 and detail > 0.36:
                    return "~"
                return "r" if n < 0.72 else ";"
            if farm_type_id == "orchard":
                return ";" if n < 0.82 else "."
            if farm_type_id == "prairie":
                return ";" if n < 0.92 else "."
            return ";" if n < 0.70 else "."

        for y in range(h):
            for x in range(w):
                if x == 0 or y == 0 or x == w - 1 or y == h - 1:
                    grid[y][x] = "#"
                else:
                    grid[y][x] = base_tile_for(x, y)

        for y in range(1, h - 1):
            for x in range(1, w - 1):
                if (x, y) in protected or grid[y][x] in ["~", "="]:
                    continue
                wx, wy = self.wilderness_world_coords(chunk_x, chunk_y, x, y)
                roll = self.wilderness_hash01(wx, wy, 2450 + plan_index)
                detail = self.wilderness_hash01(wx, wy, 2451 + plan_index)
                near_water = any(grid[y + dy][x + dx] == "~" for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)])

                if farm_type_id == "meadow":
                    if roll < 0.16:
                        grid[y][x] = "^"
                    elif roll > 0.970:
                        grid[y][x] = "F"
                    elif 0.42 < roll < 0.45:
                        grid[y][x] = season_symbols[int(detail * len(season_symbols)) % len(season_symbols)]
                    elif roll > 0.94:
                        grid[y][x] = rng.choice(["T", "o", "*"])
                elif farm_type_id == "woodland":
                    if roll < 0.24:
                        grid[y][x] = "T"
                    elif roll < 0.34:
                        grid[y][x] = "*"
                    elif roll < 0.39:
                        grid[y][x] = "L"
                    elif roll < 0.43:
                        grid[y][x] = "N"
                    elif roll > 0.985:
                        grid[y][x] = rng.choice(season_symbols)
                elif farm_type_id == "riverbend":
                    if near_water and roll < 0.24:
                        grid[y][x] = rng.choice(["W", "p", "G"])
                    elif roll < 0.08:
                        grid[y][x] = "^"
                    elif roll > 0.96:
                        grid[y][x] = rng.choice(["T", "o", "L"])
                elif farm_type_id == "stonebreak":
                    if roll < 0.24:
                        grid[y][x] = "o"
                    elif roll < 0.30:
                        grid[y][x] = "M"
                    elif roll < 0.38:
                        grid[y][x] = "^"
                    elif roll > 0.97:
                        grid[y][x] = rng.choice(["*", "L"])
                elif farm_type_id == "wetland":
                    if near_water and roll < 0.34:
                        grid[y][x] = rng.choice(["W", "p", "G"])
                    elif roll < 0.11:
                        grid[y][x] = "^"
                    elif roll > 0.965:
                        grid[y][x] = rng.choice(["L", "Z", "u"])
                elif farm_type_id == "orchard":
                    orchard_row = (x - 8) % 10 <= 1 and (y - 5) % 7 <= 1
                    if orchard_row and roll < 0.58:
                        grid[y][x] = "O"
                    elif roll < 0.11:
                        grid[y][x] = "^"
                    elif roll < 0.17:
                        grid[y][x] = "*"
                    elif roll > 0.975:
                        grid[y][x] = rng.choice(["e", "F", "G"])
                elif farm_type_id == "mushroom":
                    if roll < 0.16:
                        grid[y][x] = "Z"
                    elif roll < 0.23:
                        grid[y][x] = "u"
                    elif roll < 0.31:
                        grid[y][x] = "*"
                    elif roll < 0.38:
                        grid[y][x] = "T"
                    elif roll > 0.975:
                        grid[y][x] = rng.choice(["m", "z", "L"])
                elif farm_type_id == "prairie":
                    if roll < 0.18:
                        grid[y][x] = "^"
                    elif roll > 0.985:
                        grid[y][x] = "F"
                    elif roll > 0.955:
                        grid[y][x] = rng.choice(season_symbols)
                    elif roll > 0.925:
                        grid[y][x] = rng.choice(["o", "*", "T"])

        # A purchased claim should begin as raw land, not as a wilderness road
        # junction. Keep only edge access plus a modest cleared route between the
        # deed marker and the starter shipping bin.
        self.clear_wilderness_chunk_entry_lanes(grid)

        for cave_x, cave_y in cave_positions:
            if 1 <= cave_x < w - 1 and 1 <= cave_y < h - 1:
                grid[cave_y][cave_x] = "V"
                for ax, ay in [(cave_x, cave_y + 1), (cave_x, cave_y - 1), (cave_x + 1, cave_y), (cave_x - 1, cave_y)]:
                    if 1 <= ax < w - 1 and 1 <= ay < h - 1 and grid[ay][ax] not in ["~", "="]:
                        grid[ay][ax] = "."
                        break
        if not cave_positions:
            self.place_wilderness_caves_in_chunk(grid, chunk_x, chunk_y)

        self.clear_claim_yard(grid, marker_x, marker_y, shipping_x, shipping_y)
        self.wilderness_carve_claim_access_path(
            grid,
            (marker_x, max(1, min(h - 2, marker_y + 1))),
            (shipping_x, shipping_y),
            rng,
        )
        self.ensure_wilderness_interactable_accessibility(grid)
        if 0 <= marker_y < h and 0 <= marker_x < w:
            grid[marker_y][marker_x] = WILDERNESS_CLAIM_SYMBOL

    def claim_development_stats(self, claim_key: str, claim: Dict[str, object]) -> Dict[str, int]:
        try:
            cx = int(claim.get("chunk_x", str(claim_key).split(",", 1)[0]))
            cy = int(claim.get("chunk_y", str(claim_key).split(",", 1)[1]))
            grid = self.get_wilderness_chunk_map(cx, cy)
        except Exception:
            return {
                "cleared_percent": 0,
                "workable": 0,
                "uncleared": 0,
                "water": 0,
                "tilled": 0,
                "crops": 0,
                "objects": 0,
            }

        scope = self.claim_scope_key(cx, cy)
        crop_prefix = f"{scope}:"
        crops = sum(1 for key in self.crops if isinstance(key, str) and key.startswith(crop_prefix))
        objects = sum(1 for key in self.state.placed_objects if isinstance(key, str) and key.startswith(crop_prefix))
        workable = 0
        uncleared = 0
        water = 0
        tilled = 0
        clearable_symbols = set(["T", "o", "*", "^", "O", "L", "e", "p", "M", "G", "Z", "W", "N", "F", "Y", "u", "Q"]) | WILDERNESS_FORAGE_SYMBOLS

        for y, row in enumerate(grid):
            for x, tile in enumerate(row):
                if x == 0 or y == 0 or y == len(grid) - 1 or x == len(row) - 1:
                    continue
                if tile in ["~", "="]:
                    water += 1
                    continue
                if tile in [",", "w"]:
                    tilled += 1
                    workable += 1
                    continue
                if tile in [".", ";", "%", "l", "r", "x"]:
                    workable += 1
                    continue
                if tile in clearable_symbols:
                    uncleared += 1

        total = max(1, workable + uncleared)
        return {
            "cleared_percent": int((workable / total) * 100),
            "workable": workable,
            "uncleared": uncleared,
            "water": water,
            "tilled": tilled,
            "crops": crops,
            "objects": objects,
        }

    def claim_development_label(self, claim_key: str, claim: Dict[str, object]) -> str:
        stats = self.claim_development_stats(claim_key, claim)
        cleared = stats.get("cleared_percent", 0)
        if stats.get("objects", 0) >= 8 or stats.get("crops", 0) >= 24:
            return "Developed"
        if stats.get("objects", 0) >= 3 or stats.get("crops", 0) >= 8 or stats.get("tilled", 0) >= 12:
            return "Working"
        if cleared >= 72:
            return "Opened"
        return "Raw"

    def find_claim_marker_position(self, grid: List[List[str]], chunk_x: int, chunk_y: int) -> Tuple[int, int]:
        for y, row in enumerate(grid):
            for x, tile in enumerate(row):
                if tile == WILDERNESS_CLAIM_SYMBOL:
                    return x, y
        h = len(grid)
        w = len(grid[0]) if h else 0
        rng = random.Random(self.wilderness_chunk_seed(chunk_x, chunk_y) + 1411)
        candidates: List[Tuple[int, int, int]] = []
        blocked = set(["#", "~", "=", ":", "S", "V", "T", "o", "*"])
        for y in range(5, max(5, h - 5)):
            for x in range(6, max(6, w - 6)):
                if grid[y][x] in blocked:
                    continue
                score = 0
                for yy in range(max(1, y - 2), min(h - 1, y + 3)):
                    for xx in range(max(1, x - 3), min(w - 1, x + 4)):
                        if grid[yy][xx] not in blocked:
                            score += 1
                if score >= 18:
                    candidates.append((score, x, y))
        if candidates:
            candidates.sort(key=lambda row: (-row[0], rng.random()))
            return candidates[0][1], candidates[0][2]
        return max(2, w // 2), max(2, h // 2)

    def place_wilderness_claim_marker(self, grid: List[List[str]], chunk_x: int, chunk_y: int):
        if not self.is_claimable_wilderness_chunk(chunk_x, chunk_y):
            return
        x, y = self.find_claim_marker_position(grid, chunk_x, chunk_y)
        h = len(grid)
        w = len(grid[0]) if h else 0
        for yy in range(max(1, y - 2), min(h - 1, y + 3)):
            for xx in range(max(1, x - 3), min(w - 1, x + 4)):
                if grid[yy][xx] not in ["~", "=", "S", "V"]:
                    grid[yy][xx] = "."
        grid[y][x] = WILDERNESS_CLAIM_SYMBOL

    def ensure_wilderness_claim_marker_for_chunk(self, chunk_x: int, chunk_y: int):
        if not self.is_claimable_wilderness_chunk(chunk_x, chunk_y):
            return
        if self.owned_wilderness_claim(chunk_x, chunk_y):
            return
        grid = self.get_wilderness_chunk_map(chunk_x, chunk_y)
        if any(WILDERNESS_CLAIM_SYMBOL in row for row in grid):
            return
        self.place_wilderness_claim_marker(grid, chunk_x, chunk_y)

    def claim_shipping_bin_position(self, marker_x: int, marker_y: int) -> Tuple[int, int]:
        grid = self.active_map()
        h = len(grid)
        w = len(grid[0]) if h else 0
        candidates = [
            (marker_x + 2, marker_y),
            (marker_x - 3, marker_y),
            (marker_x, marker_y + 2),
            (marker_x, marker_y - 2),
            (marker_x + 2, marker_y + 1),
            (marker_x - 3, marker_y + 1),
        ]
        for x, y in candidates:
            if 1 <= x < w - 2 and 1 <= y < h - 1:
                footprint = [(x, y), (x + 1, y)]
                if all(grid[ty][tx] not in ["#", "~", "=", "S", "V", WILDERNESS_CLAIM_SYMBOL] for tx, ty in footprint):
                    return x, y
        return max(2, min(w - 4, marker_x + 2)), max(2, min(h - 3, marker_y))

    def claim_marker_lines(self, x: int, y: int) -> List[str]:
        traits = self.wilderness_claim_traits()
        owned = self.owned_wilderness_claim()
        recommended_id = self.recommended_wilderness_claim_farm_type_id()
        recommended = farm_claim_type_data(recommended_id)
        rows = [
            "LAND CLAIM",
            "",
            f"Chunk: {self.wilderness_chunk_key()}",
            f"Survey terrain: {traits['type']}",
            f"Terrain traits: {traits['traits']}",
            f"Status: {'Owned' if owned else 'Unclaimed'}",
        ]
        if owned:
            owned = self.ensure_wilderness_claim_identity(self.wilderness_chunk_key(), owned)
            farm_type_id = claim_farm_type_id_for_record(owned)
            farm_type = farm_claim_type_data(farm_type_id)
            stats = self.claim_development_stats(self.wilderness_chunk_key(), owned)
            rows.extend([
                f"Name: {owned.get('name', self.wilderness_claim_name())}",
                f"Deed code: {owned.get('deed_code', 'unrecorded')}",
                f"Farm type: {owned.get('farm_type', farm_type.get('name', 'Farm Claim'))}",
                f"Focus: {farm_type.get('focus', owned.get('traits', 'raw land'))}",
                f"Identity: {owned.get('identity', 'raw land')}",
                f"Landmark: {owned.get('landmark', 'survey marker')}",
                f"Development: {self.claim_development_label(self.wilderness_chunk_key(), owned)}",
                f"Cleared/workable: {stats.get('cleared_percent', 0)}%",
                "",
                str(owned.get("survey_note", "")),
                "",
                "This raw claim belongs to you.",
                "Use normal farm tools here to clear, till, plant, water, build, and automate.",
                "The starting shipping bin is shared with your farm shipments.",
            ])
        else:
            identity = self.wilderness_claim_identity(
                int(self.state.wilderness_chunk_x),
                int(self.state.wilderness_chunk_y),
                recommended_id,
            )
            rows.extend([
                f"Price: ${WILDERNESS_CLAIM_PRICE}",
                f"Survey name: {identity['name']}",
                f"Suggested plan: {recommended.get('name', 'Meadow Farm')}",
                f"Suggested focus: {recommended.get('focus', 'raw land')}",
                f"Identity: {identity['identity']}",
                f"Landmark: {identity['landmark']}",
                "",
                identity["survey_note"],
                "",
                "Buying opens a farm-type choice before the deed is signed.",
                "The chosen plan reshapes the chunk, then leaves it wild.",
                "You still clear rows, build machines, and develop it yourself.",
            ])
        rows.extend([
            "",
            f"Survey marker: {x},{y}",
        ])
        return rows

    def select_wilderness_claim_plan(self, marker_x: int, marker_y: int) -> Optional[str]:
        recommended_id = self.recommended_wilderness_claim_farm_type_id()
        while True:
            items: List[MenuItem] = []
            for farm_type_id in FARM_CLAIM_TYPE_ORDER:
                data = farm_claim_type_data(farm_type_id)
                hint = str(data.get("hint", "claim"))
                if farm_type_id == recommended_id:
                    hint = f"{hint} rec"
                items.append(MenuItem(label=str(data.get("name", farm_type_id)), value=farm_type_id, enabled=True, hint=hint))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Choose Farm Type", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Cancelled deed purchase.")
                return None
            farm_type_id = str(choice.value)
            data = farm_claim_type_data(farm_type_id)
            confirm_items = [
                MenuItem(label=f"Buy as {data.get('name', 'Farm Claim')}", value="buy", enabled=self.state.money >= WILDERNESS_CLAIM_PRICE, hint=f"${WILDERNESS_CLAIM_PRICE}"),
                MenuItem(label="Read survey plan", value="details", enabled=True),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            confirm = self.vertical_panel_select(str(data.get("name", "Farm Claim")), confirm_items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if confirm is None or confirm.value == MENU_BACK:
                continue
            if confirm.value == "details":
                self.vertical_panel_view(str(data.get("name", "Farm Claim")), self.claim_plan_description_lines(farm_type_id), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if confirm.value == "buy":
                return farm_type_id

    def purchase_current_wilderness_claim(self, marker_x: int, marker_y: int, farm_type_id: Optional[str] = None) -> bool:
        if not self.on_wilderness():
            self.set_message("Land deeds are only available in the wilderness.")
            return False
        cx = int(self.state.wilderness_chunk_x)
        cy = int(self.state.wilderness_chunk_y)
        key = self.wilderness_chunk_key(cx, cy)
        if not self.is_claimable_wilderness_chunk(cx, cy):
            self.set_message("This chunk has no purchasable survey claim.")
            return False
        if self.owned_wilderness_claim(cx, cy):
            self.set_message("You already own this claim.")
            return False
        if self.state.money < WILDERNESS_CLAIM_PRICE:
            self.set_message(f"Not enough money. This deed costs ${WILDERNESS_CLAIM_PRICE}.")
            return False

        farm_type_id = farm_type_id if farm_type_id in FARM_CLAIM_TYPE_DATA else self.recommended_wilderness_claim_farm_type_id(cx, cy)
        farm_type = farm_claim_type_data(farm_type_id)
        identity = self.wilderness_claim_identity(cx, cy, farm_type_id)
        self.state.money -= WILDERNESS_CLAIM_PRICE
        shipping_x, shipping_y = self.claim_shipping_bin_position(marker_x, marker_y)
        self.apply_wilderness_claim_plan(self.active_map(), cx, cy, marker_x, marker_y, shipping_x, shipping_y, farm_type_id)
        record = {
            "chunk_x": cx,
            "chunk_y": cy,
            "name": identity["name"],
            "deed_code": identity["deed_code"],
            "identity": identity["identity"],
            "landmark": identity["landmark"],
            "landmark_description": identity["landmark_description"],
            "survey_note": identity["survey_note"],
            "farm_type_id": farm_type_id,
            "farm_type": farm_type["name"],
            "type": farm_type["name"],
            "traits": farm_type["focus"],
            "survey_terrain": identity["survey_terrain"],
            "development_stage": "Raw",
            "purchased": self.state.date_label,
            "marker_x": int(marker_x),
            "marker_y": int(marker_y),
            "shipping_x": int(shipping_x),
            "shipping_y": int(shipping_y),
        }
        self.state.owned_wilderness_claims[key] = record
        for tx, ty in self.object_footprint_tiles("Shipping Bin", shipping_x, shipping_y):
            if self.in_active_bounds(tx, ty) and self.active_map()[ty][tx] not in ["~", "="]:
                self.active_map()[ty][tx] = "."
        self.set_placed_object(shipping_x, shipping_y, "Shipping Bin")
        self.active_map()[marker_y][marker_x] = WILDERNESS_CLAIM_SYMBOL
        self.autosave_with_message(f"Bought deed for {record['name']}. The land was surveyed as a {farm_type['name']} and remains raw.")
        return True

    def wilderness_claim_menu(self, x: int, y: int):
        owned = self.owned_wilderness_claim()
        while True:
            items: List[MenuItem] = [
                MenuItem(label="Inspect claim", value="inspect", enabled=True),
            ]
            if owned:
                items.append(MenuItem(label="Travel between farms", value="travel", enabled=True, hint="owned claims"))
            else:
                items.append(MenuItem(
                    label="Buy deed",
                    value="buy",
                    enabled=self.state.money >= WILDERNESS_CLAIM_PRICE,
                    hint=f"${WILDERNESS_CLAIM_PRICE}",
                ))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Land Claim", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed land claim.")
                return
            if choice.value == "inspect":
                self.vertical_panel_view("Land Claim", self.claim_marker_lines(x, y), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "buy":
                farm_type_id = self.select_wilderness_claim_plan(x, y)
                if farm_type_id and self.purchase_current_wilderness_claim(x, y, farm_type_id):
                    return
                owned = self.owned_wilderness_claim()
                continue
            if choice.value == "travel":
                self.show_land_claims_menu(allow_travel=True)
                return

