    def is_house_fixture_tile(self, tile: str) -> bool:
        return tile in ["B", "K", "V", "t", "c", "s", "r", "l", "p", "u"]

    def house_fixture_name_for_tile(self, tile: str) -> Optional[str]:
        return {
            "B": "Bed",
            "K": "Wall Calendar",
            "V": "Television",
            "t": "Wooden Table",
            "c": "Wooden Chair",
            "s": "Shelf",
            "r": "Decorative Rug",
            "l": "Bookshelf",
            "p": "House Plant",
            "u": "Dresser",
        }.get(tile)

    def clear_builtin_house_furniture_tiles(self):
        """Convert old immovable house furniture tiles back into open floor."""
        for y, row in enumerate(self.house_map):
            for x, ch in enumerate(row):
                if self.is_house_fixture_tile(ch):
                    self.house_map[y][x] = "."

    def house_object_key(self, x: int, y: int) -> str:
        return f"HouseInterior:{x},{y}"

    def ensure_default_house_furniture(self, preserve_existing: bool = True):
        """Place essential/default furniture as movable placed objects."""
        previous_location = self.state.location
        self.state.location = "HouseInterior"
        try:
            self.clear_builtin_house_furniture_tiles()
            existing_house_objects = {
                key for key in self.state.placed_objects
                if isinstance(key, str) and key.startswith("HouseInterior:")
            }

            if not preserve_existing:
                for key in list(existing_house_objects):
                    self.state.placed_objects.pop(key, None)
                existing_house_objects = set()

            if preserve_existing and existing_house_objects:
                # Make sure essential/upgrade furniture exists somewhere.
                existing_names = {
                    value for key, value in self.state.placed_objects.items()
                    if isinstance(key, str) and key.startswith("HouseInterior:")
                }
                layout = self.default_house_furniture_layout()
                required_names = ["Bed", "Wall Calendar", "Television", "Writing Desk", "Nightstand"]
                for optional_name in [
                    "Kitchen Counter", "Pantry", "Wash Basin", "Fireplace", "Couch", "Large Rug",
                    "Family Table", "Keepsake Chest", "Crib", "Child Bed", "Toy Shelf", "Study Desk",
                ]:
                    if optional_name in layout:
                        required_names.append(optional_name)
                for required_name in required_names:
                    if required_name not in existing_names and required_name in layout:
                        x, y = layout[required_name]
                        if self.can_place_object(required_name, x, y)[0]:
                            self.state.placed_objects[self.house_object_key(x, y)] = required_name
                            existing_names.add(required_name)
                return

            for name, (x, y) in self.default_house_furniture_layout().items():
                if self.can_place_object(name, x, y)[0]:
                    self.state.placed_objects[self.house_object_key(x, y)] = name
        finally:
            self.state.location = previous_location


    def rebuild_house_for_current_upgrades(self, preserve_existing: bool = True):
        """Rebuild the house shell for current upgrades and keep movable furniture valid."""
        previous_location = self.state.location
        self.state.location = "HouseInterior"
        try:
            old_objects = {
                key: value for key, value in self.state.placed_objects.items()
                if isinstance(key, str) and key.startswith("HouseInterior:")
            }
            non_house = {
                key: value for key, value in self.state.placed_objects.items()
                if not (isinstance(key, str) and key.startswith("HouseInterior:"))
            }

            self.house_map = self.make_house_map()
            self.clear_builtin_house_furniture_tiles()
            self.state.placed_objects = dict(non_house)

            if preserve_existing and old_objects:
                for key, value in old_objects.items():
                    try:
                        _, coords = key.split(":", 1)
                        x_str, y_str = coords.split(",", 1)
                        x, y = int(x_str), int(y_str)
                    except Exception:
                        continue
                    if self.can_place_object(value, x, y)[0]:
                        self.state.placed_objects[key] = value

            self.ensure_default_house_furniture(preserve_existing=True)
        finally:
            self.state.location = previous_location


    def purchase_farm_building(self, building_name: str, qty: int = 1) -> bool:
        data = INFRASTRUCTURE_DATA[building_name]
        price = int(data.get("price", 0))
        qty = max(1, int(qty))
        total = price * qty
        if self.state.money < total:
            self.set_message(f"Not enough money. {qty} {building_name} kit(s) cost ${total}.")
            return False
        self.state.money -= total
        self.state.inventory[building_name] = self.state.inventory.get(building_name, 0) + qty
        self.autosave_with_message(f"Bought {qty} {building_name} building kit(s) for ${total}. Place them from Tab > Farm & Home > Build Mode.")
        return True

    def purchase_house_upgrade(self, upgrade_name: str) -> bool:
        data = HOUSE_UPGRADE_DATA[upgrade_name]
        if upgrade_name in self.state.house_upgrades:
            self.set_message(f"{upgrade_name} is already complete.")
            return False
        missing = [req for req in data.get("requires", []) if req not in self.state.house_upgrades]
        if missing:
            self.set_message(f"Requires: {', '.join(missing)}.")
            return False
        price = int(data["price"])
        if self.state.money < price:
            self.set_message(f"Not enough money. {upgrade_name} costs ${price}.")
            return False
        self.state.money -= price
        self.state.house_upgrades.append(upgrade_name)
        self.rebuild_house_for_current_upgrades(preserve_existing=True)
        self.autosave_with_message(f"Purchased {upgrade_name}. Your farmhouse interior has been expanded.")
        return True

    def has_shipping_bin_available(self) -> bool:
        if self.state.held_object == "Shipping Bin":
            return True
        if self.state.inventory.get("Shipping Bin", 0) > 0:
            return True
        for obj_name in self.state.placed_objects.values():
            if obj_name == "Shipping Bin":
                return True
        return False

    def ensure_movable_shipping_bin(self):
        """Convert old fixed B map tiles into a movable placed Shipping Bin."""
        anchors = []
        for y in range(self.farm_height()):
            for x in range(self.farm_width()):
                if self.base_map[y][x] == "B":
                    # Old bin was 2 horizontal B tiles; prefer the left tile as anchor.
                    if x == 0 or self.base_map[y][x - 1] != "B":
                        anchors.append((x, y))
                    self.base_map[y][x] = "."

        if not self.has_shipping_bin_available():
            previous_location = self.state.location
            self.state.location = "Farm"
            if anchors:
                x, y = anchors[0]
            else:
                x, y = 5, 7
            try:
                if 0 <= y < self.farm_height() and 0 <= x < self.farm_width() - 1:
                    # Make sure old/default spot is usable.
                    for tx, ty in self.object_footprint_tiles("Shipping Bin", x, y):
                        if 0 <= ty < self.farm_height() and 0 <= tx < self.farm_width():
                            self.base_map[ty][tx] = "."
                    self.set_placed_object(x, y, "Shipping Bin")
                else:
                    self.state.inventory["Shipping Bin"] = self.state.inventory.get("Shipping Bin", 0) + 1
            finally:
                self.state.location = previous_location

    def shipping_bin_target(self) -> Optional[Tuple[int, int]]:
        """Return a tile belonging to a shipping bin on standing/front/adjacent tiles."""
        if not self.on_farm_work_land():
            return None

        sx, sy = self.state.player_x, self.state.player_y
        fx, fy = self.front_tile_pos()
        candidates = [(sx, sy), (fx, fy)]

        # Fallback: any adjacent tile, useful because the movable bin blocks movement.
        for dy in (-1, 0, 1):
            for dx in (-1, 0, 1):
                candidates.append((sx + dx, sy + dy))

        seen = set()
        for x, y in candidates:
            if (x, y) in seen:
                continue
            seen.add((x, y))
            if self.in_active_bounds(x, y) and self.get_placed_object(x, y) == "Shipping Bin":
                return x, y
            # Backward compatibility if any old B tile somehow remains.
            if self.on_farm() and self.in_active_bounds(x, y) and self.base_map[y][x] == "B":
                return x, y
        return None

    def add_to_shipping_report(self, item_name: str, qty: int, total: int):
        if qty <= 0:
            return
        self.state.shipped_today_items[item_name] = self.state.shipped_today_items.get(item_name, 0) + qty
        self.state.shipped_today += total

    def pending_shipping_items(self) -> List[Tuple[str, int, int]]:
        rows: List[Tuple[str, int, int]] = []
        if not isinstance(self.state.shipped_today_items, dict):
            self.state.shipped_today_items = {}
        for item_name, qty in sorted(self.state.shipped_today_items.items()):
            try:
                clean_qty = max(0, int(qty))
            except Exception:
                clean_qty = 0
            if clean_qty <= 0:
                continue
            rows.append((str(item_name), clean_qty, self.shippable_unit_price(str(item_name))))
        return rows

    def pending_shipping_total(self) -> int:
        return sum(qty * unit_price for _item_name, qty, unit_price in self.pending_shipping_items())

    def reclaim_shipped_item(self, item_name: str, qty: int) -> bool:
        if not isinstance(self.state.shipped_today_items, dict):
            self.state.shipped_today_items = {}
        item_name = str(item_name)
        available = int(self.state.shipped_today_items.get(item_name, 0) or 0)
        qty = max(0, min(int(qty), available))
        if qty <= 0:
            self.set_message(f"No pending {item_name} to reclaim.")
            return False
        remaining = available - qty
        if remaining > 0:
            self.state.shipped_today_items[item_name] = remaining
        else:
            self.state.shipped_today_items.pop(item_name, None)
        self.state.inventory[item_name] = int(self.state.inventory.get(item_name, 0) or 0) + qty
        self.state.shipped_today = self.pending_shipping_total()
        unit_price = self.shippable_unit_price(item_name)
        self.autosave_with_message(f"Reclaimed {qty} {item_name}. Pending payout reduced by ${qty * unit_price}.")
        return True

    def shipping_report_lines(self, include_prices: bool = True) -> List[str]:
        lines: List[str] = []
        if not self.state.shipped_today_items:
            lines.append("No items have been shipped today.")
            return lines

        grand_total = 0
        for item_name, qty, unit_price in self.pending_shipping_items():
            total = qty * unit_price
            grand_total += total
            if include_prices:
                lines.append(f"{qty:>3} x {item_name:<22} ${total}")
            else:
                lines.append(f"{qty:>3} x {item_name}")
        lines.append("")
        lines.append(f"Pending payout tomorrow: ${grand_total}")
        return lines

    def automation_scope_label(self, scope: str) -> str:
        if scope == "Farm":
            return "Home Farm"
        if scope.startswith("Claim:"):
            claim_key = scope.split(":", 1)[1]
            claim = (self.state.owned_wilderness_claims or {}).get(claim_key)
            if isinstance(claim, dict):
                claim = self.ensure_wilderness_claim_identity(claim_key, claim)
                return str(claim.get("name", f"Claim {claim_key}"))
            return f"Claim {claim_key}"
        return str(scope)

    def crop_key_for_scope(self, scope: str, x: int, y: int) -> str:
        return f"{scope}:{x},{y}"

    def crop_for_scope(self, scope: str, x: int, y: int) -> Optional[Crop]:
        crop = self.crops.get(self.crop_key_for_scope(scope, x, y))
        if crop is None and scope == "Farm":
            crop = self.crops.get(f"{x},{y}")
        return crop

    def set_crop_for_scope(self, scope: str, x: int, y: int, crop: Crop):
        scoped_key = self.crop_key_for_scope(scope, x, y)
        if self.state.fertilized_tiles.get(scoped_key, False):
            crop.fertilized = True
            self.state.fertilized_tiles.pop(scoped_key, None)
        if scope == "Farm" and self.state.fertilized_tiles.get(f"{x},{y}", False):
            crop.fertilized = True
            self.state.fertilized_tiles.pop(f"{x},{y}", None)
        self.crops[scoped_key] = crop

    def remove_crop_for_scope(self, scope: str, x: int, y: int):
        self.crops.pop(self.crop_key_for_scope(scope, x, y), None)
        if scope == "Farm":
            self.crops.pop(f"{x},{y}", None)

    def ensure_automation_machines(self) -> Dict[str, Dict[str, object]]:
        if not isinstance(getattr(self.state, "automation_machines", None), dict):
            self.state.automation_machines = {}
        return self.state.automation_machines

    def seed_hopper_record(self, hopper_key: str, create: bool = False) -> Optional[Dict[str, object]]:
        machines = self.ensure_automation_machines()
        hopper_key = str(hopper_key)
        record = machines.get(hopper_key)
        if record is None and create:
            record = {"seed_crop": "", "seed_qty": 0, "last_message": ""}
            machines[hopper_key] = record
        if not isinstance(record, dict):
            record = {"seed_crop": "", "seed_qty": 0, "last_message": ""}
            machines[hopper_key] = record
        return record

    def clean_seed_hopper_records(self):
        machines = self.ensure_automation_machines()
        for machine_key, record in list(machines.items()):
            if self.state.placed_objects.get(machine_key) == "Seed Hopper":
                continue
            if isinstance(record, dict):
                seed_crop = str(record.get("seed_crop", "") or "")
                try:
                    seed_qty = max(0, int(record.get("seed_qty", 0)))
                except Exception:
                    seed_qty = 0
                if seed_crop in CROP_DATA and seed_qty > 0:
                    seed_item = self.seed_item_for_crop(seed_crop)
                    self.state.inventory[seed_item] = self.state.inventory.get(seed_item, 0) + seed_qty
            machines.pop(machine_key, None)

    def unload_seed_hopper_key(self, hopper_key: str, quiet: bool = False) -> int:
        record = self.seed_hopper_record(hopper_key, create=False)
        if not record:
            return 0
        seed_crop = str(record.get("seed_crop", "") or "")
        try:
            seed_qty = max(0, int(record.get("seed_qty", 0)))
        except Exception:
            seed_qty = 0
        if seed_crop in CROP_DATA and seed_qty > 0:
            seed_item = self.seed_item_for_crop(seed_crop)
            self.state.inventory[seed_item] = self.state.inventory.get(seed_item, 0) + seed_qty
        record["seed_crop"] = ""
        record["seed_qty"] = 0
        record["last_message"] = "Unloaded."
        if not quiet:
            self.autosave_with_message(f"Unloaded {seed_qty} seed(s) from Seed Hopper.")
        return seed_qty

    def seed_hopper_loaded_label(self, hopper_key: str) -> str:
        record = self.seed_hopper_record(hopper_key, create=False) or {}
        seed_crop = str(record.get("seed_crop", "") or "")
        try:
            seed_qty = max(0, int(record.get("seed_qty", 0) or 0))
        except Exception:
            seed_qty = 0
        if seed_crop in CROP_DATA and seed_qty > 0:
            return f"{seed_crop} Seeds x{seed_qty}"
        return "empty"

    def seed_crop_valid_this_season(self, seed_crop: str) -> bool:
        crop_data = CROP_DATA.get(seed_crop, {})
        season = str(crop_data.get("season", ""))
        return season == "Any" or season == self.state.season

    def seed_hopper_candidates(self, scope: str, land_map: List[List[str]], hopper: Dict[str, object], require_loaded: bool = True) -> List[Tuple[int, int]]:
        hopper_key = str(hopper.get("key", ""))
        record = self.seed_hopper_record(hopper_key, create=False) or {}
        seed_crop = str(record.get("seed_crop", "") or "")
        seed_qty = int(record.get("seed_qty", 0) or 0)
        if require_loaded and (seed_crop not in CROP_DATA or seed_qty <= 0 or not self.seed_crop_valid_this_season(seed_crop)):
            return []

        automation = hopper.get("automation", {}) if isinstance(hopper.get("automation"), dict) else {}
        radius = max(1, int(automation.get("plant_radius", 2)))
        hx, hy = int(hopper["x"]), int(hopper["y"])
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        candidates: List[Tuple[int, int]] = []
        for yy in range(max(0, hy - radius), min(map_h, hy + radius + 1)):
            for xx in range(max(0, hx - radius), min(map_w, hx + radius + 1)):
                if land_map[yy][xx] not in [",", "w"]:
                    continue
                if self.crop_for_scope(scope, xx, yy):
                    continue
                if self.scoped_object_at(scope, xx, yy):
                    continue
                candidates.append((xx, yy))
        return candidates

    def placed_objects_for_scope(self, scope: str, automation_only: bool = False) -> List[Dict[str, object]]:
        objects: List[Dict[str, object]] = []
        for key, obj_name in list(self.state.placed_objects.items()):
            parsed = self.parse_object_key(str(key))
            if not parsed:
                continue
            obj_scope, x, y = parsed
            if obj_scope != scope:
                continue
            data = INFRASTRUCTURE_DATA.get(obj_name, {})
            automation = data.get("automation") if isinstance(data.get("automation"), dict) else {}
            if automation_only and not automation:
                continue
            objects.append({
                "key": str(key),
                "name": str(obj_name),
                "x": int(x),
                "y": int(y),
                "data": data,
                "automation": automation,
                "kind": str(automation.get("kind", "")),
            })
        return objects

    def scoped_object_at(self, scope: str, x: int, y: int) -> Optional[str]:
        for obj in self.placed_objects_for_scope(scope, automation_only=False):
            obj_name = str(obj["name"])
            ax, ay = int(obj["x"]), int(obj["y"])
            if (x, y) in self.object_footprint_tiles(obj_name, ax, ay):
                return obj_name
        return None

    def object_chebyshev_distance(self, first: Dict[str, object], second: Dict[str, object]) -> int:
        return max(abs(int(first["x"]) - int(second["x"])), abs(int(first["y"]) - int(second["y"])))

    def water_tile_for_scope(self, scope: str, land_map: List[List[str]], x: int, y: int, watered_positions: set) -> int:
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        if not (0 <= x < map_w and 0 <= y < map_h):
            return 0
        crop = self.crop_for_scope(scope, x, y)
        tile = land_map[y][x]
        if tile not in [",", "w"] and not crop:
            return 0
        changed = tile == "," or (crop is not None and not crop.watered)
        if tile == ",":
            land_map[y][x] = "w"
        if crop:
            crop.watered = True
        pos = (scope, x, y)
        if changed and pos not in watered_positions:
            watered_positions.add(pos)
            return 1
        return 0

    def pump_has_water_source(self, scope: str, land_map: List[List[str]], pump: Dict[str, object]) -> bool:
        px, py = int(pump["x"]), int(pump["y"])
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        for yy in range(max(0, py - 2), min(map_h, py + 3)):
            for xx in range(max(0, px - 2), min(map_w, px + 3)):
                tile = land_map[yy][xx]
                if tile == "~" or (scope.startswith("Claim:") and tile == "r"):
                    return True
                obj_name = self.scoped_object_at(scope, xx, yy)
                if obj_name in ["Well", "Fish Pond", "Water Tank", "Rain Barrel"]:
                    return True
        return False

    def irrigation_components(self, nodes: List[Dict[str, object]]) -> List[List[Dict[str, object]]]:
        remaining = set(range(len(nodes)))
        components: List[List[Dict[str, object]]] = []
        while remaining:
            start = remaining.pop()
            queue = [start]
            component_indices = {start}
            while queue:
                idx = queue.pop(0)
                ax, ay = int(nodes[idx]["x"]), int(nodes[idx]["y"])
                for other in list(remaining):
                    bx, by = int(nodes[other]["x"]), int(nodes[other]["y"])
                    if abs(ax - bx) + abs(ay - by) <= 1:
                        remaining.remove(other)
                        component_indices.add(other)
                        queue.append(other)
            components.append([nodes[i] for i in sorted(component_indices)])
        return components

    def apply_irrigation_automation_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, int]:
        nodes = [obj for obj in objects if obj.get("kind") in ["pipe", "pump", "water_source"]]
        result = {"watered": 0, "active_networks": 0, "inactive_networks": 0}
        if not nodes:
            return result

        watered_positions = set()
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        for component in self.irrigation_components(nodes):
            active = False
            for node in component:
                kind = str(node.get("kind", ""))
                automation = node.get("automation", {}) if isinstance(node.get("automation"), dict) else {}
                if kind == "water_source":
                    active = True
                    break
                if kind == "pump" and (not automation.get("requires_water") or self.pump_has_water_source(scope, land_map, node)):
                    active = True
                    break
            if not active:
                result["inactive_networks"] += 1
                continue

            result["active_networks"] += 1
            for node in component:
                automation = node.get("automation", {}) if isinstance(node.get("automation"), dict) else {}
                radius = max(1, int(automation.get("water_radius", 1)))
                nx, ny = int(node["x"]), int(node["y"])
                for yy in range(max(0, ny - radius), min(map_h, ny + radius + 1)):
                    for xx in range(max(0, nx - radius), min(map_w, nx + radius + 1)):
                        result["watered"] += self.water_tile_for_scope(scope, land_map, xx, yy, watered_positions)
        return result

    def shipping_loader_for_crate(
        self,
        crate: Dict[str, object],
        loaders: List[Dict[str, object]],
        bins: List[Dict[str, object]],
    ) -> Optional[Dict[str, object]]:
        for loader in loaders:
            automation = loader.get("automation", {}) if isinstance(loader.get("automation"), dict) else {}
            crate_radius = max(1, int(automation.get("crate_radius", 3)))
            bin_radius = max(1, int(automation.get("bin_radius", 4)))
            if self.object_chebyshev_distance(crate, loader) > crate_radius:
                continue
            if any(self.object_chebyshev_distance(loader, bin_obj) <= bin_radius for bin_obj in bins):
                return loader
        return None

    def apply_harvest_automation_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, int]:
        crates = [obj for obj in objects if obj.get("kind") == "harvest_crate"]
        loaders = [obj for obj in objects if obj.get("kind") == "shipping_loader"]
        bins = [obj for obj in objects if obj.get("name") == "Shipping Bin"]
        result = {"harvested": 0, "stored": 0, "shipped": 0, "shipped_value": 0}
        if not crates:
            return result

        harvested_positions = set()
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        for crate in crates:
            automation = crate.get("automation", {}) if isinstance(crate.get("automation"), dict) else {}
            radius = max(1, int(automation.get("harvest_radius", 2)))
            cx, cy = int(crate["x"]), int(crate["y"])
            loader = self.shipping_loader_for_crate(crate, loaders, bins)
            for yy in range(max(0, cy - radius), min(map_h, cy + radius + 1)):
                for xx in range(max(0, cx - radius), min(map_w, cx + radius + 1)):
                    pos = (scope, xx, yy)
                    if pos in harvested_positions:
                        continue
                    crop = self.crop_for_scope(scope, xx, yy)
                    if not crop or not crop.ready:
                        continue
                    quality = crop.projected_quality()
                    item_name = quality_item_name(crop.name, quality)
                    harvested_positions.add(pos)
                    self.remove_crop_for_scope(scope, xx, yy)
                    if land_map[yy][xx] in [",", "w"]:
                        land_map[yy][xx] = ","
                    result["harvested"] += 1

                    unit_price = self.shippable_unit_price(item_name)
                    if loader and unit_price > 0:
                        self.add_to_shipping_report(item_name, 1, unit_price)
                        result["shipped"] += 1
                        result["shipped_value"] += unit_price
                    else:
                        self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + 1
                        result["stored"] += 1
        return result

    def apply_seed_hopper_automation_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, int]:
        hoppers = [obj for obj in objects if obj.get("kind") == "seed_hopper"]
        result = {"hoppers": len(hoppers), "loaded": 0, "planted": 0, "empty": 0, "out_of_season": 0, "no_space": 0}
        if not hoppers:
            return result

        self.clean_seed_hopper_records()
        for hopper in hoppers:
            hopper_key = str(hopper.get("key", ""))
            record = self.seed_hopper_record(hopper_key, create=True)
            seed_crop = str(record.get("seed_crop", "") or "")
            try:
                seed_qty = max(0, int(record.get("seed_qty", 0)))
            except Exception:
                seed_qty = 0

            if seed_crop not in CROP_DATA or seed_qty <= 0:
                result["empty"] += 1
                record["last_message"] = "Empty. Load seeds before sleeping."
                continue

            result["loaded"] += 1
            if not self.seed_crop_valid_this_season(seed_crop):
                result["out_of_season"] += 1
                record["last_message"] = f"{seed_crop} is not a {self.state.season} crop."
                continue

            candidates = self.seed_hopper_candidates(scope, land_map, hopper, require_loaded=True)
            if not candidates:
                result["no_space"] += 1
                record["last_message"] = "No empty tilled soil in range."
                continue

            planted_here = 0
            for xx, yy in candidates:
                if seed_qty <= 0:
                    break
                crop = Crop(name=seed_crop, watered=(land_map[yy][xx] == "w"))
                self.set_crop_for_scope(scope, xx, yy, crop)
                seed_qty -= 1
                planted_here += 1
                result["planted"] += 1
            record["seed_qty"] = seed_qty
            if planted_here:
                record["last_message"] = f"Planted {planted_here} {seed_crop} seed(s)."
            elif seed_qty <= 0:
                record["last_message"] = "Out of loaded seeds."
            else:
                record["last_message"] = "No empty tilled soil in range."
        return result

    def run_daily_farm_automation(self, sprinkler_watered: int = 0) -> List[str]:
        report: List[str] = []
        if sprinkler_watered:
            report.append(f"Sprinklers watered {sprinkler_watered} tile(s) across owned farms.")

        total_automation_objects = 0
        for scope, land_map in self.owned_farm_land_maps():
            all_objects = self.placed_objects_for_scope(scope, automation_only=False)
            automation_objects = [
                obj for obj in all_objects
                if isinstance(obj.get("automation"), dict) and obj.get("automation")
            ]
            if not automation_objects:
                continue

            total_automation_objects += len(automation_objects)
            harvest = self.apply_harvest_automation_for_scope(scope, land_map, all_objects)
            seeding = self.apply_seed_hopper_automation_for_scope(scope, land_map, automation_objects)
            irrigation = self.apply_irrigation_automation_for_scope(scope, land_map, automation_objects)

            bits: List[str] = []
            if harvest["harvested"]:
                harvest_bits = [f"harvest crates picked {harvest['harvested']} crop(s)"]
                if harvest["stored"]:
                    harvest_bits.append(f"{harvest['stored']} stored in inventory")
                if harvest["shipped"]:
                    harvest_bits.append(f"{harvest['shipped']} shipped for ${harvest['shipped_value']} pending")
                bits.append(", ".join(harvest_bits))
            if seeding["planted"]:
                bits.append(f"seed hoppers planted {seeding['planted']} seed(s)")
            elif seeding["empty"]:
                bits.append(f"{seeding['empty']} seed hopper(s) need seeds")
            elif seeding["out_of_season"]:
                bits.append(f"{seeding['out_of_season']} seed hopper(s) held out-of-season seeds")
            elif seeding["no_space"]:
                bits.append(f"{seeding['no_space']} seed hopper(s) found no empty tilled soil")
            if irrigation["watered"]:
                bits.append(f"irrigation watered {irrigation['watered']} tile(s)")
            elif irrigation["inactive_networks"]:
                bits.append("irrigation needs a connected water source")
            if not bits:
                bits.append("systems checked, no ripe crops or dry soil in range")

            report.append(f"{self.automation_scope_label(scope)}: {'; '.join(bits)}.")

        if not report and total_automation_objects <= 0:
            report.append("No automation ran overnight.")

        self.state.last_automation_report = report[-24:]
        return self.state.last_automation_report

    def automation_morning_summary(self, report: Optional[List[str]] = None) -> str:
        report = report if report is not None else getattr(self.state, "last_automation_report", [])
        useful = [line for line in report if line and line != "No automation ran overnight."]
        if not useful:
            return ""
        return f" Automation report ready ({len(useful)} update(s))."

    def automation_status_lines(self, scope: Optional[str] = None) -> List[str]:
        rows: List[str] = ["FARM AUTOMATION", ""]
        target_scopes = self.owned_farm_land_maps()
        if scope:
            target_scopes = [(candidate_scope, land_map) for candidate_scope, land_map in target_scopes if candidate_scope == scope]

        if not target_scopes:
            rows.append("No owned farm land found for this report.")
            return rows

        any_objects = False
        for land_scope, _land_map in target_scopes:
            automation_objects = self.placed_objects_for_scope(land_scope, automation_only=True)
            rows.append(self.automation_scope_label(land_scope))
            if not automation_objects:
                rows.append("- No automation objects placed.")
                rows.append("")
                continue
            any_objects = True
            counts = collections.Counter(str(obj["name"]) for obj in automation_objects)
            for name in sorted(counts):
                data = INFRASTRUCTURE_DATA.get(name, {})
                daily = str(data.get("daily_behavior", data.get("description", "automation object")))
                rows.append(f"- {name} x{counts[name]}: {daily}")
                if name == "Seed Hopper":
                    loaded_labels = [
                        self.seed_hopper_loaded_label(str(obj.get("key", "")))
                        for obj in automation_objects
                        if obj.get("name") == "Seed Hopper"
                    ]
                    loaded = [label for label in loaded_labels if label != "empty"]
                    rows.append(f"  Loaded: {len(loaded)}/{counts[name]} hopper(s)")
                    if loaded:
                        rows.append(f"  Seeds: {', '.join(loaded[:3])}")
            rows.append("")

        rows.append("Last night:")
        last_report = getattr(self.state, "last_automation_report", []) or []
        if scope and last_report:
            label = self.automation_scope_label(scope)
            last_report = [
                line for line in last_report
                if line.startswith(f"{label}:") or line.startswith("Sprinklers watered")
            ]
        if last_report:
            rows.extend(f"- {line}" for line in last_report)
        else:
            rows.append("- No automation report has been recorded yet.")

        if not any_objects:
            rows.extend([
                "",
                "Build Rain Barrels, pipes, pumps, crates, and loaders to start automating owned farms.",
            ])
        return rows

    def irrigation_preview_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, object]:
        nodes = [obj for obj in objects if obj.get("kind") in ["pipe", "pump", "water_source"]]
        waterable = set()
        active_networks = 0
        inactive_networks = 0
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        for component in self.irrigation_components(nodes):
            active = False
            for node in component:
                kind = str(node.get("kind", ""))
                automation = node.get("automation", {}) if isinstance(node.get("automation"), dict) else {}
                if kind == "water_source":
                    active = True
                    break
                if kind == "pump" and (not automation.get("requires_water") or self.pump_has_water_source(scope, land_map, node)):
                    active = True
                    break
            if not active:
                inactive_networks += 1
                continue
            active_networks += 1
            for node in component:
                automation = node.get("automation", {}) if isinstance(node.get("automation"), dict) else {}
                radius = max(1, int(automation.get("water_radius", 1)))
                nx, ny = int(node["x"]), int(node["y"])
                for yy in range(max(0, ny - radius), min(map_h, ny + radius + 1)):
                    for xx in range(max(0, nx - radius), min(map_w, nx + radius + 1)):
                        if land_map[yy][xx] in [",", "w"] or self.crop_for_scope(scope, xx, yy):
                            waterable.add((xx, yy))
        return {"tiles": waterable, "active_networks": active_networks, "inactive_networks": inactive_networks}

    def harvest_preview_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, int]:
        crates = [obj for obj in objects if obj.get("kind") == "harvest_crate"]
        loaders = [obj for obj in objects if obj.get("kind") == "shipping_loader"]
        bins = [obj for obj in objects if obj.get("name") == "Shipping Bin"]
        mature_positions = set()
        loader_routes = 0
        map_h = len(land_map)
        map_w = len(land_map[0]) if map_h else 0
        for crate in crates:
            if self.shipping_loader_for_crate(crate, loaders, bins):
                loader_routes += 1
            automation = crate.get("automation", {}) if isinstance(crate.get("automation"), dict) else {}
            radius = max(1, int(automation.get("harvest_radius", 2)))
            cx, cy = int(crate["x"]), int(crate["y"])
            for yy in range(max(0, cy - radius), min(map_h, cy + radius + 1)):
                for xx in range(max(0, cx - radius), min(map_w, cx + radius + 1)):
                    crop = self.crop_for_scope(scope, xx, yy)
                    if crop and crop.ready:
                        mature_positions.add((xx, yy))
        return {"mature": len(mature_positions), "crates": len(crates), "loader_routes": loader_routes, "loaders": len(loaders), "bins": len(bins)}

    def seed_hopper_preview_for_scope(self, scope: str, land_map: List[List[str]], objects: List[Dict[str, object]]) -> Dict[str, int]:
        hoppers = [obj for obj in objects if obj.get("kind") == "seed_hopper"]
        result = {"hoppers": len(hoppers), "loaded": 0, "plantable": 0, "empty": 0, "out_of_season": 0}
        plantable_positions = set()
        for hopper in hoppers:
            record = self.seed_hopper_record(str(hopper.get("key", "")), create=False) or {}
            seed_crop = str(record.get("seed_crop", "") or "")
            try:
                seed_qty = max(0, int(record.get("seed_qty", 0) or 0))
            except Exception:
                seed_qty = 0
            if seed_crop not in CROP_DATA or seed_qty <= 0:
                result["empty"] += 1
                continue
            result["loaded"] += 1
            if not self.seed_crop_valid_this_season(seed_crop):
                result["out_of_season"] += 1
                continue
            for pos in self.seed_hopper_candidates(scope, land_map, hopper, require_loaded=True):
                plantable_positions.add(pos)
        result["plantable"] = len(plantable_positions)
        return result

    def automation_overlay_lines(self, scope: Optional[str] = None) -> List[str]:
        rows: List[str] = ["AUTOMATION OVERLAY", ""]
        target_scopes = self.owned_farm_land_maps()
        if scope:
            target_scopes = [(candidate_scope, land_map) for candidate_scope, land_map in target_scopes if candidate_scope == scope]
        for land_scope, land_map in target_scopes:
            objects = self.placed_objects_for_scope(land_scope, automation_only=False)
            automation_objects = [obj for obj in objects if isinstance(obj.get("automation"), dict) and obj.get("automation")]
            rows.append(self.automation_scope_label(land_scope))
            if not automation_objects:
                rows.append("- No automation coverage.")
                rows.append("")
                continue
            irrigation = self.irrigation_preview_for_scope(land_scope, land_map, automation_objects)
            harvest = self.harvest_preview_for_scope(land_scope, land_map, objects)
            seeding = self.seed_hopper_preview_for_scope(land_scope, land_map, automation_objects)
            workable_tiles = 0
            for yy, row in enumerate(land_map):
                for xx, tile in enumerate(row):
                    if tile in [",", "w"] or self.crop_for_scope(land_scope, xx, yy):
                        workable_tiles += 1
            rows.append(f"- Irrigation reach: {len(irrigation['tiles'])}/{workable_tiles} worked tile(s)")
            rows.append(f"- Water networks: {irrigation['active_networks']} active, {irrigation['inactive_networks']} inactive")
            rows.append(f"- Harvest crates: {harvest['crates']} crate(s), {harvest['mature']} mature crop(s) in range")
            rows.append(f"- Loader routes: {harvest['loader_routes']} crate route(s), {harvest['loaders']} loader(s), {harvest['bins']} bin(s)")
            rows.append(f"- Seed hoppers: {seeding['loaded']}/{seeding['hoppers']} loaded, {seeding['plantable']} empty tilled tile(s) in range")
            if seeding["out_of_season"]:
                rows.append(f"- Out-of-season hoppers: {seeding['out_of_season']}")
            rows.append("")
        rows.append("Symbols:")
        rows.append("- Blue machines water; wood crates harvest; yellow loaders ship; green hoppers plant.")
        rows.append("- This view is a planning report. It does not advance the day.")
        return rows

    def automation_object_status_lines(self, obj_key: str) -> List[str]:
        parsed = self.parse_object_key(obj_key)
        obj_name = self.state.placed_objects.get(obj_key, "")
        if not parsed or not obj_name:
            return ["Automation object not found."]
        scope, x, y = parsed
        land_map = self.land_map_for_object_scope(scope)
        data = INFRASTRUCTURE_DATA.get(obj_name, {})
        automation = data.get("automation") if isinstance(data.get("automation"), dict) else {}
        kind = str(automation.get("kind", ""))
        rows = [
            obj_name,
            "",
            f"Location: {self.automation_scope_label(scope)} ({x},{y})",
            f"Footprint: {self.footprint_label(obj_name)}",
            str(data.get("description", "Automation object.")),
            "",
        ]
        if not land_map:
            rows.append("No owned farm map found for this object.")
            return rows

        objects = self.placed_objects_for_scope(scope, automation_only=False)
        current = next((obj for obj in objects if obj.get("key") == obj_key), None)
        if obj_name == "Seed Hopper" and current:
            record = self.seed_hopper_record(obj_key, create=True)
            seed_crop = str(record.get("seed_crop", "") or "")
            try:
                seed_qty = max(0, int(record.get("seed_qty", 0) or 0))
            except Exception:
                seed_qty = 0
            candidates = self.seed_hopper_candidates(scope, land_map, current, require_loaded=False)
            rows.append(f"Loaded: {self.seed_hopper_loaded_label(obj_key)}")
            rows.append(f"Empty tilled soil in range: {len(candidates)}")
            if seed_crop in CROP_DATA and seed_qty > 0:
                season_label = "in season" if self.seed_crop_valid_this_season(seed_crop) else f"not a {self.state.season} crop"
                rows.append(f"Seed status: {season_label}")
            rows.append(f"Last action: {record.get('last_message', '') or 'No overnight action yet.'}")
            rows.append("")
            rows.append("Use this hopper to load or unload seeds.")
            return rows

        if kind in ["pipe", "pump", "water_source", "sprinkler"]:
            irrigation = self.irrigation_preview_for_scope(scope, land_map, [obj for obj in objects if isinstance(obj.get("automation"), dict) and obj.get("automation")])
            rows.append(f"Irrigation reach on this land: {len(irrigation['tiles'])} tile(s)")
            rows.append(f"Networks: {irrigation['active_networks']} active, {irrigation['inactive_networks']} inactive")
            if kind == "pump" and current:
                rows.append(f"Water source nearby: {'yes' if self.pump_has_water_source(scope, land_map, current) else 'no'}")
            rows.append("Connect pipes edge-to-edge to extend water coverage.")
            return rows

        if kind == "harvest_crate" and current:
            harvest = self.harvest_preview_for_scope(scope, land_map, objects)
            loaders = [obj for obj in objects if obj.get("kind") == "shipping_loader"]
            bins = [obj for obj in objects if obj.get("name") == "Shipping Bin"]
            linked = self.shipping_loader_for_crate(current, loaders, bins) is not None
            rows.append(f"Mature crops in crate range: {harvest['mature']}")
            rows.append(f"Linked to loader and bin: {'yes' if linked else 'no'}")
            rows.append("Unlinked crates place harvests in your inventory overnight.")
            return rows

        if kind == "shipping_loader" and current:
            crates = [obj for obj in objects if obj.get("kind") == "harvest_crate"]
            bins = [obj for obj in objects if obj.get("name") == "Shipping Bin"]
            linked_crates = sum(1 for crate in crates if self.shipping_loader_for_crate(crate, [current], bins))
            has_bin = any(self.object_chebyshev_distance(current, bin_obj) <= int(automation.get("bin_radius", 4)) for bin_obj in bins)
            rows.append(f"Linked harvest crates: {linked_crates}")
            rows.append(f"Shipping bin in range: {'yes' if has_bin else 'no'}")
            rows.append("A loader needs both a nearby crate and a nearby Shipping Bin.")
            return rows

        rows.append(str(data.get("daily_behavior", "Automation status unavailable.")))
        return rows

    def automation_deed_summary_lines(self, scope: str) -> List[str]:
        automation_objects = self.placed_objects_for_scope(scope, automation_only=True)
        if not automation_objects:
            return ["- No automation objects placed yet."]
        counts = collections.Counter(str(obj["name"]) for obj in automation_objects)
        lines = [f"- {name}: x{counts[name]}" for name in sorted(counts)]
        last_report = getattr(self.state, "last_automation_report", []) or []
        matching = [line for line in last_report if line.startswith(f"{self.automation_scope_label(scope)}:")]
        if matching:
            lines.append(f"- Last night: {matching[-1].split(': ', 1)[1]}")
        return lines

    def show_automation_report_menu(self):
        while True:
            last_count = len([line for line in (getattr(self.state, "last_automation_report", []) or []) if line != "No automation ran overnight."])
            items = [
                MenuItem(label="System status", value="status", enabled=True),
                MenuItem(label="Coverage overlay", value="overlay", enabled=True),
                MenuItem(label="Last night", value="last", enabled=True, hint=f"{last_count} update(s)" if last_count else "none"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Automation", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            if choice.value == "status":
                self.vertical_panel_view("Automation Status", self.automation_status_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "overlay":
                self.vertical_panel_view("Automation Overlay", self.automation_overlay_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "last":
                rows = getattr(self.state, "last_automation_report", []) or ["No automation report has been recorded yet."]
                self.vertical_panel_view("Last Night", rows, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue

    def normalize_map_transitions(self):
        """Keep map transitions and interior defaults consistent across old saves."""
        for map_attr, factory_name in self.FIXED_INTERIOR_MAP_SPECS:
            if not hasattr(self, map_attr) or not isinstance(getattr(self, map_attr), list):
                setattr(self, map_attr, getattr(self, factory_name)())
        if not hasattr(self, "mine_maps") or not isinstance(self.mine_maps, dict):
            self.mine_maps = {"1": self.mine_map if hasattr(self, "mine_map") else self.make_mine_map(1)}
        if str(getattr(self.state, "mine_floor", 1)) not in self.mine_maps:
            self.mine_maps[str(getattr(self.state, "mine_floor", 1))] = self.make_mine_map(getattr(self.state, "mine_floor", 1))
        self.mine_map = self.get_mine_floor_map(getattr(self.state, "mine_floor", 1))
        self.normalize_mine_enemies()
        self.ensure_wilderness_chunks()
        self.ensure_wilderness_points_of_interest()
        # Remove old south farm gate.
        for x in range(23, 31):
            if 0 <= x < WIDTH:
                if self.base_map[HEIGHT - 1][x] == "E":
                    self.base_map[HEIGHT - 1][x] = "#"
                if self.base_map[HEIGHT - 2][x] == ".":
                    # Leave open ground if player already used it, but not as a transition.
                    pass

        # Replace legacy compass-letter gates with visible road openings.
        for y in range(8, 13):
            self.base_map[y][0] = ":"
            self.base_map[y][1] = "."
            self.base_map[y][2] = "."

        # The north mine entrance uses the established stair/entrance mark.
        for x in range(25, 30):
            self.base_map[0][x] = "<"
            self.base_map[1][x] = "."
            self.base_map[2][x] = "."

        # Ensure farmhouse exterior is solid and has one usable door.
        for yy in range(2, 6):
            for xx in range(3, 9):
                self.base_map[yy][xx] = "H"
        self.base_map[5][5] = "D"
        self.base_map[6][5] = "."

        self.refresh_farm_border_and_gates()
        self.open_interior_expansion_borders()
        self.ensure_movable_shipping_bin()
        self.ensure_mailbox()

        # Remove old south town exit.
        for x in range(23, 31):
            if 0 <= x < WIDTH:
                if self.town_map[HEIGHT - 1][x] == "E":
                    self.town_map[HEIGHT - 1][x] = "#"
                if self.town_map[HEIGHT - 2][x] == "=":
                    self.town_map[HEIGHT - 2][x] = "."

        # Retire the old half-width east gate. The expanded town's real farm
        # boulevard is at its far eastern edge, not in the middle of town.
        for y in range(9, 13):
            if self.town_map[y][WIDTH - 1] == "E":
                self.town_map[y][WIDTH - 1] = ":"

        # Keep the real farm boulevard visibly open without compass-letter
        # transition markers. Walking through the boundary performs the move.
        for y in range(18, 23):
            self.town_map[y][TOWN_WIDTH - 1] = ":"
            self.town_map[y][TOWN_WIDTH - 2] = "="
            self.town_map[y][TOWN_WIDTH - 3] = "="

        # Remove old farm shop footprint; the shop is now in town.
        for y in range(2, 5):
            for x in range(37, 44):
                if 0 <= x < WIDTH and 0 <= y < HEIGHT and self.base_map[y][x] == "$":
                    self.base_map[y][x] = "."

        # Convert old placeholder community hall/clinic into Blacksmith.
        for yy in range(3, 8):
            for xx in range(16, 24):
                self.town_map[yy][xx] = "X"
        self.town_map[7][19] = "D"
        self.town_map[8][19] = ":"

        # Clear old problematic signposts and restore safe signposts.
        for x, y in [(27, 8), (8, 8), (38, 8), (10, 18), (19, 8), (20, 8), (37, 8), (39, 18)]:
            if 0 <= x < WIDTH and 0 <= y < HEIGHT and self.town_map[y][x] == "?":
                self.town_map[y][x] = ":"
        for x, y in [(24, 8), (14, 8), (15, 8), (43, 8), (18, 16), (32, 16)]:
            if 0 <= x < WIDTH and 0 <= y < HEIGHT and self.town_map[y][x] in [".", ":", "="]:
                self.town_map[y][x] = "?"

        # Ensure General Store door/foyer stays usable.
        self.town_map[7][8] = "D"
        self.town_map[8][8] = ":"

        # Remove the obsolete north gate from the original half-width town.
        for xx in range(25, 30):
            if self.town_map[0][xx] == "W":
                self.town_map[0][xx] = "#"
            if self.town_map[1][xx] == "W":
                self.town_map[1][xx] = "."

        # Ensure the expanded town's true north wilderness road exists on old
        # saves. Its open edge is itself the transition, so no W marker is used.
        for xx in range(56, 60):
            self.town_map[0][xx] = ":"
            self.town_map[1][xx] = "="
            self.town_map[2][xx] = "="

        if not hasattr(self, "wilderness_map") or not isinstance(self.wilderness_map, list):
            self.wilderness_map = self.make_wilderness_map(self.state.wilderness_seed)

        # Ensure Furniture Store building, door, approach, and sign exist on old saves.
        for yy in range(14, 19):
            for xx in range(45, 53):
                self.town_map[yy][xx] = "Y"
        self.town_map[18][48] = "D"
        self.town_map[19][48] = ":"
        if self.town_map[19][45] in [".", ":", "="]:
            self.town_map[19][45] = "?"

        # Ensure Carpenter building, door, approach, and sign exist on old saves.
        for yy in range(14, 19):
            for xx in range(16, 24):
                self.town_map[yy][xx] = "C"
        self.town_map[18][19] = "D"
        self.town_map[19][19] = ":"
        if self.town_map[19][24] in [".", ":", "="]:
            self.town_map[19][24] = "?"

        # v135 reassert grid town layout after old transition migration code.
        # Older normalization code used to paint legacy doors/buildings into town_map;
        # the grid layout should be the source of truth now.
        self.town_map = self.make_town_map()

        # Ensure mine map exists and has south exit.
        if not hasattr(self, "mine_map") or not isinstance(self.mine_map, list):
            self.mine_map = self.make_mine_map()
        for x in range(25, 30):
            self.mine_map[HEIGHT - 1][x] = "N"
            self.mine_map[HEIGHT - 2][x] = "."

        # Ensure house interior exists and built-in furniture has been converted to movable placed objects.
        if not hasattr(self, "house_map") or not isinstance(self.house_map, list):
            self.house_map = self.make_house_map()
        if not hasattr(self.state, "house_upgrades") or self.state.house_upgrades is None:
            self.state.house_upgrades = []
        try:
            existing_house_objects = [
                key for key in self.state.placed_objects
                if isinstance(key, str) and key.startswith("HouseInterior:")
            ]

            # If this is an older save with fixed furniture tiles, remove those tiles.
            # If the player had not placed custom house furniture yet, use the new logical layout
            # instead of preserving the awkward old arrangement.
            old_fixtures = []
            for yy, row in enumerate(self.house_map):
                for xx, ch in enumerate(row):
                    fixture_name = self.house_fixture_name_for_tile(ch)
                    if fixture_name:
                        old_fixtures.append((fixture_name, xx, yy))
                        self.house_map[yy][xx] = "."

            if old_fixtures and not existing_house_objects:
                self.rebuild_house_for_current_upgrades(preserve_existing=False)
            else:
                for fixture_name, xx, yy in old_fixtures:
                    key = self.house_object_key(xx, yy)
                    if not self.state.placed_objects.get(key):
                        self.state.placed_objects[key] = fixture_name
                self.rebuild_house_for_current_upgrades(preserve_existing=True)
        except Exception:
            self.house_map = self.make_house_map()
            self.ensure_default_house_furniture(preserve_existing=False)

        # Fixed town interiors are code-defined. Always regenerate them so older
        # saves cannot restore stale rooms with mismatched door/entry positions.
        self.refresh_town_interior_maps()

    def crop_key(self, x: int, y: int) -> str:
        if self.on_owned_wilderness_claim():
            return f"{self.claim_scope_key()}:{x},{y}"
        if self.on_farm():
            return f"Farm:{x},{y}"
        return f"{self.state.location}:{x},{y}"

    def get_crop(self, x: int, y: int) -> Optional[Crop]:
        crop = self.crops.get(self.crop_key(x, y))
        if crop is None and self.on_farm():
            crop = self.crops.get(f"{x},{y}")
        return crop

    def tile_key(self, x: int, y: int) -> str:
        if self.on_owned_wilderness_claim():
            return f"{self.claim_scope_key()}:{x},{y}"
        if self.on_farm():
            return f"Farm:{x},{y}"
        return f"{self.state.location}:{x},{y}"

    def is_tile_fertilized(self, x: int, y: int) -> bool:
        if self.state.fertilized_tiles.get(self.tile_key(x, y), False):
            return True
        return bool(self.on_farm() and self.state.fertilized_tiles.get(f"{x},{y}", False))

    def set_tile_fertilized(self, x: int, y: int, value: bool = True):
        key = self.tile_key(x, y)
        if value:
            self.state.fertilized_tiles[key] = True
        else:
            self.state.fertilized_tiles.pop(key, None)

    def set_crop(self, x: int, y: int, crop: Crop):
        if self.is_tile_fertilized(x, y):
            crop.fertilized = True
            self.set_tile_fertilized(x, y, False)
        self.crops[self.crop_key(x, y)] = crop

    def remove_crop(self, x: int, y: int):
        self.crops.pop(self.crop_key(x, y), None)
        if self.on_farm():
            self.crops.pop(f"{x},{y}", None)

    def tile_at(self, x: int, y: int) -> str:
        if self.on_farm_work_land():
            crop = self.get_crop(x, y)
            if crop:
                return crop.symbol()
        return self.active_map()[y][x]

    def player_color_code(self) -> str:
        colors = dict(PLAYER_COLOR_OPTIONS)
        return colors.get(str(self.state.player_color), C.PLAYER)

    def render_player(self) -> str:
        color = self.player_color_code()
        if self.state.tool_target_mode == "STANDING":
            return colorize("@", color)

        facing_symbols = {
            "UP": "^",
            "DOWN": "v",
            "LEFT": "<",
            "RIGHT": ">",
        }
        return colorize(facing_symbols.get(self.state.facing, "@"), color)

    def object_storage_position(self, x: int, y: int) -> Tuple[int, int]:
        if (
            hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
        ):
            building = self.current_procedural_town_building()
            if building:
                return self.procedural_town_display_to_source_position(x, y, building)
        return int(x), int(y)

    def obj_key(self, x: int, y: int) -> str:
        storage_x, storage_y = self.object_storage_position(x, y)
        return f"{self.current_object_location_key()}:{storage_x},{storage_y}"

    def object_footprint_size(self, obj_name: str) -> Tuple[int, int]:
        data = INFRASTRUCTURE_DATA.get(obj_name, {})
        footprint = data.get("footprint", [1, 1])
        try:
            w = max(1, int(footprint[0]))
            h = max(1, int(footprint[1]))
            return w, h
        except Exception:
            return 1, 1

    def object_footprint_tiles(self, obj_name: str, x: int, y: int) -> List[Tuple[int, int]]:
        w, h = self.object_footprint_size(obj_name)
        return [(x + dx, y + dy) for dy in range(h) for dx in range(w)]

    def parse_object_key(self, key: str) -> Optional[Tuple[str, int, int]]:
        try:
            if ":" in key:
                location, coords = key.rsplit(":", 1)
            else:
                location, coords = "Farm", key
            x_str, y_str = coords.split(",", 1)
            return location, int(x_str), int(y_str)
        except Exception:
            return None

    def placed_object_at(self, x: int, y: int) -> Tuple[Optional[str], Optional[str], Optional[int], Optional[int]]:
        """Return anchor key, object name, anchor x, anchor y for the object covering this tile."""
        frame_lookup = getattr(self, "_frame_placed_object_lookup", None)
        if isinstance(frame_lookup, dict):
            return frame_lookup.get((int(x), int(y)), (None, None, None, None))
        direct_key = self.obj_key(x, y)
        if direct_key in self.state.placed_objects:
            return direct_key, self.state.placed_objects[direct_key], x, y
        if self.on_farm() and f"{x},{y}" in self.state.placed_objects:
            return f"{x},{y}", self.state.placed_objects[f"{x},{y}"], x, y

        current_location = self.current_object_location_key()
        residence_building = (
            self.current_procedural_town_building()
            if hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
            else None
        )
        for key, obj_name in list(self.state.placed_objects.items()):
            parsed = self.parse_object_key(key)
            if not parsed:
                continue
            location, ax, ay = parsed
            if location != current_location:
                continue
            footprint = self.object_footprint_tiles(obj_name, ax, ay)
            if residence_building:
                source_w, source_h = self.procedural_town_interior_source_dimensions(residence_building)
                side = self.procedural_town_building_door_side(residence_building)
                display_footprint = {
                    self.procedural_town_orient_position(px, py, source_w, source_h, side)
                    for px, py in footprint
                }
                if (x, y) in display_footprint:
                    display_ax, display_ay = self.procedural_town_orient_position(ax, ay, source_w, source_h, side)
                    return key, obj_name, display_ax, display_ay
            elif (x, y) in footprint:
                return key, obj_name, ax, ay
        return None, None, None, None

    def build_frame_placed_object_lookup(self) -> Dict[Tuple[int, int], Tuple[str, str, int, int]]:
        """Index visible object footprints once instead of rescanning them per tile."""
        lookup: Dict[Tuple[int, int], Tuple[str, str, int, int]] = {}
        current_location = self.current_object_location_key()
        residence_building = (
            self.current_procedural_town_building()
            if hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
            else None
        )
        for key, obj_name in list(self.state.placed_objects.items()):
            parsed = self.parse_object_key(key)
            if not parsed:
                continue
            location, ax, ay = parsed
            if location != current_location:
                continue
            footprint = self.object_footprint_tiles(obj_name, ax, ay)
            if residence_building:
                source_w, source_h = self.procedural_town_interior_source_dimensions(residence_building)
                side = self.procedural_town_building_door_side(residence_building)
                display_ax, display_ay = self.procedural_town_orient_position(ax, ay, source_w, source_h, side)
                positions = [
                    self.procedural_town_orient_position(px, py, source_w, source_h, side)
                    for px, py in footprint
                ]
            else:
                display_ax, display_ay = int(ax), int(ay)
                positions = [(int(px), int(py)) for px, py in footprint]
            for position in positions:
                lookup.setdefault(position, (str(key), str(obj_name), display_ax, display_ay))
        return lookup

    def get_placed_object(self, x: int, y: int) -> Optional[str]:
        _key, obj_name, _ax, _ay = self.placed_object_at(x, y)
        return obj_name

    def set_placed_object(self, x: int, y: int, obj_name: str):
        # Only the anchor tile is stored. The footprint is resolved dynamically.
        self.state.placed_objects[self.obj_key(x, y)] = obj_name

    def remove_placed_object(self, x: int, y: int):
        key, obj_name, _ax, _ay = self.placed_object_at(x, y)
        if key:
            self.clear_placed_object_state(key, obj_name or "")
            self.state.placed_objects.pop(key, None)
            return
        self.state.placed_objects.pop(self.obj_key(x, y), None)
        if self.on_farm():
            self.state.placed_objects.pop(f"{x},{y}", None)

    def can_hold_objects_here(self) -> bool:
        return (
            self.on_farm_work_land()
            or self.on_house()
            or (
                hasattr(self, "on_player_owned_procedural_residence")
                and self.on_player_owned_procedural_residence()
            )
        )

    def held_object_label(self) -> str:
        return self.state.held_object if self.state.held_object else "None"

    def pickup_front_object_to_hand(self):
        if not self.can_hold_objects_here():
            self.set_message("You can only pick up placed objects on owned farm land or inside a home you own.")
            return False
        if self.state.held_object:
            self.set_message(f"You are already holding {self.state.held_object}. Press Z/Enter to place it, or X to store it.")
            return False

        x, y = self.front_tile_pos()
        key, obj_name, ax, ay = self.placed_object_at(x, y)
        if not obj_name:
            self.set_message("There is no placed object in front of you.")
            return False
        if key and self.object_has_attached_state(key, obj_name):
            self.set_message(f"{obj_name} has attached state. Use Tab > Farm & Home > Build Mode to move it safely.")
            return False

        self.remove_placed_object(x, y)
        self.state.held_object = obj_name
        self.autosave_with_message(f"Picked up {obj_name}. Press Z/Enter to place it, or X to store it.")
        return True

    def store_held_object(self):
        obj_name = self.state.held_object
        if not obj_name:
            self.set_message("You are not holding an object.")
            return False
        self.state.inventory[obj_name] = self.state.inventory.get(obj_name, 0) + 1
        self.state.held_object = None
        self.autosave_with_message(f"Stored {obj_name} in inventory.")
        return True

    def place_held_object(self):
        obj_name = self.state.held_object
        if not obj_name:
            return False

        if not self.can_hold_objects_here():
            self.set_message("You can only place held objects on owned farm land or inside a home you own.")
            return False

        x, y = self.front_tile_pos()
        ok, reason = self.can_place_object(obj_name, x, y)
        if not ok:
            self.set_message(f"Cannot place {obj_name}: {reason}.")
            return False

        self.set_placed_object(x, y, obj_name)
        self.state.held_object = None
        self.autosave_with_message(f"Placed {obj_name}.")
        return True

    def handle_x_object_key(self):
        if self.state.held_object:
            return self.store_held_object()
        return self.pickup_front_object_to_hand()

    def render_placed_object(self, obj_name: str, x: Optional[int] = None, y: Optional[int] = None, ax: Optional[int] = None, ay: Optional[int] = None) -> str:
        data = INFRASTRUCTURE_DATA.get(obj_name, {})
        symbol = data.get("symbol", "*")
        category = data.get("category", "infrastructure")
        if obj_name in {"Fence", "Stone Path", "Pipe Segment"} and x is not None and y is not None:
            def direct_object_at(nx: int, ny: int) -> str:
                name = str(self.state.placed_objects.get(self.obj_key(nx, ny), "") or "")
                if not name and self.on_farm():
                    name = str(self.state.placed_objects.get(f"{int(nx)},{int(ny)}", "") or "")
                return name

            glyph = connected_network_glyph(
                direct_object_at(int(x), int(y) - 1) == obj_name,
                direct_object_at(int(x) + 1, int(y)) == obj_name,
                direct_object_at(int(x), int(y) + 1) == obj_name,
                direct_object_at(int(x) - 1, int(y)) == obj_name,
                bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                str(symbol)[:1],
            )
            network_color = {
                "Fence": C.WOOD,
                "Stone Path": C.PATH,
                "Pipe Segment": C.WATER,
            }[obj_name]
            if bool(getattr(self.state, "high_contrast_enabled", False)):
                network_color = C.SERVICE
            return colorize(glyph, network_color)
        if category == "building" and x is not None and y is not None and ax is not None and ay is not None:
            width, height = self.object_footprint_size(obj_name)
            structure = farm_structure_surface(
                obj_name,
                width,
                height,
                int(x) - int(ax),
                int(y) - int(ay),
                bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                int(getattr(self, "_ambient_visual_phase", 0)),
                int(x) * 31 + int(y) * 17,
                bool(getattr(self.state, "high_contrast_enabled", False)),
            )
            if structure:
                return colorize(*structure)
        if category == "storage":
            return colorize(symbol, C.WOOD)
        if category == "automation":
            automation = data.get("automation") if isinstance(data.get("automation"), dict) else {}
            kind = str(automation.get("kind", ""))
            automation_color = {
                "pipe": C.STONE,
                "pump": C.WATER,
                "water_source": C.WATER,
                "harvest_crate": C.WOOD,
                "shipping_loader": C.LAMP,
                "seed_hopper": C.CROP_READY,
                "sprinkler": C.WATER,
            }.get(kind, C.INFRA)
            return colorize(symbol, automation_color)
        if category != "furniture":
            return colorize(symbol, C.INFRA)

        patterns = {
            "Bed": ["ooo", "==="],
            "Wooden Table": ["[]"],
            "Bookshelf": ["L", "L"],
            "Decorative Rug": ["/-\\", "\\-/"],
            "Dresser": ["[]"],
            "Kitchen Counter": ["[==]"],
            "Couch": ["[=]"],
            "Large Rug": ["/---\\", "|...|", "\\---/"],
            "Wash Basin": ["()"],
            "Pantry": ["[]"],
            "Fireplace": ["[F]"],
            "Writing Desk": ["[_"],
            "Wardrobe": ["[]"],
            "Room Divider": ["|", "|"],
            "Crib": ["[]"],
            "Child Bed": ["=="],
            "Toy Shelf": ["*"],
            "Study Desk": ["[_"],
            "Family Table": ["[+]"],
            "Keepsake Chest": ["[]"],
        }
        if x is not None and y is not None and ax is not None and ay is not None:
            pattern = patterns.get(obj_name)
            if pattern:
                ox = int(x) - int(ax)
                oy = int(y) - int(ay)
                if 0 <= oy < len(pattern) and 0 <= ox < len(pattern[oy]):
                    symbol = pattern[oy][ox]

        color = {
            "Bed": C.PLAYER,
            "Wooden Chair": C.WOOD,
            "Wooden Table": C.WOOD,
            "Bookshelf": C.SNOW,
            "Decorative Rug": C.CROP_READY,
            "Large Rug": C.CROP_READY,
            "House Plant": C.GRASS,
            "Flower Vase": C.CROP_READY,
            "Dresser": C.WOOD,
            "Wardrobe": C.WOOD,
            "Nightstand": C.LAMP,
            "Standing Lamp": C.LAMP,
            "Wall Calendar": C.CROP_READY,
            "Television": C.WATER,
            "Kitchen Counter": C.STONE,
            "Pantry": C.WOOD,
            "Wash Basin": C.WATER,
            "Fireplace": C.LAMP,
            "Writing Desk": C.WOOD,
            "Couch": C.HOUSE,
            "Armchair": C.HOUSE,
            "Tea Table": C.WOOD,
            "Wall Mirror": C.WATER,
            "Room Divider": C.WOOD,
            "Wall Art": C.PLACEMENT,
            "Shelf": C.WOOD,
            "Crib": C.CROP_READY,
            "Child Bed": C.PLAYER,
            "Toy Shelf": C.LAMP,
            "Study Desk": C.WOOD,
            "Family Table": C.HOUSE,
            "Keepsake Chest": C.WOOD,
        }.get(obj_name, C.INFRA)
        return colorize(symbol, color)

    def footprint_label(self, obj_name: str) -> str:
        w, h = self.object_footprint_size(obj_name)
        return f"{w}x{h}" if (w, h) != (1, 1) else "1 tile"

    def can_place_object(
        self,
        obj_name: str,
        x: int,
        y: int,
        ignore_object_key: Optional[str] = None,
    ) -> Tuple[bool, str]:
        if not self.in_active_bounds(x, y):
            return False, "out of bounds"

        data = INFRASTRUCTURE_DATA.get(obj_name, {})
        category = data.get("category", "infrastructure")
        place_locations = data.get("place_locations")
        footprint_tiles = self.object_footprint_tiles(obj_name, x, y)
        owned_town_home = (
            hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
        )

        location_allowed = (self.state.location in place_locations) if place_locations else True
        if place_locations and "Farm" in place_locations and self.on_farm_work_land():
            location_allowed = True
        if place_locations and "HouseInterior" in place_locations and owned_town_home:
            location_allowed = True
        if place_locations and not location_allowed:
            if category == "furniture":
                return False, "furniture goes inside a home you own"
            return False, "wrong location"

        if category == "furniture" or (category == "storage" and (self.on_house() or owned_town_home)):
            if not (self.on_house() or owned_town_home):
                return False, "furniture goes inside a home you own"
            floor_map = self.house_map if self.on_house() else self.active_map()
            for tx, ty in footprint_tiles:
                if not self.in_active_bounds(tx, ty):
                    return False, "footprint out of bounds"
                placed_key, _placed_name, _placed_x, _placed_y = self.placed_object_at(tx, ty)
                if placed_key and placed_key != ignore_object_key:
                    return False, "something is already placed there"
                tile = floor_map[ty][tx]
                if tile not in self.house_floor_tiles():
                    return False, "place it on open floor"
                if self.travel_follower_at(tx, ty):
                    return False, "your follower is standing there"
                if owned_town_home and self.procedural_town_resident_at(tx, ty):
                    return False, "someone is standing there"
                if tx == self.state.player_x and ty == self.state.player_y:
                    return False, "you are standing there"
            return True, "ok"

        if not self.on_farm_work_land():
            return False, "farm infrastructure/buildings go outside on owned farm land"
        land_map = self.active_farm_work_map()
        for tx, ty in footprint_tiles:
            if not self.in_active_bounds(tx, ty):
                return False, "footprint out of bounds"
            if self.on_farm() and self.farm_animal_at(tx, ty):
                return False, "a farm animal is standing there"
            if self.travel_follower_at(tx, ty):
                return False, "your follower is standing there"
            placed_key, _placed_name, _placed_x, _placed_y = self.placed_object_at(tx, ty)
            if placed_key and placed_key != ignore_object_key:
                return False, "something is already built there"
            if self.get_crop(tx, ty):
                return False, "a crop is already growing there"
            tile = land_map[ty][tx]
            buildable_tiles = [".", ",", "w"]
            if self.on_owned_wilderness_claim():
                buildable_tiles.extend(list(WILDERNESS_BIOME_TILES))
            if tile not in buildable_tiles:
                return False, "build on grass or tilled soil"
            if tx == self.state.player_x and ty == self.state.player_y:
                return False, "you are standing there"

        if obj_name == "Stone Path":
            return True, "ok"

        return True, "ok"

    def render_weather_overlay(
        self,
        x: int,
        y: int,
        tile_map: Optional[List[List[str]]] = None,
        world_x: Optional[int] = None,
        world_y: Optional[int] = None,
    ) -> Optional[str]:
        """Sparse, stable precipitation overlay for outdoor map tiles."""
        if self.location_is_weather_sheltered():
            return None
        weather = self.state.weather
        if not weather_has_precipitation(weather):
            return None

        if self.on_farm_work_land() and self.get_placed_object(x, y):
            return None
        if self.on_farm_work_land() and self.get_crop(x, y):
            return None

        tile_map = tile_map if tile_map is not None else self.active_map()
        base_tile = tile_map[y][x]
        if not tile_outdoors(base_tile) or not weather_overlay_allowed(base_tile):
            return None

        # Wilderness precipitation is a world-space field. It therefore covers
        # neighboring streamed chunks and remains stable across redraws instead
        # of changing according to render order.
        if self.on_wilderness():
            if world_x is None or world_y is None:
                world_x, world_y = self.wilderness_world_coords(
                    int(self.state.wilderness_chunk_x),
                    int(self.state.wilderness_chunk_y),
                    int(x),
                    int(y),
                )
            calendar_phase = (
                int(getattr(self.state, "year", 1)) * 70000
                + int(getattr(self.state, "day", 1)) * 1900
                + int(getattr(self.state, "hour", 6)) * 60
                + int(getattr(self.state, "minute", 0))
            )
            phase = calendar_phase + int(getattr(self, "_weather_visual_phase", 0))
            weather_roll = self.wilderness_hash01(
                int(world_x) + phase * 3,
                int(world_y) - phase * 2,
                12051,
            )
            if weather_roll >= precipitation_density(weather):
                return None
            weather_symbols = weather_glyphs(weather)
            symbol_roll = self.wilderness_hash01(
                int(world_x) - phase,
                int(world_y) + phase,
                12052,
            )
            symbol_index = min(len(weather_symbols) - 1, int(symbol_roll * len(weather_symbols)))
            depth_roll = self.wilderness_hash01(
                int(world_x) + phase,
                int(world_y) - phase,
                12053,
            )
        else:
            # Stable screen-space precipitation prevents random pop-in on every
            # redraw while the visual phase still makes the field move.
            phase = int(getattr(self, "_weather_visual_phase", 0))
            roll = ((int(x) * 92821 + int(y) * 68917 + phase * 31337) & 0xFFFF) / 65535.0
            if roll >= precipitation_density(weather):
                return None
            symbols = weather_glyphs(weather)
            symbol_index = (int(x) * 7 + int(y) * 11 + phase) % len(symbols)
            depth_roll = ((int(x) * 31337 + int(y) * 7919 + phase * 1543) & 0xFFFF) / 65535.0

        symbol, color = weather_overlay_style(weather, symbol_index, depth_roll)
        return colorize(symbol, color)

    def location_is_weather_sheltered(self) -> bool:
        return bool(
            self.on_mine()
            or self.on_house()
            or self.on_town_interior()
            or self.on_procedural_town_interior()
            or self.on_wilderness_cave()
            or self.on_wilderness_dungeon()
            or self.on_wilderness_outpost()
            or self.on_wilderness_structure()
        )

    def visible_weather_label(self) -> str:
        if self.on_mine() or self.on_wilderness_cave() or self.on_wilderness_dungeon():
            return "Underground"
        if self.location_is_weather_sheltered():
            return "Sheltered"
        return str(self.state.weather)

    def visible_lighting_label(self) -> str:
        if self.location_is_weather_sheltered():
            return "Interior"
        return self.outdoor_lighting_label()

    def is_night_time(self) -> bool:
        return int(self.state.hour) >= 19 or int(self.state.hour) < 6

    def is_dusk_time(self) -> bool:
        return 17 <= int(self.state.hour) < 19

    def outdoor_lighting_label(self) -> str:
        if self.is_night_time():
            return "Night"
        if self.is_dusk_time():
            return "Dusk"
        return "Day"

    def tile_is_near_streetlamp(self, x: int, y: int, radius: int = 5) -> bool:
        if not self.on_town():
            return False
        town = self.town_map
        for yy in range(max(0, y - radius), min(TOWN_HEIGHT, y + radius + 1)):
            for xx in range(max(0, x - radius), min(TOWN_WIDTH, x + radius + 1)):
                if town[yy][xx] == "!" and abs(xx - x) + abs(yy - y) <= radius:
                    return True
        return False

    def town_streetlamp_lit_tile_lookup(self, radius: int = 5) -> Set[Tuple[int, int]]:
        """Build the town's lamp-lit area once for a complete rendered frame."""
        radius = max(0, int(radius))
        lit_tiles: Set[Tuple[int, int]] = set()
        town = self.town_map
        for lamp_y, row in enumerate(town):
            for lamp_x, tile in enumerate(row):
                if tile != "!":
                    continue
                for dy in range(-radius, radius + 1):
                    remaining = radius - abs(dy)
                    y = lamp_y + dy
                    if not (0 <= y < len(town)):
                        continue
                    for x in range(
                        max(0, lamp_x - remaining),
                        min(len(row), lamp_x + remaining + 1),
                    ):
                        lit_tiles.add((x, y))
        return lit_tiles

    def town_lamp_count(self) -> int:
        return sum(row.count("!") for row in self.town_map)

    def town_lighting_report_lines(self) -> List[str]:
        return [
            "TOWN LIGHTING",
            "",
            f"Current light level: {self.outdoor_lighting_label()}",
            f"Streetlamps installed: {self.town_lamp_count()}",
            "",
            "Night behavior:",
            "- Outdoor town tiles are dimmer at night.",
            "- Tiles near streetlamps remain easier to read.",
            "- Civic projects can add more lamps.",
            "",
            "Useful projects:",
            "- Road Grid Signage adds lamps at grid intersections.",
            "- Clinic Supply Board adds clinic-side lamps.",
            "- Park Beautification adds park lamps.",
        ]

    def night_lighting_color_for_tile(self, tile: str, x: int, y: int, base_color: str) -> str:
        if self.location_is_weather_sheltered():
            return base_color
        lit = bool(tile in {"!", "H", "f"})
        if self.on_town() and self.tile_is_near_streetlamp(x, y):
            lit = True
        return outdoor_time_color(
            base_color,
            int(getattr(self.state, "hour", 12)),
            lit=lit,
            ambient=bool(getattr(self.state, "ambient_visuals_enabled", True)),
        )

    def architectural_display_tile(
        self,
        tile_map: List[List[str]],
        x: int,
        y: int,
        allow_windows: bool = False,
        visual_key: Optional[int] = None,
    ) -> str:
        """Return presentation-only architecture for a stored map cell."""
        tile = str(tile_map[int(y)][int(x)] or " ")[:1]
        if tile != "#":
            return tile
        detailed = bool(getattr(self.state, "detailed_glyphs_enabled", True))
        key = int(x) * 31 + int(y) * 17 if visual_key is None else int(visual_key)
        if allow_windows and exterior_window_at(tile_map, x, y, key, detailed):
            return "o"
        return architectural_wall_glyph(tile_map, x, y, detailed)

    def render_interior_visual_tile(
        self,
        tile_map: List[List[str]],
        x: int,
        y: int,
        context: str,
        override_color: str = "",
    ) -> str:
        """Render shaped walls and local light while retaining raw map data."""
        tile = str(tile_map[int(y)][int(x)] or " ")[:1]
        display_tile = self.architectural_display_tile(tile_map, x, y)
        ambient = bool(getattr(self.state, "ambient_visuals_enabled", True))
        high_contrast = bool(getattr(self.state, "high_contrast_enabled", False))
        color = override_color or interior_tile_color(
            tile,
            context,
            int(getattr(self, "_ambient_visual_phase", 0)),
            int(x) * 31 + int(y) * 17,
            ambient,
            high_contrast,
        )
        hour = int(getattr(self.state, "hour", 12)) % 24
        if ambient and not high_contrast and tile in {".", ":", ","} and not (7 <= hour < 19):
            light_cache = getattr(self, "_interior_light_position_cache", None)
            if not isinstance(light_cache, dict):
                light_cache = {}
                self._interior_light_position_cache = light_cache
            cache_key = (id(tile_map), 4)
            if cache_key not in light_cache:
                light_cache[cache_key] = interior_light_positions(tile_map, 4)
            if (int(x), int(y)) in light_cache[cache_key]:
                color = C.LIT
        return colorize(display_tile, color)

    def render_tile(
        self,
        x: int,
        y: int,
        tile_map: Optional[List[List[str]]] = None,
        civic_overlay_lookup: Optional[
            Dict[Tuple[int, int], Dict[str, object]]
        ] = None,
        procedural_town_active: Optional[bool] = None,
        procedural_town_color_lookup: Optional[Dict[Tuple[int, int], str]] = None,
        player_owned_residence: Optional[bool] = None,
        town_public_event_lookup: Optional[
            Dict[Tuple[int, int], Dict[str, object]]
        ] = None,
        town_streetlamp_lit_tiles: Optional[Set[Tuple[int, int]]] = None,
        unlocked_town_buildings: Optional[Set[str]] = None,
    ) -> str:
        """Return a one-character tile with location/season-aware color applied."""
        tile_map = tile_map if tile_map is not None else self.active_map()
        visual_key = int(x) * 31 + int(y) * 17
        if self.on_wilderness():
            visual_world_x, visual_world_y = self.wilderness_world_coords(
                int(self.state.wilderness_chunk_x), int(self.state.wilderness_chunk_y),
                int(x), int(y),
            )
            visual_key = int(visual_world_x) * 31 + int(visual_world_y) * 17

        if player_owned_residence is None:
            player_owned_residence = bool(
                hasattr(self, "on_player_owned_procedural_residence")
                and self.on_player_owned_procedural_residence()
            )
        if self.on_farm_work_land() or self.on_house() or player_owned_residence:
            _key, placed, ax, ay = self.placed_object_at(x, y)
            if placed:
                return self.render_placed_object(placed, x, y, ax, ay)
        if self.dropped_pack_at(x, y):
            return colorize("*", C.CROP_READY)

        if self.on_farm_work_land():
            crop = self.get_crop(x, y)
            if crop:
                return self.render_crop(crop)
        if self.on_wilderness():
            encounter_visual = self.wilderness_random_combat_visual_at(x, y)
            if encounter_visual:
                return colorize(str(encounter_visual.get("symbol", "!"))[:1], C.HOSTILE)
        if (self.on_wilderness_dungeon() or self.on_wilderness()) and self.dungeon_floor_loot_at(x, y):
            return colorize("*", C.CROP_READY)
        if self.on_wilderness_dungeon() and tile_map[y][x] == "+":
            return self.render_dungeon_door(x, y)
        if self.on_wilderness_dungeon() and tile_map[y][x] == "!":
            return self.render_dungeon_trap(x, y)
        if self.map_native_combat_active():
            skill_zone = self.render_dungeon_skill_zone(x, y)
            if skill_zone is not None:
                return skill_zone

        if procedural_town_active is None:
            procedural_town_active = bool(
                self.on_wilderness() and self.current_procedural_town_plan()
            )
        if procedural_town_active:
            civic_overlay = (
                civic_overlay_lookup.get((int(x), int(y)))
                if civic_overlay_lookup is not None
                else self.procedural_town_civic_overlay_at(x, y)
            )
            if civic_overlay:
                overlay_colors = {
                    "residence": C.PLAYER,
                    "business": C.SHOP,
                    "initiative": C.CROP_READY,
                    "regional_project": C.WATER,
                }
                return colorize(
                    str(civic_overlay.get("symbol", "+"))[:1],
                    overlay_colors.get(str(civic_overlay.get("kind", "")), C.PLACEMENT),
                )

        if self.on_wilderness():
            wilderness_ground = self.active_map()[y][x]
            if wilderness_ground in {"`", '"', "["}:
                return colorize(
                    wilderness_ground,
                    wilderness_tile_color(
                        wilderness_ground,
                        self.state.season,
                        int(getattr(self, "_ambient_visual_phase", 0)),
                        visual_key,
                        bool(getattr(self.state, "ambient_visuals_enabled", True)),
                        bool(getattr(self.state, "high_contrast_enabled", False)),
                        str(getattr(self.state, "weather", "")),
                    ),
                )
            consequence_kind = self.wilderness_vitality_consequence_at(x, y)
            if consequence_kind:
                consequence_style = wilderness_landmark_style(
                    self.active_map()[y][x],
                    detailed=bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                    high_contrast=bool(getattr(self.state, "high_contrast_enabled", False)),
                )
                if consequence_style:
                    return colorize(*consequence_style)
            hinterland = self.procedural_town_hinterland_at(x, y)
            if hinterland:
                hinterland_colors = {"quarry": C.STONE, "fishery": C.WATER, "woodlot": C.WOOD, "reed_croft": C.WATER, "herding_station": C.SNOW}
                return colorize(str(hinterland.get("symbol", "h"))[:1], hinterland_colors.get(str(hinterland.get("type_id", "")), C.CROP_READY))
            maritime = self.wilderness_maritime_encounter_at(x, y)
            if maritime:
                return colorize(str(maritime.get("symbol", "?"))[:1], C.CROP_READY)
            if self.wilderness_water_salvage_at(x, y):
                return colorize("z", C.CROP_READY)
            island_site = self.wilderness_island_site_at(x, y)
            if island_site:
                return colorize(str(island_site.get("symbol", "I"))[:1], C.WOOD)
            if self.wilderness_expedition_camp_visual_at(x, y):
                camp_style = wilderness_landmark_style(
                    "R",
                    detailed=bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                    high_contrast=bool(getattr(self.state, "high_contrast_enabled", False)),
                )
                return colorize(*(camp_style or ("R", C.ACTOR_RANGER)))
            expedition_objective = self.wilderness_expedition_objective_visual_at(x, y)
            if expedition_objective:
                return colorize("+" if expedition_objective.get("surveyed") else str(expedition_objective.get("symbol", "?"))[:1], C.DIM if expedition_objective.get("surveyed") else C.CROP_READY)
            event_visual = self.wilderness_event_visual_at(x, y)
            if event_visual:
                event_colors = {"crop": C.CROP_READY, "wood": C.WOOD, "magic": C.BIN, "water": C.WATER, "stone": C.STONE}
                return colorize(str(event_visual.get("symbol", "'"))[:1], event_colors.get(str(event_visual.get("color", "crop")), C.CROP_READY))
            frame_seasonal_lookup = getattr(self, "_frame_wilderness_seasonal_surface_lookup", None)
            seasonal_surface = (
                frame_seasonal_lookup.get((int(x), int(y)), {})
                if isinstance(frame_seasonal_lookup, dict)
                else self.wilderness_seasonal_surface_at(x, y)
            )
            if seasonal_surface:
                seasonal_colors = {"crop": C.CROP_READY, "wood": C.WOOD, "water": C.SNOW, "stone": C.STONE}
                return colorize(
                    str(seasonal_surface.get("symbol", "'"))[:1],
                    seasonal_colors.get(str(seasonal_surface.get("color", "crop")), C.CROP_READY),
                )
        if self.on_town():
            public_feature = (
                town_public_event_lookup.get((int(x), int(y)), {})
                if town_public_event_lookup is not None
                else self.town_public_event_feature_at(x, y)
            )
            if public_feature:
                return colorize(
                    str(public_feature.get("symbol", "*"))[:1],
                    str(public_feature.get("color", C.CROP_READY)),
                )
        tile = tile_map[y][x]
        if self.on_wilderness() and tile == RECLAIMED_STRONGHOLD_BUILD_BOARD_SYMBOL:
            return colorize(tile, C.SHOP)
        if self.on_wilderness():
            _feature_id, stronghold_feature = self.reclaimed_stronghold_feature_at(x, y)
            if stronghold_feature:
                feature_color = {
                    "road": C.DIM,
                    "building": C.SHOP,
                    "decoration": C.CROP_READY,
                }.get(str(stronghold_feature.get("kind", "")), C.PLACEMENT)
                return colorize(tile, feature_color)
        if self.on_wilderness() and tile == "!":
            record = self.wilderness_stronghold_record(create=False)
            return colorize(tile, C.CROP_READY if record.get("cleared") else C.HOSTILE)
        if self.on_wilderness() and tile == PROCEDURAL_TOWN_DOOR_SYMBOL:
            building = self.procedural_town_building_door_at(x, y)
            if building:
                return colorize(tile, C.WOOD if self.procedural_town_building_is_open(building) else C.DIM)
        if self.on_wilderness():
            landmark_kind = (
                str(self.wilderness_landscape_record().get("type_id", ""))
                if tile == WILDERNESS_LANDSCAPE_SYMBOL
                else ""
            )
            display_tile = (
                self.architectural_display_tile(
                    tile_map, x, y, allow_windows=True, visual_key=visual_key,
                )
                if tile == "#" and (
                    procedural_town_active
                    or (int(self.state.wilderness_chunk_x), int(self.state.wilderness_chunk_y)) == (0, 0)
                )
                else None
            )
            return self.render_streamed_wilderness_raw_tile(
                tile,
                visual_key,
                display_tile,
                landmark_kind,
                tile == "~" and self.wilderness_water_is_frozen_at(x, y),
            )
        if self.on_procedural_town_interior():
            custom_color_key = (
                procedural_town_color_lookup.get((int(x), int(y)), "")
                if procedural_town_color_lookup is not None
                else (
                    self.procedural_town_custom_tile_color_key(x, y)
                    if hasattr(self, "procedural_town_custom_tile_color_key")
                    else ""
                )
            )
            custom_colors = {
                "white": C.PLAYER,
                "brown": C.WOOD,
                "red": C.HOSTILE,
                "orange": C.SOIL_WET,
                "yellow": C.CROP_READY,
                "green": C.GRASS,
                "blue": C.WATER,
                "purple": C.BIN,
                "gray": C.STONE,
            }
            if custom_color_key in custom_colors:
                return self.render_interior_visual_tile(tile_map, x, y, "public", custom_colors[custom_color_key])
            return self.render_interior_visual_tile(tile_map, x, y, "public")
        if self.on_wilderness_outpost():
            return self.render_interior_visual_tile(tile_map, x, y, "outpost")
        if self.on_wilderness_structure():
            return self.render_interior_visual_tile(tile_map, x, y, "structure")
        if self.on_house():
            return self.render_interior_visual_tile(tile_map, x, y, "home")
        if self.on_town_interior():
            return self.render_interior_visual_tile(tile_map, x, y, "public")
        if self.on_town():
            building_surface = town_building_surface(
                tile_map,
                x,
                y,
                bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                visual_key,
                bool(getattr(self.state, "high_contrast_enabled", False)),
            )
            if building_surface:
                building_glyph, building_color = building_surface
                building_id = self.town_building_id_at(x, y)
                building_unlocked = bool(
                    not building_id
                    or (
                        building_id in unlocked_town_buildings
                        if unlocked_town_buildings is not None
                        else self.is_town_building_unlocked(building_id)
                    )
                )
                if not building_unlocked:
                    if building_glyph == "o":
                        building_glyph = "\u2593"
                    building_color = C.DIM + building_color
                building_color = outdoor_time_color(
                    building_color,
                    int(getattr(self.state, "hour", 12)),
                    lit=building_glyph == "o" and building_unlocked,
                    ambient=bool(getattr(self.state, "ambient_visuals_enabled", True)) and building_unlocked,
                )
                return colorize(building_glyph, building_color)
            if tile == "Q":
                return colorize(
                    "\u2501" if bool(getattr(self.state, "detailed_glyphs_enabled", True)) else "Q",
                    C.WOOD + C.BOLD,
                )
            if tile == "D":
                is_entry = (
                    (int(x), int(y)) in set(TOWN_DOORS.values())
                    or (int(x), int(y)) in AUTHORED_TOWN_RESIDENCE_ID_BY_DOOR
                )
                return colorize(tile, (C.DOOR if is_entry else C.SERVICE) + C.BOLD)
        if self.on_farm() and tile == "H":
            surface = farmhouse_surface(
                tile_map,
                x,
                y,
                bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                visual_key,
                bool(getattr(self.state, "high_contrast_enabled", False)),
                "Deluxe Farmhouse" in set(getattr(self.state, "house_upgrades", []) or []),
            )
            if surface:
                glyph, color = surface
                color = outdoor_time_color(
                    color,
                    int(getattr(self.state, "hour", 12)),
                    lit=glyph == "o",
                    ambient=bool(getattr(self.state, "ambient_visuals_enabled", True)),
                )
                return colorize(glyph, color)
        if self.on_farm() and tile == "D":
            return colorize(tile, C.DOOR + C.BOLD)
        if self.on_farm_work_land() and self.is_tile_fertilized(x, y) and tile in [",", "w"]:
            tile = "f" if tile == "," else "F"
        if self.on_mine() and tile == ">" and not self.mine_floor_stairs_available(self.state.mine_floor):
            return colorize("x", C.WALL)
        if self.on_mine() or self.on_wilderness_cave() or self.on_wilderness_dungeon():
            underground_context = (
                "mine" if self.on_mine()
                else "cave" if self.on_wilderness_cave()
                else "dungeon"
            )
            display_tile, underground_color = underground_tile_style(
                tile_map,
                x,
                y,
                underground_context,
                bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                int(getattr(self, "_ambient_visual_phase", 0)),
                visual_key,
                bool(getattr(self.state, "ambient_visuals_enabled", True)),
                bool(getattr(self.state, "high_contrast_enabled", False)),
            )
            return colorize(display_tile, underground_color)
        season = self.state.season
        color_cache = getattr(self, "_base_tile_color_cache", None)
        if (
            isinstance(color_cache, tuple)
            and len(color_cache) == 2
            and color_cache[0] == season
        ):
            colors = color_cache[1]
        else:
            colors = {
            ".": season_tile_color(".", season),
            ",": season_tile_color(",", season),
            "w": season_tile_color("w", season),
            "f": C.CROP_MID,
            "F": C.CROP_READY,
            "#": C.WALL,
            "~": season_tile_color("~", season),
            "H": C.HOUSE,
            "B": C.BIN,
            "$": C.SHOP,
            "^": season_tile_color("^", season),
            "o": season_tile_color("o", season),
            "*": season_tile_color("*", season),
            "=": C.ROAD,
            ":": C.PATH,
            "D": C.WOOD,
            "t": C.WOOD,
            "s": C.WOOD,
            "r": C.BIN,
            "K": C.CROP_READY,
            "V": C.WATER,
            "P": C.SHOP,
            "g": C.SHOP,
            "x": C.STONE,
            "a": C.STONE,
            "f": C.CROP_READY,
            "l": C.SNOW,
            "d": C.WOOD,
            "n": C.SHOP,
            "&": C.CROP_READY,
            "p": C.GRASS,
            "u": C.WOOD,
            "Y": C.SHOP,
            "C": C.WOOD,
            "w": C.WOOD,
            "G": C.SHOP,
            "C": C.WATER,
            "X": C.STONE,
            "L": C.SNOW,
            "M": C.HOUSE,
            "I": C.BIN,
            "F": C.WATER,
            "T": C.GRASS,
            "b": C.WOOD,
            "?": C.SHOP,
            "E": C.CROP_READY,
            "N": C.CROP_READY,
            "W": C.CROP_READY,
            "S": C.CROP_READY,
            "h": C.CROP_READY,
            "i": C.CROP_MID,
            "z": C.CROP_READY,
            "v": C.CROP_MID,
            "y": C.CROP_READY,
            "b": C.CROP_MID,
            "m": C.SNOW,
            "n": C.WOOD,
            "a": C.CROP_READY,
            "j": C.SNOW,
            "k": C.SNOW,
            "!": C.CROP_READY,
            "r": C.STONE,
            "O": C.SNOW,
            "I": C.STONE,
            "G": C.CROP_READY,
            "M": C.CROP_MID,
            "q": C.DIM,
            "c": C.WATER,
            "g": C.CROP_READY,
            "<": C.CROP_READY,
            "U": C.CROP_READY,
            ">": C.CROP_READY,
            "A": C.CROP_READY,
            "P": C.CROP_READY,
            "S": C.CROP_READY,
            "B": C.BIN,
            "R": C.WOOD,
            "H": C.CROP_READY,
            "J": C.STONE,
            "Y": C.CROP_MID,
            "u": C.SNOW,
            "K": C.CROP_READY,
            "Q": C.CROP_READY,
            ";": C.GRASS,
            "%": C.WALL,
            "r": C.WATER,
            "x": C.STONE,
            "W": C.WATER,
            "N": C.WOOD,
            "F": C.CROP_READY,
            "V": C.STONE,
            "O": C.CROP_READY,
            "L": C.WOOD,
            "e": C.CROP_READY,
            "p": C.WATER,
            "M": C.STONE,
            "G": C.CROP_READY,
            "Z": C.SNOW,
            "c": C.CROP_READY,
            "i": C.STONE,
            "g": C.CROP_READY,
            "A": C.CROP_READY,
            "C": C.WATER,
            "h": C.CROP_READY,
            "b": C.WOOD,
            "d": C.SOIL_DRY,
            "B": C.SHOP,
            "!": C.CROP_READY,
            "m": C.WOOD,
            "+": C.WOOD,
            "'": C.GRASS,
            "\"": C.WOOD,
            ",": C.GRASS,
                " ": C.WALL,
            }
            self._base_tile_color_cache = (season, colors)
        base_color = colors.get(tile, C.RESET)
        display_tile = tile
        if tile == "#" and (self.on_town() or self.on_wilderness_dungeon() or self.on_farm()):
            display_tile = self.architectural_display_tile(
                tile_map,
                x,
                y,
                allow_windows=self.on_town(),
                visual_key=visual_key,
            )
            if display_tile == "o":
                base_color = C.LIT if self.is_night_time() else C.FLOOR_WARM
        elif tile == "~" and self.on_farm():
            if self.state.season == "Winter":
                display_tile = "═" if bool(getattr(self.state, "detailed_glyphs_enabled", True)) else "~"
                base_color = C.SNOW
            else:
                display_tile = wilderness_display_glyph(
                    tile,
                    int(getattr(self, "_ambient_visual_phase", 0)),
                    visual_key,
                    bool(getattr(self.state, "ambient_visuals_enabled", True)),
                    bool(getattr(self.state, "detailed_glyphs_enabled", True)),
                )
        if town_streetlamp_lit_tiles is not None:
            base_color = outdoor_time_color(
                base_color,
                int(getattr(self.state, "hour", 12)),
                lit=bool(
                    tile in {"!", "H", "f"}
                    or (int(x), int(y)) in town_streetlamp_lit_tiles
                ),
                ambient=bool(getattr(self.state, "ambient_visuals_enabled", True)),
            )
        else:
            base_color = self.night_lighting_color_for_tile(tile, x, y, base_color)
        return colorize(display_tile, base_color)


    def render_crop(self, crop: Crop) -> str:
        """Render crops with visible symbol changes across growth stages."""
        stage = crop.stage_index()
        symbol = crop.symbol()

        if crop.ready or stage >= 3:
            return colorize(symbol, C.CROP_READY)

        # Dry crops are visually muted regardless of growth stage.
        if not crop.watered:
            return colorize(symbol, C.CROP_DRY)

        if stage == 0:
            return colorize(symbol, C.CROP_SPROUT)
        if stage == 1:
            return colorize(symbol, C.CROP_MID)
        return colorize(symbol.upper(), C.CROP_READY)

    def describe_crop(self, crop: Crop) -> str:
        data = CROP_DATA.get(crop.name, {})
        growth_days = max(1, int(data.get("growth_days", 1)))
        remaining = max(0, growth_days - int(crop.age))
        quality = crop.projected_quality()
        sell_price = quality_sell_price(crop.name, quality) if crop.name in CROP_DATA else 0

        if crop.ready:
            growth_text = "ready to harvest"
        elif remaining == 1:
            growth_text = "1 day to harvest"
        else:
            growth_text = f"{remaining} days to harvest"

        care_bits = []
        care_bits.append("watered" if crop.watered else "needs water")
        if crop.fertilized:
            care_bits.append("fertilized")
        if crop.missed_water_days:
            care_bits.append(f"{crop.missed_water_days} missed watering day(s)")

        return (
            f"{crop.name}: {growth_text}; {', '.join(care_bits)}; "
            f"{quality} quality estimate; harvest value ${sell_price}"
        )

    def refresh_farm_border_and_gates(self):
        """Rebuild farm borders/gates after the farm changes size."""
        h = self.farm_height()
        w = self.farm_width()
        if h <= 0 or w <= 0:
            return
        for x in range(w):
            self.base_map[0][x] = "#"
            self.base_map[h - 1][x] = "#"
        for y in range(h):
            self.base_map[y][0] = "#"
            self.base_map[y][w - 1] = "#"

        for y in range(8, min(13, h - 1)):
            self.base_map[y][0] = ":"
            if w > 1:
                self.base_map[y][1] = "."
            if w > 2:
                self.base_map[y][2] = "."

        for x in range(25, min(30, w - 1)):
            self.base_map[0][x] = "<"
            if h > 1:
                self.base_map[1][x] = "."
            if h > 2:
                self.base_map[2][x] = "."

        for y in range(8, min(13, h - 1)):
            self.base_map[y][w - 1] = ":"
            if w > 1:
                self.base_map[y][w - 2] = "."
            if w > 2:
                self.base_map[y][w - 3] = "."

        for yy in range(2, min(6, h)):
            for xx in range(3, min(9, w)):
                self.base_map[yy][xx] = "H"
        if h > 6 and w > 6:
            self.base_map[5][5] = "D"
            self.base_map[6][5] = "."

    def open_interior_expansion_borders(self, previous_width: Optional[int] = None, previous_height: Optional[int] = None):
        """Remove old farm edge fences after expansions turn them into interior rows/columns."""
        h = self.farm_height()
        w = self.farm_width()
        if h <= 0 or w <= 0:
            return

        candidate_columns: List[int] = []
        candidate_rows: List[int] = []

        if previous_width is not None and 0 < int(previous_width) < w:
            candidate_columns.append(int(previous_width) - 1)
        if previous_height is not None and 0 < int(previous_height) < h:
            candidate_rows.append(int(previous_height) - 1)

        # Existing saves may already have expanded dimensions but still contain
        # the old starter/expansion borders as interior fence lines.
        for old_width in sorted({WIDTH, 72}):
            if 0 < old_width < w:
                candidate_columns.append(old_width - 1)
        for old_height in sorted({HEIGHT, 30}):
            if 0 < old_height < h:
                candidate_rows.append(old_height - 1)

        protected = set(["H", "D", "E", "N"])
        for x in sorted(set(candidate_columns)):
            if not (1 <= x < w - 1):
                continue
            for y in range(1, h - 1):
                if self.base_map[y][x] == "#" and self.base_map[y][x] not in protected:
                    self.base_map[y][x] = self.generate_expanded_farm_tile(x, y)
        for y in sorted(set(candidate_rows)):
            if not (1 <= y < h - 1):
                continue
            for x in range(1, w - 1):
                if self.base_map[y][x] == "#" and self.base_map[y][x] not in protected:
                    self.base_map[y][x] = self.generate_expanded_farm_tile(x, y)

    def generate_expanded_farm_tile(self, x: int, y: int) -> str:
        if (x * 17 + y * 31) % 29 == 0:
            return "^"
        if (x * 11 + y * 7) % 41 == 0:
            return "o"
        if (x * 13 + y * 19) % 53 == 0:
            return "*"
        return "."

    def expand_farm_map_to(self, target_width: int, target_height: int):
        old_h = self.farm_height()
        old_w = self.farm_width()
        target_width = max(target_width, old_w)
        target_height = max(target_height, old_h)
        if target_width == old_w and target_height == old_h:
            return

        new_map: List[List[str]] = []
        for y in range(target_height):
            row: List[str] = []
            for x in range(target_width):
                if y < old_h and x < old_w:
                    row.append(self.base_map[y][x])
                else:
                    row.append(self.generate_expanded_farm_tile(x, y))
            new_map.append(row)
        self.base_map = new_map
        self.open_interior_expansion_borders(old_w, old_h)
        self.refresh_farm_border_and_gates()

    def purchase_farm_expansion(self, expansion_name: str) -> bool:
        data = FARM_EXPANSION_DATA[expansion_name]
        if expansion_name in self.state.farm_expansions:
            self.set_message(f"{expansion_name} is already complete.")
            return False
        missing = [req for req in data.get("requires", []) if req not in self.state.farm_expansions]
        if missing:
            self.set_message(f"Requires: {', '.join(missing)}.")
            return False
        price = int(data["price"])
        if self.state.money < price:
            self.set_message(f"Not enough money. {expansion_name} costs ${price}.")
            return False
        self.state.money -= price
        self.state.farm_expansions.append(expansion_name)
        self.expand_farm_map_to(int(data["width"]), int(data["height"]))
        self.autosave_with_message(f"Purchased {expansion_name}. Farm size is now {self.farm_width()}x{self.farm_height()}.")
        return True

    def passable(
        self,
        x: int,
        y: int,
        ignore_travel_follower_id: Optional[str] = None,
        ignore_all_travel_followers: bool = False,
    ) -> bool:
        if not self.in_active_bounds(x, y):
            return False
        if not ignore_all_travel_followers:
            occupying_follower = self.travel_follower_at(x, y)
            if occupying_follower and occupying_follower != str(ignore_travel_follower_id or ""):
                return False
        if (self.on_farm() or self.on_mine()) and self.town_npc_at(x, y):
            return False
        if self.on_farm() and self.farm_animal_at(x, y):
            return False
        if (self.on_wilderness() or self.on_procedural_town_interior()) and self.procedural_town_resident_at(x, y):
            return False
        owned_town_home = (
            hasattr(self, "on_player_owned_procedural_residence")
            and self.on_player_owned_procedural_residence()
        )
        if (self.on_farm_work_land() or self.on_house() or owned_town_home) and self.get_placed_object(x, y):
            obj = self.get_placed_object(x, y)
            if not INFRASTRUCTURE_DATA.get(obj, {}).get("walkable", False):
                return False
        tile = self.active_map()[y][x]
        if self.on_procedural_town_interior():
            return self.procedural_town_interior_tile_passable(tile)
        if self.on_town():
            return tile not in ["#", "~", "G", "C", "X", "L", "M", "I", "Y", "A", "H", "R", "P", "U", "Q", "F", "T", "b", "B", "N", "m", "$", "h"]
        if self.on_mine():
            if self.mine_enemy_at(x, y):
                return False
            if tile == ">" and not self.mine_floor_stairs_available(self.state.mine_floor):
                return False
            return tile not in ["#", " ", "r", "O", "I", "G", "M", "q", "c", "g", "B", "?"]
        if self.on_wilderness():
            if self.procedural_town_hinterland_at(x, y) or self.wilderness_maritime_encounter_at(x, y) or self.wilderness_island_site_at(x, y):
                return False
            if self.wilderness_water_salvage_at(x, y):
                return False
            if self.state.wilderness_boating:
                if tile == "~" and self.wilderness_water_is_frozen_at(x, y):
                    return False
                return tile in {"~", "="} and not self.wilderness_event_blocking_at(x, y)
            if self.wilderness_expedition_camp_visual_at(x, y):
                return False
            if self.wilderness_event_blocking_at(x, y):
                return False
            if self.wilderness_seasonal_surface_blocking_at(x, y):
                return False
            if self.wilderness_traveler_at(x, y):
                return False
            encounter_visual = self.wilderness_random_combat_visual_at(x, y)
            if encounter_visual and bool(encounter_visual.get("blocking", False)):
                return False
            if self.bounty_target_at(x, y):
                return False
            if self.wilderness_stronghold_enemy_at(x, y):
                return False
            if self.wilderness_random_combat_enemy_at(x, y):
                return False
            if self.reclaimed_stronghold_build_board_at(x, y):
                return False
            _feature_id, stronghold_feature = self.reclaimed_stronghold_feature_at(x, y)
            if stronghold_feature and not bool(stronghold_feature.get("walkable", False)):
                return False
            if self.current_procedural_town_plan() and (
                self.procedural_town_building_at(x, y)
                or tile == PROCEDURAL_TOWN_SIGN_SYMBOL
            ):
                return False
            if tile == "~":
                return self.wilderness_water_is_frozen_at(x, y)
            return tile not in ["#", "T", "o", "*", "?", FIELD_SITE_SYMBOL, WILDERNESS_OUTPOST_SYMBOL, WILDERNESS_STRUCTURE_SYMBOL, WILDERNESS_LANDSCAPE_SYMBOL, WILDERNESS_DOCK_SYMBOL, WILDERNESS_FISHING_SETTLEMENT_SYMBOL, WILDERNESS_REFUGE_SYMBOL, WILDERNESS_STAFFED_SITE_SYMBOL, WILDERNESS_EXCURSION_SYMBOL, WILDERNESS_CLAIM_SYMBOL, "R", "J", "P", "K", "Q", "Y", "u", "W", "N", "F", "V", "X", "O", "L", "e", "p", "M", "G", "Z"]
        if self.on_wilderness_outpost():
            return tile not in ["#", " ", "-", "&", "@", "n", "b", "t", "c", "f", "s", "P", "l", "w", "a", "p"]
        if self.on_wilderness_structure():
            return tile not in ["#", " ", "-", "&", "@", "b", "t", "c", "f", "s", "P", "d", "+"]
        if self.on_wilderness_cave():
            return tile not in ["#", " ", "o", "q", "m", "c", "i", "g", "A", "C", "h", "b", "d"]
        if self.on_wilderness_dungeon():
            if self.wilderness_dungeon_enemy_at(x, y):
                return False
            if self.dungeon_door_closed(x, y):
                return False
            return tile not in ["#", " ", "$", "P"]
        if self.on_town_interior():
            return tile not in self.town_interior_blocking_tiles()
        if self.on_house():
            return tile not in ["#", " "]
        if self.on_general_store():
            return tile not in ["#", " ", "$", "s", "t", "g", "P", "&"]
        if self.on_blacksmith_interior():
            return tile not in ["#", " ", "$", "x", "a", "f", "o", "t", "&"]
        if self.on_library_interior():
            return tile not in ["#", " ", "l", "t", "c", "P", "&"]
        if self.on_mayor_house():
            return tile not in ["#", " ", "d", "c", "s", "P", "r", "&"]
        if self.on_inn_interior():
            return tile not in ["#", " ", "$", "n", "B", "t", "c", "r", "&"]
        if self.on_furniture_store():
            return tile not in ["#", " ", "$", "&", "c", "t", "l", "p", "r", "u", "h", "T", "L", "f", "-", "U", "!", "m", "A", "C", "P"]
        if self.on_carpenter_store():
            return tile not in ["#", " ", "$", "&", "w", "t", "l", "P", "s"]
        if self.on_animal_store():
            return tile not in ["#", " ", "$", "&", "c", "p", "h", "f", "P"]
        if self.on_clinic():
            return tile not in ["#", " ", "$", "&", "b", "m", "s", "P"]
        if self.on_town_hall():
            return tile not in ["#", " ", "$", "&", "c", "p", "r", "P"]
        if self.on_market_row():
            return tile not in ["#", " ", "$", "&", "v", "f", "r", "t", "P"]
        if self.on_museum():
            return tile not in ["#", " ", "$", "&", "d", "C", "S", "A", "G", "F", "M", "E", "P"]
        if self.on_farm() and tile == "~" and self.state.season == "Winter":
            return True
        return tile not in ["#", "~", "H"]


    def centered_print(self, text: str = "", width: int = UI_WIDTH):
        print(left_margin(width) + text)

