    def tutorial_guide_menu(
        self,
        title: str,
        guide_keys: List[str],
        catalog: Dict[str, Dict[str, object]],
    ):
        while True:
            items = [
                MenuItem(
                    label=str(catalog[key]["title"]),
                    value=key,
                    enabled=True,
                    hint=str(catalog[key].get("hint", "")),
                )
                for key in guide_keys
                if key in catalog
            ]
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select(title, items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return
            data = catalog.get(str(choice.value))
            if data:
                self.vertical_panel_view(str(data["title"]), list(data["lines"]), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

    def tutorial_menu(self, source_title: str = "Tutorials"):
        catalog = self.tutorial_catalog()
        while True:
            items = [
                MenuItem(label=title, value=f"category:{index}", enabled=True, hint=hint)
                for index, (title, hint, _guide_keys) in enumerate(self.tutorial_categories())
            ]
            items.append(MenuItem(label="All Guides", value="all", enabled=True, hint="complete alphabetical index"))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select(source_title, items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message(f"Closed {source_title.lower()}.")
                return
            if choice.value == "all":
                guide_keys = sorted(catalog, key=lambda key: str(catalog[key]["title"]))
                self.tutorial_guide_menu("All Guides", guide_keys, catalog)
                continue
            value = str(choice.value)
            if not value.startswith("category:"):
                continue
            try:
                category_index = int(value.split(":", 1)[1])
                title, _hint, guide_keys = self.tutorial_categories()[category_index]
            except (ValueError, IndexError):
                continue
            self.tutorial_guide_menu(title, guide_keys, catalog)

