    def known_recipe_names(self) -> List[str]:
        known = set(self.basic_known_recipes())
        for recipe_name in self.state.learned_recipe_ids or []:
            if recipe_name in COOKING_RECIPES:
                known.add(recipe_name)
        return [name for name in COOKING_RECIPES if name in known]

    def unknown_recipe_names(self) -> List[str]:
        known = set(self.known_recipe_names())
        return [name for name in COOKING_RECIPES if name not in known]

    def recipe_research_cost(self, recipe_name: str) -> int:
        recipe = COOKING_RECIPES.get(recipe_name, {})
        ingredient_count = sum(int(v) for v in recipe.get("ingredients", {}).values())
        if not recipe.get("requires_kitchen", True):
            base_cost = 40
        else:
            base_cost = 70 + ingredient_count * 30
        if self.has_town_project("library_outreach"):
            base_cost = max(25, int(base_cost * 0.8))
        return base_cost

    def learn_recipe(self, recipe_name: str) -> bool:
        if recipe_name not in COOKING_RECIPES:
            self.set_message("That recipe does not exist.")
            return False
        if recipe_name in self.known_recipe_names():
            self.set_message(f"You already know {recipe_name}.")
            return False
        cost = self.recipe_research_cost(recipe_name)
        if self.state.money < cost:
            self.set_message(f"Researching {recipe_name} costs ${cost}.")
            return False
        self.state.money -= cost
        self.state.learned_recipe_ids.append(recipe_name)
        self.autosave_with_message(f"Learned recipe: {recipe_name}.")
        return True

