    def library_research_lines(self) -> List[str]:
        catalog = self.library_research_catalog()
        known = set(self.state.library_research_ids or [])
        lines = ["LIBRARY RESEARCH", ""]
        for key, data in catalog.items():
            status = "read" if key in known else f"${data['cost']}"
            lines.append(f"- {data['title']}: {status}")
        lines.extend(["", "Research entries are paid once and then remain available."])
        return lines

    def library_recipe_catalog_lines(self) -> List[str]:
        lines = ["RECIPE CATALOG", "", "Known recipes:"]
        for name in self.known_recipe_names():
            lines.append(f"- {name}")
        lines.extend(["", "Unknown recipes:"])
        for name in self.unknown_recipe_names():
            lines.append(f"- {name}: research cost ${self.recipe_research_cost(name)}")
        return lines

    def library_research_menu(self):
        catalog = self.library_research_catalog()
        while True:
            items: List[MenuItem] = []
            known = set(self.state.library_research_ids or [])
            for key, data in catalog.items():
                already = key in known
                cost = int(data["cost"])
                items.append(MenuItem(
                    label=str(data["title"]),
                    value=key,
                    enabled=True,
                    hint="read" if already else (f"${cost}" if self.state.money >= cost else f"${cost} no"),
                ))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Library Research", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return
            key = str(choice.value)
            data = catalog.get(key)
            if not data:
                continue
            if key not in known:
                cost = int(data["cost"])
                if self.state.money < cost:
                    self.set_message(f"{data['title']} research costs ${cost}.")
                    continue
                self.state.money -= cost
                self.state.library_research_ids.append(key)
                self.autosave_with_message(f"Researched: {data['title']}.")
                known.add(key)
            self.vertical_panel_view(str(data["title"]), list(data["lines"]), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

    def library_recipe_menu(self):
        while True:
            items: List[MenuItem] = []
            for recipe_name in self.unknown_recipe_names():
                cost = self.recipe_research_cost(recipe_name)
                items.append(MenuItem(label=f"Learn {recipe_name}", value=recipe_name, enabled=True, hint=f"${cost}" if self.state.money >= cost else f"${cost} no"))
            items.append(MenuItem(label="View recipe catalog", value="catalog", enabled=True))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Recipe Research", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return
            if choice.value == "catalog":
                self.vertical_panel_view("Recipe Catalog", self.library_recipe_catalog_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            recipe_name = str(choice.value)
            if self.learn_recipe(recipe_name):
                self.show_cooking_recipe_details(recipe_name)
                return

    def library_menu(self):
        if not self.ensure_current_town_service_unlocked():
            return
        while True:
            items = [
                MenuItem(label="Tutorial guides", value="tutorials", enabled=True, hint="how to play"),
                MenuItem(label="Research topics", value="research", enabled=True, hint=f"{len(self.state.library_research_ids or [])} read"),
                MenuItem(label="Recipe research", value="recipes", enabled=True, hint=f"{len(self.unknown_recipe_names())} unknown"),
                MenuItem(label="View recipe catalog", value="catalog", enabled=True),
                MenuItem(label="Journal / Codex", value="journal", enabled=True, hint="reference"),
                MenuItem(label="Ask Tess for a tip", value="tip", enabled=True, hint="free"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Library", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Library closed.")
                return
            if choice.value == "tutorials":
                self.tutorial_menu("Library Guides")
                continue
            if choice.value == "research":
                self.library_research_menu()
                continue
            if choice.value == "recipes":
                self.library_recipe_menu()
                continue
            if choice.value == "catalog":
                self.vertical_panel_view("Recipe Catalog", self.library_recipe_catalog_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "journal":
                self.show_journal_codex_menu()
                continue
            if choice.value == "tip":
                self.vertical_panel_view("Tess's Tip", [
                    "TESS'S TIP",
                    "",
                    "The fastest way to make the town feel useful is to connect errands, food, market stock, and friendship.",
                    "",
                    "Cooked food keeps you exploring longer.",
                    "Errands turn spare items into money and friendship.",
                    "Library recipes give your farm and wilderness items more purpose.",
                ], LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue

