    def count_wilderness_forage(self) -> int:
        if not hasattr(self, "wilderness_map") or not self.wilderness_map:
            return 0
        return sum(1 for row in self.wilderness_map for ch in row if ch in WILDERNESS_FORAGE_SYMBOLS and ch != "!")

    def clear_out_of_season_wilderness_forage(self) -> int:
        """Hibernate stale forage across every generated persistent chunk."""
        allowed = set(self.wilderness_seasonal_forage_symbols())
        removed = 0
        maps: List[Tuple[int, int, List[List[str]]]] = []
        seen_ids = set()
        for key, grid in (getattr(self, "wilderness_maps", {}) or {}).items():
            if not isinstance(grid, list) or id(grid) in seen_ids:
                continue
            try:
                chunk_x, chunk_y = [int(value) for value in str(key).split(",", 1)]
            except (TypeError, ValueError):
                continue
            maps.append((chunk_x, chunk_y, grid))
            seen_ids.add(id(grid))
        if isinstance(getattr(self, "wilderness_map", None), list) and id(self.wilderness_map) not in seen_ids:
            maps.append((int(self.state.wilderness_chunk_x), int(self.state.wilderness_chunk_y), self.wilderness_map))

        for chunk_x, chunk_y, grid in maps:
            for y, row in enumerate(grid):
                for x, ch in enumerate(row):
                    # '!' is shared with strongholds/events, so never reinterpret it here.
                    if ch == "!":
                        continue
                    if ch in WILDERNESS_FORAGE_SYMBOLS and ch not in allowed:
                        wx, wy = self.wilderness_world_coords(chunk_x, chunk_y, x, y)
                        replacement = self.wilderness_world_biome_tile(wx, wy)
                        grid[y][x] = replacement if replacement in WILDERNESS_BIOME_TILES else "."
                        removed += 1
        return removed

    def regrow_wilderness_forage(self, force: bool = False) -> int:
        """Regrow seasonal forage overnight with biome-specific weighting."""
        if not hasattr(self, "wilderness_map") or not self.wilderness_map:
            self.wilderness_map = self.make_wilderness_map(self.state.wilderness_seed)

        # Keep seasonal identity strong: remove wrong-season forage first.
        self.clear_out_of_season_wilderness_forage()

        current_count = self.count_wilderness_forage()
        max_forage = 65
        if current_count >= max_forage and not force:
            return 0

        day_seed = (
            int(self.state.wilderness_seed)
            + self.state.year * 10000
            + self.state.month * 100
            + self.state.day
            + 9400
        )
        rng = random.Random(day_seed)
        season_symbols = self.wilderness_seasonal_forage_symbols()

        candidates = []
        h = len(self.wilderness_map)
        w = len(self.wilderness_map[0]) if h else 0
        open_tiles = [".", ";", "%", "l", "r", "x"]
        for y in range(1, h - 1):
            for x in range(1, w - 1):
                if self.wilderness_map[y][x] not in open_tiles:
                    continue
                if y >= h - 5 and abs(x - (w // 2)) <= 5:
                    continue
                neighbors = [
                    self.wilderness_map[y + dy][x + dx]
                    for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)]
                    if 0 <= y + dy < h and 0 <= x + dx < w
                ]
                biome_tile = self.wilderness_map[y][x] if self.wilderness_map[y][x] in WILDERNESS_BIOME_TILES else self.wilderness_biome_tile_at(x, y)
                score = 0.10
                if ":" in neighbors:
                    score += 0.08
                if "T" in neighbors or "%" in neighbors:
                    score += 0.08
                if "~" in neighbors or biome_tile == "r":
                    score += 0.10
                if biome_tile in [";", "l", "%", "r", "x"]:
                    score += 0.10
                if rng.random() < score:
                    candidates.append((x, y, biome_tile))

        rng.shuffle(candidates)
        target_new = min(len(candidates), max(4 if force else 1, 8 + (2 if self.state.season == "Spring" else 0)))
        if not force:
            target_new = min(target_new, max_forage - current_count)
        if target_new <= 0:
            return 0

        spawned = 0
        for x, y, biome_tile in candidates[:target_new]:
            if biome_tile in WILDERNESS_BIOME_TILES and rng.random() < 0.72:
                symbol = self.choose_biome_forage_symbol(biome_tile, rng)
            else:
                symbol = rng.choice(season_symbols)
            if self.wilderness_spawn_economy_score(symbol) >= 30 and rng.random() < 0.55:
                symbol = min(season_symbols, key=lambda candidate: self.wilderness_spawn_economy_score(candidate))
            self.wilderness_map[y][x] = symbol
            spawned += 1
        self.limit_wilderness_valuable_spawns(
            self.wilderness_map,
            int(getattr(self.state, "wilderness_chunk_x", 0) or 0),
            int(getattr(self.state, "wilderness_chunk_y", 0) or 0),
            rng,
        )
        return spawned

    def forage_symbol(self, x: int, y: int) -> bool:
        return self.in_active_bounds(x, y) and self.active_map()[y][x] in WILDERNESS_FORAGE_SYMBOLS

    def wilderness_tool_effect_tiles(self, tool_name: str, x: int, y: int) -> List[Tuple[int, int]]:
        """Tool effect area for wilderness chunks, using active-map bounds instead of farm WIDTH/HEIGHT."""
        level = self.tool_level(tool_name)
        if tool_name in ["Axe", "Pickaxe"] and level >= 3:
            tiles = [(x, y)] + self.surrounding_tiles(x, y)
        else:
            tiles = [(x, y)]

        unique: List[Tuple[int, int]] = []
        seen = set()
        for tx, ty in tiles:
            if self.in_active_bounds(tx, ty) and (tx, ty) not in seen:
                unique.append((tx, ty))
                seen.add((tx, ty))
        return unique

    def wilderness_restore_tile_after_clear(self, x: int, y: int) -> str:
        """Return a reasonable walkable ground tile after clearing wilderness clutter."""
        if not self.in_active_bounds(x, y):
            return "."
        # Preserve biome identity if nearby/underlying can be inferred; otherwise use grass.
        biome = self.wilderness_biome_tile_at(x, y)
        return biome if biome in WILDERNESS_BIOME_TILES else "."

    def clear_wilderness_weeds(self, x: int, y: int):
        if not self.spend_stamina(2):
            return
        self.active_map()[y][x] = self.wilderness_restore_tile_after_clear(x, y)
        drops = roll_weed_drops(1)
        add_inventory_items(self.state.inventory, drops)
        self.autosave_with_message(f"Pulled wild grass and found {format_drops(drops)}.")

    def chop_wilderness_wood(self, x: int, y: int):
        if not self.owns_tool("Axe"):
            self.set_message("You need to buy an Axe before you can chop wilderness wood.")
            return
        tiles = self.wilderness_tool_effect_tiles("Axe", x, y)
        chopped = 0
        for tx, ty in tiles:
            if self.active_map()[ty][tx] in ["T", "*"]:
                self.active_map()[ty][tx] = self.wilderness_restore_tile_after_clear(tx, ty)
                chopped += 1
        if chopped <= 0:
            self.set_message("No wilderness wood in range.")
            return
        stamina_cost = max(1, chopped * (3 if self.tool_level("Axe") >= 2 else 6))
        if not self.spend_stamina(stamina_cost):
            return
        drops = roll_wood_drops(chopped, self.tool_level("Axe"))
        # Full trees give a little more wood than fallen logs on average.
        add_inventory_items(self.state.inventory, drops)
        self.autosave_with_message(f"Chopped {chopped} wilderness wood tile(s) and found {format_drops(drops)}.")

    def break_wilderness_stone(self, x: int, y: int):
        if not self.owns_tool("Pickaxe"):
            self.set_message("You need to buy a Pickaxe before you can break wilderness rocks.")
            return
        tiles = self.wilderness_tool_effect_tiles("Pickaxe", x, y)
        broken = 0
        for tx, ty in tiles:
            if self.active_map()[ty][tx] == "o":
                self.active_map()[ty][tx] = self.wilderness_restore_tile_after_clear(tx, ty)
                broken += 1
        if broken <= 0:
            self.set_message("No wilderness rocks in range.")
            return
        stamina_cost = max(1, broken * (3 if self.tool_level("Pickaxe") >= 2 else 6))
        if not self.spend_stamina(stamina_cost):
            return
        drops = roll_stone_drops(broken, self.tool_level("Pickaxe"))
        add_inventory_items(self.state.inventory, drops)
        self.autosave_with_message(f"Broke {broken} wilderness rock(s) and found {format_drops(drops)}.")

    def use_wilderness_cave_action(self, x: int, y: int):
        tile = self.active_map()[y][x] if self.in_active_bounds(x, y) else "#"
        if tile in {"<", "U"}:
            self.exit_wilderness_cave()
            return
        if tile == "m":
            self.active_map()[y][x] = "."
            self.state.inventory["Cave Mushroom"] = self.state.inventory.get("Cave Mushroom", 0) + 1
            self.autosave_with_message("Gathered 1 Cave Mushroom.")
            return
        if tile == "h":
            self.active_map()[y][x] = "."
            self.state.inventory["Cave Herbs"] = self.state.inventory.get("Cave Herbs", 0) + 1
            self.autosave_with_message("Gathered 1 Cave Herbs.")
            return
        if tile == "b":
            self.active_map()[y][x] = "."
            self.state.inventory["Bat Guano"] = self.state.inventory.get("Bat Guano", 0) + 1
            self.autosave_with_message("Collected 1 Bat Guano.")
            return
        if tile == "d":
            self.set_message("A soft clay deposit. Use F with Pickaxe to dig it out.")
            return
        if tile in ["c", "i", "g", "A", "C"]:
            self.set_message("A mineral node. Use F with Pickaxe to mine it.")
            return
        if tile == "q":
            self.set_message("A coal seam. Use F with Pickaxe to mine it.")
            return
        if tile == "o":
            self.set_message("A cave rock. Use F with Pickaxe to break it.")
            return
        if tile == "#":
            self.set_message("Nothing to interact with here. Press I to inspect the cave wall.")
            return
        self.set_message("Nothing to interact with here. Press I to inspect the cave.")

    def use_wilderness_action(self, x: int, y: int):
        if self.on_wilderness() and not self.in_active_bounds(x, y):
            chunk_x, chunk_y, local_x, local_y = self.wilderness_stream_resolve(x, y)
            dx = int(chunk_x) - int(self.state.wilderness_chunk_x)
            dy = int(chunk_y) - int(self.state.wilderness_chunk_y)
            if abs(dx) + abs(dy) == 1:
                if self.transition_wilderness_chunk(dx, dy, interaction_target=True):
                    self.use_wilderness_action(local_x, local_y)
                return
        if self.in_active_bounds(x, y):
            if self.on_wilderness() and self.dungeon_floor_loot_at(x, y):
                loot_record = self.world_container_at(x, y)
                if loot_record:
                    self.show_world_container(loot_record)
                if self.wilderness_field_combat_active():
                    self.advance_dungeon_roguelike_turn("search remains")
                return
            if self.on_wilderness() and self.wilderness_random_combat_visual_at(x, y):
                visual = self.wilderness_random_combat_visual_at(x, y)
                encounter = self.wilderness_random_combat_record(
                    self.state.wilderness_chunk_x, self.state.wilderness_chunk_y, create=False
                )
                self.set_message(
                    f"{visual.get('name', 'Encounter site')}: {encounter.get('description', 'Signs of nearby danger.')}"
                )
                if self.wilderness_field_combat_active():
                    self.advance_dungeon_roguelike_turn("inspect encounter site")
                return
            resident = self.procedural_town_resident_at(x, y)
            if resident:
                if resident.get("procedural_caravan"):
                    self.procedural_caravan_menu(resident)
                elif resident.get("household_town_resident"):
                    self.town_npc_menu(resident)
                else:
                    self.procedural_town_resident_menu(resident)
                return
            home_gateway = self.origin_world_gateway_at(x, y)
            if home_gateway:
                self.enter_origin_world_gateway(home_gateway)
                return
            home_sign = self.origin_world_sign_at(x, y)
            if home_sign:
                self.read_origin_world_sign(home_sign)
                return
            consequence_kind = self.wilderness_vitality_consequence_at(x, y)
            if consequence_kind:
                self.use_wilderness_vitality_consequence(consequence_kind)
                return
            if self.procedural_town_hinterland_at(x, y):
                self.work_procedural_town_hinterland()
                return
            if self.wilderness_maritime_encounter_at(x, y):
                self.resolve_wilderness_maritime_encounter()
                return
            if self.wilderness_water_salvage_at(x, y):
                self.collect_wilderness_water_salvage()
                return
            if self.wilderness_island_site_at(x, y):
                self.show_wilderness_island_site()
                return
            if self.wilderness_expedition_camp_visual_at(x, y):
                self.show_wilderness_expedition_camp()
                return
            if self.wilderness_expedition_objective_at(x, y):
                self.survey_wilderness_expedition_objective(x, y)
                return
            traveler = self.wilderness_traveler_at(x, y)
            if traveler:
                self.show_wilderness_traveler(traveler)
                return
            bounty = self.bounty_target_at(x, y)
            if bounty:
                self.start_bounty_combat_encounter(bounty, reason="interact")
                return
            enemy = self.wilderness_stronghold_enemy_at(x, y)
            if enemy:
                self.start_wilderness_stronghold_combat_encounter(enemy, reason="interact")
                return
            enemy = self.wilderness_random_combat_enemy_at(x, y)
            if enemy:
                if self.begin_wilderness_field_combat(enemy, reason="interact"):
                    self.dungeon_player_melee_attack(enemy)
                return
            animal = self.animal_at(x, y)
            if animal:
                self.observe_wilderness_animal(animal)
                return
            if self.wilderness_event_visual_at(x, y):
                self.interact_with_wilderness_event_feature(x, y)
                return
            if self.wilderness_seasonal_surface_at(x, y):
                self.interact_with_wilderness_seasonal_surface(x, y)
                return
        civic_overlay = self.procedural_town_civic_overlay_at(x, y)
        if civic_overlay:
            self.vertical_panel_view(
                str(civic_overlay.get("name", "Civic Improvement")),
                [
                    str(civic_overlay.get("name", "Civic Improvement")).upper(),
                    "",
                    str(civic_overlay.get("description", "A visible regional improvement.")),
                    "",
                    "This marker updates as local ownership, upgrades, and public projects change.",
                ],
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
            )
            self.set_message(f"Inspected {civic_overlay.get('name', 'the civic improvement')}.")
            return
        tile = self.active_map()[y][x] if self.in_active_bounds(x, y) else "#"
        if self.reclaimed_stronghold_build_board_at(x, y):
            self.show_reclaimed_stronghold_build_board()
            return
        _feature_id, stronghold_feature = self.reclaimed_stronghold_feature_at(x, y)
        if stronghold_feature:
            self.show_reclaimed_stronghold_feature(stronghold_feature)
            return
        building = self.procedural_town_building_door_at(x, y)
        if building:
            self.enter_procedural_town_building(building)
            return
        building = self.procedural_town_building_at(x, y)
        if building:
            self.vertical_panel_view(
                str(building.get("name", "Settlement Building")),
                self.procedural_town_building_lines(building),
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
            )
            self.set_message(f"You inspected {building.get('name', 'the building')}.")
            return
        plan = self.current_procedural_town_plan()
        if plan and int(plan.get("sign_x", -1)) == x and int(plan.get("sign_y", -1)) == y:
            self.vertical_panel_view(
                str(plan.get("name", "Wilderness Town")),
                self.procedural_town_sign_lines(plan),
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
            )
            self.set_message(f"You read the {plan.get('name', 'town')} sign.")
            return
        if tile == "S":
            self.return_from_wilderness_to_town(emergency=False)
            return
        if tile == "=":
            self.set_message("A simple wooden bridge crosses the river.")
            return
        if tile == "~":
            self.set_message(self.wilderness_water_description(x, y))
            return
        if tile == "V":
            self.enter_wilderness_cave(x, y)
            return
        if tile == "X":
            self.enter_wilderness_dungeon(x, y)
            return
        if tile == WILDERNESS_OUTPOST_SYMBOL:
            self.enter_wilderness_outpost(x, y)
            return
        if tile == WILDERNESS_STRUCTURE_SYMBOL and self.wilderness_structure_marker_at(x, y):
            self.show_wilderness_structure_exterior(x, y)
            return
        if tile == WILDERNESS_LANDSCAPE_SYMBOL:
            self.open_wilderness_landscape_site()
            return
        if tile == WILDERNESS_DOCK_SYMBOL:
            self.show_wilderness_dock(x, y)
            return
        if tile == WILDERNESS_FISHING_SETTLEMENT_SYMBOL:
            self.show_wilderness_fishing_settlement(x, y)
            return
        if tile == WILDERNESS_CLAIM_SYMBOL:
            self.wilderness_claim_menu(x, y)
            return
        if tile == "!":
            self.show_wilderness_stronghold_status()
            return
        if tile in WILDERNESS_BIOME_TILES:
            self.set_message(f"Nothing to interact with here. Press I to inspect the {wilderness_biome_name(tile)}.")
            return
        if tile in ["W", "N", "F"]:
            item_name = self.add_biome_forage_to_inventory(tile)
            if item_name:
                self.active_map()[y][x] = self.wilderness_biome_tile_at(x, y)
                self.autosave_with_message(f"Gathered 1 {item_name}.")
            else:
                self.set_message("There is nothing useful to gather here.")
            return
        if tile in ["O", "L", "e", "p", "G", "Z"]:
            self.search_wilderness_feature(x, y)
            return
        if tile == "M":
            self.set_message("A mineral outcrop. Use F with the Pickaxe selected to break it.")
            return
        if tile == FIELD_SITE_SYMBOL:
            self.show_wilderness_field_site(x, y)
            return
        if tile == "R":
            self.show_wilderness_ranger_camp(x, y)
            return
        if tile == "H":
            self.rest_at_wilderness_poi(x, y, "campfire", "Campfire Ring", 12, 0.06, 15)
            return
        if tile == "B":
            self.active_map()[y][x] = "."
            drops = {"Wood": 2, "Fiber": 2}
            if random.random() < 0.5:
                drops["Wild Herbs"] = 1
            add_inventory_items(self.state.inventory, drops)
            self.autosave_with_message(f"Searched the supply crate and found {format_drops(drops)}.")
            return
        if tile in ["J", "P"]:
            anchor_x, anchor_y = self.wilderness_ruin_anchor(x, y)
            self.open_wilderness_ruin_site(anchor_x, anchor_y)
            return
        if tile == "Y":
            self.active_map()[y][x] = "."
            item_name = "Wild Berries"
            if self.state.season == "Spring":
                item_name = "Salmonberry"
            elif self.state.season == "Fall":
                item_name = "Blackberry"
            qty = 1 + (1 if random.random() < 0.20 else 0)
            self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + qty
            self.autosave_with_message(f"Gathered {qty} {item_name} from the thicket.")
            return
        if tile == "u":
            self.active_map()[y][x] = "."
            item_name = "Morel" if self.state.season == "Spring" and random.random() < 0.35 else "Mushrooms"
            self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + 1
            self.autosave_with_message(f"Gathered 1 {item_name} from the hollow.")
            return
        if tile == "K":
            self.show_wilderness_overlook(x, y)
            return
        if tile == "Q":
            self.show_wilderness_shelter_menu(x, y)
            return
        if tile == "?":
            self.show_wilderness_landmark(x, y)
            return
        if tile in WILDERNESS_FORAGE_SYMBOLS:
            item_name = forage_item_for_symbol(tile) or "Wild Forage"
            self.active_map()[y][x] = self.wilderness_biome_tile_at(x, y)
            self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + 1
            self.autosave_with_message(f"Foraged 1 {item_name}.")
            return
        if tile == "T":
            self.set_message("Use F with the Axe selected to chop this wilderness tree.")
            return
        if tile == "o":
            self.set_message("Use F with the Pickaxe selected to break this wilderness rock.")
            return
        if tile == "*":
            self.set_message("Use F with the Axe selected to chop this fallen log.")
            return
        if tile == "^":
            self.set_message("Use F with the Hoe selected to clear this wild grass.")
            return
        self.set_message("Nothing to interact with here. Press I to inspect.")


    def animal_health_label(self, animal: Dict[str, object]) -> str:
        if animal.get("sick"):
            return "Sick"
        health = int(animal.get("health", 100))
        if health >= 85:
            return "Healthy"
        if health >= 60:
            return "Stable"
        if health >= 35:
            return "Weak"
        return "Critical"

    def sick_farm_animals(self) -> List[Dict[str, object]]:
        self.normalize_farm_animals()
        return [a for a in self.state.farm_animals if a.get("sick")]

    def weak_farm_animals(self) -> List[Dict[str, object]]:
        self.normalize_farm_animals()
        return [a for a in self.state.farm_animals if int(a.get("health", 100)) < 60 or a.get("sick")]

    def clinic_treat_all_sick_animals(self) -> bool:
        sick = self.sick_farm_animals()
        if not sick:
            self.set_message("No farm animals are sick right now.")
            return False
        base_cost = 70 if self.has_town_project("clinic_supply_board") else 95
        medicine = int(self.state.inventory.get("Animal Medicine", 0))
        treated = 0
        cost_paid = 0
        medicine_used = 0
        for animal in sick:
            if self.state.inventory.get("Animal Medicine", 0) > 0:
                self.state.inventory["Animal Medicine"] -= 1
                medicine_used += 1
            else:
                if self.state.money < base_cost:
                    continue
                self.state.money -= base_cost
                cost_paid += base_cost
            animal["sick"] = False
            animal["health"] = min(100, int(animal.get("health", 40)) + 45)
            animal["happiness"] = min(100, int(animal.get("happiness", 45)) + 6)
            treated += 1
        if treated <= 0:
            self.set_message(f"Need Animal Medicine or ${base_cost} per sick animal.")
            return False
        self.autosave_with_message(f"Clinic treated {treated} sick animal(s). Used {medicine_used} medicine and paid ${cost_paid}.")
        return True

    def clinic_wellness_check(self) -> bool:
        animals = self.weak_farm_animals()
        if not animals:
            self.set_message("No farm animals need a wellness check right now.")
            return False
        cost = 90 if self.has_town_project("clinic_supply_board") else 130
        if self.state.money < cost:
            self.set_message(f"Animal wellness check costs ${cost}.")
            return False
        self.state.money -= cost
        for animal in animals:
            animal["health"] = min(100, int(animal.get("health", 50)) + 20)
            animal["happiness"] = min(100, int(animal.get("happiness", 50)) + 4)
            if int(animal.get("health", 0)) >= 75 and animal.get("sick"):
                animal["sick"] = False
        self.autosave_with_message(f"Clinic wellness check helped {len(animals)} animal(s).")
        return True

    def clinic_health_report_lines(self) -> List[str]:
        self.normalize_farm_animals()
        animals = self.state.farm_animals
        lines = [
            "CLINIC HEALTH REPORT",
            "",
            f"Player stamina: {self.state.stamina}/{self.max_stamina()}",
            f"Animal Medicine owned: {self.state.inventory.get('Animal Medicine', 0)}",
            "",
            "Farm animals:",
        ]
        if not animals:
            return lines + ["No farm animals yet.", "", "Buy animals at the Animal Store."]
        sick_count = 0
        weak_count = 0
        for animal in animals:
            label = self.animal_health_label(animal)
            if label == "Sick":
                sick_count += 1
            if label in ["Weak", "Critical", "Sick"]:
                weak_count += 1
            lines.append(f"- {animal.get('name')} the {animal.get('species')}: {label} | Health {animal.get('health', 0)} | Mood {self.animal_mood(animal)}")
        lines.extend([
            "",
            f"Sick animals: {sick_count}",
            f"Weak/critical/sick animals: {weak_count}",
            "",
            "Animal Medicine now treats sickness directly from the animal menu.",
            "The Clinic can also treat all sick animals or perform a wellness check.",
        ])
        return lines

    def clinic_menu(self):
        if not self.ensure_current_town_service_unlocked():
            return
        while True:
            stamina_missing = self.missing_stamina()
            treatment_cost = 60 if self.has_town_project("clinic_supply_board") else 80
            full_checkup_cost = 120 if self.has_town_project("clinic_supply_board") else 160
            medicine_cost = 95 if self.has_town_project("clinic_supply_board") else 120
            herbs_cost = 25 if self.has_town_project("clinic_supply_board") else 35
            medicine_max = self.state.money // medicine_cost if medicine_cost > 0 else 0
            herbs_max = self.state.money // herbs_cost if herbs_cost > 0 else 0
            potion_entry = self.combat_supply_shop_stock("clinic")[0]
            ether_entry = self.combat_supply_shop_stock("clinic")[1]
            potion_cost = int(potion_entry["price"])
            ether_cost = int(ether_entry["price"])
            potion_max = self.state.money // potion_cost if potion_cost > 0 else 0
            ether_max = self.state.money // ether_cost if ether_cost > 0 else 0
            sick_count = len(self.sick_farm_animals())
            weak_count = len(self.weak_farm_animals())
            items = [
                MenuItem(label="Rest treatment", value="rest", enabled=self.state.money >= treatment_cost and stamina_missing > 0, hint=f"${treatment_cost} +40 stamina"),
                MenuItem(label="Full checkup", value="full_checkup", enabled=self.state.money >= full_checkup_cost and stamina_missing > 0, hint=f"${full_checkup_cost} full stamina"),
                MenuItem(label="Treat all sick animals", value="treat_animals", enabled=sick_count > 0, hint=f"{sick_count} sick"),
                MenuItem(label="Animal wellness check", value="wellness", enabled=weak_count > 0 and self.state.money >= (90 if self.has_town_project("clinic_supply_board") else 130), hint=f"{weak_count} need care"),
                MenuItem(label="Buy Health Potion", value="potion", enabled=self.state.money >= potion_cost, hint=f"${potion_cost} x{potion_max}"),
                MenuItem(label="Buy Mana Potion", value="ether", enabled=self.state.money >= ether_cost, hint=f"${ether_cost} x{ether_max}"),
                MenuItem(label="Buy Animal Medicine", value="animal_medicine", enabled=self.state.money >= medicine_cost, hint=f"${medicine_cost} x{medicine_max}"),
                MenuItem(label="Buy Cave Herbs", value="herbs", enabled=self.state.money >= herbs_cost, hint=f"${herbs_cost} x{herbs_max}"),
                MenuItem(label="Health report", value="report", enabled=True, hint="farm"),
                MenuItem(label="Health advice", value="advice", enabled=True, hint="free"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Clinic", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Clinic closed.")
                return
            if choice.value == "rest":
                self.state.money -= treatment_cost
                restored = self.restore_stamina(40)
                self.autosave_with_message(f"Clinic treatment restored {restored} stamina.")
                return
            if choice.value == "full_checkup":
                self.state.money -= full_checkup_cost
                before = int(self.state.stamina)
                self.state.stamina = self.max_stamina()
                self.autosave_with_message(f"Full clinic checkup restored {self.state.stamina - before} stamina.")
                return
            if choice.value == "treat_animals":
                self.clinic_treat_all_sick_animals()
                return
            if choice.value == "wellness":
                self.clinic_wellness_check()
                return
            if choice.value == "potion":
                if self.buy_combat_supply_item("Potion", potion_cost, title="Buy Health Potion"):
                    return
                continue
            if choice.value == "ether":
                if self.buy_combat_supply_item("Ether", ether_cost, title="Buy Mana Potion"):
                    return
                continue
            if choice.value == "animal_medicine":
                qty = self.vertical_quantity_select(
                    "Buy Medicine",
                    "Animal Medicine",
                    medicine_cost,
                    max_qty=max(1, medicine_max),
                    start_qty=1,
                    panel_width=LEFT_PANEL_WIDTH,
                    panel_height=LEFT_PANEL_HEIGHT,
                    return_back=True,
                )
                if qty == MENU_BACK or qty is None or int(qty) <= 0:
                    continue
                qty = int(qty)
                total = qty * medicine_cost
                self.state.money -= total
                self.state.inventory["Animal Medicine"] = self.state.inventory.get("Animal Medicine", 0) + qty
                self.autosave_with_message(f"Bought {qty} Animal Medicine for ${total}.")
                return
            if choice.value == "herbs":
                qty = self.vertical_quantity_select(
                    "Buy Herbs",
                    "Cave Herbs",
                    herbs_cost,
                    max_qty=max(1, herbs_max),
                    start_qty=min(5, max(1, herbs_max)),
                    panel_width=LEFT_PANEL_WIDTH,
                    panel_height=LEFT_PANEL_HEIGHT,
                    return_back=True,
                )
                if qty == MENU_BACK or qty is None or int(qty) <= 0:
                    continue
                qty = int(qty)
                total = qty * herbs_cost
                self.state.money -= total
                self.state.inventory["Cave Herbs"] = self.state.inventory.get("Cave Herbs", 0) + qty
                self.autosave_with_message(f"Bought {qty} Cave Herbs for ${total}.")
                return
            if choice.value == "report":
                self.vertical_panel_view("Clinic Health Report", self.clinic_health_report_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "advice":
                self.vertical_panel_view("Clinic Advice", [
                    "CLINIC ADVICE",
                    "",
                    "Stamina management is part of farm planning.",
                    "Food is cheaper than treatment, but the Clinic can help in a pinch.",
                    "",
                    "Animal Medicine now treats sick animals directly from their individual menu.",
                    "The Clinic can treat all sick animals at once if you have medicine or money.",
                    "Wellness checks help weak animals recover before sickness gets worse.",
                    "Cave Herbs are liked by Dr. Ivy and can be useful in recipes.",
                ], LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue


    def errand_day_key(self) -> str:
        return f"{self.state.year}-{self.state.month}-{self.state.day}"

    def npc_errand_item_pool(self, npc: Dict[str, object]) -> List[Tuple[str, int]]:
        role = str(npc.get("role", "Villager"))
        season = self.state.season
        pools = {
            "Seed Seller": [("Wildflower", 2), ("Berries", 2), ("Watercress", 1), ("Turnip Seeds", 2), ("Carrot Seeds", 2)],
            "Blacksmith": [("Stone", 8), ("Ore", 3), ("Coal", 2), ("Iron Ore", 1)],
            "Carpenter": [("Wood", 10), ("Hardwood", 3), ("Soft Fiber", 2), ("Stone", 6)],
            "Animal Keeper": [("Animal Medicine", 1), ("Bird Egg", 1), ("Duck Egg", 1), ("Large Bird Egg", 1)],
            "Librarian": [("Cave Herbs", 1), ("Wildflower", 2), ("Cave Mushroom", 1), ("Strange Spores", 1)],
            "Traveler": [("Berries", 2), ("Watercress", 2), ("Cave Mushroom", 1), ("Wildflower", 2)],
            "Doctor": [("Cave Herbs", 2), ("Honey", 1), ("Animal Medicine", 1), ("Watercress", 2)],
            "Innkeeper": [("Berries", 2), ("Honey", 1), ("Woodland Salad", 1), ("Carrot", 2)],
            "Chef": [("Carrot", 2), ("Tomato", 2), ("Corn", 2), ("Cave Mushroom", 1), ("Woodland Salad", 1)],
            "Market Vendor": [("Wildflower", 2), ("Soft Fiber", 2), ("Honey", 1), ("Cave Herbs", 1)],
            "Gardener": [("Wildflower", 3), ("Watercress", 2), ("Maple", 2), ("Berries", 2)],
            "Fisher": [("Minnow", 2), ("Sunfish", 1), ("River Chub", 1), ("Carp", 1)],
            "Miner": [("Stone", 10), ("Ore", 4), ("Coal", 3), ("Iron Ore", 2)],
            "Kid": [("Berries", 2), ("Wildflower", 1), ("Bird Egg", 1), ("Minnow", 1)],
            "Courier": [("Berries", 2), ("Watercress", 1), ("Sunfish", 1), ("Honey", 1)],
            "Artist": [("Wildflower", 2), ("Soft Fiber", 3), ("Maple", 1), ("Honey", 1)],
            "Recluse": [("Cave Mushroom", 2), ("Cave Herbs", 2), ("Strange Spores", 1), ("River Chub", 1)],
            "Orchardist": [("Maple", 2), ("Wild Berries", 2), ("Berry Jam", 1), ("Wildflower Honey", 1)],
            "Tailor": [("Soft Fiber", 2), ("Fiber", 5), ("Wildflowers", 2), ("Maple", 1)],
            "Musician": [("Jam Toast", 1), ("Wildflower", 2), ("Honey", 1), ("Sunfish", 1)],
            "Beekeeper": [("Wild Honey", 1), ("Wildflowers", 3), ("Wildflower Honey", 1), ("Maple", 1)],
            "Botanist": [("Cave Herbs", 2), ("Strange Spores", 1), ("Watercress", 2), ("Cave Mushroom", 1)],
            "Mechanic": [("Copper Bar", 1), ("Iron Bar", 1), ("Crystal Shard", 1), ("Coal", 3)],
            "Scholar": [("Cave Herbs", 2), ("Maple", 2), ("Quartz", 1), ("Ancient Preserves", 1)],
            "Retiree": [("Jam Toast", 1), ("Milk", 1), ("Wild Berries", 2), ("River Chub", 1)],
            "Mayor": [("Wood", 8), ("Stone", 8), ("Wildflower", 2), ("Honey", 1)],
        }
        base = list(pools.get(role, [("Berries", 2), ("Wildflower", 2), ("Stone", 5)]))
        if season == "Spring":
            base.append(("Turnip Seeds", 2))
        elif season == "Summer":
            base.append(("Tomato", 2))
        elif season == "Fall":
            base.append(("Cave Mushroom", 1))
        elif season == "Winter":
            base.append(("Coal", 2))
        return base

    def daily_errand_for_npc(self, npc: Dict[str, object]) -> Dict[str, object]:
        npc_id = str(npc.get("id", "npc"))
        pool = self.npc_errand_item_pool(npc)
        seed_text = f"{self.errand_day_key()}:{npc_id}:{self.state.weather}"
        seed_value = sum(ord(ch) for ch in seed_text)
        item, qty = pool[seed_value % len(pool)]
        # Scale reward with quantity and friendship, but keep early errands modest.
        friendship = self.town_npc_relationship(npc_id)
        money = max(40, int(qty) * 35 + min(120, max(0, friendship // 2)))
        if friendship < 60:
            rel_gain = 3
        elif friendship < 150:
            rel_gain = 2
        else:
            rel_gain = 1
        errand_id = f"errand:{self.errand_day_key()}:{npc_id}:{item}:{qty}"
        return {
            "id": errand_id,
            "npc_id": npc_id,
            "npc_name": str(npc.get("name", "Townsperson")),
            "role": str(npc.get("role", "Villager")),
            "item": item,
            "qty": int(qty),
            "money": int(money),
            "relationship": int(rel_gain),
            "completed": errand_id in set(self.state.completed_errand_ids or []),
        }

    def today_errands(self) -> List[Dict[str, object]]:
        self.normalize_town_npcs()
        return [self.daily_errand_for_npc(npc) for npc in self.active_town_npcs()]

    def errand_for_npc(self, npc: Dict[str, object]) -> Dict[str, object]:
        return self.daily_errand_for_npc(npc)

    def can_complete_errand(self, errand: Dict[str, object]) -> bool:
        if errand.get("completed"):
            return False
        return int(self.state.inventory.get(str(errand.get("item")), 0)) >= int(errand.get("qty", 1))

    def complete_errand(self, errand: Dict[str, object]) -> bool:
        errand_id = str(errand.get("id", ""))
        if not errand_id or errand_id in set(self.state.completed_errand_ids or []):
            self.set_message("That errand is already complete.")
            return False
        item = str(errand.get("item", ""))
        qty = int(errand.get("qty", 1))
        if self.state.inventory.get(item, 0) < qty:
            self.set_message(f"You need {qty} {item} to complete this errand.")
            return False
        self.state.inventory[item] -= qty
        if self.state.inventory[item] <= 0:
            self.state.inventory[item] = 0
        reward_money = int(errand.get("money", 0))
        if self.has_town_project("errand_bonus_fund"):
            reward_money += 25
        self.state.money += reward_money
        npc_id = str(errand.get("npc_id", ""))
        self.adjust_town_npc_relationship(npc_id, int(errand.get("relationship", 0)))
        self.state.completed_errand_ids.append(errand_id)
        self.autosave_with_message(
            f"Completed {errand.get('npc_name')}'s errand: delivered {qty} {item}. "
            f"Reward: ${reward_money} and relationship +{errand.get('relationship')}."
        )
        return True

    def errand_lines(self, errand: Dict[str, object]) -> List[str]:
        status = "Complete" if errand.get("completed") else ("Ready to turn in" if self.can_complete_errand(errand) else "Incomplete")
        return [
            f"{errand.get('npc_name')} - {errand.get('role')}",
            "",
            f"Request: Bring {errand.get('qty')} {errand.get('item')}.",
            f"Status: {status}",
            "",
            "Reward:",
            f"- ${errand.get('money')}",
            f"- Relationship +{errand.get('relationship')}",
            "",
            "Turn in:",
            "Find the NPC and choose Errand from their menu, or use the Errand Board if the item is ready.",
        ]

    def errand_board_lines(self) -> List[str]:
        bonus = 25 if self.has_town_project("errand_bonus_fund") else 0
        lines = [
            "ERRAND BOARD",
            "",
            f"Today: {self.state.date_label}",
            f"Weather: {self.state.weather}",
            f"Town bonus: ${bonus}" if bonus else "Town bonus: none",
            "",
            "Daily errands:",
        ]
        for errand in self.today_errands():
            marker = "x" if errand.get("completed") else ("!" if self.can_complete_errand(errand) else " ")
            lines.append(
                f"{marker} {errand.get('npc_name')}: {errand.get('qty')} {errand.get('item')} "
                f"-> ${int(errand.get('money')) + bonus}, +{errand.get('relationship')}"
            )
        lines.extend([
            "",
            "Legend:",
            "! = ready to turn in",
            "x = completed today",
            "",
            "Errands refresh daily. Complete them through NPC menus or the board.",
        ])
        return lines

    def errand_board_menu(self):
        while True:
            errands = self.today_errands()
            items: List[MenuItem] = []
            for errand in errands:
                marker = "x" if errand.get("completed") else ("!" if self.can_complete_errand(errand) else " ")
                hint = "done" if errand.get("completed") else (f"ready ${errand.get('money')}" if self.can_complete_errand(errand) else f"need {errand.get('qty')} {errand.get('item')}")
                items.append(MenuItem(
                    label=f"{marker} {errand.get('npc_name')}: {errand.get('qty')} {errand.get('item')}",
                    value=str(errand.get("id")),
                    enabled=not bool(errand.get("completed")),
                    hint=hint,
                ))
            items.append(MenuItem(label="Board details", value="details", enabled=True, hint="list"))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Errand Board", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed errand board.")
                return
            if choice.value == "details":
                self.vertical_panel_view("Errand Board", self.errand_board_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            errand = next((e for e in errands if str(e.get("id")) == str(choice.value)), None)
            if errand:
                if self.can_complete_errand(errand):
                    self.complete_errand(errand)
                    return
                self.vertical_panel_view("Errand Details", self.errand_lines(errand), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                self.set_message(f"Errand needs {errand.get('qty')} {errand.get('item')}.")
                continue

