    def has_town_project(self, project_id: str) -> bool:
        return str(project_id) in set(self.state.completed_town_project_ids or [])

    def completed_town_project_count(self) -> int:
        return len(set(self.state.completed_town_project_ids or []))

    def fund_town_project(self, project_id: str) -> bool:
        catalog = self.town_project_catalog()
        project = catalog.get(project_id)
        if not project:
            self.set_message("Unknown town project.")
            return False
        if self.has_town_project(project_id):
            self.set_message(f"{project['title']} is already funded.")
            return False
        cost = int(project["cost"])
        if self.state.money < cost:
            self.set_message(f"{project['title']} costs ${cost}.")
            return False
        self.state.money -= cost
        self.state.completed_town_project_ids.append(str(project_id))
        self.refresh_town_map_for_projects()
        self.autosave_with_message(f"Funded town project: {project['title']}. The town layout now visibly reflects the upgrade.")
        return True

    def town_project_lines(self, project_id: str) -> List[str]:
        catalog = self.town_project_catalog()
        project = catalog.get(project_id, {})
        status = "Funded" if self.has_town_project(project_id) else f"Unfunded (${project.get('cost', '?')})"
        return [
            str(project.get("title", "Town Project")),
            "",
            f"Status: {status}",
            "",
            "Description:",
            str(project.get("description", "")),
            "",
            "Benefit:",
            str(project.get("benefit", "")),
        ]

    def town_projects_overview_lines(self) -> List[str]:
        lines = [
            "TOWN PROJECTS",
            "",
            f"Funded projects: {self.completed_town_project_count()}/{len(self.town_project_catalog())}",
            "",
        ]
        for project_id, project in self.town_project_catalog().items():
            marker = "x" if self.has_town_project(project_id) else " "
            lines.append(f"{marker} {project['title']} - ${project['cost']}")
            lines.append(f"  {project['benefit']}")
        lines.extend([
            "",
            "Fund projects through Town Hall.",
            "Projects are permanent and persist through save/load.",
            "Completed projects now visibly alter the town exterior.",
            "Road projects can also unlock Town Hall quick travel.",
        ])
        return lines

    def town_projects_menu(self):
        while True:
            items: List[MenuItem] = []
            for project_id, project in self.town_project_catalog().items():
                funded = self.has_town_project(project_id)
                cost = int(project["cost"])
                items.append(MenuItem(
                    label=("x " if funded else "  ") + str(project["title"]),
                    value=project_id,
                    enabled=True,
                    hint="funded" if funded else (f"${cost}" if self.state.money >= cost else f"${cost} no"),
                ))
            items.append(MenuItem(label="Project overview", value="overview", enabled=True))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Town Projects", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed town projects.")
                return
            if choice.value == "overview":
                self.vertical_panel_view("Town Projects", self.town_projects_overview_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            project_id = str(choice.value)
            details_items = [
                MenuItem(label="Fund project", value="fund", enabled=not self.has_town_project(project_id), hint=str(self.town_project_catalog()[project_id]["cost"])),
                MenuItem(label="Read details", value="details", enabled=True),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            confirm = self.vertical_panel_select(str(self.town_project_catalog()[project_id]["title"]), details_items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if confirm is None or confirm.value == MENU_BACK:
                continue
            if confirm.value == "details":
                self.vertical_panel_view("Project Details", self.town_project_lines(project_id), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if confirm.value == "fund":
                self.fund_town_project(project_id)
                return

