    def festival_id_for_date(self, month: int, day: int, year: Optional[int] = None) -> Optional[str]:
        for festival_id, data in self.festival_catalog().items():
            if int(data["month"]) == int(month) and int(data["day"]) == int(day):
                return festival_id
        return None

    def todays_festival_id(self) -> Optional[str]:
        return self.festival_id_for_date(self.state.month, self.state.day, self.state.year)

    def todays_festival(self) -> Optional[Dict[str, object]]:
        festival_id = self.todays_festival_id()
        if not festival_id:
            return None
        data = dict(self.festival_catalog()[festival_id])
        data["id"] = festival_id
        return data

    def festival_attendance_id(self, festival_id: str) -> str:
        return f"festival:{self.state.year}:{festival_id}"

    def has_attended_todays_festival(self) -> bool:
        festival_id = self.todays_festival_id()
        if not festival_id:
            return False
        return self.festival_attendance_id(festival_id) in set(self.state.attended_festival_ids or [])

    def festival_calendar_lines(self) -> List[str]:
        lines = ["FESTIVAL CALENDAR", ""]
        for festival_id, data in self.festival_catalog().items():
            lines.append(f"- {data['name']}: Month {data['month']} Day {data['day']} ({data['season']})")
            lines.append(f"  Location: {data['location']}")
        today = self.todays_festival()
        lines.extend(["", f"Today: {today['name']} at {today['location']}" if today else "Today: no festival"])
        return lines

    def festival_detail_lines(self, festival: Dict[str, object]) -> List[str]:
        attended = self.has_attended_todays_festival()
        items = festival.get("reward_items", {}) or {}
        item_lines = [f"- {qty} {item}" for item, qty in items.items()] or ["- none"]
        lines = [
            str(festival.get("name", "Festival")),
            "",
            f"Date: Month {festival.get('month')} Day {festival.get('day')}",
            f"Location: {festival.get('location')}",
            f"Status: {'attended this year' if attended else 'not attended this year'}",
            "",
            str(festival.get("description", "")),
            "",
            "Attendance reward:",
            f"- Friendship +{festival.get('friendship', 0)} with every town NPC",
            f"- Stamina +{festival.get('stamina', 0)}",
            f"- ${festival.get('money', 0)}",
            *item_lines,
        ]
        activities = self.festival_activity_options(festival)
        if activities:
            lines.extend(["", "Festival activities:"])
            for activity in activities:
                done = "done" if self.festival_activity_completed(str(festival.get("id", "")), str(activity.get("id", ""))) else "open"
                lines.append(f"- {activity.get('title', 'Activity')}: {done}")
        return lines

    def festival_activity_completion_id(self, festival_id: str, activity_id: str) -> str:
        return f"festival_activity:{self.state.year}:{festival_id}:{activity_id}"

    def festival_activity_completed(self, festival_id: str, activity_id: str) -> bool:
        return self.festival_activity_completion_id(festival_id, activity_id) in set(self.state.attended_festival_ids or [])

    def festival_reward_lines(self, reward: Dict[str, object]) -> List[str]:
        lines: List[str] = []
        money = int(reward.get("money", 0) or 0)
        stamina = int(reward.get("stamina", 0) or 0)
        friendship = int(reward.get("friendship", 0) or 0)
        items = reward.get("items", {}) or {}
        if money:
            lines.append(f"- ${money}")
        if stamina:
            lines.append(f"- Stamina +{stamina}")
        if friendship:
            lines.append(f"- Town friendship +{friendship}")
        if isinstance(items, dict) and items:
            lines.append(f"- Items: {format_drops(items)}")
        npc_relationships = reward.get("relationships", {}) or {}
        if isinstance(npc_relationships, dict):
            for npc_id, amount in npc_relationships.items():
                lines.append(f"- {self.town_npc_name(str(npc_id))} friendship +{int(amount)}")
        return lines or ["- None"]

