    def festival_activity_lines(self, festival: Dict[str, object], activity: Dict[str, object]) -> List[str]:
        reward = activity.get("reward", {}) or {}
        completed = self.festival_activity_completed(str(festival.get("id", "")), str(activity.get("id", "")))
        return [
            str(activity.get("title", "Festival Activity")),
            "",
            str(activity.get("description", "")),
            "",
            f"Time: {int(activity.get('time', 30))} minutes",
            f"Status: {'complete this year' if completed else 'open this year'}",
            "",
            "Reward:",
            *self.festival_reward_lines(reward if isinstance(reward, dict) else {}),
        ]

    def apply_festival_reward(self, reward: Dict[str, object]):
        money = int(reward.get("money", 0) or 0)
        if money:
            self.state.money += money
        stamina = int(reward.get("stamina", 0) or 0)
        if stamina:
            self.restore_stamina(stamina)
        items = reward.get("items", {}) or {}
        if isinstance(items, dict):
            for item, qty in items.items():
                self.state.inventory[str(item)] = int(self.state.inventory.get(str(item), 0)) + int(qty)
        friendship = int(reward.get("friendship", 0) or 0)
        if friendship:
            for npc in self.active_town_npcs():
                self.adjust_town_npc_relationship(str(npc.get("id", "")), friendship)
        npc_relationships = reward.get("relationships", {}) or {}
        if isinstance(npc_relationships, dict):
            for npc_id, amount in npc_relationships.items():
                self.adjust_town_npc_relationship(str(npc_id), int(amount))

    def complete_festival_activity(self, festival: Dict[str, object], activity: Dict[str, object]) -> bool:
        festival_id = str(festival.get("id", ""))
        activity_id = str(activity.get("id", ""))
        if not festival_id or not activity_id:
            self.set_message("That festival activity is not available.")
            return False
        completion_id = self.festival_activity_completion_id(festival_id, activity_id)
        if completion_id in set(self.state.attended_festival_ids or []):
            self.set_message(f"{activity.get('title', 'Festival activity')} is already complete this year.")
            return False
        self.state.attended_festival_ids.append(completion_id)
        reward = activity.get("reward", {}) or {}
        if isinstance(reward, dict):
            self.apply_festival_reward(reward)
        self.advance_time(int(activity.get("time", 30)))
        self.autosave_with_message(f"Joined {activity.get('title', 'festival activity')} at {festival.get('name', 'the festival')}.")
        return True

    def festival_activities_menu(self):
        festival = self.todays_festival()
        if not festival:
            self.set_message("There is no festival today.")
            return
        while True:
            activities = self.festival_activity_options(festival)
            items: List[MenuItem] = []
            for activity in activities:
                activity_id = str(activity.get("id", ""))
                done = self.festival_activity_completed(str(festival.get("id", "")), activity_id)
                marker = "x" if done else " "
                items.append(MenuItem(
                    label=f"{marker} {activity.get('title', activity_id)}",
                    value=activity_id,
                    enabled=not done,
                    hint="done" if done else f"{int(activity.get('time', 30))} min",
                ))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Festival Activities", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed festival activities.")
                return
            activity = next((a for a in activities if str(a.get("id", "")) == str(choice.value)), None)
            if not activity:
                continue
            self.vertical_panel_view("Festival Activity", self.festival_activity_lines(festival, activity), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            if self.festival_activity_completed(str(festival.get("id", "")), str(activity.get("id", ""))):
                continue
            confirm_items = [
                MenuItem(label="Join activity", value="join", enabled=True, hint=f"{int(activity.get('time', 30))} min"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            confirm = self.vertical_panel_select(str(activity.get("title", "Festival Activity")), confirm_items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if confirm and confirm.value == "join":
                self.complete_festival_activity(festival, activity)
                return

    def attend_todays_festival(self) -> bool:
        festival = self.todays_festival()
        if not festival:
            self.set_message("There is no festival today.")
            return False
        festival_id = str(festival["id"])
        attendance_id = self.festival_attendance_id(festival_id)
        if attendance_id in set(self.state.attended_festival_ids or []):
            self.vertical_panel_view(str(festival["name"]), self.festival_detail_lines(festival), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            self.set_message(f"You already attended {festival['name']} this year.")
            return False

        self.state.attended_festival_ids.append(attendance_id)
        friendship = int(festival.get("friendship", 0))
        for npc in self.active_town_npcs():
            self.adjust_town_npc_relationship(str(npc.get("id", "")), friendship)
        self.restore_stamina(int(festival.get("stamina", 0)))
        self.state.money += int(festival.get("money", 0))
        for item, qty in (festival.get("reward_items", {}) or {}).items():
            self.state.inventory[item] = self.state.inventory.get(item, 0) + int(qty)
        self.advance_time(90)
        self.vertical_panel_view(str(festival["name"]), self.festival_detail_lines(festival), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        self.autosave_with_message(f"Attended {festival['name']}. Friendship improved around town.")
        return True

    def festival_status_line(self) -> str:
        festival = self.todays_festival()
        if not festival:
            return "No festival today."
        status = "attended" if self.has_attended_todays_festival() else "not attended"
        return f"Today: {festival['name']} at {festival['location']} ({status})."

    def festival_menu(self):
        festival = self.todays_festival()
        if not festival:
            self.vertical_panel_view("Festivals", self.festival_calendar_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            self.set_message("No festival today.")
            return
        while True:
            open_activities = sum(
                1
                for activity in self.festival_activity_options(festival)
                if not self.festival_activity_completed(str(festival.get("id", "")), str(activity.get("id", "")))
            )
            items = [
                MenuItem(label=f"Attend {festival['name']}", value="attend", enabled=not self.has_attended_todays_festival(), hint="90 min"),
                MenuItem(label="Festival activities", value="activities", enabled=open_activities > 0, hint=f"{open_activities} open" if open_activities else "done"),
                MenuItem(label="Read details", value="details", enabled=True),
                MenuItem(label="Festival calendar", value="calendar", enabled=True),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Festival", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Festival menu closed.")
                return
            if choice.value == "attend":
                self.attend_todays_festival()
                return
            if choice.value == "activities":
                self.festival_activities_menu()
                continue
            if choice.value == "details":
                self.vertical_panel_view(str(festival["name"]), self.festival_detail_lines(festival), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "calendar":
                self.vertical_panel_view("Festival Calendar", self.festival_calendar_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue

    def road_network_lines(self) -> List[str]:
        lines = [
            "ROAD NETWORK",
            "",
            "Town routes:",
            "- North Market Street: General Store, Blacksmith, Library",
            "- Civic Boulevard: Inn, Town Hall, craft/ranch shops, Farm Road",
            "- South Civic Walk: Clinic and Market Row",
            "- East Commons: orchard walk and the farm-road approach",
            "- South Canal Walk: bridges beneath the main avenues",
            "- North Wilderness Road: route to wilderness",
            "",
            "Infrastructure projects:",
            f"- Farm Road Paving: {'funded' if self.has_town_project('farm_road_paving') else 'not funded'}",
            f"- Wilderness Trail Bridge: {'funded' if self.has_town_project('wilderness_trail_bridge') else 'not funded'}",
            f"- Road Grid Signage: {'funded' if self.has_town_project('road_grid_signage') else 'not funded'}",
            "",
            "Quick travel:",
        ]
        lines.append("- Farm Road: unlocked" if self.has_town_project("farm_road_paving") else "- Farm Road: requires Farm Road Paving")
        lines.append("- Wilderness Road: unlocked" if self.has_town_project("wilderness_trail_bridge") else "- Wilderness Road: requires Wilderness Trail Bridge")
        lines.append("- Central Park / Market route: unlocked" if self.has_town_project("road_grid_signage") else "- Central Park / Market route: requires Road Grid Signage")
        return lines

    def road_network_menu(self):
        while True:
            items = [
                MenuItem(label="Read road network", value="read", enabled=True),
                MenuItem(label="Quick travel: Farm Road", value="farm", enabled=self.has_town_project("farm_road_paving"), hint="requires paving" if not self.has_town_project("farm_road_paving") else "east gate"),
                MenuItem(label="Quick travel: Wilderness Road", value="wilderness", enabled=self.has_town_project("wilderness_trail_bridge"), hint="requires bridge" if not self.has_town_project("wilderness_trail_bridge") else "north gate"),
                MenuItem(label="Quick travel: Central Park", value="park", enabled=self.has_town_project("road_grid_signage"), hint="requires signage" if not self.has_town_project("road_grid_signage") else "park"),
                MenuItem(label="Quick travel: Market Row", value="market", enabled=self.has_town_project("road_grid_signage"), hint="requires signage" if not self.has_town_project("road_grid_signage") else "market promenade"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Road Network", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed road network.")
                return
            if choice.value == "read":
                self.vertical_panel_view("Road Network", self.road_network_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "farm":
                self.state.location = "Town"
                self.state.player_x = TOWN_WIDTH - 3
                self.state.player_y = 20
                self.state.facing = "RIGHT"
                self.autosave_with_message("Used the paved road network to reach the Farm Road.")
                return
            if choice.value == "wilderness":
                self.state.location = "Town"
                self.state.player_x = 57
                self.state.player_y = 1
                self.state.facing = "UP"
                self.autosave_with_message("Used the trail bridge route to reach the Wilderness Road.")
                return
            if choice.value == "park":
                self.state.location = "Town"
                self.state.player_x = 49
                self.state.player_y = 29
                self.state.facing = "DOWN"
                self.autosave_with_message("Used the signed grid roads to reach Central Park.")
                return
            if choice.value == "market":
                self.state.location = "Town"
                self.state.player_x = TOWN_DOORS["market_row"][0]
                self.state.player_y = TOWN_DOORS["market_row"][1] + 1
                self.state.facing = "UP"
                self.autosave_with_message("Used the signed grid roads to reach Market Row.")
                return

    def town_hall_menu(self):
        while True:
            avg_friendship = 0
            active_npcs = self.active_town_npcs()
            if active_npcs:
                avg_friendship = int(sum(self.town_npc_relationship(str(npc.get("id", ""))) for npc in active_npcs) / max(1, len(active_npcs)))
            claim_count = len(self.state.owned_wilderness_claims) if isinstance(self.state.owned_wilderness_claims, dict) else 0
            items = [
                MenuItem(label="View town status", value="status", enabled=True, hint=f"avg {avg_friendship}"),
                MenuItem(label="View NPC directory", value="npcs", enabled=True, hint=str(len(active_npcs))),
                MenuItem(label="Find NPC", value="find_npc", enabled=True, hint="whereabouts"),
                MenuItem(label="Errand Board", value="errand_board", enabled=True, hint="daily tasks"),
                MenuItem(label="Land Records", value="claims", enabled=True, hint=f"{claim_count} claim(s)"),
                MenuItem(label="Farm Automation", value="automation", enabled=True, hint="systems"),
                MenuItem(label="Apply for small grant", value="grant", enabled=True, hint="once/day"),
                MenuItem(label="Town Projects", value="projects", enabled=True, hint=f"{self.completed_town_project_count()} funded"),
                MenuItem(label="Festival", value="festival", enabled=True, hint=self.festival_status_line()),
                MenuItem(label="Town Lighting", value="lighting", enabled=True, hint=self.outdoor_lighting_label()),
                MenuItem(label="Road Network", value="roads", enabled=True, hint="routes"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Town Hall", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Town Hall closed.")
                return
            if choice.value == "status":
                lines = [
                    "TOWN STATUS",
                    "",
                    f"Town stage: {self.town_stage_label()}",
                    f"Active residents: {len(active_npcs)}",
                    f"Later arrivals: {len(self.inactive_town_npcs())}",
                    f"Average friendship: {avg_friendship}",
                    f"Farm expansions: {len(self.state.farm_expansions)}",
                    f"House upgrades: {len(self.state.house_upgrades)}",
                    f"Owned land claims: {claim_count}",
                    f"Deepest mine floor: {self.state.deepest_mine_floor}",
                    f"Wilderness chunks visited: {self.state.wilderness_chunks_visited}",
                    f"Bulletin jobs today: {len(self.today_bulletin_jobs())}",
                    f"Fish ponds: {self.fish_pond_summary_counts()[1]}/{self.fish_pond_summary_counts()[0]} stocked, {self.fish_pond_summary_counts()[2]} ready",
                    f"Artisan jars: {self.artisan_processor_summary_counts()[1]}/{self.artisan_processor_summary_counts()[0]} active, {self.artisan_processor_summary_counts()[2]} ready",
                    "",
                    "Town Hall will become a natural home for permits, projects, and festivals.",
                ]
                self.vertical_panel_view("Town Status", lines, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "npcs":
                self.vertical_panel_view("NPC Directory", self.town_npc_directory_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "find_npc":
                self.find_town_npc_menu()
                continue
            if choice.value == "errand_board":
                self.errand_board_menu()
                continue
            if choice.value == "claims":
                result = self.show_land_claims_menu(allow_travel=True)
                if result == "changed":
                    return
                continue
            if choice.value == "automation":
                self.vertical_panel_view("Farm Automation", self.automation_status_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "grant":
                key = f"town_grant_{self.town_npc_day_key()}"
                if self.state.farm_building_harvest_days.get(key):
                    self.set_message("You already received today's small town grant.")
                    return
                grant = 75 + min(125, max(0, avg_friendship))
                if self.has_town_project("park_beautification"):
                    grant += 50
                if self.has_town_project("road_grid_signage"):
                    grant += 25
                self.state.money += grant
                self.state.farm_building_harvest_days[key] = True
                self.autosave_with_message(f"Town Hall approved a small community grant: ${grant}.")
                return
            if choice.value == "projects":
                self.town_projects_menu()
                continue
            if choice.value == "festival":
                self.festival_menu()
                continue
            if choice.value == "lighting":
                self.vertical_panel_view("Town Lighting", self.town_lighting_report_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "roads":
                self.road_network_menu()
                continue

    def market_day_key(self) -> str:
        return f"{self.state.year}-{self.state.month}-{self.state.day}"

    def market_stock_key(self, item: str) -> str:
        return f"{self.market_day_key()}:{item}"

    def market_item_bought_today(self, item: str) -> int:
        return int((self.state.market_purchase_counts or {}).get(self.market_stock_key(item), 0))

    def market_item_remaining(self, entry: Dict[str, object]) -> int:
        limit = int(entry.get("limit", 99))
        return max(0, limit - self.market_item_bought_today(str(entry.get("item", ""))))

    def vera_friendship(self) -> int:
        return self.town_npc_relationship("vera_vendor")

    def daily_market_vendor_name(self) -> str:
        vendors = ["Vera", "Basil", "Old Jun", "Finn", "Cora", "Penny"]
        index = (int(self.state.day) + int(self.state.month) * 3 + int(self.state.year)) % len(vendors)
        if self.town_weather_is_bad_for_routines():
            return "Vera"
        return vendors[index]

    def today_market_day_label(self) -> Optional[str]:
        return self.market_day_label_for_date(self.state.month, self.state.day, self.state.year)

    def market_day_discount_percent(self) -> int:
        if self.todays_festival():
            return 15
        if self.state.weekday in ["Wednesday", "Saturday"]:
            return 10
        if int(self.state.day) in [1, 15]:
            return 8
        return 0

    def market_day_sample_key(self) -> str:
        return f"{self.market_day_key()}:market_day_sample"

    def market_day_sample_claimed(self) -> bool:
        counts = self.state.market_purchase_counts if isinstance(self.state.market_purchase_counts, dict) else {}
        return int(counts.get(self.market_day_sample_key(), 0) or 0) > 0

    def market_day_sample_reward(self) -> Dict[str, object]:
        festival = self.todays_festival()
        if festival:
            festival_id = str(festival.get("id", ""))
            table = {
                "spring_seed_fair": {"items": {"Mixed Seeds": 3}, "stamina": 4},
                "summer_river_picnic": {"items": {"Berries": 2}, "stamina": 8},
                "fall_harvest_market": {"items": {"Honey": 1}, "stamina": 5},
                "winter_lantern_night": {"items": {"Cave Herbs": 1}, "stamina": 6},
            }
            return dict(table.get(festival_id, {"items": {"Field Snack": 1}, "stamina": 5}))
        season_table = {
            "Spring": {"items": {"Mixed Seeds": 2}, "stamina": 4},
            "Summer": {"items": {"Berries": 2}, "stamina": 5},
            "Fall": {"items": {"Cave Mushroom": 1}, "stamina": 4},
            "Winter": {"items": {"Coal": 2}, "stamina": 4},
        }
        return dict(season_table.get(self.state.season, {"items": {"Field Snack": 1}, "stamina": 4}))

    def market_day_sample_lines(self) -> List[str]:
        label = self.today_market_day_label()
        reward = self.market_day_sample_reward()
        status = "claimed today" if self.market_day_sample_claimed() else "available today"
        return [
            "MARKET DAY SAMPLE",
            "",
            label or "No market day sample is available today.",
            "",
            f"Status: {status}",
            "",
            "Sample reward:",
            *self.festival_reward_lines(reward),
            "",
            "Market samples are small once-per-day bonuses for checking the town calendar and visiting Market Row on busier days.",
        ]

    def claim_market_day_sample(self) -> bool:
        if not self.today_market_day_label():
            self.vertical_panel_view("Market Day Sample", self.market_day_sample_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            self.set_message("Market day samples are only available on market days or festivals.")
            return False
        if self.market_day_sample_claimed():
            self.vertical_panel_view("Market Day Sample", self.market_day_sample_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            self.set_message("You already claimed today's market sample.")
            return False
        if not isinstance(self.state.market_purchase_counts, dict):
            self.state.market_purchase_counts = {}
        reward = self.market_day_sample_reward()
        self.apply_festival_reward(reward)
        self.adjust_town_npc_relationship("vera_vendor", 1)
        self.state.market_purchase_counts[self.market_day_sample_key()] = 1
        self.advance_time(10)
        self.vertical_panel_view("Market Day Sample", self.market_day_sample_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        self.autosave_with_message("Collected today's Market Row sample.")
        return True

    def market_stock_entry(self, item: str, price: int, limit: int, tag: str, note: str = "") -> Dict[str, object]:
        return {"item": item, "price": int(price), "limit": int(limit), "tag": tag, "note": note}

    def today_market_stock(self) -> List[Dict[str, object]]:
        season = self.state.season
        weekday = self.state.weekday
        weather = self.state.weather
        vera_rel = self.vera_friendship()
        stock: List[Dict[str, object]] = []

        # Reliable basics, but still limited per day.
        stock.extend([
            self.market_stock_entry("Wildflower", 25, 3, "Daily", "A simple gift item."),
            self.market_stock_entry("Berries", 35, 3, "Daily", "A common snack and gift."),
            self.market_stock_entry("Watercress", 40, 2, "Daily", "Useful forage from damp places."),
        ])

        seasonal = {
            "Spring": [
                self.market_stock_entry("Turnip Seeds", 45, 4, "Spring", "Spring seed special."),
                self.market_stock_entry("Carrot Seeds", 60, 3, "Spring", "Spring crop stock."),
                self.market_stock_entry("Wildflower", 20, 2, "Spring", "Extra spring flowers."),
            ],
            "Summer": [
                self.market_stock_entry("Tomato Seeds", 75, 3, "Summer", "Summer seed special."),
                self.market_stock_entry("Corn Seeds", 85, 3, "Summer", "Summer crop stock."),
                self.market_stock_entry("Sunfish", 90, 1, "Summer", "Warm-weather fish."),
            ],
            "Fall": [
                self.market_stock_entry("Cave Mushroom", 55, 3, "Autumn", "Autumn forage stock."),
                self.market_stock_entry("Maple", 70, 2, "Autumn", "Seasonal tree goods."),
                self.market_stock_entry("Honey", 90, 2, "Autumn", "Autumn market sweet."),
            ],
            "Winter": [
                self.market_stock_entry("Cave Herbs", 65, 3, "Winter", "Winter remedies."),
                self.market_stock_entry("Coal", 55, 3, "Winter", "Warmth and crafting."),
                self.market_stock_entry("Animal Medicine", 120, 1, "Winter", "Winter care stock."),
            ],
        }
        stock.extend(seasonal.get(season, []))

        weekday_stock = {
            "Monday": [self.market_stock_entry("Wood", 50, 5, "Monday", "Building material bundle.")],
            "Tuesday": [self.market_stock_entry("Stone", 35, 8, "Tuesday", "Basic stone bundle.")],
            "Wednesday": [self.market_stock_entry("Soft Fiber", 110, 2, "Wednesday", "Crafting and gift material.")],
            "Thursday": [self.market_stock_entry("Ore", 90, 3, "Thursday", "Mining goods shipment.")],
            "Friday": [self.market_stock_entry("Honey", 80, 2, "Friday", "Market discount sweet.")],
            "Saturday": [self.market_stock_entry("Woodland Salad", 140, 1, "Saturday", "Prepared meal.")],
            "Sunday": [self.market_stock_entry("Cave Mushroom", 50, 2, "Sunday", "Weekend forage special.")],
        }
        stock.extend(weekday_stock.get(weekday, []))

        if self.today_market_day_label():
            stock.extend([
                self.market_stock_entry("Mixed Seeds", 22, 5, "Market Day", "Busy-day seed packets."),
                self.market_stock_entry("Field Snack", 35, 2, "Market Day", "Sample-table trail food."),
                self.market_stock_entry("Basic Fertilizer", 20, 4, "Market Day", "Small farm supply bags."),
            ])

        combat_contract = self.seasonal_combat_contract_label_for_date(self.state.month, self.state.day, self.state.year)
        mine_hazard = self.mine_hazard_label_for_date(self.state.month, self.state.day, self.state.year)
        if combat_contract or mine_hazard:
            stock.extend([
                self.market_stock_entry("Field Snack", 30, 3, "Combat Prep", "Quick food for mine contracts."),
                self.market_stock_entry("Honey", 75, 2, "Combat Prep", "Focus recovery for tactical fights."),
                self.market_stock_entry("Cave Herbs", 50, 2, "Combat Prep", "Useful before poison or hazard days."),
            ])

        if weather in ["Rain", "Rainy", "Storm", "Stormy"]:
            stock.extend([
                self.market_stock_entry("Cave Herbs", 55, 2, "Rain", "Rainy-day remedy discount."),
                self.market_stock_entry("River Chub", 100, 1, "Rain", "Fish bite better in bad weather."),
            ])
        elif weather in ["Snow", "Snowy", "Blizzard"]:
            stock.extend([
                self.market_stock_entry("Coal", 45, 4, "Snow", "Snow-day warmth stock."),
                self.market_stock_entry("Animal Medicine", 100, 1, "Snow", "Cold weather animal care."),
            ])

        if self.has_town_project("market_charter"):
            stock.extend([
                self.market_stock_entry("Berries", 25, 3, "Market Charter", "Town-funded fresh stock."),
                self.market_stock_entry("Honey", 65, 2, "Market Charter", "Better stall storage keeps this affordable."),
                self.market_stock_entry("Cave Herbs", 50, 1, "Market Charter", "A licensed specialty stall item."),
            ])

        festival = self.todays_festival()
        if festival:
            fid = str(festival.get("id", ""))
            if fid == "spring_seed_fair":
                stock.extend([
                    self.market_stock_entry("Turnip Seeds", 30, 5, "Festival", "Spring Seed Fair discount."),
                    self.market_stock_entry("Carrot Seeds", 45, 4, "Festival", "Spring Seed Fair discount."),
                ])
            elif fid == "summer_river_picnic":
                stock.extend([
                    self.market_stock_entry("Woodland Salad", 95, 2, "Festival", "Picnic-ready meal."),
                    self.market_stock_entry("Sunfish", 70, 2, "Festival", "Summer fish stall."),
                ])
            elif fid == "fall_harvest_market":
                stock.extend([
                    self.market_stock_entry("Honey", 55, 3, "Festival", "Harvest Market sweet stock."),
                    self.market_stock_entry("Cave Mushroom", 40, 3, "Festival", "Harvest fungus stall."),
                ])
            elif fid == "winter_lantern_night":
                stock.extend([
                    self.market_stock_entry("Coal", 35, 5, "Festival", "Lantern Night warmth stock."),
                    self.market_stock_entry("Cave Herbs", 45, 3, "Festival", "Winter remedy bundle."),
                ])

        # Friendship unlocks with Vera make Market Row progressively more useful.
        if vera_rel >= 25:
            stock.append(self.market_stock_entry("Soft Fiber", 85, 2, "Vera 25", "Vera saves this for familiar customers."))
        if vera_rel >= 60:
            stock.append(self.market_stock_entry("Animal Medicine", 95, 1, "Vera 60", "A preferred-customer clinic tie-in."))
            stock.append(self.market_stock_entry("Honey", 70, 2, "Vera 60", "Vera's friend price."))
        if vera_rel >= 100:
            stock.append(self.market_stock_entry("Iron Ore", 120, 2, "Vera 100", "Rare stock for trusted friends."))
            stock.append(self.market_stock_entry("Large Bird Egg", 150, 1, "Vera 100", "Special farm goods shipment."))

        discount = self.market_day_discount_percent()
        if discount:
            for entry in stock:
                entry["price"] = max(1, int(round(int(entry["price"]) * (100 - discount) / 100)))

        # De-duplicate by item by merging limits and keeping the lowest price.
        merged: Dict[str, Dict[str, object]] = {}
        for entry in stock:
            item = str(entry["item"])
            if item not in merged:
                merged[item] = dict(entry)
            else:
                existing = merged[item]
                existing["price"] = min(int(existing["price"]), int(entry["price"]))
                existing["limit"] = int(existing["limit"]) + int(entry["limit"])
                existing["tag"] = str(existing["tag"]) + "+" + str(entry["tag"])
                if entry.get("note") and str(entry.get("note")) not in str(existing.get("note", "")):
                    existing["note"] = (str(existing.get("note", "")) + " " + str(entry.get("note"))).strip()
        return list(merged.values())

    def today_market_notice_lines(self) -> List[str]:
        lines = [
            "TODAY'S MARKET",
            "",
            f"Date: {self.state.date_label} ({self.state.weekday})",
            f"Season: {self.state.season}",
            f"Weather: {self.state.weather}",
            f"Vendor of the day: {self.daily_market_vendor_name()}",
            f"Vera friendship: {self.vera_friendship()}",
            f"Market day: {self.today_market_day_label() or 'none'}",
            f"Market discount: {self.market_day_discount_percent()}%",
            f"Daily sample: {'claimed' if self.market_day_sample_claimed() else ('available' if self.today_market_day_label() else 'none')}",
            "",
            "Stock:",
        ]
        for entry in self.today_market_stock():
            remaining = self.market_item_remaining(entry)
            lines.append(f"- {entry['item']}: ${entry['price']} | {remaining}/{entry['limit']} left | {entry['tag']}")
        lines.extend([
            "",
            "Notes:",
            "- Stock changes by season, weekday, weather, and Vera friendship.",
            "- Quantities refresh each day.",
            "- Rare goods appear at higher Vera friendship.",
            "- Market days and festivals discount stall prices and add practical farm supplies.",
        ])
        return lines

    def market_row_menu(self):
        if not self.ensure_current_town_service_unlocked():
            return
        while True:
            stock = self.today_market_stock()
            items: List[MenuItem] = []
            for entry in stock:
                item = str(entry["item"])
                price = int(entry["price"])
                remaining = self.market_item_remaining(entry)
                affordable = self.state.money >= price
                enabled = remaining > 0 and affordable
                if remaining <= 0:
                    hint = "sold out"
                elif not affordable:
                    hint = f"${price} no | {remaining} left"
                else:
                    max_qty = min(remaining, self.state.money // price)
                    hint = f"${price} x{max_qty} | {remaining} left | {entry.get('tag', '')}"
                items.append(MenuItem(label=f"Buy {item}", value=item, enabled=enabled, hint=hint))
            sample_open = bool(self.today_market_day_label()) and not self.market_day_sample_claimed()
            items.append(MenuItem(label="Market day sample", value="sample", enabled=sample_open, hint="today only" if sample_open else "none"))
            items.append(MenuItem(label="Today's Market", value="notice", enabled=True, hint="stock rules"))
            items.append(MenuItem(label="Market gossip", value="gossip", enabled=True, hint=self.daily_market_vendor_name()))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Market Row", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Market Row closed.")
                return
            if choice.value == "notice":
                self.vertical_panel_view("Today's Market", self.today_market_notice_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "sample":
                self.claim_market_day_sample()
                return
            if choice.value == "gossip":
                self.vertical_panel_view("Market Gossip", [
                    "MARKET GOSSIP",
                    "",
                    f"{self.daily_market_vendor_name()} is drawing the most attention today.",
                    "Vera says weekday stock follows deliveries, not luck.",
                    "Basil checks produce first; Sable checks fiber; Poppy asks after eggs and milk.",
                    "Cora says rare goods arrive faster now that the market road has a clean route.",
                    "",
                    "Friendship, weather, weekdays, and seasons all affect what reaches the tables.",
                ], LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue

            item = str(choice.value)
            entry = next((e for e in stock if str(e.get("item")) == item), None)
            if not entry:
                self.set_message("That market item is not available today.")
                return
            price = int(entry["price"])
            if self.market_item_remaining(entry) <= 0:
                self.set_message(f"{item} is sold out today.")
                return
            if self.state.money < price:
                self.set_message(f"Not enough money for {item}.")
                return
            max_qty = min(self.market_item_remaining(entry), self.state.money // price)
            qty = self.vertical_quantity_select(
                "Buy Market Stock",
                item,
                price,
                max_qty=max_qty,
                start_qty=min(max_qty, 5),
                panel_width=LEFT_PANEL_WIDTH,
                panel_height=LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if qty == MENU_BACK or qty is None or int(qty) <= 0:
                continue
            qty = int(qty)
            total = qty * price
            self.state.money -= total
            self.state.inventory[item] = self.state.inventory.get(item, 0) + qty
            key = self.market_stock_key(item)
            self.state.market_purchase_counts[key] = int(self.state.market_purchase_counts.get(key, 0)) + qty
            self.autosave_with_message(f"Bought {qty} {item} at Market Row for ${total}. {self.market_item_remaining(entry)} left today.")
            return


