    def bulletin_job_day_key(self) -> str:
        return f"{self.state.year}-{self.state.month}-{self.state.day}"

    def bulletin_job_id(self, job: Dict[str, object]) -> str:
        return str(job.get("id", ""))

    def bulletin_job_templates(self) -> List[Dict[str, object]]:
        return [
            {
                "kind": "shipping",
                "title": "Shipping Request",
                "pool": [("Stone", 12), ("Wood", 10), ("Berries", 3), ("Wildflower", 3), ("Cave Herbs", 2), ("Honey", 1)],
                "reward": 180,
                "note": "The town needs goods moved through the shipping office.",
            },
            {
                "kind": "community",
                "title": "Community Supply Drive",
                "pool": [("Fiber", 6), ("Soft Fiber", 2), ("Animal Medicine", 1), ("Woodland Salad", 1), ("Coal", 3), ("Watercress", 3), ("Fish Stew", 1), ("Cave Herbs", 2), ("Berry Jam", 1), ("Mushroom Preserve", 1), ("Wildflower Honey", 1), ("Jam Toast", 1)],
                "reward": 220,
                "note": "A resident posted a supply request for the neighborhood.",
            },
            {
                "kind": "crafting",
                "title": "Workshop Order",
                "pool": [("Stone Path", 5), ("Basic Fertilizer", 3), ("Copper Bar", 1), ("Iron Bar", 1), ("Crystal Shard", 2), ("Quality Sprinkler", 1), ("Fish Stew", 1), ("Cave Herbs", 2), ("Berry Jam", 1), ("Mushroom Preserve", 1), ("Pickle Plate", 1), ("Pantry Stew", 1)],
                "reward": 320,
                "note": "A town workshop needs materials for maintenance.",
            },
        ]

    def today_bulletin_jobs(self) -> List[Dict[str, object]]:
        jobs: List[Dict[str, object]] = []
        seed_base = sum(ord(ch) for ch in f"{self.bulletin_job_day_key()}:{self.state.weather}:{self.state.weekday}")
        for idx, template in enumerate(self.bulletin_job_templates()):
            pool = template["pool"]
            item, qty = pool[(seed_base + idx * 7) % len(pool)]
            reward = int(template["reward"]) + int(qty) * 18
            if self.has_town_project("errand_bonus_fund"):
                reward += 35
            if self.todays_festival():
                reward += 50
            elif self.today_market_day_label():
                reward += 25
            if self.mine_hazard_label_for_date(self.state.month, self.state.day, self.state.year):
                reward += 45
            job_id = f"bulletin:{self.bulletin_job_day_key()}:{template['kind']}:{item}:{qty}"
            completed = job_id in set(self.state.completed_bulletin_job_ids or [])
            jobs.append({
                "id": job_id,
                "kind": template["kind"],
                "title": template["title"],
                "item": item,
                "qty": int(qty),
                "reward": int(reward),
                "friendship": 1,
                "note": template["note"],
                "completed": completed,
            })
        return jobs

    def can_complete_bulletin_job(self, job: Dict[str, object]) -> bool:
        if job.get("completed"):
            return False
        return int(self.state.inventory.get(str(job.get("item")), 0)) >= int(job.get("qty", 1))

    def complete_bulletin_job(self, job: Dict[str, object]) -> bool:
        job_id = self.bulletin_job_id(job)
        if not job_id or job_id in set(self.state.completed_bulletin_job_ids or []):
            self.set_message("That bulletin job is already complete.")
            return False
        item = str(job.get("item", ""))
        qty = int(job.get("qty", 1))
        if int(self.state.inventory.get(item, 0)) < qty:
            self.set_message(f"Bulletin job needs {qty} {item}.")
            return False
        self.state.inventory[item] = max(0, int(self.state.inventory.get(item, 0)) - qty)
        self.state.money += int(job.get("reward", 0))
        friendship = int(job.get("friendship", 0))
        for npc in self.active_town_npcs():
            self.adjust_town_npc_relationship(str(npc.get("id", "")), friendship)
        self.state.completed_bulletin_job_ids.append(job_id)
        self.autosave_with_message(f"Completed bulletin job: delivered {qty} {item}. Reward: ${job.get('reward')} and town friendship +{friendship}.")
        return True

    def bulletin_job_lines(self, job: Dict[str, object]) -> List[str]:
        status = "Complete" if job.get("completed") else ("Ready to turn in" if self.can_complete_bulletin_job(job) else "Incomplete")
        return [
            str(job.get("title", "Bulletin Job")),
            "",
            str(job.get("note", "")),
            "",
            f"Request: Bring {job.get('qty')} {job.get('item')}.",
            f"Status: {status}",
            "",
            "Reward:",
            f"- ${job.get('reward')}",
            f"- Town friendship +{job.get('friendship')}",
            "",
            "Turn in this job from the physical town bulletin board.",
        ]

    def bulletin_jobs_overview_lines(self) -> List[str]:
        lines = [
            "BULLETIN JOBS",
            "",
            f"Today: {self.state.date_label}",
            f"Weather: {self.state.weather}",
            "",
            "Posted jobs:",
        ]
        for job in self.today_bulletin_jobs():
            marker = "x" if job.get("completed") else ("!" if self.can_complete_bulletin_job(job) else " ")
            lines.append(f"{marker} {job.get('title')}: {job.get('qty')} {job.get('item')} -> ${job.get('reward')}")
        lines.extend([
            "",
            "Legend:",
            "! = ready to complete",
            "x = completed today",
            "",
            "Jobs refresh daily and reward money plus a little town-wide friendship.",
        ])
        return lines

    def bulletin_board_menu(self):
        while True:
            jobs = self.today_bulletin_jobs()
            items: List[MenuItem] = []
            for job in jobs:
                marker = "x" if job.get("completed") else ("!" if self.can_complete_bulletin_job(job) else " ")
                hint = "done" if job.get("completed") else (f"ready ${job.get('reward')}" if self.can_complete_bulletin_job(job) else f"need {job.get('qty')} {job.get('item')}")
                items.append(MenuItem(label=f"{marker} {job.get('title')}: {job.get('qty')} {job.get('item')}", value=str(job.get("id")), enabled=not bool(job.get("completed")), hint=hint))
            items.append(MenuItem(label="View posted jobs", value="jobs", enabled=True))
            items.append(MenuItem(label="Town notices", value="notices", enabled=True))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Town Bulletin Board", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed bulletin board.")
                return
            if choice.value == "jobs":
                self.vertical_panel_view("Bulletin Jobs", self.bulletin_jobs_overview_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "notices":
                self.vertical_panel_view("Town Notices", self.town_bulletin_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            job = next((j for j in jobs if str(j.get("id")) == str(choice.value)), None)
            if job:
                if self.can_complete_bulletin_job(job):
                    self.complete_bulletin_job(job)
                    return
                self.vertical_panel_view("Bulletin Job", self.bulletin_job_lines(job), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                self.set_message(f"Bulletin job needs {job.get('qty')} {job.get('item')}.")
                continue

    def read_town_bulletin(self):
        self.bulletin_board_menu()


    def rest_on_town_bench(self):
        restored = self.restore_stamina(6)
        if restored:
            self.set_message(f"You rest on the bench and recover {restored} stamina.")
        else:
            self.set_message("You rest on the bench for a quiet moment.")

    def town_landmark_message(self, tile: str) -> str:
        if tile == "!":
            return "A streetlamp. At night it helps keep the wider town readable."
        if tile == "m":
            return "A market stall. Town projects and festivals make this promenade busier."
        if tile == "$":
            return "A vendor counter for market stock and future festival traffic."
        if tile == ",":
            return "Soft park grass."
        return self.describe_tile(*self.interaction_target_pos())

    def use_town_action(self, x: int, y: int):
        npc = self.town_npc_at(x, y) if self.in_active_bounds(x, y) else None
        if npc:
            self.town_npc_menu(npc)
            return
        public_feature = self.town_public_event_feature_at(x, y)
        if public_feature:
            self.interact_town_public_event_feature(public_feature)
            return
        tile = self.active_map()[y][x] if self.in_active_bounds(x, y) else "#"
        if self.in_seed_shop(x, y): self.transition_to_general_store(); return
        if self.in_blacksmith(x, y): self.transition_to_blacksmith_interior(); return
        door_building_id = TOWN_BUILDING_ID_BY_DOOR.get((x, y), "")
        if door_building_id and not self.is_town_building_unlocked(door_building_id):
            self.set_message(self.locked_town_building_message(door_building_id))
            return
        if tile == "E": self.transition_to_farm(); return
        if tile == "W":
            self.transition_to_wilderness()
            return
        residence_id = AUTHORED_TOWN_RESIDENCE_ID_BY_DOOR.get((int(x), int(y)), "")
        if residence_id:
            self.enter_authored_town_residence(residence_id)
            return
        if tile == "D" and (x, y) in TOWN_DIRECTORY_TILES:
            self.read_town_directory()
            return
        if tile == "D":
            if (x, y) == TOWN_DOORS["library"]:
                self.transition_to_library_interior()
                return
            if (x, y) == TOWN_DOORS["mayor_house"]:
                self.transition_to_mayor_house()
                return
            if (x, y) == TOWN_DOORS["inn"]:
                self.transition_to_inn_interior()
                return
            if (x, y) == TOWN_DOORS["furniture_store"]:
                self.transition_to_furniture_store()
                return
            if (x, y) == TOWN_DOORS["carpenter"]:
                self.transition_to_carpenter_store()
                return
            if (x, y) == TOWN_DOORS["animal_store"]:
                self.transition_to_animal_store()
                return
            if (x, y) == TOWN_DOORS["clinic"]:
                self.transition_to_clinic()
                return
            if (x, y) == TOWN_DOORS["town_hall"]:
                self.transition_to_town_hall()
                return
            if (x, y) == TOWN_DOORS["market_row"]:
                self.transition_to_market_row()
                return
            if (x, y) == TOWN_DOORS["museum"]:
                self.transition_to_museum()
                return
            self.set_message("The door is locked for now. This building interior is not implemented yet.")
            return
        if tile == "Q":
            building_id = self.town_building_id_at(x, y)
            self.set_message(self.locked_town_building_message(building_id) if building_id else "This entrance is boarded up for future restoration.")
            return
        if tile == "?": self.read_town_sign(x, y); return
        if tile == "B": self.read_town_bulletin(); return
        if tile == "N":
            self.town_notice_board_menu()
            return
        if tile == "h":
            residence_id = next(
                (
                    key for key, residence in AUTHORED_TOWN_RESIDENCE_DATA.items()
                    if abs(int(residence["door"][0]) - int(x)) <= 5
                    and int(residence["door"][1]) - 5 <= int(y) <= int(residence["door"][1])
                ),
                "",
            )
            residence = AUTHORED_TOWN_RESIDENCE_DATA.get(residence_id, {})
            residents = [
                self.town_npc_definition(npc_id).get("name", npc_id)
                for npc_id in residence.get("residents", ())
            ]
            self.set_message(
                f"{residence.get('label', 'Town residence')}: {residence.get('style', 'private home')}. "
                f"Residents: {', '.join(str(name) for name in residents)}."
            )
            return
        if tile in ["G", "X", "L", "M", "I", "Y", "C", "A", "H", "R", "P", "U"]:
            building_id = self.town_building_id_at(x, y)
            self.set_message(self.town_building_exterior_message(building_id) if building_id else self.describe_tile(x, y))
            return
        if tile == "F": self.set_message("The fountain burbles peacefully."); return
        if tile == "b": self.rest_on_town_bench(); return
        if tile in ["!", "m", "$", ","]:
            self.set_message(self.town_landmark_message(tile))
            return
        self.set_message(self.describe_tile(x, y))

    def use_fertilizer(self, x: int, y: int):
        if not self.on_farm_work_land():
            self.set_message("Fertilizer can only be used on owned farm land.")
            return
        item_name = "Basic Fertilizer"
        if self.state.inventory.get(item_name, 0) <= 0:
            self.set_message("You do not have any Basic Fertilizer.")
            return

        crop = self.get_crop(x, y)
        tile = self.active_farm_work_map()[y][x]

        if crop:
            if crop.fertilized:
                self.set_message(f"{crop.name} is already fertilized.")
                return
            crop.fertilized = True
            self.state.inventory[item_name] -= 1
            self.autosave_with_message(f"Applied Basic Fertilizer to {crop.name}.")
            return

        if tile in [",", "w"]:
            if self.is_tile_fertilized(x, y):
                self.set_message("This soil is already fertilized.")
                return
            self.set_tile_fertilized(x, y, True)
            self.state.inventory[item_name] -= 1
            self.autosave_with_message("Applied Basic Fertilizer to the soil.")
            return

        self.set_message("Fertilizer needs tilled soil or a growing crop.")

    def water_tile_at(self, x: int, y: int) -> bool:
        if not self.in_active_bounds(x, y):
            if self.on_wilderness():
                chunk_x, chunk_y, local_x, local_y = self.wilderness_stream_resolve(x, y)
                return self.wilderness_stream_preview_tile(chunk_x, chunk_y, local_x, local_y) == "~"
            return False
        return self.active_map()[y][x] == "~"

    def fishing_location_name(self) -> Optional[str]:
        if self.on_farm():
            return "Farm"
        if self.on_wilderness():
            profile = self.wilderness_region_profile(
                self.state.wilderness_chunk_x,
                self.state.wilderness_chunk_y,
            )
            if profile.get("biome") == "[":
                return "Coast"
            return "Wilderness"
        if self.on_mine():
            return "Mine"
        return None

    def fish_matches_conditions(self, fish_name: str, data: Dict[str, object]) -> bool:
        location = self.fishing_location_name()
        if location is None:
            return False
        if location not in data.get("locations", []):
            return False
        if self.state.season not in data.get("seasons", []):
            return False
        weather_rules = data.get("weather", ["Any"])
        if "Any" not in weather_rules and self.state.weather not in weather_rules:
            return False
        time_rule = data.get("time", "Any")
        if time_rule != "Any" and fishing_time_bucket(self.state.hour) != time_rule:
            return False
        return True

    def wilderness_coastal_fishing_habitat(
        self,
        x: Optional[int] = None,
        y: Optional[int] = None,
    ) -> str:
        if not self.on_wilderness() or self.fishing_location_name() != "Coast":
            return ""
        local_x = int(self.state.player_x if x is None else x)
        local_y = int(self.state.player_y if y is None else y)
        chunk_x, chunk_y = int(self.state.wilderness_chunk_x), int(self.state.wilderness_chunk_y)
        if not self.in_active_bounds(local_x, local_y):
            chunk_x, chunk_y, local_x, local_y = self.wilderness_stream_resolve(local_x, local_y)
        wx, wy = self.wilderness_world_coords(chunk_x, chunk_y, local_x, local_y)
        if self.wilderness_world_reef_at(wx, wy):
            return "Reef"
        current = self.wilderness_world_current(wx, wy)
        if int(current.get("strength", 0)) >= 2:
            return "Current"
        return "Open Coast"

    def available_fish_here(
        self,
        target_x: Optional[int] = None,
        target_y: Optional[int] = None,
    ) -> List[str]:
        weighted: List[str] = []
        for fish_name, data in FISH_DATA.items():
            if self.fish_matches_conditions(fish_name, data):
                weighted.extend([fish_name] * int(data.get("weight", 1)))
        if self.fishing_location_name() == "Coast":
            habitat = self.wilderness_coastal_fishing_habitat(target_x, target_y)
            tropical = {
                "Coral Dart", "Parrotfish", "Reef Grouper", "Lantern Angelfish",
            }
            if habitat != "Reef":
                weighted = [fish_name for fish_name in weighted if fish_name not in tropical]
            else:
                weighted.extend(["Coral Dart"] * 8)
                weighted.extend(["Parrotfish"] * 5)
                weighted.extend(["Reef Grouper"] * 3)
                if fishing_time_bucket(self.state.hour) == "Night":
                    weighted.extend(["Lantern Angelfish"] * 4)
            if habitat == "Current":
                weighted.extend(["Mackerel"] * 5)
                weighted.extend(["Sunfin Tuna"] * 4)
            elif habitat != "Reef":
                weighted = [fish_name for fish_name in weighted if fish_name != "Sunfin Tuna"]
        if self.on_mine() and self.state.mine_floor == 10:
            weighted.extend(["Cave Carp"] * 4)
            weighted.extend(["Blind Minnow"] * 3)
            weighted.extend(["Crystal Eel"] * 2)
            weighted.extend(["Pale Koi"] * 2)
        if not weighted:
            weighted = ["Old Boot"]
        return weighted

    def fishing_power(self) -> int:
        # Hook for future rod upgrades; keep simple for now.
        return 1

    def clear_fishing_state(self):
        self.state.fishing_active = False
        self.state.fishing_target_x = 0
        self.state.fishing_target_y = 0
        self.state.fishing_elapsed = 0.0
        self.state.fishing_bite_at = 0.0
        self.state.fishing_end_at = 0.0
        self.state.fishing_will_bite = True
        self.state.fishing_pool = []

    def fishing_phase(self) -> str:
        if not self.state.fishing_active:
            return "none"
        if not self.state.fishing_will_bite:
            return "waiting" if self.state.fishing_elapsed < self.state.fishing_bite_at else "no_bite"
        if self.state.fishing_elapsed < max(0.0, self.state.fishing_bite_at - 1.0):
            return "waiting"
        if self.state.fishing_elapsed < self.state.fishing_bite_at:
            return "nibble"
        if self.state.fishing_elapsed <= self.state.fishing_end_at:
            return "bite"
        return "escaped"

    def fishing_status_text(self) -> str:
        phase = self.fishing_phase()
        if phase == "waiting":
            return "Fishing: bobber floating..."
        if phase == "nibble":
            return "Fishing: nibble... wait for it..."
        if phase == "bite":
            return "Fishing: BOBBER UNDER! Press F now!"
        if phase == "no_bite":
            return "Fishing: nothing bit."
        if phase == "escaped":
            return "Fishing: the fish got away."
        return ""

    def fishing_tick(self, elapsed_seconds: float):
        if not self.state.fishing_active:
            return
        self.state.fishing_elapsed += max(0.0, elapsed_seconds)
        phase = self.fishing_phase()
        if phase == "no_bite":
            self.advance_time(8)
            self.clear_fishing_state()
            self.autosave_with_message("The bobber floated quietly. Nothing bit.")
        elif phase == "escaped":
            self.advance_time(10)
            self.clear_fishing_state()
            self.autosave_with_message("The bobber went under, but you reacted too late. The fish got away.")

    def start_fishing_cast(self, x: int, y: int):
        if not (self.on_farm() or self.on_wilderness() or self.on_mine()):
            self.set_message("You need open water to fish.")
            return
        if not self.water_tile_at(x, y):
            self.set_message("Cast the Fishing Rod into water.")
            return
        if self.on_wilderness() and self.in_active_bounds(x, y) and self.active_map()[y][x] == "~" and self.wilderness_water_is_frozen_at(x, y):
            self.set_message("The freshwater is frozen solid. Coastal water remains fishable in winter.")
            return
        if self.on_farm() and self.in_active_bounds(x, y) and self.active_map()[y][x] == "~" and self.state.season == "Winter":
            self.set_message("The farm pond is frozen solid. It will be fishable again after the spring thaw.")
            return
        if self.state.fishing_active:
            self.set_message("You already have a line in the water. Press F when the bobber goes under.")
            return
        if not self.spend_stamina(4):
            return

        pool = self.available_fish_here(x, y)
        seed = (
            int(self.state.wilderness_seed)
            + self.state.year * 1000000
            + self.state.month * 10000
            + self.state.day * 100
            + self.state.hour * 7
            + self.state.minute
            + x * 31
            + y * 17
            + len(str(self.state.inventory))
        )
        rng = random.Random(seed)

        bite_chance = 0.76
        if self.state.weather in ["Rain", "Rainy", "Storm", "Stormy"]:
            bite_chance += 0.10
        if self.state.weather in ["Snow", "Snowy", "Blizzard"]:
            bite_chance -= 0.05

        wait_time = rng.uniform(2.0, 5.5)
        bite_window = 1.35
        if self.state.weather in ["Rain", "Rainy", "Storm", "Stormy"]:
            wait_time = max(1.5, wait_time - 0.5)

        self.state.fishing_active = True
        self.state.fishing_target_x = x
        self.state.fishing_target_y = y
        self.state.fishing_elapsed = 0.0
        self.state.fishing_bite_at = wait_time
        self.state.fishing_end_at = wait_time + bite_window
        self.state.fishing_will_bite = rng.random() <= bite_chance
        self.state.fishing_pool = list(pool)

        self.set_message("You cast your line. Wait for the bobber to go under, then press F.")

    def reel_fishing_line(self):
        if not self.state.fishing_active:
            return False

        phase = self.fishing_phase()
        if phase in ["waiting", "nibble"]:
            self.advance_time(5)
            self.clear_fishing_state()
            self.autosave_with_message("You reeled in too early. The fish scattered.")
            return True
        if phase == "no_bite":
            self.advance_time(8)
            self.clear_fishing_state()
            self.autosave_with_message("You reeled in, but nothing was there.")
            return True
        if phase == "escaped":
            self.advance_time(10)
            self.clear_fishing_state()
            self.autosave_with_message("You reeled in too late. The fish got away.")
            return True
        if phase == "bite":
            pool = self.state.fishing_pool or self.available_fish_here()
            seed = (
                int(self.state.wilderness_seed)
                + self.state.year * 1000000
                + self.state.month * 10000
                + self.state.day * 100
                + self.state.hour * 17
                + self.state.minute * 3
                + self.state.fishing_target_x * 43
                + self.state.fishing_target_y * 19
                + len(str(self.state.inventory))
            )
            rng = random.Random(seed)
            fish_name = rng.choice(pool)
            self.state.inventory[fish_name] = self.state.inventory.get(fish_name, 0) + 1
            self.advance_time(10)
            self.clear_fishing_state()
            price = fish_sell_price(fish_name)
            if fish_name == "Old Boot":
                self.autosave_with_message("You reeled in an Old Boot. Not exactly dinner.")
            else:
                self.autosave_with_message(f"You reeled in {fish_name}! It can sell for ${price} or be cooked/eaten.")
            return True
        return False

    def use_fishing_rod(self, x: int, y: int):
        if self.state.fishing_active:
            self.reel_fishing_line()
            return
        self.start_fishing_cast(x, y)

    def use_wilderness_cave_tool(self):
        """Use F-selected tools inside wilderness caves."""
        x, y = self.target_tile_pos()
        if not self.in_active_bounds(x, y):
            self.set_message("There is nothing to use the tool on.")
            return
        tile = self.active_map()[y][x]
        tool = self.state.selected_tool
        if tool == "Pickaxe":
            if not self.owns_tool("Pickaxe"):
                self.set_message("You need to buy a Pickaxe before mining cave rocks.")
                return
            if tile in ["o", "q", "c", "i", "g", "A", "C", "d"]:
                if not self.spend_stamina(5 if self.tool_level("Pickaxe") <= 1 else 3):
                    return
                self.active_map()[y][x] = "."
                if tile == "q":
                    drops = {"Coal": 1}
                    if random.random() < 0.25:
                        drops["Stone"] = 1
                elif tile == "c":
                    drops = {"Copper Ore": random.randint(1, 2)}
                elif tile == "i":
                    drops = {"Iron Ore": 1}
                    if random.random() < 0.20:
                        drops["Coal"] = 1
                elif tile == "g":
                    drops = {"Gold Ore": 1}
                elif tile == "A":
                    drops = {"Amethyst": 1}
                    if random.random() < 0.20:
                        drops["Crystal Shard"] = 1
                elif tile == "C":
                    drops = {"Crystal Shard": random.randint(1, 2)}
                    if random.random() < 0.25:
                        drops["Quartz"] = 1
                elif tile == "d":
                    drops = {"Clay": random.randint(1, 3)}
                else:
                    drops = roll_stone_drops(1, self.tool_level("Pickaxe"))
                add_inventory_items(self.state.inventory, drops)
                self.autosave_with_message(f"Mined cave node and found {format_drops(drops)}.")
                return
            self.set_message("Use the Pickaxe on cave rocks, ore, coal, clay, or crystals.")
            return
        if tool == "Fishing Rod":
            self.set_message("There is nowhere to fish in this cave.")
            return
        self.set_message("That tool is not useful in this cave. Use Z/Enter for mushrooms or the exit.")

    def use_wilderness_tool(self):
        """Use F-selected tools in the wilderness, matching farm controls."""
        if self.state.fishing_active:
            self.reel_fishing_line()
            return
        x, y = self.target_tile_pos()
        if not self.in_active_bounds(x, y):
            chunk_x, chunk_y, local_x, local_y = self.wilderness_stream_resolve(x, y)
            dx = int(chunk_x) - int(self.state.wilderness_chunk_x)
            dy = int(chunk_y) - int(self.state.wilderness_chunk_y)
            if abs(dx) + abs(dy) != 1:
                self.set_message("There is nothing to use the tool on.")
                return
            if not self.transition_wilderness_chunk(dx, dy, interaction_target=True):
                return
            x, y = local_x, local_y

        tool = self.state.selected_tool
        tile = self.active_map()[y][x]

        if tool == "Fishing Rod":
            self.use_fishing_rod(x, y)
            return
        if tool == "Axe":
            if tile in ["T", "*"]:
                self.chop_wilderness_wood(x, y)
            else:
                self.set_message("Use the Axe on wilderness trees or fallen logs.")
            return
        if tool == "Pickaxe":
            if tile == "o":
                self.break_wilderness_stone(x, y)
            elif tile == "M":
                self.mine_wilderness_mineral_outcrop(x, y)
            else:
                self.set_message("Use the Pickaxe on wilderness rocks or mineral outcrops.")
            return
        if tool == "Hoe":
            if tile == "^":
                self.clear_wilderness_weeds(x, y)
            else:
                self.set_message("Use the Hoe on wild grass, or Z/Enter to gather forage.")
            return

        self.set_message("That tool is not useful in the wilderness. Use Z/Enter for forage and landmarks.")

    def use_tool(self):
        if self.state.fishing_active:
            self.reel_fishing_line()
            return
        if self.on_mine():
            if self.state.selected_tool == "Fishing Rod":
                self.use_selected_tool_direct()
            else:
                self.use_mine_tool()
            return
        if self.on_wilderness():
            if self.on_owned_wilderness_claim() and self.state.selected_tool in ["Hoe", "Seeds", "Watering Can", "Fertilizer"]:
                self.use_selected_tool_direct()
            else:
                self.use_wilderness_tool()
            return
        if self.on_wilderness_cave():
            self.use_wilderness_cave_tool()
            return
        if self.on_wilderness_dungeon():
            self.use_wilderness_dungeon_tool()
            return
        self.use_selected_tool_direct()

    def use_selected_tool_direct(self):
        """
        Use the selected tool/action on the current target tile.
        Targeting can be toggled between front-tile and standing-tile modes.
        Standing-based interactions like shop, bin, and sleep remain separate.
        """
        s = self.state
        x, y = self.target_tile_pos()

        if not self.in_active_bounds(x, y):
            if self.on_wilderness():
                chunk_x, chunk_y, local_x, local_y = self.wilderness_stream_resolve(x, y)
                dx = int(chunk_x) - int(self.state.wilderness_chunk_x)
                dy = int(chunk_y) - int(self.state.wilderness_chunk_y)
                if abs(dx) + abs(dy) == 1:
                    if not self.transition_wilderness_chunk(dx, dy, interaction_target=True):
                        return
                    x, y = local_x, local_y
                else:
                    self.set_message("There is nothing to use the tool on.")
                    return
            else:
                self.set_message("There is nothing to use the tool on.")
                return

        tool = s.selected_tool

        if tool == "Hoe":
            if self.on_owned_wilderness_claim() and self.active_map()[y][x] == "^":
                self.clear_wilderness_weeds(x, y)
            else:
                self.use_hoe(x, y)
        elif tool == "Seeds":
            self.use_seeds(x, y)
        elif tool == "Watering Can":
            self.use_watering_can(x, y)
        elif tool == "Fertilizer":
            self.use_fertilizer(x, y)
        elif tool == "Fishing Rod":
            self.use_fishing_rod(x, y)
        elif tool == "Axe":
            land_map = self.active_farm_work_map() if self.on_farm_work_land() else self.active_map()
            if self.on_owned_wilderness_claim() and land_map[y][x] in ["T", "*"]:
                self.chop_wilderness_wood(x, y)
            elif self.on_farm_work_land() and land_map[y][x] == "*":
                self.use_weeds(x, y)
            else:
                self.set_message("Use the Axe on wood/stumps, or use Z/Enter to clear debris contextually.")
        elif tool == "Pickaxe":
            land_map = self.active_farm_work_map() if self.on_farm_work_land() else self.active_map()
            if self.on_owned_wilderness_claim() and land_map[y][x] == "M":
                self.mine_wilderness_mineral_outcrop(x, y)
            elif self.on_farm_work_land() and land_map[y][x] == "o":
                self.use_weeds(x, y)
            else:
                self.set_message("Use the Pickaxe on stones, or use Z/Enter to clear debris contextually.")

    def context_action_menu(self):
        s = self.state
        x, y = s.player_x, s.player_y
        tile_map = self.active_farm_work_map() if self.on_farm_work_land() else self.active_map()
        tile = tile_map[y][x] if self.in_active_bounds(x, y) else "#"
        crop = self.get_crop(x, y)

        items: List[MenuItem] = []

        # Context-first actions.
        if self.in_seed_shop(x, y):
            items.append(MenuItem(label="Open general store", value="shop", enabled=True))

        if self.on_shipping_bin(x, y):
            items.append(MenuItem(label="Open shipping bin", value="bin", enabled=True))

        if self.in_farmhouse(x, y):
            items.append(MenuItem(label="Sleep until tomorrow", value="sleep", enabled=True, hint="restore stamina"))

        if crop:
            if crop.ready:
                items.append(MenuItem(label=f"Harvest {crop.name}", value="harvest", enabled=True))
            else:
                items.append(MenuItem(label=f"Water {crop.name}", value="water", enabled=not crop.watered, hint="already watered" if crop.watered else ""))
        else:
            if tile == ".":
                items.append(MenuItem(label="Till soil", value="hoe", enabled=True))
            elif tile in [",", "w"]:
                seed_item = f"{s.selected_seed} Seeds"
                has_seed = s.inventory.get(seed_item, 0) > 0
                items.append(MenuItem(
                    label=f"Plant {s.selected_seed}",
                    value="plant",
                    enabled=has_seed,
                    hint=f"{seed_item} x{s.inventory.get(seed_item, 0)}" if has_seed else "no selected seeds",
                ))
                items.append(MenuItem(label="Water soil", value="water", enabled=(tile != "w"), hint="already wet" if tile == "w" else ""))
            elif tile == "^":
                items.append(MenuItem(label="Pull weeds", value="weeds", enabled=True))
            elif tile == "o":
                items.append(MenuItem(
                    label="Break stone",
                    value="weeds",
                    enabled=self.owns_tool("Pickaxe"),
                    hint="requires Pickaxe" if not self.owns_tool("Pickaxe") else "",
                ))
            elif tile == "*":
                items.append(MenuItem(
                    label="Chop fallen wood/stump",
                    value="weeds",
                    enabled=self.owns_tool("Axe"),
                    hint="requires Axe" if not self.owns_tool("Axe") else "",
                ))

        # General submenu actions.
        items.append(MenuItem(label=f"Use selected tool: {s.selected_tool}", value="selected_tool", enabled=True))
        items.append(MenuItem(label="Open inventory", value="inventory", enabled=True))
        items.append(MenuItem(label="Cycle tool", value="cycle_tool", enabled=True, hint=f"currently {s.selected_tool}"))
        items.append(MenuItem(label="Close", value=None, enabled=True))

        choice = compact_menu_select(
            self,
            "Action Menu",
            items,
            footer="Arrow keys/WASD move | Z/Enter choose | X/Esc/Q close",
        )

        if choice is None or choice.value is None:
            self.set_message("Closed action menu.")
            return

        action = choice.value
        if action == "shop":
            self.buy_menu(auto_opened=False)
        elif action == "bin":
            self.shipping_menu(auto_opened=False)
        elif action == "sleep":
            self.sleep()
        elif action == "harvest":
            self.use_harvest(x, y)
        elif action == "water":
            self.use_watering_can(x, y)
        elif action == "hoe":
            self.use_hoe(x, y)
        elif action == "plant":
            self.use_seeds(x, y)
        elif action == "weeds":
            self.use_weeds(x, y)
        elif action == "selected_tool":
            self.use_selected_tool_direct()
        elif action == "inventory":
            self.show_inventory()
        elif action == "cycle_tool":
            self.cycle_tool(1)
        else:
            self.set_message("Nothing happened.")

    def use_hoe(self, x: int, y: int):
        if not self.on_farm_work_land():
            self.set_message("Hoeing needs owned farm land.")
            return
        land_map = self.active_farm_work_map()
        tiles = self.tool_effect_tiles("Hoe", x, y)
        tilled = 0
        blocked = 0
        for tx, ty in tiles:
            if self.get_placed_object(tx, ty) or self.get_crop(tx, ty):
                blocked += 1
                continue
            tile = land_map[ty][tx]
            tillable = tile == "." or (self.on_owned_wilderness_claim() and tile in WILDERNESS_BIOME_TILES)
            if tillable:
                land_map[ty][tx] = ","
                tilled += 1
            else:
                blocked += 1

        if tilled <= 0:
            self.set_message("Hoe needs clear grass on the target tile/area.")
            return

        stamina_cost = max(1, tilled * (2 if self.tool_level("Hoe") >= 2 else 3))
        if not self.spend_stamina(stamina_cost):
            # Revert if stamina failed.
            for tx, ty in tiles:
                if land_map[ty][tx] == "," and tilled > 0:
                    # Conservative: do not try to identify preexisting tilled soil here.
                    pass
            return

        extra = f" Skipped {blocked} blocked tile(s)." if blocked else ""
        self.set_message(f"Tilled {tilled} tile(s).{extra}")


    def use_seeds(self, x: int, y: int):
        if not self.on_farm_work_land():
            self.set_message("Seeds need owned farm land.")
            return
        s = self.state
        if not s.selected_seed or s.selected_seed not in CROP_DATA:
            self.set_message("Select a seed from inventory first.")
            return
        seed_item = self.seed_item_for_crop(s.selected_seed)
        land_map = self.active_farm_work_map()
        tile = land_map[y][x]
        if tile not in [",", "w"]:
            self.set_message("Seeds need empty tilled soil on the target tile.")
            return
        if self.get_placed_object(x, y):
            self.set_message("There is infrastructure built there.")
            return
        if self.get_crop(x, y):
            self.set_message("There is already something growing here.")
            return
        if s.inventory.get(seed_item, 0) <= 0:
            self.set_message(f"You don't have any {seed_item}.")
            return
        if not self.crop_can_grow_now(s.selected_seed):
            self.set_message(f"{s.selected_seed} does not grow in {s.season}.")
            return
        if not self.spend_stamina(1):
            return
        s.inventory[seed_item] -= 1
        crop = Crop(name=s.selected_seed, watered=(tile == "w"))
        self.set_crop(x, y, crop)
        self.set_message(f"You planted {s.selected_seed}.")


    def use_watering_can(self, x: int, y: int):
        if not self.on_farm_work_land():
            self.set_message("Watering crops needs owned farm land.")
            return
        land_map = self.active_farm_work_map()
        tiles = self.tool_effect_tiles("Watering Can", x, y)
        watered = 0
        skipped = 0
        for tx, ty in tiles:
            tile = land_map[ty][tx]
            crop = self.get_crop(tx, ty)
            if tile in [",", "w"] or crop:
                if tile == ",":
                    land_map[ty][tx] = "w"
                if crop:
                    crop.watered = True
                watered += 1
            else:
                skipped += 1

        if watered <= 0:
            self.set_message("Nothing in the target area needs watering.")
            return

        stamina_cost = max(1, watered * (1 if self.tool_level("Watering Can") >= 2 else 2))
        if not self.spend_stamina(stamina_cost):
            return

        extra = f" Skipped {skipped} tile(s)." if skipped else ""
        self.set_message(f"Watered {watered} tile(s).{extra}")


    def use_harvest(self, x: int, y: int):
        if not self.on_farm_work_land():
            self.set_message("Harvesting needs owned farm land.")
            return
        crop = self.get_crop(x, y)
        if not crop:
            self.set_message("There is no crop on the target tile to harvest.")
            return
        if not crop.ready:
            self.set_message(f"The {crop.name} is not ready yet.")
            return
        if not self.spend_stamina(2):
            return
        quality = crop.projected_quality()
        item_name = quality_item_name(crop.name, quality)
        harvest_qty = 1
        work_record = self.home_region_work_record()
        if (
            str(work_record.get("crop_bonus_day", "")) == self.town_npc_day_key()
            and not bool(work_record.get("crop_bonus_used", False))
        ):
            harvest_qty += 1
            work_record["crop_bonus_used"] = True
        self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + harvest_qty
        self.remove_crop(x, y)
        self.active_farm_work_map()[y][x] = ","
        bonus_text = " Rowan's field review produced one extra." if harvest_qty > 1 else ""
        if quality == "Normal":
            self.set_message(f"You harvested {harvest_qty} {crop.name}.{bonus_text}")
        else:
            self.set_message(f"You harvested {harvest_qty} {quality} {crop.name}.{bonus_text}")

    def owns_tool(self, tool_name: str) -> bool:
        return self.tool_level(tool_name) > 0

    def use_weeds(self, x: int, y: int):
        """Clear weeds by hand; use Axe/Pickaxe levels for hard debris and collect resources."""
        if not self.on_farm_work_land():
            self.set_message("Clearing farm debris needs owned farm land.")
            return
        land_map = self.active_farm_work_map()
        tile = land_map[y][x]

        if tile == "^":
            if not self.spend_stamina(2):
                return
            land_map[y][x] = "."
            drops = roll_weed_drops(1)
            add_inventory_items(self.state.inventory, drops)
            self.set_message(f"Pulled weeds and found {format_drops(drops)}.")
            return

        if tile == "o":
            if not self.owns_tool("Pickaxe"):
                self.set_message("You need to buy a Pickaxe before you can break stones.")
                return
            tiles = self.tool_effect_tiles("Pickaxe", x, y)
            broken = 0
            for tx, ty in tiles:
                if land_map[ty][tx] == "o":
                    land_map[ty][tx] = "."
                    broken += 1
            if broken <= 0:
                self.set_message("No stones in range.")
                return
            stamina_cost = max(1, broken * (3 if self.tool_level("Pickaxe") >= 2 else 6))
            if not self.spend_stamina(stamina_cost):
                return
            drops = roll_stone_drops(broken, self.tool_level("Pickaxe"))
            add_inventory_items(self.state.inventory, drops)
            self.set_message(f"Broke {broken} stone(s) and found {format_drops(drops)}.")
            return

        if tile == "*":
            if not self.owns_tool("Axe"):
                self.set_message("You need to buy an Axe before you can chop fallen wood/stumps.")
                return
            tiles = self.tool_effect_tiles("Axe", x, y)
            chopped = 0
            for tx, ty in tiles:
                if land_map[ty][tx] == "*":
                    land_map[ty][tx] = "."
                    chopped += 1
            if chopped <= 0:
                self.set_message("No wood/stumps in range.")
                return
            stamina_cost = max(1, chopped * (3 if self.tool_level("Axe") >= 2 else 6))
            if not self.spend_stamina(stamina_cost):
                return
            drops = roll_wood_drops(chopped, self.tool_level("Axe"))
            add_inventory_items(self.state.inventory, drops)
            self.set_message(f"Chopped {chopped} wood/stump tile(s) and found {format_drops(drops)}.")
            return

        self.set_message("Nothing clearable there. Stones need Pickaxe; wood/stumps need Axe.")


    def in_farmhouse(self, x: int, y: int) -> bool:
        """Farmhouse exterior footprint from make_map: x 3..8, y 2..5."""
        return self.on_farm() and 3 <= x <= 8 and 2 <= y <= 5

    def is_farmhouse_door(self, x: int, y: int) -> bool:
        return self.on_farm() and x == 5 and y == 5

    def on_general_store_counter(self, x: int, y: int) -> bool:
        return self.on_general_store() and 0 <= x < WIDTH and 0 <= y < HEIGHT and self.active_map()[y][x] == "g"

    def on_blacksmith_counter(self, x: int, y: int) -> bool:
        return self.on_blacksmith_interior() and 0 <= x < WIDTH and 0 <= y < HEIGHT and self.active_map()[y][x] == "x"
    def in_seed_shop(self, x: int, y: int) -> bool:
        """Town General Store trigger. Only the actual grid-layout door opens the shop."""
        if not self.on_town():
            return False
        return (x, y) == TOWN_DOORS["general_store"]


    def in_blacksmith(self, x: int, y: int) -> bool:
        """Town Blacksmith trigger. Only the actual grid-layout door opens the shop."""
        if not self.on_town():
            return False
        return (x, y) == TOWN_DOORS["blacksmith"]


    def on_shipping_bin(self, x: int, y: int) -> bool:
        """True when the given tile is occupied by the movable shipping bin."""
        if not self.on_farm_work_land() or not self.in_active_bounds(x, y):
            return False
        return self.get_placed_object(x, y) == "Shipping Bin" or (self.on_farm() and self.base_map[y][x] == "B")

    def near_shipping_bin(self, x: int, y: int) -> bool:
        """Backward-compatible name: true if a shipping bin can be interacted with nearby."""
        return self.shipping_bin_target() is not None

    def is_near_tile(self, x: int, y: int, targets: set[str]) -> bool:
        """True if the player is standing on or adjacent to one of the target tiles."""
        for dy in (-1, 0, 1):
            for dx in (-1, 0, 1):
                nx, ny = x + dx, y + dy
                if 0 <= nx < WIDTH and 0 <= ny < HEIGHT:
                    if self.active_map()[ny][nx] in targets:
                        return True
        return False

    def shippable_items(self) -> List[Tuple[str, int, int]]:
        """Return safe-to-ship inventory as (item, quantity, unit sell price)."""
        s = self.state
        result: List[Tuple[str, int, int]] = []
        for item_name, qty in sorted(s.inventory.items()):
            try:
                clean_qty = max(0, int(qty))
            except Exception:
                clean_qty = 0
            if clean_qty <= 0 or not self.is_shippable_item(item_name):
                continue
            result.append((str(item_name), clean_qty, self.shippable_unit_price(str(item_name))))
        return result

    def shipping_menu(self, auto_opened: bool = False):
        s = self.state
        if self.shipping_bin_target() is None:
            self.set_message("Face the shipping bin and press Z/Enter to sell shippable items.")
            return

        while True:
            shippable = self.shippable_items()
            total_available_items = sum(qty for _item, qty, _price in shippable)
            total_available_value = sum(qty * price for _item, qty, price in shippable)
            pending_item_count = sum(qty for _item, qty, _price in self.pending_shipping_items())

            items: List[MenuItem] = [
                MenuItem(
                    label="Ship all safe goods",
                    value="__all__",
                    enabled=bool(shippable),
                    hint=f"{total_available_items} item(s), ${total_available_value}",
                ),
                MenuItem(
                    label="Ship item by quantity",
                    value="__select__",
                    enabled=bool(shippable),
                    hint=f"{len(shippable)} stack(s)",
                ),
                MenuItem(
                    label="Reclaim pending items",
                    value="__reclaim__",
                    enabled=bool(pending_item_count),
                    hint=f"{pending_item_count} item(s)",
                ),
                MenuItem(
                    label="View pending shipment",
                    value="__report__",
                    enabled=True,
                    hint=f"${s.shipped_today}",
                ),
                MenuItem(label="Close shipping bin", value=None, enabled=True),
            ]

            selected = menu_select(
                "SHIPPING BIN",
                items,
                footer="Arrow keys/WASD move | Z/Enter choose | X/Esc/Q leave",
                extra_lines=[
                    f"Money now: ${s.money}",
                    f"Pending payout tomorrow: ${s.shipped_today}",
                    f"Available to ship now: {total_available_items} item(s), ${total_available_value}",
                    "Crafting and unlock materials are protected from shipping.",
                    "Payment arrives when you sleep.",
                ],
            )

            if selected is None or selected.value is None:
                if auto_opened:
                    s.bin_menu_suppressed_until_exit = True
                self.set_message("Closed shipping bin.")
                return

            if selected.value == "__report__":
                self.vertical_panel_view(
                    "Pending Shipment",
                    self.shipping_report_lines(include_prices=True),
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                )
                continue

            if selected.value == "__all__":
                total_items = 0
                total_money = 0
                for item_name, qty, price in self.shippable_items():
                    total_items += qty
                    total_money += qty * price
                    s.inventory[item_name] = 0
                    self.add_to_shipping_report(item_name, qty, qty * price)

                if total_items <= 0:
                    self.set_message("You have nothing to ship.")
                    return

                if auto_opened:
                    s.bin_menu_suppressed_until_exit = True
                self.autosave_with_message(f"Shipped {total_items} item(s) for ${total_money}. Payment arrives tomorrow.")
                return

            if selected.value == "__select__":
                while True:
                    shippable = self.shippable_items()
                    item_choices: List[MenuItem] = []
                    for item_name, qty, price in shippable:
                        item_choices.append(MenuItem(
                            label=item_name,
                            value=item_name,
                            enabled=True,
                            hint=f"x{qty}, ${price} each",
                        ))
                    item_choices.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                    item_choice = self.vertical_panel_select(
                        "Ship Selected Item",
                        item_choices,
                        LEFT_PANEL_WIDTH,
                        LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if item_choice is None or item_choice.value == MENU_BACK:
                        break

                    item_name = str(item_choice.value)
                    qty_owned = s.inventory.get(item_name, 0)
                    if qty_owned <= 0:
                        self.set_message(f"You do not have any {item_name} to ship.")
                        break

                    unit_price = self.shippable_unit_price(item_name)
                    if unit_price <= 0 or not self.is_shippable_item(item_name):
                        self.set_message(f"{item_name} is not shippable.")
                        break
                    qty = self.vertical_quantity_select(
                        "Ship Item",
                        item_name,
                        unit_price,
                        max_qty=qty_owned,
                        start_qty=qty_owned,
                        panel_width=LEFT_PANEL_WIDTH,
                        panel_height=LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if qty == MENU_BACK or qty is None or qty <= 0:
                        self.set_message("Shipping cancelled.")
                        break

                    qty = int(qty)
                    total = qty * unit_price
                    s.inventory[item_name] = qty_owned - qty
                    self.add_to_shipping_report(item_name, qty, total)
                    self.autosave_with_message(f"Shipped {qty} {item_name} for ${total}. Payment arrives tomorrow.")
                    # Stay in the selected-item loop so several stacks can be shipped.

            if selected.value == "__reclaim__":
                while True:
                    pending = self.pending_shipping_items()
                    reclaim_choices: List[MenuItem] = []
                    for item_name, qty, price in pending:
                        reclaim_choices.append(MenuItem(
                            label=item_name,
                            value=item_name,
                            enabled=True,
                            hint=f"x{qty}, ${price} each",
                        ))
                    reclaim_choices.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                    reclaim_choice = self.vertical_panel_select(
                        "Reclaim Pending Items",
                        reclaim_choices,
                        LEFT_PANEL_WIDTH,
                        LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if reclaim_choice is None or reclaim_choice.value == MENU_BACK:
                        break

                    item_name = str(reclaim_choice.value)
                    qty_pending = int(s.shipped_today_items.get(item_name, 0) or 0)
                    if qty_pending <= 0:
                        self.set_message(f"No pending {item_name} to reclaim.")
                        break

                    qty = self.vertical_quantity_select(
                        "Reclaim Item",
                        item_name,
                        self.shippable_unit_price(item_name),
                        max_qty=qty_pending,
                        start_qty=qty_pending,
                        panel_width=LEFT_PANEL_WIDTH,
                        panel_height=LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if qty == MENU_BACK or qty is None or qty <= 0:
                        self.set_message("Reclaim cancelled.")
                        break

                    self.reclaim_shipped_item(item_name, int(qty))
                    # Stay in the reclaim loop so several mistakes can be fixed.

    def ship_items(self):
        """Compatibility wrapper for older menu paths."""
        self.shipping_menu(auto_opened=False)

    def automation_shop_item_names(self, shop_key: str) -> List[str]:
        return [
            name for name, data in INFRASTRUCTURE_DATA.items()
            if data.get("category") == "automation"
            and data.get("shop") == shop_key
            and int(data.get("price", 0)) > 0
        ]

    def automation_item_detail_lines(self, item_name: str) -> List[str]:
        data = INFRASTRUCTURE_DATA.get(item_name, {})
        automation = data.get("automation") if isinstance(data.get("automation"), dict) else {}
        cost = data.get("cost") if isinstance(data.get("cost"), dict) else {}
        rows = [
            item_name,
            "",
            str(data.get("description", "Farm automation object.")),
            "",
            f"Price: ${int(data.get('price', 0))}",
            f"Footprint: {self.footprint_label(item_name)}",
            f"Daily behavior: {data.get('daily_behavior', automation.get('kind', 'automation'))}",
            "Works on: home farm and owned land claims",
        ]
        if cost:
            rows.extend(["", "Crafting cost:"])
            rows.extend(f"- {ingredient} x{qty}" for ingredient, qty in sorted(cost.items()))
        rows.extend([
            "",
            "Placement:",
            "- Build it on owned farm land.",
            "- It cannot be placed on crops, water, town tiles, interiors, or mines.",
        ])
        return rows

    def purchase_automation_item(self, item_name: str, auto_opened: bool = False, qty: int = 1) -> bool:
        data = INFRASTRUCTURE_DATA.get(item_name)
        if not data:
            self.set_message("That automation item is not available.")
            return False
        price = int(data.get("price", 0))
        if price <= 0:
            self.set_message(f"{item_name} is crafted, not purchased.")
            return False
        qty = max(1, int(qty))
        total = price * qty
        if self.state.money < total:
            self.set_message(f"Not enough money. {qty} {item_name} cost ${total}.")
            return False
        self.state.money -= total
        self.state.inventory[item_name] = self.state.inventory.get(item_name, 0) + qty
        if auto_opened:
            self.state.shop_menu_suppressed_until_exit = True
        self.autosave_with_message(f"Bought {qty} {item_name}(s) for ${total}. Place them from Tab > Farm & Home > Build Mode.")
        return True

    def automation_shop_menu(self, shop_key: str, title: str, auto_opened: bool = False):
        names = self.automation_shop_item_names(shop_key)
        if not names:
            self.set_message("No automation items are stocked here yet.")
            return MENU_BACK

        while True:
            items: List[MenuItem] = []
            for name in names:
                data = INFRASTRUCTURE_DATA[name]
                price = int(data.get("price", 0))
                affordable = self.state.money >= price
                max_qty = self.state.money // price if price > 0 and affordable else 0
                hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                items.append(MenuItem(label=name, value=name, enabled=affordable, hint=hint))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

            choice = self.vertical_panel_select(title, items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK

            item_name = str(choice.value)
            self.vertical_panel_view("Automation Item", self.automation_item_detail_lines(item_name), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            price = int(INFRASTRUCTURE_DATA[item_name].get("price", 0))
            confirm = self.vertical_panel_select(
                f"Buy {item_name}",
                [
                    MenuItem(label=f"Choose quantity", value="buy", enabled=self.state.money >= price, hint=f"${price} each"),
                    MenuItem(label="Back", value=MENU_BACK, enabled=True),
                ],
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if confirm is None or confirm.value == MENU_BACK:
                continue
            if confirm.value == "buy":
                max_qty = self.state.money // price
                qty = self.vertical_quantity_select(
                    "Buy Automation",
                    item_name,
                    price,
                    max_qty=max_qty,
                    start_qty=1,
                    panel_width=LEFT_PANEL_WIDTH,
                    panel_height=LEFT_PANEL_HEIGHT,
                    return_back=True,
                )
                if qty == MENU_BACK or qty is None or int(qty) <= 0:
                    continue
                self.purchase_automation_item(item_name, auto_opened=auto_opened, qty=int(qty))
                return "changed"

    def combat_supply_shop_stock(self, shop_key: str = "general") -> List[Dict[str, object]]:
        clinic_discount = shop_key == "clinic" and self.has_town_project("clinic_supply_board")
        return [
            {
                "item": "Potion",
                "label": "Health Potion",
                "price": 80 if clinic_discount else (90 if shop_key == "clinic" else 100),
                "hint": "restores HP",
            },
            {
                "item": "Ether",
                "label": "Mana Potion",
                "price": 110 if clinic_discount else (125 if shop_key == "clinic" else 140),
                "hint": "restores focus",
            },
        ]

    def buy_combat_supply_item(self, item_name: str, price: int, title: str = "Buy Supplies") -> bool:
        price = max(1, int(price))
        max_qty = self.state.money // price
        if max_qty <= 0:
            self.set_message(f"Not enough money for {item_name}.")
            return False
        qty = self.vertical_quantity_select(
            title,
            item_name,
            price,
            max_qty=max_qty,
            start_qty=min(3, max_qty),
            panel_width=LEFT_PANEL_WIDTH,
            panel_height=LEFT_PANEL_HEIGHT,
            return_back=True,
        )
        if qty == MENU_BACK or qty is None or int(qty) <= 0:
            self.set_message("Purchase cancelled.")
            return False
        qty = int(qty)
        total = qty * price
        self.state.money -= total
        self.state.inventory[item_name] = int(self.state.inventory.get(item_name, 0) or 0) + qty
        self.autosave_with_message(f"Bought {qty} {item_name} for ${total}.")
        return True

    def buy_menu(self, auto_opened: bool = False):
        s = self.state
        if self.on_general_store() and not self.ensure_current_town_service_unlocked():
            return
        if not (self.in_seed_shop(s.player_x, s.player_y) or self.on_general_store()):
            self.set_message("Visit the General Store shopkeeper to buy seeds and infrastructure.")
            return

        page = "main"

        while True:
            if page == "main":
                ring_ok, ring_hint = self.can_purchase_wedding_ring()
                pack_price = self.backpack_upgrade_price()
                main_items = [
                    MenuItem(label="Buy seeds", value="seeds", enabled=True, hint=f"${s.money}"),
                    MenuItem(label="Buy combat supplies", value="combat_supplies", enabled=True, hint="HP/focus"),
                    MenuItem(label="Buy infrastructure", value="infrastructure", enabled=True, hint="farm items"),
                    MenuItem(
                        label="Expand backpack",
                        value="backpack_upgrade",
                        enabled=s.money >= pack_price,
                        hint=f"${pack_price} | {self.backpack_capacity()} -> {self.backpack_capacity() + 50}",
                    ),
                    MenuItem(
                        label="Buy wedding ring",
                        value="wedding_ring",
                        enabled=ring_ok,
                        hint=ring_hint,
                    ),
                    MenuItem(label="Leave", value="leave", enabled=True),
                ]

                selected_main = self.vertical_panel_select(
                    "General Store",
                    main_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=False,
                )

                if selected_main is None or selected_main.value == "leave":
                    if auto_opened:
                        s.shop_menu_suppressed_until_exit = True
                    self.set_message("You left the General Store. Walk out and back in to auto-open it again.")
                    return

                if selected_main.value == "seeds":
                    page = "seeds"
                    continue

                if selected_main.value == "infrastructure":
                    page = "infrastructure"
                    continue

                if selected_main.value == "combat_supplies":
                    page = "combat_supplies"
                    continue

                if selected_main.value == "backpack_upgrade":
                    if self.purchase_backpack_upgrade():
                        if auto_opened:
                            s.shop_menu_suppressed_until_exit = True
                        return
                    continue

                if selected_main.value == "wedding_ring":
                    if self.purchase_wedding_ring():
                        if auto_opened:
                            s.shop_menu_suppressed_until_exit = True
                        return
                    continue

            elif page == "infrastructure":
                infra_items: List[MenuItem] = []

                for infra_name, data in INFRASTRUCTURE_DATA.items():
                    price = int(data.get("price", 0))
                    # Craft-only items and furniture are not sold at the General Store.
                    if price <= 0 or data.get("category") == "furniture":
                        continue
                    if data.get("shop") and data.get("shop") != "general":
                        continue
                    affordable = s.money >= price
                    max_qty = s.money // price if price > 0 and affordable else 0
                    hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                    infra_items.append(MenuItem(label=infra_name, value=f"infra:{infra_name}", enabled=affordable, hint=hint))

                infra_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                infra_choice = self.vertical_panel_select(
                    "Buy Infrastructure",
                    infra_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if infra_choice is None or infra_choice.value == MENU_BACK:
                    page = "main"
                    continue

                raw_choice = str(infra_choice.value)
                if raw_choice.startswith("infra:"):
                    infra_name = raw_choice.split(":", 1)[1]
                    data = INFRASTRUCTURE_DATA[infra_name]
                    price = int(data["price"])
                    max_qty = max(1, s.money // price)
                    confirm_items = [
                        MenuItem(label="Choose quantity", value="buy_infra", enabled=True, hint=f"${price} each"),
                        MenuItem(label=str(data.get("description", ""))[:38], value="info", enabled=False),
                        MenuItem(label="Back", value=MENU_BACK, enabled=True),
                    ]
                    confirm = self.vertical_panel_select(
                        f"Confirm {infra_name}",
                        confirm_items,
                        LEFT_PANEL_WIDTH,
                        LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if confirm is None or confirm.value == MENU_BACK:
                        page = "infrastructure"
                        continue

                    if confirm.value == "buy_infra":
                        start_qty = min(10, max_qty) if infra_name in ["Fence", "Stone Path", "Pipe Segment"] else 1
                        qty_choice = self.vertical_quantity_select(
                            "Buy Infrastructure",
                            infra_name,
                            price,
                            max_qty=max_qty,
                            start_qty=start_qty,
                            panel_width=LEFT_PANEL_WIDTH,
                            panel_height=LEFT_PANEL_HEIGHT,
                            return_back=True,
                        )
                        if qty_choice == MENU_BACK or qty_choice is None or int(qty_choice) <= 0:
                            page = "infrastructure"
                            continue
                        qty = int(qty_choice)

                        total = qty * price
                        s.money -= total
                        s.inventory[infra_name] = s.inventory.get(infra_name, 0) + qty
                        if auto_opened:
                            s.shop_menu_suppressed_until_exit = True
                        self.autosave_with_message(f"Bought {qty} {infra_name}(s). Open inventory > Place to build.")
                        return

            elif page == "seeds":
                names = [name for name, data in CROP_DATA.items() if int(data.get("seed_price", 0)) > 0]
                items: List[MenuItem] = []
                for name in names:
                    data = CROP_DATA[name]
                    seasonal = data["season"] == s.season
                    affordable = s.money >= data["seed_price"]
                    enabled = seasonal and affordable
                    if not seasonal:
                        hint = f"{data['season']} only"
                    elif not affordable:
                        hint = "too $"
                    else:
                        max_qty = s.money // data["seed_price"]
                        hint = f"${data['seed_price']} x{max_qty}"
                    items.append(MenuItem(label=f"{name}", value=name, enabled=enabled, hint=hint))

                items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                selected = self.vertical_panel_select(
                    "Buy Seeds",
                    items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if selected is None or selected.value == MENU_BACK:
                    page = "main"
                    continue

                name = str(selected.value)
                data = CROP_DATA[name]
                max_qty = s.money // data["seed_price"]

                qty = self.vertical_quantity_select(
                    "Buy Seeds",
                    f"{name} Seeds",
                    data["seed_price"],
                    max_qty=max_qty,
                    start_qty=min(5, max_qty),
                    panel_width=LEFT_PANEL_WIDTH,
                    panel_height=LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if qty == MENU_BACK or qty == 0:
                    page = "seeds"
                    continue

                qty = int(qty)
                total = qty * data["seed_price"]
                s.money -= total
                item = f"{name} Seeds"
                s.inventory[item] = s.inventory.get(item, 0) + qty
                s.selected_seed = name
                self.select_tool_by_name("Seeds")
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                self.autosave_with_message(f"Bought {qty} {item} for ${total}. Selected {name} Seeds.")
                return

            elif page == "combat_supplies":
                supply_items: List[MenuItem] = []
                for entry in self.combat_supply_shop_stock("general"):
                    item_name = str(entry["item"])
                    price = int(entry["price"])
                    affordable = s.money >= price
                    max_qty = s.money // price if affordable else 0
                    hint = f"${price} x{max_qty} {entry['hint']}" if affordable else f"${price} no"
                    supply_items.append(MenuItem(label=str(entry["label"]), value=f"supply:{item_name}", enabled=affordable, hint=hint))
                supply_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                selected = self.vertical_panel_select(
                    "Combat Supplies",
                    supply_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )
                if selected is None or selected.value == MENU_BACK:
                    page = "main"
                    continue

                item_name = str(selected.value).split(":", 1)[1]
                entry = next((stock for stock in self.combat_supply_shop_stock("general") if str(stock["item"]) == item_name), None)
                if not entry:
                    page = "combat_supplies"
                    continue
                if self.buy_combat_supply_item(item_name, int(entry["price"]), title="Buy Combat Supply"):
                    if auto_opened:
                        s.shop_menu_suppressed_until_exit = True
                    return

    def carpenter_menu(self, auto_opened: bool = False):
        s = self.state
        if self.on_carpenter_store() and not self.ensure_current_town_service_unlocked():
            return
        if not self.on_carpenter_store():
            self.set_message("Visit the Carpenter to buy farm expansions, buildings, and house upgrades.")
            return

        farm_building_names = [name for name, data in INFRASTRUCTURE_DATA.items() if data.get("category") == "building" and int(data.get("price", 0)) > 0]
        automation_names = self.automation_shop_item_names("carpenter")

        while True:
            items: List[MenuItem] = []

            for name, data in FARM_EXPANSION_DATA.items():
                owned = name in s.farm_expansions
                missing = [req for req in data.get("requires", []) if req not in s.farm_expansions]
                price = int(data["price"])
                affordable = s.money >= price
                enabled = (not owned) and (not missing) and affordable
                if owned:
                    hint = "done"
                elif missing:
                    hint = "requires prior"
                elif not affordable:
                    hint = f"${price} no"
                else:
                    hint = f"${price}"
                items.append(MenuItem(label=f"Farm: {name}", value=f"farm::{name}", enabled=enabled, hint=hint))

            for name in farm_building_names:
                data = INFRASTRUCTURE_DATA[name]
                price = int(data.get("price", 0))
                affordable = s.money >= price
                max_qty = s.money // price if price > 0 and affordable else 0
                hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                items.append(MenuItem(label=f"Building: {name}", value=f"building::{name}", enabled=affordable, hint=hint))

            for name in automation_names:
                data = INFRASTRUCTURE_DATA[name]
                price = int(data.get("price", 0))
                affordable = s.money >= price
                max_qty = s.money // price if price > 0 and affordable else 0
                hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                items.append(MenuItem(label=f"Automation: {name}", value=f"automation::{name}", enabled=affordable, hint=hint))

            for name, data in HOUSE_UPGRADE_DATA.items():
                owned = name in s.house_upgrades
                missing = [req for req in data.get("requires", []) if req not in s.house_upgrades]
                price = int(data["price"])
                affordable = s.money >= price
                enabled = (not owned) and (not missing) and affordable
                if owned:
                    hint = "done"
                elif missing:
                    hint = "requires prior"
                elif not affordable:
                    hint = f"${price} no"
                else:
                    hint = f"${price}"
                items.append(MenuItem(label=f"House: {name}", value=f"house::{name}", enabled=enabled, hint=hint))

            items.append(MenuItem(label="Leave", value="leave", enabled=True))

            choice = self.vertical_panel_select(
                "Carpenter",
                items,
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=False,
            )

            if choice is None or choice.value == "leave":
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                self.set_message("You left the Carpenter's Store.")
                return

            raw_value = str(choice.value)
            if "::" not in raw_value:
                continue
            project_type, project_name = raw_value.split("::", 1)

            if project_type == "farm":
                data = FARM_EXPANSION_DATA[project_name]
                rows = [
                    project_name,
                    "",
                    data["description"],
                    "",
                    f"Cost: ${data['price']}",
                    f"New farm size: {data['width']}x{data['height']}",
                    "",
                    "Buying this permanently expands the actual farm map.",
                ]
                confirm_label = f"Buy {project_name}"
            elif project_type == "building":
                data = INFRASTRUCTURE_DATA[project_name]
                rows = [
                    project_name,
                    "",
                    data["description"],
                    "",
                    f"Cost: ${data['price']}",
                    f"Footprint: {self.footprint_label(project_name)}",
                    "",
                    "Buying this adds one building kit to your inventory.",
                    "Place it on the farm from Tab > Farm & Home > Build Mode.",
                ]
                confirm_label = f"Buy {project_name}"
            elif project_type == "automation":
                data = INFRASTRUCTURE_DATA[project_name]
                rows = self.automation_item_detail_lines(project_name)
                confirm_label = f"Buy {project_name}"
            else:
                data = HOUSE_UPGRADE_DATA[project_name]
                rows = [
                    project_name,
                    "",
                    data["description"],
                    "",
                    f"Cost: ${data['price']}",
                    "",
                    "Buying this expands and rearranges the farmhouse interior.",
                    "Existing movable furniture is preserved when possible.",
                ]
                confirm_label = f"Buy {project_name}"

            self.vertical_panel_view("Carpenter Plan", rows, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

            confirm_items = [
                MenuItem(label=confirm_label, value="buy", enabled=True, hint=f"${data['price']}"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            confirm = self.vertical_panel_select(
                "Confirm Project",
                confirm_items,
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if confirm is None or confirm.value == MENU_BACK:
                continue
            if confirm.value == "buy":
                if project_type == "farm":
                    self.purchase_farm_expansion(project_name)
                elif project_type == "building":
                    price = int(data["price"])
                    max_qty = max(1, s.money // price)
                    qty = self.vertical_quantity_select(
                        "Buy Building Kits",
                        project_name,
                        price,
                        max_qty=max_qty,
                        start_qty=1,
                        panel_width=LEFT_PANEL_WIDTH,
                        panel_height=LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )
                    if qty == MENU_BACK or qty is None or int(qty) <= 0:
                        continue
                    self.purchase_farm_building(project_name, qty=int(qty))
                elif project_type == "automation":
                    price = int(data["price"])
                    max_qty = max(1, s.money // price)
                    qty = self.vertical_quantity_select(
                        "Buy Automation",
                        project_name,
                        price,
                        max_qty=max_qty,
                        start_qty=1,
                        panel_width=LEFT_PANEL_WIDTH,
                        panel_height=LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )
                    if qty == MENU_BACK or qty is None or int(qty) <= 0:
                        continue
                    self.purchase_automation_item(project_name, auto_opened=auto_opened, qty=int(qty))
                else:
                    self.purchase_house_upgrade(project_name)
                return

    def furniture_store_menu(self, auto_opened: bool = False):
        s = self.state
        if self.on_furniture_store() and not self.ensure_current_town_service_unlocked():
            return
        if not self.on_furniture_store():
            self.set_message("Visit the Furniture Store clerk to buy furniture.")
            return

        furniture_names = [name for name, data in INFRASTRUCTURE_DATA.items() if data.get("category") == "furniture" and int(data.get("price", 0)) > 0]

        while True:
            items: List[MenuItem] = []
            for name in furniture_names:
                data = INFRASTRUCTURE_DATA[name]
                price = int(data.get("price", 0))
                affordable = s.money >= price
                max_qty = s.money // price if price > 0 and affordable else 0
                hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                items.append(MenuItem(label=name, value=name, enabled=affordable, hint=hint))
            items.append(MenuItem(label="Leave", value="leave", enabled=True))

            choice = self.vertical_panel_select(
                "Furniture Store",
                items,
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=False,
            )

            if choice is None or choice.value == "leave":
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                self.set_message("You left the Furniture Store.")
                return

            name = str(choice.value)
            price = int(INFRASTRUCTURE_DATA[name]["price"])
            max_qty = s.money // price
            qty = self.vertical_quantity_select(
                "Buy Furniture",
                name,
                price,
                max_qty=max_qty,
                start_qty=1,
                panel_width=LEFT_PANEL_WIDTH,
                panel_height=LEFT_PANEL_HEIGHT,
                return_back=True,
            )

            if qty == MENU_BACK or qty == 0:
                continue

            qty = int(qty)
            total = qty * price
            s.money -= total
            s.inventory[name] = s.inventory.get(name, 0) + qty
            if auto_opened:
                s.shop_menu_suppressed_until_exit = True
            self.autosave_with_message(f"Bought {qty} {name}(s) for ${total}. Place furniture inside your farmhouse from the Tab menu.")
            return

    def blacksmith_menu(self, auto_opened: bool = False):
        s = self.state
        if self.on_blacksmith_interior() and not self.ensure_current_town_service_unlocked():
            return
        if not self.is_town_building_unlocked("blacksmith"):
            self.set_message(self.locked_town_building_message("blacksmith"))
            return
        if not (self.in_blacksmith(s.player_x, s.player_y) or self.on_blacksmith_interior()):
            self.set_message("Visit the Blacksmith to buy tools, upgrades, and ore.")
            return

        page = "main"

        while True:
            if page == "main":
                unowned_tools = [name for name in BASE_TOOL_SHOP_DATA if not self.owns_tool(name)]
                upgradeable_tools = [
                    name for name in ["Hoe", "Watering Can", "Axe", "Pickaxe"]
                    if self.owns_tool(name) and self.next_tool_upgrade(name) is not None
                ]
                main_items = [
                    MenuItem(label="Buy tools", value="buy_tools", enabled=bool(unowned_tools), hint=f"{len(unowned_tools)} available" if unowned_tools else "owned"),
                    MenuItem(label="Upgrade tools", value="upgrade_tools", enabled=bool(upgradeable_tools), hint=f"{len(upgradeable_tools)} available" if upgradeable_tools else "max/none"),
                    MenuItem(label="Buy ore", value="ore", enabled=True, hint="materials"),
                    MenuItem(label="Farm Automation", value="automation", enabled=True, hint=f"{len(self.automation_shop_item_names('blacksmith'))} item(s)"),
                    MenuItem(label="Combat Gear", value="combat_gear", enabled=True, hint=f"{self.available_blacksmith_combat_gear_count()} available"),
                    MenuItem(label="Party Loadout", value="party_loadout", enabled=True, hint="tactical gear, supplies, drills"),
                    MenuItem(label="Leave", value="leave", enabled=True),
                ]

                selected_main = self.vertical_panel_select(
                    "Blacksmith",
                    main_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=False,
                )

                if selected_main is None or selected_main.value == "leave":
                    if auto_opened:
                        s.shop_menu_suppressed_until_exit = True
                    self.set_message("You left the Blacksmith. Walk out and back in to auto-open it again.")
                    return

                if selected_main.value == "buy_tools":
                    page = "buy_tools"
                    continue
                if selected_main.value == "upgrade_tools":
                    page = "upgrade_tools"
                    continue
                if selected_main.value == "ore":
                    page = "ore"
                    continue
                if selected_main.value == "automation":
                    page = "automation"
                    continue
                if selected_main.value == "combat_gear":
                    page = "combat_gear"
                    continue
                if selected_main.value == "party_loadout":
                    page = "party_loadout"
                    continue

            elif page == "buy_tools":
                tool_items: List[MenuItem] = []

                for tool_name, data in BASE_TOOL_SHOP_DATA.items():
                    if self.owns_tool(tool_name):
                        tool_items.append(MenuItem(
                            label=tool_name,
                            value=f"base_tool:{tool_name}",
                            enabled=False,
                            hint="owned",
                        ))
                    else:
                        price = int(data["price"])
                        affordable = s.money >= price
                        tool_items.append(MenuItem(
                            label=tool_name,
                            value=f"base_tool:{tool_name}",
                            enabled=affordable,
                            hint=f"${price}" if affordable else f"${price} no",
                        ))

                tool_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                tool_choice = self.vertical_panel_select(
                    "Buy Tools",
                    tool_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if tool_choice is None or tool_choice.value == MENU_BACK:
                    page = "main"
                    continue

                raw_choice = str(tool_choice.value)
                if raw_choice.startswith("base_tool:"):
                    tool_name = raw_choice.split(":", 1)[1]
                    if self.owns_tool(tool_name):
                        self.set_message(f"You already own a {tool_name}.")
                        page = "buy_tools"
                        continue

                    data = BASE_TOOL_SHOP_DATA[tool_name]
                    price = int(data["price"])
                    confirm_items = [
                        MenuItem(label=f"Buy Basic {tool_name}", value="buy_base_tool", enabled=s.money >= price, hint=f"${price}"),
                        MenuItem(label=data["description"], value="info", enabled=False),
                        MenuItem(label="Back", value=MENU_BACK, enabled=True),
                    ]
                    confirm = self.vertical_panel_select(
                        f"Buy {tool_name}",
                        confirm_items,
                        LEFT_PANEL_WIDTH,
                        LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if confirm is None or confirm.value == MENU_BACK:
                        page = "buy_tools"
                        continue

                    if confirm.value == "buy_base_tool":
                        s.money -= price
                        s.tool_levels[tool_name] = max(1, s.tool_levels.get(tool_name, 0))
                        if tool_name not in s.owned_tools:
                            s.owned_tools.append(tool_name)
                        self.select_tool_by_name(tool_name)
                        if auto_opened:
                            s.shop_menu_suppressed_until_exit = True
                        self.autosave_with_message(f"Bought Basic {tool_name}.")
                        return

            elif page == "upgrade_tools":
                tool_items: List[MenuItem] = []

                for tool_name in ["Hoe", "Watering Can", "Axe", "Pickaxe", "Fishing Rod"]:
                    if not self.owns_tool(tool_name):
                        continue

                    upgrade = self.next_tool_upgrade(tool_name)
                    current_name = self.tool_level_name(tool_name)
                    if upgrade is None:
                        tool_items.append(MenuItem(
                            label=f"{tool_name}",
                            value=f"tool:{tool_name}",
                            enabled=False,
                            hint=f"{current_name} max",
                        ))
                    else:
                        affordable = s.money >= upgrade["price"]
                        next_name = TOOL_LEVEL_NAMES.get(upgrade["level"], f"Lv{upgrade['level']}")
                        hint = f"{current_name}->{next_name} ${upgrade['price']}" if affordable else f"${upgrade['price']} no"
                        tool_items.append(MenuItem(
                            label=f"{tool_name}",
                            value=f"tool:{tool_name}",
                            enabled=affordable,
                            hint=hint,
                        ))

                tool_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                tool_choice = self.vertical_panel_select(
                    "Upgrade Tools",
                    tool_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if tool_choice is None or tool_choice.value == MENU_BACK:
                    page = "main"
                    continue

                raw_choice = str(tool_choice.value)
                if raw_choice.startswith("tool:"):
                    tool_name = raw_choice.split(":", 1)[1]
                    if not self.owns_tool(tool_name):
                        self.set_message(f"Buy a basic {tool_name} before upgrading it.")
                        page = "upgrade_tools"
                        continue

                    upgrade = self.next_tool_upgrade(tool_name)
                    if upgrade is None:
                        self.set_message(f"{tool_name} is already fully upgraded.")
                        page = "upgrade_tools"
                        continue

                    next_name = TOOL_LEVEL_NAMES.get(upgrade["level"], f"Lv{upgrade['level']}")
                    confirm_items = [
                        MenuItem(label=f"Upgrade to {next_name} {tool_name}", value="buy_tool", enabled=True, hint=f"${upgrade['price']}"),
                        MenuItem(label=upgrade["description"], value="info", enabled=False),
                        MenuItem(label="Back", value=MENU_BACK, enabled=True),
                    ]
                    confirm = self.vertical_panel_select(
                        f"Upgrade {tool_name}",
                        confirm_items,
                        LEFT_PANEL_WIDTH,
                        LEFT_PANEL_HEIGHT,
                        return_back=True,
                    )

                    if confirm is None or confirm.value == MENU_BACK:
                        page = "upgrade_tools"
                        continue

                    if confirm.value == "buy_tool":
                        s.money -= upgrade["price"]
                        s.tool_levels[tool_name] = upgrade["level"]
                        if auto_opened:
                            s.shop_menu_suppressed_until_exit = True
                        self.autosave_with_message(f"Upgraded to {next_name} {tool_name}.")
                        return

            elif page == "ore":
                ore_items: List[MenuItem] = []
                for ore_name, data in ORE_SHOP_DATA.items():
                    price = int(data["price"])
                    affordable = s.money >= price
                    max_qty = s.money // price if affordable else 0
                    hint = f"${price} x{max_qty}" if affordable else f"${price} no"
                    ore_items.append(MenuItem(label=ore_name, value=ore_name, enabled=affordable, hint=hint))

                ore_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

                selected = self.vertical_panel_select(
                    "Buy Ore",
                    ore_items,
                    LEFT_PANEL_WIDTH,
                    LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if selected is None or selected.value == MENU_BACK:
                    page = "main"
                    continue

                ore_name = str(selected.value)
                price = int(ORE_SHOP_DATA[ore_name]["price"])
                max_qty = s.money // price

                qty = self.vertical_quantity_select(
                    "Buy Ore",
                    ore_name,
                    price,
                    max_qty=max_qty,
                    start_qty=min(5, max_qty),
                    panel_width=LEFT_PANEL_WIDTH,
                    panel_height=LEFT_PANEL_HEIGHT,
                    return_back=True,
                )

                if qty == MENU_BACK or qty == 0:
                    page = "ore"
                    continue

                qty = int(qty)
                total = qty * price
                s.money -= total
                s.inventory[ore_name] = s.inventory.get(ore_name, 0) + qty
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                self.autosave_with_message(f"Bought {qty} {ore_name} for ${total}.")
                return

            elif page == "combat_gear":
                result = self.blacksmith_combat_gear_menu()
                if result == MENU_BACK:
                    page = "main"
                    continue
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                return

            elif page == "party_loadout":
                result = self.show_tactical_loadout_menu()
                if result == MENU_BACK:
                    page = "main"
                    continue
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                return

            elif page == "automation":
                result = self.automation_shop_menu("blacksmith", "Blacksmith Automation", auto_opened=auto_opened)
                if result == MENU_BACK:
                    page = "main"
                    continue
                if auto_opened:
                    s.shop_menu_suppressed_until_exit = True
                return


    def sprinkler_targets(self, x: int, y: int, obj_name: str = "Sprinkler") -> List[Tuple[int, int]]:
        """Tiles watered by sprinkler-type infrastructure."""
        radius = INFRASTRUCTURE_DATA.get(obj_name, {}).get("radius")
        targets: List[Tuple[int, int]] = []

        if radius == "orthogonal_1":
            offsets = [(0, -1), (1, 0), (0, 1), (-1, 0)]
        elif radius == "surrounding_1":
            offsets = [
                (dx, dy)
                for dy in [-1, 0, 1]
                for dx in [-1, 0, 1]
                if not (dx == 0 and dy == 0)
            ]
        else:
            offsets = []

        for dx, dy in offsets:
            nx, ny = x + dx, y + dy
            if 0 <= nx < WIDTH and 0 <= ny < HEIGHT:
                targets.append((nx, ny))

        return targets

    def apply_sprinklers(self) -> int:
        """Water all valid sprinkler target tiles. Returns number of tiles/crops affected."""
        watered_count = 0
        for key, obj_name in list(self.state.placed_objects.items()):
            radius = INFRASTRUCTURE_DATA.get(obj_name, {}).get("radius")
            if radius not in ["orthogonal_1", "surrounding_1"]:
                continue
            parsed = self.parse_object_key(key)
            if not parsed:
                continue
            scope, x, y = parsed
            land_map = self.land_map_for_object_scope(scope)
            if not land_map:
                continue
            map_h = len(land_map)
            map_w = len(land_map[0]) if map_h else 0
            if radius == "orthogonal_1":
                offsets = [(0, -1), (1, 0), (0, 1), (-1, 0)]
            else:
                offsets = [
                    (dx, dy)
                    for dy in [-1, 0, 1]
                    for dx in [-1, 0, 1]
                    if not (dx == 0 and dy == 0)
                ]

            for dx, dy in offsets:
                tx, ty = x + dx, y + dy
                if not (0 <= tx < map_w and 0 <= ty < map_h):
                    continue
                crop_key = f"{scope}:{tx},{ty}"
                crop = self.crops.get(crop_key)
                if crop is None and scope == "Farm":
                    crop = self.crops.get(f"{tx},{ty}")
                tile = land_map[ty][tx]
                if tile in [",", "w"] or crop:
                    if tile == ",":
                        land_map[ty][tx] = "w"
                    if crop:
                        crop.watered = True
                    watered_count += 1
        return watered_count

    def refresh_wilderness_caves(self, force: bool = False) -> int:
        """Lightly refresh explored wilderness caves overnight/monthly without fully resetting them."""
        self.ensure_wilderness_caves()
        if not self.wilderness_cave_maps:
            return 0

        # Small daily refresh; stronger when forced by season/month changes.
        day_seed = int(self.state.wilderness_seed) + self.state.year * 10000 + self.state.month * 100 + self.state.day + 10600
        rng = random.Random(day_seed)
        refreshed = 0

        for cave_key, grid in list(self.wilderness_cave_maps.items()):
            if not grid:
                continue
            cave_type = self.cave_type_for_key(cave_key)
            open_tiles = []
            h = len(grid)
            w = len(grid[0]) if h else 0
            for y in range(2, h - 2):
                for x in range(2, w - 2):
                    if grid[y][x] != ".":
                        continue
                    neighbors = [grid[y+dy][x+dx] for dx, dy in [(-1,0),(1,0),(0,-1),(0,1)]]
                    # Prefer refresh near walls/edges, not right on the exit.
                    if "#" in neighbors and not (y >= h - 4 and abs(x - (w // 2)) <= 4):
                        open_tiles.append((x, y))
            # If a cave was heavily cleared or hand-edited, fall back to any open
            # floor tile away from the exit so caves can still recover lightly.
            if not open_tiles:
                for y in range(2, h - 3):
                    for x in range(2, w - 2):
                        if grid[y][x] == "." and not (y >= h - 4 and abs(x - (w // 2)) <= 4):
                            open_tiles.append((x, y))

            rng.shuffle(open_tiles)
            if not open_tiles:
                continue

            base = 1 if force else (1 if rng.random() < 0.35 else 0)
            if force:
                base += 1
            for x, y in open_tiles[:base]:
                choice_rng = random.Random(day_seed + x * 31 + y * 17)
                symbol = choice_rng.choice(self.cave_resource_choices(cave_type))
                # Bias refresh toward softer renewable cave items; ores still appear rarely.
                if not force and symbol in ["c", "i", "g", "A", "C"]:
                    symbol = choice_rng.choice(["m", "h", "q", "o", "d"])
                grid[y][x] = symbol
                refreshed += 1
        return refreshed

    def update_farm_animals_overnight(self):
        """Age animals and adjust happiness, health, sickness, and daily flags."""
        self.normalize_farm_animals()
        for animal in self.state.farm_animals:
            try:
                animal["age"] = int(animal.get("age", 0)) + 1
                happy = int(animal.get("happiness", 50))
                health = int(animal.get("health", 100))
                trait = str(animal.get("trait", "Gentle"))

                if animal.get("fed"):
                    happy += 3 if trait != "Greedy" else 5
                    health += 3
                else:
                    happy -= 10 if trait == "Greedy" else 8
                    health -= 8

                if animal.get("petted_today"):
                    happy += 3
                else:
                    happy -= 2

                if animal.get("brushed_today"):
                    happy += 2
                    health += 1

                if animal.get("shelter_cleaned_today"):
                    happy += 2
                    health += 2
                elif not animal.get("outside"):
                    health -= 1

                if animal.get("treat_today"):
                    happy += 2
                    health += 1

                # Sickness risk increases with low health/neglect.
                sick = bool(animal.get("sick", False))
                if health < 25 and random.random() < 0.35:
                    sick = True
                elif health < 45 and random.random() < 0.12:
                    sick = True
                elif health > 80 and sick and random.random() < 0.25:
                    sick = False

                if sick:
                    happy -= 4
                    health -= 2

                received_attention = bool(animal.get("petted_today") or animal.get("brushed_today"))
                well_cared = bool(animal.get("fed") and received_attention and animal.get("shelter_cleaned_today"))
                if well_cared:
                    animal["care_streak"] = min(999, int(animal.get("care_streak", 0)) + 1)
                    animal["neglect_days"] = 0
                elif animal.get("fed") and received_attention:
                    animal["care_streak"] = max(0, int(animal.get("care_streak", 0)) - 1)
                    animal["neglect_days"] = 0
                else:
                    animal["care_streak"] = 0
                    animal["neglect_days"] = min(999, int(animal.get("neglect_days", 0)) + 1)

                if (
                    self.farm_animal_growth_stage(animal) == "Adult"
                    and animal.get("fed")
                    and not sick
                    and health >= 40
                ):
                    progress = int(animal.get("product_progress", 0)) + 1
                    cycle = self.farm_animal_product_cycle_days(animal)
                    while progress >= cycle and int(animal.get("product_ready_count", 0)) < 3:
                        progress -= cycle
                        animal["product_ready_count"] = int(animal.get("product_ready_count", 0)) + 1
                    animal["product_progress"] = min(cycle - 1, progress)

                animal["happiness"] = max(0, min(100, happy))
                animal["health"] = max(0, min(100, health))
                animal["sick"] = bool(sick)
                animal["fed"] = False
                animal["petted_today"] = False
                animal["treat_today"] = False
                animal["brushed_today"] = False
                animal["hand_fed_today"] = False
                animal["shelter_cleaned_today"] = False
                self.set_farm_animal_inside(animal, "sleeping indoors")
            except Exception:
                continue


