    def friendship_mail_subject(self, npc: Dict[str, object], tier: int) -> str:
        tier_name = {25: "A note", 60: "A friendly letter", 100: "A trusted friend's gift"}.get(tier, "A letter")
        return f"{tier_name} from {npc.get('name')}"

    def friendship_mail_body(self, npc: Dict[str, object], tier: int) -> List[str]:
        name = str(npc.get("name", "Someone"))
        role = str(npc.get("role", "Villager"))
        data = self.town_npc_dialogue_data(npc)
        mail = data.get("mail", {})
        note = ""
        if isinstance(mail, dict):
            note = str(mail.get(int(tier), ""))
        if not note:
            if tier == 25:
                note = "You have been showing up lately, and that changes how a place feels."
            elif tier == 60:
                note = str(data.get("motivation", "I am glad this town is starting to feel less anonymous."))
            else:
                note = str(data.get("secret", "You have become someone I trust with the quieter parts of town life."))
        if tier == 25:
            opening = f"Hey, it is {name}. I realized I have started looking for you on my usual route."
        elif tier == 60:
            opening = f"{name} here. I am glad our conversations have become part of the week."
        else:
            opening = f"{name} here. I trust you, so I wanted this to reach you directly."
        return [
            self.friendship_mail_subject(npc, tier),
            "",
            opening,
            "",
            note,
            "",
            f"- {name}, {role}",
        ]

    def reward_description(self, reward: Dict[str, object]) -> str:
        parts: List[str] = []
        money = int(reward.get("money", 0) or 0)
        if money:
            parts.append(f"${money}")
        items = reward.get("items", {}) or {}
        if isinstance(items, dict):
            for item, qty in items.items():
                parts.append(f"{qty} {item}")
        return ", ".join(parts) if parts else "No reward"

    def progress_mail_letters(self) -> List[Dict[str, object]]:
        letters: List[Dict[str, object]] = []
        claims = getattr(self.state, "owned_wilderness_claims", {}) or {}
        claim_count = len(claims) if isinstance(claims, dict) else 0
        automation = getattr(self.state, "automation_machines", {}) or {}
        automation_count = len(automation) if isinstance(automation, dict) else 0
        victories = int(getattr(self.state, "mine_combat_victories", 0) or 0)
        deepest_floor = int(getattr(self.state, "deepest_mine_floor", 1) or 1)
        spouse_id = str(getattr(self.state, "spouse_npc_id", "") or "")
        spouse_name = self.town_npc_name(spouse_id) if spouse_id else "your spouse"

        def add(mail_id: str, sender: str, subject: str, body: List[str], reward: Optional[Dict[str, object]] = None, condition: bool = True):
            if not condition:
                return
            letters.append({
                "id": mail_id,
                "from": sender,
                "subject": subject,
                "tier": 0,
                "reward": reward or {},
                "body": [subject, "", *body],
            })

        add(
            "progress_first_claim_deed",
            "Town Hall",
            "Your first wilderness deed",
            [
                "The deed office recorded your first wilderness claim. Raw land is work, but it is also room to choose what kind of farm you are building.",
                "",
                "Eli asked us to include a small starter stipend for route markers and early repairs.",
            ],
            {"money": 400, "items": {"Wood": 15, "Stone": 10}},
            claim_count >= 1,
        )
        add(
            "progress_claim_network",
            "Courier Office",
            "Multiple farms on the route",
            [
                "Cora added your farms to the courier route manifest. More land means more choices, but also more places where small supplies prevent long walks.",
                "",
                "Keep shipping bins visible and routes uncluttered. Future delivery work will assume those stops exist.",
            ],
            {"items": {"Field Snack": 2, "Mixed Seeds": 4}},
            claim_count >= 2,
        )
        add(
            "progress_first_automation",
            "Jules",
            "About that first machine",
            [
                "I saw the new farm machine on your records. Good. Automation should take pressure off your hands, not erase your decisions.",
                "",
                "Keep room around it. Machines are easiest to love when you can reach the part that jams.",
                "",
                "- Jules",
            ],
            {"items": {"Coal": 3, "Copper Ore": 2}},
            automation_count >= 1,
        )
        add(
            "progress_first_mine_win",
            "Brom",
            "After your first mine fight",
            [
                "You won a mine fight and came back. That is worth noting once, then turning into maintenance.",
                "",
                "Eat before hard floors. Repair your kit. Do not let victory teach you to be careless.",
                "",
                "- Brom",
            ],
            {"items": {"Field Snack": 1, "Coal": 2}},
            victories >= 1,
        )
        add(
            "progress_deep_floor_warning",
            "Garrick",
            "The mine is changing",
            [
                f"The records say you reached floor {deepest_floor}. Past the first stretch, the mine gets less polite about mistakes.",
                "",
                "Mark exits, save food, and stop pretending every strange sound is only scenery.",
                "",
                "- Garrick",
            ],
            {"items": {"Stone": 12, "Cave Herbs": 1}},
            deepest_floor >= 5,
        )
        add(
            "progress_marriage_recorded",
            "Town Hall",
            "Marriage recorded",
            [
                f"Your marriage to {spouse_name} has been entered into the town record.",
                "",
                "The legal part is simple. The living part is what you make of it every morning.",
            ],
            {"items": {"Honey": 1, "Wildflower": 2}},
            bool(spouse_id),
        )
        add(
            "progress_spouse_move_in",
            spouse_name,
            "I moved a few things",
            [
                "I put my things where they seemed to belong, then moved half of them because a home should be negotiated gently.",
                "",
                "Thank you for making room for me without making it feel like I had to disappear into your routine.",
                "",
                f"- {spouse_name}",
            ],
            {"items": {"Field Snack": 2}},
            bool(spouse_id and getattr(self.state, "spouse_moved_to_farm", False)),
        )
        add(
            "progress_pregnancy_household",
            "Dr. Ivy",
            "A long household season",
            [
                "Pregnancy is not a countdown to skip. Nine months gives a household time to plan, rest, adjust, and ask for help before help is urgent.",
                "",
                "The clinic will keep check-ins on the calendar.",
                "",
                "- Dr. Ivy",
            ],
            {"items": {"Cave Herbs": 2}},
            bool(getattr(self.state, "pregnancy_active", False)),
        )
        add(
            "progress_first_child_home",
            "Tess",
            "A birthday worth writing down",
            [
                "The household records now include a child. That means birthdays, stages, favorite things, and a thousand tiny details that deserve somewhere to live.",
                "",
                "I am sending a simple snack because even ledgers know everyone gets hungry.",
                "",
                "- Tess",
            ],
            {"items": {"Field Snack": 2, "Wildflower": 1}},
            bool(getattr(self.state, "children", []) or []),
        )
        add(
            "progress_first_family_meal",
            "Mae",
            "About that shared table",
            [
                "A shared meal is not fancy, but it is one of the first signs a house has become a household.",
                "",
                "Keep doing the small things on purpose. They last longer than people expect.",
                "",
                "- Mae",
            ],
            {"items": {"Woodland Salad": 1}},
            bool(str(getattr(self.state, "family_last_meal", "") or "")),
        )
        return letters

    def generated_mail(self) -> List[Dict[str, object]]:
        self.normalize_town_npcs()
        letters: List[Dict[str, object]] = [
            {
                "id": "welcome_mailbox",
                "from": "Town Hall",
                "subject": "Welcome to your mailbox",
                "tier": 0,
                "reward": {},
                "body": [
                    "Welcome to your mailbox",
                    "",
                    "This mailbox will collect letters from townspeople.",
                    "",
                    "As your friendships grow, NPCs may send thank-you notes, gifts, tips, or small rewards.",
                    "",
                    "If you need practical instructions, check the bookshelf in your farmhouse.",
                    "",
                    "Letters are generated from your current relationships, so older saves can immediately receive any earned mail.",
                ],
            },
            {
                "id": "tutorial_bookshelf_note",
                "from": "Town Hall",
                "subject": "Guides at your bookshelf",
                "tier": 0,
                "reward": {},
                "body": [
                    "Guides at your bookshelf",
                    "",
                    "The farmhouse bookshelf now holds an organized guide library covering controls, farming, crafting, town life, relationships, family, followers, wilderness travel, combat, property, business, trade, politics, and succession.",
                    "",
                    "The library keeps the same guide index if you prefer to read in town.",
                    "",
                    "Use Z or Enter while facing the bookshelf, then choose Tutorials.",
                    "",
                    "- Town Hall",
                ],
            }
        ]
        for npc in self.state.town_npcs:
            npc_id = str(npc.get("id", ""))
            rel = self.town_npc_relationship(npc_id)
            for tier in [25, 60, 100]:
                if rel >= tier:
                    mail_id = f"friendship_{npc_id}_{tier}"
                    reward = self.friendship_mail_reward_data(npc_id, tier)
                    letters.append({
                        "id": mail_id,
                        "from": str(npc.get("name", "Townsperson")),
                        "subject": self.friendship_mail_subject(npc, tier),
                        "tier": tier,
                        "reward": reward,
                        "body": self.friendship_mail_body(npc, tier),
                    })
        letters.extend(self.progress_mail_letters())
        return letters

    def unread_mail_count(self) -> int:
        read_ids = set(self.state.mail_read_ids or [])
        return sum(1 for letter in self.generated_mail() if str(letter.get("id")) not in read_ids)

    def claim_mail_reward(self, letter: Dict[str, object]) -> str:
        mail_id = str(letter.get("id", ""))
        if not mail_id or mail_id in set(self.state.mail_claimed_ids or []):
            return "Reward already claimed."
        reward = letter.get("reward", {}) or {}
        if not reward:
            self.state.mail_claimed_ids.append(mail_id)
            return "No reward attached."
        money = int(reward.get("money", 0) or 0)
        if money:
            self.state.money += money
        items = reward.get("items", {}) or {}
        if isinstance(items, dict):
            for item, qty in items.items():
                self.state.inventory[item] = self.state.inventory.get(item, 0) + int(qty)
        self.state.mail_claimed_ids.append(mail_id)
        return f"Claimed: {self.reward_description(reward)}."

    def read_mail_letter(self, letter: Dict[str, object]):
        mail_id = str(letter.get("id", ""))
        if mail_id and mail_id not in self.state.mail_read_ids:
            self.state.mail_read_ids.append(mail_id)
        lines = list(letter.get("body", []))
        reward = letter.get("reward", {}) or {}
        lines.extend(["", f"Attached reward: {self.reward_description(reward)}"])
        if mail_id not in set(self.state.mail_claimed_ids or []):
            lines.append(self.claim_mail_reward(letter))
        else:
            lines.append("Reward already claimed.")
        self.vertical_panel_view(str(letter.get("subject", "Letter")), lines, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        self.autosave_with_message(f"Read mail: {letter.get('subject', 'Letter')}")

    def mailbox_menu(self):
        while True:
            letters = self.generated_mail()
            read_ids = set(self.state.mail_read_ids or [])
            claimed_ids = set(self.state.mail_claimed_ids or [])
            items: List[MenuItem] = []
            for letter in letters:
                mail_id = str(letter.get("id", ""))
                unread = mail_id not in read_ids
                unclaimed = mail_id not in claimed_ids and bool(letter.get("reward"))
                marker = "!" if unread else " "
                reward_marker = "*" if unclaimed else " "
                label = f"{marker}{reward_marker} {letter.get('subject', 'Letter')}"
                hint = f"from {letter.get('from', 'Unknown')}"
                items.append(MenuItem(label=label, value=mail_id, enabled=True, hint=hint))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Mailbox", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed mailbox.")
                return
            letter = next((l for l in letters if str(l.get("id", "")) == str(choice.value)), None)
            if letter:
                self.read_mail_letter(letter)
                continue

    def has_mailbox_available(self) -> bool:
        if self.state.inventory.get("Mailbox", 0) > 0:
            return True
        for key, obj in self.state.placed_objects.items():
            if obj == "Mailbox":
                return True
        return False

    def ensure_mailbox(self):
        """Place a default mailbox near the farmhouse for old and new saves."""
        if self.has_mailbox_available():
            return
        x, y = 9, 6
        previous_location = self.state.location
        self.state.location = "Farm"
        try:
            if 0 <= y < self.farm_height() and 0 <= x < self.farm_width():
                if self.base_map[y][x] in [".", ",", "w"] and not self.get_placed_object(x, y):
                    self.set_placed_object(x, y, "Mailbox")
                    return
            self.state.inventory["Mailbox"] = self.state.inventory.get("Mailbox", 0) + 1
        finally:
            self.state.location = previous_location

    def sleep(self, force: bool = False):
        if self.state.fishing_active:
            self.clear_fishing_state()
        s = self.state
        if not force:
            if self.on_house():
                target_x, target_y = self.interaction_target_pos()
                tile = self.active_map()[s.player_y][s.player_x]
                target_tile = self.active_map()[target_y][target_x] if 0 <= target_x < WIDTH and 0 <= target_y < HEIGHT else "#"
                current_obj = self.get_placed_object(s.player_x, s.player_y)
                target_obj = self.get_placed_object(target_x, target_y) if self.in_active_bounds(target_x, target_y) else None
                if tile != "B" and target_tile != "B" and current_obj != "Bed" and target_obj != "Bed":
                    self.set_message("Use Z/Enter on the bed to sleep.")
                    return
            elif self.can_sleep_at_primary_town_residence():
                target_x, target_y = self.interaction_target_pos()
                interior = self.active_map()
                tile = interior[s.player_y][s.player_x]
                target_tile = (
                    interior[target_y][target_x]
                    if 0 <= target_y < len(interior)
                    and 0 <= target_x < len(interior[target_y])
                    else "#"
                )
                if tile != "b" and target_tile != "b":
                    self.set_message("Use Z/Enter beside a bed in your town residence.")
                    return
            elif not self.in_farmhouse(s.player_x, s.player_y):
                self.set_message(
                    "Sleep in your farmhouse or primary town residence. "
                    "Sleeping restores stamina to your current maximum."
                )
                return

        old_season = s.season

        # Add shipped money in the morning.
        earned = s.shipped_today
        if s.shipped_today_items:
            s.last_shipping_report = self.shipping_report_lines(include_prices=True)
        elif earned:
            s.last_shipping_report = [f"Shipment payout: ${earned}"]
        else:
            s.last_shipping_report = []
        s.money += earned
        s.shipped_today = 0
        s.shipped_today_items = {}

        # Advance real calendar date.
        s.month, s.day, s.year = advance_date(s.month, s.day, s.year)
        new_season = s.season

        s.hour = self.wake_time_hour()
        s.minute = 0
        self.reset_travel_follower_work_day()
        s.active_food_buffs = {}
        residence_cap_bonus = self.residence_stamina_bonus()
        family_sleep_bonus = self.family_sleep_bonus()
        s.stamina = self.max_stamina()
        s.natural_stamina_recovery_minutes = 0
        s.natural_health_recovery_minutes = 0
        s.natural_health_recovery_delay_minutes = 0
        s.weather = forecast_weather_for_date(s.month, s.day, s.year)
        freeze_thaw_msg = self.resolve_wilderness_freeze_thaw(old_season, new_season)
        civic_income = self.process_civic_economy()
        restore_combat_state_after_sleep(s)
        self.update_farm_animals_overnight()
        self.reset_town_npc_daily_routines()

        # Overnight crop growth.
        dead = []
        for key, crop in list(self.crops.items()):
            # Real-season rule: crops outside their listed season die overnight.
            if CROP_DATA[crop.name].get("season") != "Any" and CROP_DATA[crop.name]["season"] != s.season:
                dead.append(key)
                continue

            if weather_waters_crops(s.weather):
                crop.watered = True

            if crop.watered:
                crop.care_days += 1
                crop.age += 1
                crop.watered = False
                if crop.age >= CROP_DATA[crop.name]["growth_days"]:
                    crop.ready = True
            else:
                if not crop.ready:
                    crop.missed_water_days += 1

            # Tilled soil dries overnight if no crop is present handled separately elsewhere.

        for key in dead:
            del self.crops[key]

        # Dry tilled/wet soil overnight. Rain will re-wet visible tilled soil.
        for _scope, land_map in self.owned_farm_land_maps():
            for y, row in enumerate(land_map):
                for x, tile in enumerate(row):
                    if tile == "w":
                        land_map[y][x] = ","

        if weather_waters_crops(s.weather):
            for _scope, land_map in self.owned_farm_land_maps():
                for y, row in enumerate(land_map):
                    for x, tile in enumerate(row):
                        if tile == ",":
                            land_map[y][x] = "w"

        sprinkler_watered = self.apply_sprinklers()
        automation_report = self.run_daily_farm_automation(sprinkler_watered=sprinkler_watered)
        mine_rocks, mine_ore, mine_crystals = self.respawn_mine_nodes()
        wilderness_regrown = self.regrow_wilderness_forage(force=(old_season != new_season))
        cave_refreshed = self.refresh_wilderness_caves(force=(old_season != new_season or s.day == 1))
        pond_produced = self.update_fish_ponds_overnight()
        artisan_finished = self.update_artisan_processors_overnight()
        wedding_msg = self.process_scheduled_wedding_overnight(
            interactive=not force
        )
        spouse_death_msg = self.process_spouse_lifespan_overnight(
            interactive=not force
        )
        family_msg = self.update_family_overnight(interactive=not force)
        family_help_msg = self.apply_family_household_help_overnight()
        dynasty_family_msg = self.process_dynasty_family_overnight()
        dynasty_msg = self.process_player_lifespan_overnight()

        if dead:
            season_msg = f" {len(dead)} out-of-season crop(s) died."
        else:
            season_msg = ""

        if old_season != new_season:
            season_msg += f" The season changed to {new_season}."
            season_msg += freeze_thaw_msg

        if sprinkler_watered:
            season_msg += f" Sprinklers watered {sprinkler_watered} tile(s)."

        automation_summary = self.automation_morning_summary(automation_report)
        if automation_summary:
            season_msg += automation_summary

        if mine_rocks or mine_ore or mine_crystals:
            season_msg += f" Mine refreshed: {mine_rocks} rock(s), {mine_ore} ore seam(s), {mine_crystals} crystal(s)."

        if wilderness_regrown:
            season_msg += f" Wilderness regrew {wilderness_regrown} forage item(s)."

        if cave_refreshed:
            season_msg += f" Caves refreshed {cave_refreshed} deposit(s)."

        if pond_produced:
            season_msg += f" Fish ponds prepared {pond_produced} harvest(s)."

        if artisan_finished:
            season_msg += f" Artisan processors finished {artisan_finished} batch(es)."

        if residence_cap_bonus:
            season_msg += (
                f" Primary-home comfort supports +{residence_cap_bonus} "
                "maximum stamina."
            )

        if family_sleep_bonus:
            season_msg += (
                f" Family bond supports +{family_sleep_bonus} "
                "maximum stamina."
            )

        if family_msg:
            season_msg += family_msg

        if family_help_msg:
            season_msg += family_help_msg

        if dynasty_family_msg:
            season_msg += dynasty_family_msg

        if wedding_msg:
            season_msg += wedding_msg

        if spouse_death_msg:
            season_msg += spouse_death_msg

        if dynasty_msg:
            season_msg += dynasty_msg

        if civic_income:
            season_msg += f" Businesses and trade routes paid {civic_income}g."

        calendar_summary = self.daily_calendar_notice_summary()
        if calendar_summary:
            season_msg += calendar_summary

        progression_summary = self.progression_morning_priority_summary()
        if progression_summary:
            season_msg += f" Priority: {progression_summary}."

        self.save(quiet=True)
        if earned:
            self.set_message(f"Slept until {s.date_label}. Shipping paid ${earned}.{season_msg}")
        else:
            self.set_message(f"Slept until {s.date_label}. No shipping payout today.{season_msg}")

    def dynamic_menu_panel_width(self, title: str, items: List[MenuItem], panel_width: int = LEFT_PANEL_WIDTH, footer_lines: Optional[List[str]] = None) -> int:
        rows = [f" {title} "]
        for item in items:
            status = " [unavailable]" if not item.enabled else ""
            rows.append(f"> {item.label}{status}")
        if footer_lines:
            rows.extend(footer_lines)
        rows.extend([" ^ more", " v more", " Z/Enter select", " X/Esc back"])
        return dynamic_panel_width_for_text(rows, panel_width)

    def dynamic_view_panel_width(self, title: str, rows: List[str], panel_width: int = LEFT_PANEL_WIDTH, footer_lines: Optional[List[str]] = None) -> int:
        all_rows = [f" {title} "] + [f" {row}" for row in rows]
        if footer_lines:
            all_rows.extend(footer_lines)
        all_rows.extend([" ^ more", " v more", " W/S scroll", " X/Esc back"])
        return dynamic_panel_width_for_text(all_rows, panel_width)

    def draw_with_left_panel(
        self,
        panel_lines: List[str],
        panel_width: int = LEFT_PANEL_WIDTH,
        context_lines: Optional[List[str]] = None,
    ):
        """Draw the vertical menu panel to the left of the farm map without centering."""
        gutter = " " * GUTTER_WIDTH
        lines: List[str] = []

        lines.extend(self.header_lines())

        farm_lines = self.map_lines()
        max_rows = max(len(panel_lines), len(farm_lines))

        for i in range(max_rows):
            panel = panel_lines[i] if i < len(panel_lines) else ""
            farm = farm_lines[i] if i < len(farm_lines) else ""
            lines.append(pad_to(panel, panel_width) + gutter + farm)

        if context_lines:
            context_width = max(
                40,
                panel_width + GUTTER_WIDTH + MAP_LINE_WIDTH,
            )
            lines.append("-" * context_width)
            lines.extend(
                menu_context_lines(
                    " ".join(
                        str(line)
                        for line in context_lines
                        if str(line).strip()
                    ),
                    "",
                    context_width,
                )
            )

        lines.extend(self.footer_lines())
        frame = "".join("\033[2K" + str(line) + "\n" for line in lines)

        try:
            sys.stdout.write("\033[?25l\033[H" + frame + "\033[J")
            sys.stdout.flush()
            self._terminal_prepared = True
            self._last_draw_frame = frame
            self._force_full_redraw = False
        except Exception:
            clear_screen()
            print(frame, end="")


    def vertical_panel_select(
        self,
        title: str,
        items: List[MenuItem],
        panel_width: int = LEFT_PANEL_WIDTH,
        panel_height: int = LEFT_PANEL_HEIGHT,
        return_back: bool = False,
        hotkeys: Optional[Dict[str, object]] = None,
        hotkey_footer: str = "",
    ) -> Optional[MenuItem]:
        """
        Vertical sidebar menu with scrolling and dynamic width.
        If return_back=True, X/Esc/Q/Tab returns a BACK sentinel MenuItem instead of None.
        """
        if not items:
            return MenuItem(label="Back", value=MENU_BACK) if return_back else None

        # Every nested gameplay menu needs a visible, selectable way out.  Key
        # cancellation still works, but it should never be the only exit.
        items = list(items)
        if return_back and not any(item.value == MENU_BACK for item in items):
            items.append(MenuItem(
                label="Back",
                value=MENU_BACK,
                enabled=True,
                hint="Return to the previous screen without taking an action.",
            ))

        back_label = " B/X/Esc back" if return_back else " B/X/Esc close"
        select_footer = " Z/Enter select"
        if hotkey_footer:
            select_footer += f" | {hotkey_footer}"
        panel_width = self.dynamic_menu_panel_width(
            title,
            items,
            panel_width,
            footer_lines=[select_footer, back_label],
        )
        inner_width = panel_width - 2

        selected = 0
        for i, item in enumerate(items):
            if item.enabled:
                selected = i
                break

        visible_rows = max(4, panel_height - 6)
        scroll_top = 0

        while True:
            if selected < scroll_top:
                scroll_top = selected
            elif selected >= scroll_top + visible_rows:
                scroll_top = selected - visible_rows + 1

            scroll_top = max(0, min(scroll_top, max(0, len(items) - visible_rows)))
            visible = items[scroll_top:scroll_top + visible_rows]

            panel_lines: List[str] = []
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))
            panel_lines.append("|" + pad_to(colorize(fit_text(f" {title} ", inner_width), C.UI_TITLE), inner_width) + "|")

            range_text = f"{selected + 1}/{len(items)}" if len(items) > visible_rows else ""
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))

            panel_lines.append("|" + pad_to(" ^ more" if scroll_top > 0 else "", inner_width) + "|")

            for offset, item in enumerate(visible):
                actual_index = scroll_top + offset
                cursor = ">" if actual_index == selected else " "
                disabled = not item.enabled

                raw = f"{cursor} {item.label}"

                if actual_index == selected and range_text:
                    max_text = inner_width - len(range_text) - 1
                    raw = fit_text(raw, max_text) + " " + range_text
                else:
                    raw = fit_text(raw, inner_width)

                if disabled:
                    raw = colorize(raw, C.DIM)
                elif actual_index == selected:
                    raw = colorize(raw, C.UI_SELECTED)

                panel_lines.append("|" + pad_to(raw, inner_width) + "|")

            while len(panel_lines) < panel_height - 3:
                panel_lines.append("|" + pad_to("", inner_width) + "|")

            panel_lines.append("|" + pad_to(" v more" if scroll_top + visible_rows < len(items) else "", inner_width) + "|")
            selected_hint = items[selected].hint if 0 <= selected < len(items) else ""
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))
            panel_lines.append("|" + pad_to(select_footer, inner_width) + "|")
            panel_lines.append("|" + pad_to(back_label, inner_width) + "|")
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))

            self.draw_with_left_panel(
                panel_lines,
                panel_width,
                context_lines=[selected_hint] if selected_hint else None,
            )

            key = normalize_key(read_key())
            if hotkeys and key in hotkeys:
                return MenuItem(label=str(key), value=hotkeys[key], enabled=True)
            if key in ["\t", "\x1b", "q", "x", "b"]:
                return MenuItem(label="Back", value=MENU_BACK) if return_back else None
            elif key in ["w", "UP"]:
                selected = (selected - 1) % len(items)
            elif key in ["s", "DOWN"]:
                selected = (selected + 1) % len(items)
            elif key in ["a", "LEFT"]:
                selected = max(0, selected - visible_rows)
            elif key in ["d", "RIGHT"]:
                selected = min(len(items) - 1, selected + visible_rows)
            elif key in MENU_CONFIRM_KEYS:
                if items[selected].enabled:
                    return items[selected]


    def vertical_panel_view(
        self,
        title: str,
        rows: List[str],
        panel_width: int = LEFT_PANEL_WIDTH,
        panel_height: int = LEFT_PANEL_HEIGHT,
    ):
        """Scrollable left panel viewer with dynamic width."""
        panel_width = self.dynamic_view_panel_width(
            title,
            rows,
            panel_width,
            footer_lines=[" W/S scroll", " B/X/Esc back"],
        )
        inner_width = panel_width - 2
        visible_rows = max(4, panel_height - 6)
        scroll_top = 0
        display_rows = wrap_panel_rows([(" " + str(row)) if str(row) else "" for row in rows], inner_width)

        while True:
            visible = display_rows[scroll_top:scroll_top + visible_rows]
            panel_lines: List[str] = []
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))
            panel_lines.append("|" + pad_to(colorize(fit_text(f" {title} ", inner_width), C.UI_TITLE), inner_width) + "|")
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))

            panel_lines.append("|" + pad_to(" ^ more" if scroll_top > 0 else "", inner_width) + "|")

            for row in visible:
                panel_lines.append("|" + pad_to(fit_text(str(row), inner_width), inner_width) + "|")

            while len(panel_lines) < panel_height - 3:
                panel_lines.append("|" + pad_to("", inner_width) + "|")

            panel_lines.append("|" + pad_to(" v more" if scroll_top + visible_rows < len(display_rows) else "", inner_width) + "|")
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))
            panel_lines.append("|" + pad_to(" W/S scroll", inner_width) + "|")
            panel_lines.append("|" + pad_to(" B/X/Esc back", inner_width) + "|")
            panel_lines.append(colorize("+" + "-" * inner_width + "+", C.UI_BORDER))

            self.draw_with_left_panel(panel_lines, panel_width)

            key = normalize_key(read_key())
            if key in ["\t", "\x1b", "q", "x", "b"] + MENU_CONFIRM_KEYS:
                return
            elif key in ["w", "UP"]:
                scroll_top = max(0, scroll_top - 1)
            elif key in ["s", "DOWN"]:
                scroll_top = min(max(0, len(display_rows) - visible_rows), scroll_top + 1)
            elif key in ["a", "LEFT"]:
                scroll_top = max(0, scroll_top - visible_rows)
            elif key in ["d", "RIGHT"]:
                scroll_top = min(max(0, len(display_rows) - visible_rows), scroll_top + visible_rows)


    def vertical_quantity_select(
        self,
        title: str,
        unit_label: str,
        unit_price: int,
        max_qty: int,
        start_qty: int = 1,
        panel_width: int = LEFT_PANEL_WIDTH,
        panel_height: int = LEFT_PANEL_HEIGHT,
        return_back: bool = False,
    ) -> int | str:
        """Sidebar quantity selector matching the inventory/shop sidebar style."""
        if max_qty <= 0:
            return 0

        qty = max(1, min(start_qty, max_qty))
        priced = int(unit_price) > 0
        base_rows = [f"Item: {unit_label}"]
        if priced:
            base_rows.append(f"Unit: ${unit_price}")
        base_rows.extend([
            f"Qty:  {qty}",
            f"Max:  {max_qty}",
        ])
        if priced:
            base_rows.append(f"Cost: ${qty * unit_price}")
        base_rows.extend([
            "A/D: -/+ 1",
            "W/S: +/- 5",
            "Z/Enter confirm",
            "B/X/Esc back",
        ])
        panel_width = self.dynamic_view_panel_width(title, base_rows, panel_width)
        inner_width = panel_width - 2

        while True:
            rows = [f"Item: {unit_label}"]
            if priced:
                rows.append(f"Unit: ${unit_price}")
            rows.extend([
                "",
                f"Qty:  {qty}",
                f"Max:  {max_qty}",
            ])
            if priced:
                rows.append(f"Cost: ${qty * unit_price}")
            rows.extend([
                "",
                "A/D: -/+ 1",
                "W/S: +/- 5",
            ])

            panel_lines: List[str] = []
            panel_lines.append("+" + "-" * inner_width + "+")
            panel_lines.append("|" + pad_to(fit_text(f" {title} ", inner_width), inner_width) + "|")
            panel_lines.append("+" + "-" * inner_width + "+")

            for row in rows[:panel_height - 6]:
                panel_lines.append("|" + pad_to(fit_text(" " + row, inner_width), inner_width) + "|")

            while len(panel_lines) < panel_height - 3:
                panel_lines.append("|" + pad_to("", inner_width) + "|")

            panel_lines.append("+" + "-" * inner_width + "+")
            panel_lines.append("|" + pad_to(" Z/Enter confirm", inner_width) + "|")
            panel_lines.append("|" + pad_to(" B/X/Esc back", inner_width) + "|")
            panel_lines.append("+" + "-" * inner_width + "+")

            self.draw_with_left_panel(panel_lines, panel_width)

            key = normalize_key(read_key())
            if key in ["\t", "\x1b", "q", "x", "b"]:
                return MENU_BACK if return_back else 0
            elif key in ["a", "LEFT"]:
                qty = max(1, qty - 1)
            elif key in ["d", "RIGHT"]:
                qty = min(max_qty, qty + 1)
            elif key in ["w", "UP"]:
                qty = min(max_qty, qty + 5)
            elif key in ["s", "DOWN"]:
                qty = max(1, qty - 5)
            elif key in MENU_CONFIRM_KEYS:
                return qty


    def compact_inventory_panel_select(self, title: str, items: List[MenuItem], footer: str = "") -> Optional[MenuItem]:
        """Compatibility wrapper for the new scrolling vertical panel."""
        return self.vertical_panel_select(title, items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

    def surrounding_tiles(self, x: int, y: int) -> List[Tuple[int, int]]:
        tiles: List[Tuple[int, int]] = []
        max_x = self.active_map_width()
        max_y = self.active_map_height()
        for dy in [-1, 0, 1]:
            for dx in [-1, 0, 1]:
                if dx == 0 and dy == 0:
                    continue
                nx, ny = x + dx, y + dy
                if 0 <= nx < max_x and 0 <= ny < max_y:
                    tiles.append((nx, ny))
        return tiles

    def area_sow_selected_seed(self):
        """Plant selected seed on all surrounding tilled/wet tiles when possible."""
        if not self.on_farm_work_land():
            self.set_message("You can only sow seeds on owned farm land.")
            return
        land_map = self.active_farm_work_map()
        s = self.state
        name = s.selected_seed
        if not name or name not in CROP_DATA:
            self.set_message("Select a seed from inventory first.")
            return

        if not self.crop_can_grow_now(name):
            self.set_message(f"{name} grows in {CROP_DATA[name]['season']}, not {s.season}.")
            return

        seed_item = self.seed_item_for_crop(name)
        available = s.inventory.get(seed_item, 0)
        if available <= 0:
            self.set_message(f"You do not have any {seed_item}.")
            return

        planted = 0
        skipped = 0
        for x, y in self.surrounding_tiles(s.player_x, s.player_y):
            if s.inventory.get(seed_item, 0) <= 0:
                break

            if land_map[y][x] not in [",", "w"]:
                skipped += 1
                continue
            if self.get_crop(x, y):
                skipped += 1
                continue
            if self.get_placed_object(x, y):
                skipped += 1
                continue

            watered = land_map[y][x] == "w"
            self.set_crop(x, y, Crop(name=name, watered=watered))
            s.inventory[seed_item] -= 1
            planted += 1

        remaining = s.inventory.get(seed_item, 0)
        if planted:
            if remaining <= 0:
                extra = " No seeds left."
            elif skipped:
                extra = f" Skipped {skipped} blocked/non-tilled tile(s)."
            else:
                extra = ""
            self.autosave_with_message(f"Area sowed {planted} {name} seed(s).{extra}")
        else:
            self.set_message("No surrounding empty tilled tiles could be planted.")

    def seed_item_for_crop(self, crop_name: str) -> str:
        if crop_name == "Ancient Fruit":
            return "Ancient Seed"
        return f"{crop_name} Seeds"

    def crop_name_for_seed_item(self, item_name: str) -> Optional[str]:
        if item_name == "Ancient Seed":
            return "Ancient Fruit"
        if item_name.endswith(" Seeds"):
            crop_name = item_name[:-6]
            if crop_name in CROP_DATA:
                return crop_name
        return None

    def crop_can_grow_now(self, crop_name: str) -> bool:
        season = CROP_DATA[crop_name].get("season")
        return season == "Any" or season == self.state.season

    def owned_seed_names(self) -> List[str]:
        """Crop names for seeds currently in inventory."""
        names: List[str] = []
        for crop_name in CROP_DATA:
            seed_item = self.seed_item_for_crop(crop_name)
            if self.state.inventory.get(seed_item, 0) > 0:
                names.append(crop_name)
        return names


    def cycle_selected_seed(self, direction: int = 1):
        """Cycle through owned seed types with 1/2."""
        seeds = self.owned_seed_names()
        if not seeds:
            self.set_message("You do not have any seeds to cycle through.")
            return

        current = self.state.selected_seed
        if len(seeds) == 1:
            next_seed = seeds[0]
            self.state.selected_seed = next_seed
            self.state.selected_tool_index = TOOLS.index("Seeds")
            seed_item = self.seed_item_for_crop(next_seed)
            qty = self.state.inventory.get(seed_item, 0)
            self.set_message(f"Selected {seed_item} x{qty}. No other seed types owned.")
            return

        if current in seeds:
            idx = seeds.index(current)
            next_seed = seeds[(idx + direction) % len(seeds)]
        else:
            next_seed = seeds[0]

        self.state.selected_seed = next_seed
        self.state.selected_tool_index = TOOLS.index("Seeds")
        seed_item = self.seed_item_for_crop(next_seed)
        qty = self.state.inventory.get(seed_item, 0)
        self.autosave_with_message(f"Selected {seed_item} x{qty}.")


    def on_off(self, value: bool) -> str:
        return "on" if value else "off"

    def time_speed_key(self) -> str:
        speed = str(getattr(self.state, "time_speed", DEFAULT_TIME_SPEED) or DEFAULT_TIME_SPEED)
        return speed if speed in TIME_SPEED_OPTIONS else DEFAULT_TIME_SPEED

    def time_speed_label(self) -> str:
        speed = self.time_speed_key()
        seconds = float(TIME_SPEED_REAL_SECONDS.get(speed, GAME_MINUTE_REAL_SECONDS))
        return f"{speed} ({seconds:g}s/min)"

    def cycle_time_speed_setting(self):
        current = self.time_speed_key()
        index = TIME_SPEED_OPTIONS.index(current) if current in TIME_SPEED_OPTIONS else 0
        self.state.time_speed = TIME_SPEED_OPTIONS[(index + 1) % len(TIME_SPEED_OPTIONS)]
        self.autosave_with_message(f"Clock speed: {self.time_speed_label()}.")

    def wake_time_hour(self) -> int:
        try:
            return max(4, min(12, int(getattr(self.state, "wake_hour", 7))))
        except (TypeError, ValueError):
            return 7

    def wake_time_label(self) -> str:
        hour = self.wake_time_hour()
        return f"{hour}:00 AM" if hour < 12 else "12:00 PM"

    def cycle_wake_time_setting(self):
        hour = self.wake_time_hour()
        self.state.wake_hour = 4 if hour >= 12 else hour + 1
        self.autosave_with_message(f"Wake-up time: {self.wake_time_label()}.")

    def game_minute_real_seconds(self) -> float:
        speed = self.time_speed_key()
        return max(0.1, float(TIME_SPEED_REAL_SECONDS.get(speed, GAME_MINUTE_REAL_SECONDS)))

    def startup_settings_snapshot(self) -> Dict[str, object]:
        return {
            "color_enabled": bool(self.state.color_enabled),
            "ambient_visuals_enabled": bool(self.state.ambient_visuals_enabled),
            "high_contrast_enabled": bool(self.state.high_contrast_enabled),
            "detailed_glyphs_enabled": bool(self.state.detailed_glyphs_enabled),
            "show_target_info": bool(self.state.show_target_info),
            "show_control_hints": bool(self.state.show_control_hints),
            "live_time_enabled": bool(self.state.live_time_enabled),
            "time_speed": self.time_speed_key(),
            "wake_hour": self.wake_time_hour(),
            "aging_and_death_enabled": bool(
                self.state.aging_and_death_enabled
            ),
            "shop_auto_open_enabled": bool(self.state.shop_auto_open_enabled),
            "bin_auto_open_enabled": bool(self.state.bin_auto_open_enabled),
            "tool_target_mode": str(self.state.tool_target_mode),
        }

    def apply_startup_settings_snapshot(self, settings: Dict[str, object]):
        self.state.color_enabled = bool(settings.get("color_enabled", self.state.color_enabled))
        set_color_enabled(self.state.color_enabled)
        self.state.ambient_visuals_enabled = bool(
            settings.get("ambient_visuals_enabled", self.state.ambient_visuals_enabled)
        )
        self.state.high_contrast_enabled = bool(
            settings.get("high_contrast_enabled", self.state.high_contrast_enabled)
        )
        self.state.detailed_glyphs_enabled = bool(
            settings.get("detailed_glyphs_enabled", self.state.detailed_glyphs_enabled)
        )
        self.state.show_target_info = bool(settings.get("show_target_info", self.state.show_target_info))
        self.state.show_control_hints = bool(settings.get("show_control_hints", self.state.show_control_hints))
        self.state.live_time_enabled = bool(settings.get("live_time_enabled", self.state.live_time_enabled))
        speed = str(settings.get("time_speed", getattr(self.state, "time_speed", DEFAULT_TIME_SPEED)))
        self.state.time_speed = speed if speed in TIME_SPEED_OPTIONS else DEFAULT_TIME_SPEED
        try:
            self.state.wake_hour = max(4, min(12, int(settings.get("wake_hour", getattr(self.state, "wake_hour", 7)))))
        except (TypeError, ValueError):
            self.state.wake_hour = 7
        self.state.aging_and_death_enabled = bool(
            settings.get(
                "aging_and_death_enabled",
                self.state.aging_and_death_enabled,
            )
        )
        auto_open = bool(settings.get("shop_auto_open_enabled", self.state.shop_auto_open_enabled))
        self.state.shop_auto_open_enabled = auto_open
        self.state.bin_auto_open_enabled = bool(settings.get("bin_auto_open_enabled", auto_open))
        target_mode = str(settings.get("tool_target_mode", self.state.tool_target_mode))
        self.state.tool_target_mode = target_mode if target_mode in VALID_TOOL_TARGET_MODES else "FRONT"


    def startup_settings_menu(self):
        while True:
            items = [
                MenuItem(label="Target info line", value="target_info", enabled=True, hint=self.on_off(self.state.show_target_info)),
                MenuItem(label="Control hint line", value="control_hints", enabled=True, hint=self.on_off(self.state.show_control_hints)),
                MenuItem(label="Color display", value="color", enabled=True, hint=self.on_off(self.state.color_enabled)),
                MenuItem(label="Ambient animation/lighting", value="ambient_visuals", enabled=True, hint=self.on_off(self.state.ambient_visuals_enabled)),
                MenuItem(label="High-contrast palette", value="high_contrast", enabled=True, hint=self.on_off(self.state.high_contrast_enabled)),
                MenuItem(label="Detailed map glyphs", value="detailed_glyphs", enabled=True, hint=self.on_off(self.state.detailed_glyphs_enabled)),
                MenuItem(label="Live time/weather", value="live", enabled=True, hint=self.on_off(self.state.live_time_enabled)),
                MenuItem(label="Clock speed", value="time_speed", enabled=True, hint=self.time_speed_label()),
                MenuItem(label="Wake-up time", value="wake_time", enabled=True, hint=self.wake_time_label()),
                MenuItem(label="Aging & natural death", value="aging", enabled=True, hint=self.on_off(self.state.aging_and_death_enabled)),
                MenuItem(label="Auto-open shop/bin", value="auto_open", enabled=True, hint=self.on_off(self.state.shop_auto_open_enabled and self.state.bin_auto_open_enabled)),
                MenuItem(label="Tool targeting", value="target_mode", enabled=True, hint=self.target_mode_label()),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = menu_select(
                "Settings",
                items,
                footer="Arrow keys/WASD move | Z/Enter select | X/Esc/Q back",
                extra_lines=["These settings apply before a new game is created."],
            )
            if choice is None or choice.value == MENU_BACK:
                return
            if choice.value == "target_info":
                self.state.show_target_info = not self.state.show_target_info
            elif choice.value == "control_hints":
                self.state.show_control_hints = not self.state.show_control_hints
            elif choice.value == "color":
                set_color_enabled(not get_color_enabled())
                self.state.color_enabled = get_color_enabled()
            elif choice.value == "ambient_visuals":
                self.state.ambient_visuals_enabled = not self.state.ambient_visuals_enabled
            elif choice.value == "high_contrast":
                self.state.high_contrast_enabled = not self.state.high_contrast_enabled
            elif choice.value == "detailed_glyphs":
                self.state.detailed_glyphs_enabled = not self.state.detailed_glyphs_enabled
            elif choice.value == "live":
                self.state.live_time_enabled = not self.state.live_time_enabled
            elif choice.value == "time_speed":
                current = self.time_speed_key()
                index = TIME_SPEED_OPTIONS.index(current) if current in TIME_SPEED_OPTIONS else 0
                self.state.time_speed = TIME_SPEED_OPTIONS[(index + 1) % len(TIME_SPEED_OPTIONS)]
            elif choice.value == "wake_time":
                self.state.wake_hour = 4 if self.wake_time_hour() >= 12 else self.wake_time_hour() + 1
            elif choice.value == "aging":
                self.state.aging_and_death_enabled = (
                    not self.state.aging_and_death_enabled
                )
            elif choice.value == "auto_open":
                new_value = not (self.state.shop_auto_open_enabled and self.state.bin_auto_open_enabled)
                self.state.shop_auto_open_enabled = new_value
                self.state.bin_auto_open_enabled = new_value
            elif choice.value == "target_mode":
                self.state.tool_target_mode = "STANDING" if self.state.tool_target_mode == "FRONT" else "FRONT"

