    def draw_birthday_picker_panel(self, view_month: int, cursor_day: int):
        days = days_in_month(view_month, 1)
        first_weekday = self.month_first_weekday_index(view_month, 1)

        self.invalidate_draw_cache()
        clear_screen()
        title = f"Choose Birthday: {MONTH_NAMES[view_month]}"
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to(title.center(50), 50) + "|", 52)
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to(" Mo  Tu  We  Th  Fr  Sa  Su", 50) + "|", 52)

        cells: List[str] = ["    "] * first_weekday
        for day in range(1, days + 1):
            if day == cursor_day:
                cell = colorize(f"[{day:2d}]", C.PLAYER)
            else:
                cell = f" {day:2d} "
            cells.append(cell)

        while len(cells) % 7 != 0:
            cells.append("    ")

        for i in range(0, len(cells), 7):
            row = "".join(cells[i:i + 7])
            self.centered_print("|" + pad_to(row, 50) + "|", 52)

        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to(f"Selected: {format_birthday(view_month, cursor_day)}", 50) + "|", 52)
        self.centered_print("|" + pad_to(f"Season: {season_for_month(view_month)}", 50) + "|", 52)
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to("Arrows/WASD move | Q/E month | Enter choose", 50) + "|", 52)
        self.centered_print("|" + pad_to("Esc/Tab backs out", 50) + "|", 52)
        self.centered_print("+" + "-" * 50 + "+", 52)

    def choose_player_birthday_menu(self) -> Optional[Tuple[int, int]]:
        view_month, cursor_day = self.birthday_tuple_from(self.state.player_birthday_month, self.state.player_birthday_day)
        while True:
            cursor_day = max(1, min(days_in_month(view_month, 1), cursor_day))
            self.draw_birthday_picker_panel(view_month, cursor_day)
            key = normalize_key(read_key())

            if key in ["\t", "\x1b"]:
                return None
            if key in ["\r", "\n", " ", "z"]:
                return view_month, cursor_day
            if key == "q":
                old_day = cursor_day
                view_month = 12 if view_month <= 1 else view_month - 1
                cursor_day = min(old_day, days_in_month(view_month, 1))
            elif key == "e":
                old_day = cursor_day
                view_month = 1 if view_month >= 12 else view_month + 1
                cursor_day = min(old_day, days_in_month(view_month, 1))
            elif key in ["a", "LEFT"]:
                if cursor_day <= 1:
                    view_month = 12 if view_month <= 1 else view_month - 1
                    cursor_day = days_in_month(view_month, 1)
                else:
                    cursor_day -= 1
            elif key in ["d", "RIGHT"]:
                if cursor_day >= days_in_month(view_month, 1):
                    view_month = 1 if view_month >= 12 else view_month + 1
                    cursor_day = 1
                else:
                    cursor_day += 1
            elif key in ["w", "UP"]:
                cursor_day = self.move_calendar_cursor(cursor_day, -7, view_month, 1)
            elif key in ["s", "DOWN"]:
                cursor_day = self.move_calendar_cursor(cursor_day, 7, view_month, 1)

    def character_creation_menu(self) -> bool:
        name = text_entry_menu("Character Creation", "What is your name?", self.state.player_name, 16)
        if name is None:
            return False
        sex = self.choose_player_sex_menu()
        if sex is None:
            return False
        color = self.choose_player_color_menu()
        if color is None:
            return False
        birthday = self.choose_player_birthday_menu()
        if birthday is None:
            return False
        birthday_month, birthday_day = birthday
        starting_age = self.choose_player_starting_age_menu()
        if starting_age is None:
            return False
        starting_class = self.choose_player_starting_class_menu()
        if starting_class is None:
            return False
        birthday_passed = (
            birthday_month,
            birthday_day,
        ) <= (
            int(self.state.month),
            int(self.state.day),
        )
        birth_year = (
            int(self.state.year) - starting_age
            if birthday_passed
            else int(self.state.year) - starting_age - 1
        )

        preview = [
            f"Name: {name}",
            f"Sex: {sex}",
            f"Color: {colorize('@', dict(PLAYER_COLOR_OPTIONS).get(color, C.PLAYER))} {color}",
            f"Born: {format_date(birthday_month, birthday_day, birth_year)}",
            f"Starting age: {starting_age}",
            f"Combat class: {starting_class}",
            "",
            "Marriage will be available with opposite-sex romance candidates.",
        ]
        items = [
            MenuItem(label="Start game", value="start", enabled=True),
            MenuItem(label="Back", value=MENU_BACK, enabled=True),
        ]
        choice = menu_select("Confirm Character", items, footer="Enter starts the farm.", extra_lines=preview)
        if choice is None or choice.value == MENU_BACK:
            return False

        self.state.player_name = name
        self.state.player_sex = sex
        self.state.player_color = color
        self.state.player_birthday_month = birthday_month
        self.state.player_birthday_day = birthday_day
        self.state.player_birth_year = birth_year
        self.state.player_generation = 1
        self.state.dynasty_name = f"{name} Family"
        self.state.player_lifespan_age = self.dynasty_lifespan_for_identity(
            name,
            birth_year,
            1,
        )
        self.state.player_frozen_age = (
            starting_age
            if not self.state.aging_and_death_enabled
            else 0
        )
        self.state.player_background = "First-Generation Farmer"
        self.state.player_starting_class = starting_class
        self.state.message = f"Welcome, {name}. Press H for help or K for calendar."
        return True

    def start_new_game_from_menu(self) -> bool:
        settings = self.startup_settings_snapshot()
        self.__init__()
        # New dynasties use a mature calendar epoch so adult birth years are
        # ordinary positive years. Existing saves retain their original years.
        self.state.year = 100
        self.apply_startup_settings_snapshot(settings)
        if not self.character_creation_menu():
            self.__init__()
            self.apply_startup_settings_snapshot(settings)
            return False
        self.save(quiet=True, path=SAVE_PATH)
        append_debug_log("Started new game from main menu.")
        return True

    def confirm_new_game_from_menu(self) -> bool:
        if not SAVE_PATH.exists():
            return True
        items = [
            MenuItem(label="Start new game", value="start", enabled=True, hint="Replaces the current save."),
            MenuItem(label="Back", value=MENU_BACK, enabled=True),
        ]
        choice = menu_select(
            "New Game",
            items,
            footer="Starting a new game replaces the current save.",
            extra_lines=[
                f"Current save: {self.current_save_summary()}",
                "Use Load Game first if you want to keep another slot active.",
            ],
        )
        return bool(choice is not None and choice.value == "start")

    def startup_load_game_menu(self) -> bool:
        while True:
            items = [
                MenuItem(label="Current save", value="current", enabled=SAVE_PATH.exists(), hint=self.current_save_summary()),
            ]
            for i in range(1, SAVE_SLOT_COUNT + 1):
                summary = self.slot_summary(i)
                items.append(MenuItem(label=f"Slot {i}", value=f"slot:{i}", enabled=summary != "empty", hint=summary))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = menu_select("Load Game", items, footer="Choose a save to load.")
            if choice is None or choice.value == MENU_BACK:
                return False
            if choice.value == "current":
                return bool(self.load())
            raw = str(choice.value)
            if raw.startswith("slot:"):
                slot_number = int(raw.split(":", 1)[1])
                return bool(self.load_slot(slot_number))

    def confirm_startup_delete_path(self, title: str, path: Path, summary: str) -> bool:
        items = [
            MenuItem(label="Delete game", value="delete", enabled=True, hint=summary),
            MenuItem(label="Back", value=MENU_BACK, enabled=True),
        ]
        choice = menu_select(title, items, footer="This cannot be undone.", extra_lines=[summary])
        if choice is None or choice.value != "delete":
            return False
        try:
            if path.exists():
                path.unlink()
            self.state.message = "Save deleted."
            return True
        except Exception as exc:
            self.state.message = f"Could not delete save: {exc}"
            return False

    def startup_delete_game_menu(self):
        while True:
            items = [
                MenuItem(label="Current save", value="current", enabled=SAVE_PATH.exists(), hint=self.current_save_summary()),
            ]
            for i in range(1, SAVE_SLOT_COUNT + 1):
                summary = self.slot_summary(i)
                items.append(MenuItem(label=f"Slot {i}", value=f"slot:{i}", enabled=summary != "empty", hint=summary))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = menu_select("Delete Game", items, footer="Choose a save to delete.")
            if choice is None or choice.value == MENU_BACK:
                return
            if choice.value == "current":
                self.confirm_startup_delete_path("Delete Current Save", SAVE_PATH, self.current_save_summary())
                continue
            raw = str(choice.value)
            if raw.startswith("slot:"):
                slot_number = int(raw.split(":", 1)[1])
                self.confirm_startup_delete_path(f"Delete Slot {slot_number}", save_slot_path(slot_number), self.slot_summary(slot_number))

    def startup_main_menu(self) -> bool:
        while True:
            current_summary = self.current_save_summary()
            continue_hint = current_summary if SAVE_PATH.exists() else "No current save."
            items = [
                MenuItem(label="Continue game", value="continue", enabled=SAVE_PATH.exists(), hint=continue_hint),
                MenuItem(label="New game", value="new", enabled=True, hint="Start character creation."),
                MenuItem(label="Load game", value="load", enabled=self.any_save_file_exists(), hint="Choose current save or save slot."),
                MenuItem(label="Delete game", value="delete", enabled=self.any_save_file_exists(), hint="Delete current save or save slot."),
                MenuItem(label="Settings", value="settings", enabled=True, hint="Display and control defaults."),
                MenuItem(label="Custom Content", value="custom", enabled=True, hint="Create abilities, classes, enemies, gear, maps, rooms, and buildings."),
            ]
            choice = menu_select(
                GAME_TITLE,
                items,
                footer="Arrow keys/WASD move | Z/Enter select | X/Esc/Q quit",
                extra_lines=[
                    f"Version {GAME_VERSION}",
                    "A terminal life-sim RPG.",
                    f"Current save: {current_summary}",
                ],
            )
            if choice is None:
                self.running = False
                return False
            if choice.value == "continue":
                if SAVE_PATH.exists():
                    if self.load():
                        return True
                    continue
                continue
            if choice.value == "new":
                if self.confirm_new_game_from_menu() and self.start_new_game_from_menu():
                    return True
                continue
            if choice.value == "load":
                if self.startup_load_game_menu():
                    return True
                continue
            if choice.value == "delete":
                self.startup_delete_game_menu()
                continue
            if choice.value == "settings":
                self.startup_settings_menu()
                continue
            if choice.value == "custom":
                self.startup_custom_content_menu()
                continue

    def toggle_color_setting(self):
        set_color_enabled(not get_color_enabled())
        self.state.color_enabled = get_color_enabled()
        self.autosave_with_message("Color display enabled." if self.state.color_enabled else "Color display disabled.")

    def toggle_auto_open_setting(self):
        new_value = not (self.state.shop_auto_open_enabled and self.state.bin_auto_open_enabled)
        self.state.shop_auto_open_enabled = new_value
        self.state.bin_auto_open_enabled = new_value
        status = "enabled" if new_value else "disabled"
        self.autosave_with_message(f"Auto-open shop/bin {status}.")

    def toggle_target_info_setting(self):
        self.state.show_target_info = not self.state.show_target_info
        state = "shown" if self.state.show_target_info else "hidden"
        self.autosave_with_message(f"Target info line {state}.")

    def toggle_control_hints_setting(self):
        self.state.show_control_hints = not self.state.show_control_hints
        state = "shown" if self.state.show_control_hints else "hidden"
