    def tactical_mission_roster_names(self) -> List[str]:
        names = set(MINE_ENEMY_PROFILES.keys())
        for preset in self.all_tactical_mission_presets():
            for enemy_name in preset.get("enemies", []) if isinstance(preset, dict) else []:
                names.add(self.combat_enemy_base_name(enemy_name))
        try:
            from ascii_farmstead_custom_extended import custom_enemy_records

            names.update(
                str(record.get("name", ""))
                for record in custom_enemy_records()
                if str(record.get("name", ""))
            )
        except (ImportError, OSError, TypeError, ValueError):
            pass
        return sorted(name for name in names if name)

    def combat_enemy_floor_hint(self, enemy_name: str) -> str:
        profile = mine_enemy_profile(enemy_name)
        weights = profile.get("weight_by_tier", []) if isinstance(profile, dict) else []
        ranges = ["1-5", "6-11", "12-19", "20-27", "28-35", "36+"]
        likely = [
            ranges[index]
            for index, weight in enumerate(weights if isinstance(weights, list) else [])
            if index < len(ranges) and int(weight or 0) > 0
        ]
        return ", ".join(likely) if likely else "mission-only or rare"

