    def combat_bestiary_lines(self, enemy_name: str) -> List[str]:
        base = self.combat_enemy_base_name(enemy_name)
        profile = mine_enemy_profile(base) if base in MINE_ENEMY_PROFILES else {}
        loot = tactical_loot_profile_for_enemy(base)
        seen = base in set(getattr(self.state, "combat_bestiary_seen", []) or [])
        defeated = int((getattr(self.state, "combat_bestiary_defeated", {}) or {}).get(base, 0) or 0)
        prep = self.combat_enemy_prep_profile(base)
        lines = [
            base,
            "",
            f"Seen: {'yes' if seen else 'no'}",
            f"Defeated: {defeated}",
            f"Likely Floors: {self.combat_enemy_floor_hint(base)}",
        ]
        if profile:
            lines.extend(["", str(profile.get("description", "")), f"Mine EXP: {profile.get('exp_reward', 0)}"])
        lines.extend([
            "",
            "Weaknesses and Prep:",
            "Weak to: " + str(prep.get("weakness", "")),
            "Threat: " + str(prep.get("danger", "")),
            "Bring: " + str(prep.get("prep", "")),
        ])
        lines.extend([
            "",
            "Likely drops:",
            "Common: " + self.tactical_loot_preview_text(self.tactical_int_dict(loot.get("common", {}))),
            "Uncommon: " + self.tactical_loot_preview_text(self.tactical_int_dict(loot.get("uncommon", {}))),
            "Rare: " + self.tactical_loot_preview_text(self.tactical_int_dict(loot.get("rare", {}))),
        ])
        sample = self.museum_bestiary_sample_for_enemy(base)
        sample_id = self.museum_record_id("bestiary", sample, base)
        lines.extend(["", f"Museum specimen: {sample} ({'donated' if sample_id in self.museum_donated_record_ids() else 'not donated'})"])
        if not seen:
            lines.extend(["", "This entry will fill in after you encounter the enemy."])
        return lines

