    def combat_mission_identity_for_id(self, mission_id: str) -> Dict[str, str]:
        mission_id = str(mission_id or "")
        for preset in tactical_mission_builtin_presets():
            name = str(preset.get("name", "Combat Mission") or "Combat Mission")
            if self.tactical_slug(name, "combat-mission") == mission_id:
                return self.combat_mission_identity(mission_id, name, str(preset.get("theme", "") or ""))
        return self.combat_mission_identity(mission_id, mission_id, "")

    def combat_mission_estimated_minutes(self, enemy_names: List[str]) -> int:
        return max(35, min(90, 35 + 6 * max(1, len(enemy_names or []))))

    def apply_combat_mission_impact(self, mission_id: str, first_clear: bool) -> List[str]:
        if not first_clear:
            return []
        identity = self.combat_mission_identity_for_id(mission_id)
        poster_id = str(identity.get("poster_id", "") or "")
        lines: List[str] = []
        if poster_id:
            gained = self.adjust_town_npc_relationship(poster_id, 4)
            if gained:
                lines.append(f"{self.request_npc_name(poster_id)} friendship +{gained}.")
        for npc in self.active_town_npcs():
            npc_id = str(npc.get("id", "") or "")
            if npc_id and npc_id != poster_id:
                self.adjust_town_npc_relationship(npc_id, 1)
        lines.append("Town confidence +1 from a first contract clear.")
        return lines

    def tactical_enemy_reward_estimate(self, enemy_names: List[str]) -> Dict[str, int]:
        estimate: Dict[str, int] = {}
        for raw_name in enemy_names or []:
            name = " ".join(str(raw_name or "").split())
            if not name:
                continue
            base = self.combat_enemy_base_name(name)
            profile = tactical_loot_profile_for_enemy(base)
            reward_sets = [
                self.tactical_int_dict(profile.get("common", {})),
                self.tactical_int_dict(profile.get("uncommon", {})),
            ]
            if name.startswith("Elite "):
                common_coin = max(4, reward_sets[0].get("Coin", 0) + reward_sets[1].get("Coin", 0))
                reward_sets.extend([self.tactical_int_dict(profile.get("rare", {})), {"Coin": common_coin, "Shard": 1}])
            for rewards in reward_sets:
                for item_name, qty in rewards.items():
                    if qty > 0:
                        estimate[item_name] = estimate.get(item_name, 0) + int(qty)
        return estimate

    def combat_mission_lines(self, preset: Dict[str, object]) -> List[str]:
        request = self.mission_preset_request(preset)
        completed = str(request.mission_id) in set(getattr(self.state, "completed_combat_mission_ids", []) or [])
        reward_estimate = self.tactical_enemy_reward_estimate(request.requested_enemy_names())
        identity = self.combat_mission_identity(str(request.mission_id), str(preset.get("name", "")), str(preset.get("theme", "")))
        return [
            str(preset.get("name", "Combat Mission")),
            "",
            str(preset.get("flavor", "")),
            "",
            f"Posted by: {identity.get('poster', 'Town Hall')}",
            f"Map: {request.map_name}",
            f"Objective: {request.objective}",
            "Enemies: " + ", ".join(request.requested_enemy_names()),
            f"Theme: {preset.get('theme', '')}",
            "Estimated Rewards: " + self.tactical_loot_preview_text(reward_estimate),
            f"Estimated Time: {self.combat_mission_estimated_minutes(request.requested_enemy_names())} minutes",
            "Town Effect: " + str(identity.get("impact", "")),
            "Preparation: " + str(identity.get("prep", "")),
            f"Status: {'cleared before' if completed else 'available'}",
            "",
            "Party:",
            self.party_menu_hint(),
        ]

    def apply_combat_mission_result(self, result: object):
        outcome = combat_result_outcome(result)
        defeated = list(getattr(result, "defeated_enemies", []) or [])
        remaining_items = apply_party_status_to_combat_state(self.state, result)
        result_context = getattr(result, "return_context", {}) or {}
        if not isinstance(result_context, dict):
            result_context = {}
        starting_items = result_context.get("farm_player_items", {})
        used_items = consumed_combat_items(starting_items, remaining_items)
        for item_name, qty in used_items.items():
            self.state.inventory[item_name] = max(0, int(self.state.inventory.get(item_name, 0)) - int(qty))
        mission_id = str(getattr(result, "mission_id", "") or result_context.get("mission_id", "") or "")
        first_clear = bool(mission_id and mission_id not in set(getattr(self.state, "completed_combat_mission_ids", []) or []))
        tactical_lines = self.apply_tactical_progression_result(result)
        mission_name = str(getattr(result, "mission_name", "") or result_context.get("mission_name", "Combat mission") or "Combat mission")

        if outcome == "victory":
            loot = self.combat_loot_for_result(result)
            money, items = self.grant_farm_combat_loot(loot)
            exp_gain = mine_combat_exp_for_defeated(defeated, max(1, int(getattr(self.state, "deepest_mine_floor", 1) or 1)))
            _amount, level_lines = grant_combat_exp(self.state, exp_gain)
            self.state.mine_combat_victories += 1
            self.state.mine_enemies_defeated += len(defeated)
            minutes = self.apply_combat_time_cost(result, "mission")
            progress_lines = level_lines + tactical_lines
            progress_lines.extend(self.apply_combat_mission_impact(mission_id, first_clear))
            progress_lines.extend(self.grant_party_relationship_after_battle("victory"))
            progress_lines.extend(self.companion_after_battle_lines("victory"))
            extra = " " + " ".join(progress_lines) if progress_lines else ""
            summary = self.combat_summary_text(f"Victory: {mission_name}", exp_gain, money, items, used_items, minutes)
            self.autosave_with_message(f"{summary}.{extra}")
            return

        if outcome == "defeat":
            self.state.mine_combat_defeats += 1
            self.state.combat_current_hp = max(1, int(getattr(self.state, "combat_current_hp", 1)))
            minutes = self.apply_combat_time_cost(result, "mission")
            summary = self.combat_summary_text(f"Defeat: {mission_name}", 0, 0, {}, used_items, minutes)
            self.autosave_with_message(f"{summary}. You pulled back alive.")
            return

        self.state.mine_combat_flees += 1
        minutes = self.apply_combat_time_cost(result, "mission")
        summary = self.combat_summary_text(f"Retreat: {mission_name}", 0, 0, {}, used_items, minutes)
        self.autosave_with_message(f"{summary}.")

    def start_combat_mission(self, preset: Dict[str, object]):
        request = self.mission_preset_request(preset)
        self.set_message(f"Starting {request.mission_name}...")
        self.invalidate_draw_cache()
        try:
            result = run_mine_battle(request)
        except Exception as exc:
            append_debug_log(f"Combat mission error: {type(exc).__name__}: {exc}")
            write_debug_report(self, exc, f"combat_mission {request.mission_id}")
            self.set_message(f"Combat mission could not start. Error logged to {CRASH_REPORT_PATH.name}: {exc}")
            self.invalidate_draw_cache()
            return
        self.invalidate_draw_cache()
        self.apply_combat_mission_result(result)

    def show_combat_mission_menu(self):
        while True:
            completed = set(getattr(self.state, "completed_combat_mission_ids", []) or [])
            items = []
            for preset in self.all_tactical_mission_presets():
                request = self.mission_preset_request(preset)
                items.append(MenuItem(
                    label=str(preset.get("name", "Mission")),
                    value=preset,
                    enabled=True,
                    hint=("cleared | " if str(request.mission_id) in completed else "") + f"{request.objective} | {preset.get('theme', '')}",
                ))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select("Combat Missions", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            preset = dict(choice.value)
            self.vertical_panel_view(str(preset.get("name", "Mission")), self.combat_mission_lines(preset), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
            confirm = self.vertical_panel_select(
                str(preset.get("name", "Mission")),
                [
                    MenuItem(label="Start mission", value="start", enabled=True, hint=self.party_menu_hint()),
                    MenuItem(label="Back", value=MENU_BACK, enabled=True),
                ],
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if confirm is None or confirm.value == MENU_BACK:
                continue
            self.start_combat_mission(preset)
            return "changed"

    def show_last_combat_report(self):
        report = list(getattr(self.state, "last_combat_report", []) or [])
        if not report:
            report = ["No combat report recorded yet."]
        self.vertical_panel_view("Battle Report", report, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        return MENU_BACK

    def grant_party_relationship_after_battle(self, outcome: str) -> List[str]:
        if str(outcome) != "victory":
            return []
        if not isinstance(self.state.party_member_last_relationship_gain_day, dict):
            self.state.party_member_last_relationship_gain_day = {}
        today = self.town_npc_day_key()
        lines: List[str] = []
        for companion_id in self.active_party_member_ids():
            if self.state.party_member_last_relationship_gain_day.get(companion_id) == today:
                continue
            data = self.party_companion_data(companion_id)
            npc_id = str(data.get("npc_id", companion_id))
            gained = self.adjust_town_npc_relationship(npc_id, 2)
            self.state.party_member_last_relationship_gain_day[companion_id] = today
            if gained > 0:
                lines.append(f"{data.get('name', companion_id)} friendship +{gained}.")
        return lines

