    def show_combat_equipment_slot_menu(self, slot: str):
        info = COMBAT_EQUIPMENT_SLOTS.get(str(slot))
        if not info:
            self.set_message("Unknown combat equipment slot.")
            return MENU_BACK
        field_name, _data, default = info
        while True:
            self.repair_combat_equipment(announce=True)
            current = str(getattr(self.state, field_name, default) or default)
            items: List[MenuItem] = []
            for item_name in self.owned_combat_equipment_names(slot):
                equipped = item_name == current
                label = f"{item_name} [equipped]" if equipped else item_name
                owned_qty = int(self.state.inventory.get(item_name, 0) or 0)
                source = "starter" if item_name == default else (f"x{owned_qty}" if owned_qty else "equipped")
                items.append(MenuItem(
                    label=label,
                    value=item_name,
                    enabled=True,
                    hint=f"{self.combat_equipment_effect_text(slot, item_name)} | {source}",
                ))
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))
            choice = self.vertical_panel_select(f"Change {slot.title()}", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            item_name = str(choice.value)
            if item_name == current:
                self.vertical_panel_view(item_name, self.combat_equipment_lines(slot, item_name), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            self.equip_combat_item(slot, item_name)
            return "changed"

    def show_combat_status_menu(self):
        self.repair_combat_equipment(announce=True)
