    def combat_gear_catalog(self) -> Dict[str, Dict[str, object]]:
        catalog: Dict[str, Dict[str, object]] = {}
        for _slot, (_field_name, data, _default) in COMBAT_EQUIPMENT_SLOTS.items():
            catalog.update(data)
        return catalog

    def combat_gear_slot_for_item(self, item_name: str) -> str:
        item_name = str(item_name)
        for slot, (_field_name, data, _default) in COMBAT_EQUIPMENT_SLOTS.items():
            if item_name in data:
                return slot
        return ""

    def combat_gear_data(self, item_name: str) -> Dict[str, object]:
        return self.combat_gear_catalog().get(str(item_name), {})

    def combat_gear_is_starter(self, item_name: str) -> bool:
        data = self.combat_gear_data(item_name)
        return str(data.get("unlock", "")) == "starter"

    def owns_combat_gear(self, item_name: str) -> bool:
        item_name = str(item_name)
        if self.combat_gear_is_starter(item_name):
            return True
        return int(self.state.inventory.get(item_name, 0) or 0) > 0

    def combat_gear_unlock_available(self, item_name: str) -> bool:
        data = self.combat_gear_data(item_name)
        unlock = str(data.get("unlock", "blacksmith"))
        if unlock == "starter":
            return False
        if unlock == "blacksmith":
            return True
        if unlock == "iron":
            return (
                int(getattr(self.state, "deepest_mine_floor", 1)) >= 5
                or int(self.state.inventory.get("Iron Ore", 0) or 0) > 0
                or int(self.state.inventory.get("Iron Bar", 0) or 0) > 0
            )
        if unlock == "quartz":
            return (
                int(getattr(self.state, "deepest_mine_floor", 1)) >= 3
                or int(self.state.inventory.get("Quartz", 0) or 0) > 0
            )
        if unlock == "deep_mine":
            return (
                int(getattr(self.state, "deepest_mine_floor", 1)) >= 10
                or int(self.state.inventory.get("Crystal Shard", 0) or 0) > 0
                or int(self.state.inventory.get("Strange Spores", 0) or 0) > 0
                or int(self.state.inventory.get("Ruin Scrap", 0) or 0) > 0
                or int(self.state.inventory.get("Relic Fragment", 0) or 0) > 0
                or int(self.state.inventory.get("Ancient Cog", 0) or 0) > 0
            )
        return True

    def combat_gear_unlock_hint(self, item_name: str) -> str:
        unlock = str(self.combat_gear_data(item_name).get("unlock", "blacksmith"))
        if unlock == "iron":
            return "reach floor 5 or find iron"
        if unlock == "quartz":
            return "find Quartz or reach floor 3"
        if unlock == "deep_mine":
            return "reach floor 10 or find deep mine/ruin materials"
        if unlock == "starter":
            return "starter gear"
        return "restored blacksmith"

    def combat_gear_cost(self, item_name: str) -> Tuple[int, Dict[str, int]]:
        raw_cost = self.combat_gear_data(item_name).get("cost", {})
        if not isinstance(raw_cost, dict):
            return 0, {}
        try:
            money = max(0, int(raw_cost.get("money", 0) or 0))
        except Exception:
            money = 0
        raw_items = raw_cost.get("items", {})
        items: Dict[str, int] = {}
        if isinstance(raw_items, dict):
            for item, qty in raw_items.items():
                try:
                    count = max(0, int(qty))
                except Exception:
                    count = 0
                if count:
                    items[str(item)] = count
        return money, items

    def combat_gear_cost_text(self, item_name: str) -> str:
        money, items = self.combat_gear_cost(item_name)
        parts: List[str] = []
        if money:
            parts.append(f"${money}")
        parts.extend([f"{qty} {item}" for item, qty in items.items()])
        return ", ".join(parts) if parts else "No cost"

    def combat_gear_missing_requirements(self, item_name: str) -> List[str]:
        missing: List[str] = []
        if not self.combat_gear_data(item_name):
            return ["invalid gear"]
        if not self.combat_gear_unlock_available(item_name):
            missing.append(self.combat_gear_unlock_hint(item_name))
        if self.owns_combat_gear(item_name):
            missing.append("already owned")
        money, items = self.combat_gear_cost(item_name)
        if int(self.state.money) < money:
            missing.append(f"${money - int(self.state.money)}")
        for item, qty in items.items():
            have = int(self.state.inventory.get(item, 0) or 0)
            if have < qty:
                missing.append(f"{qty - have} {item}")
        return missing

    def can_purchase_combat_gear(self, item_name: str) -> bool:
        return not self.combat_gear_missing_requirements(item_name)

    def combat_gear_purchase_status(self, item_name: str) -> str:
        if self.owns_combat_gear(item_name):
            return "owned"
        missing = self.combat_gear_missing_requirements(item_name)
        if not missing:
            return "ready"
        return "need " + ", ".join(missing[:2])

    def combat_gear_detail_lines(self, item_name: str) -> List[str]:
        data = self.combat_gear_data(item_name)
        if not data:
            return [f"{item_name}: invalid combat gear."]
        slot = self.combat_gear_slot_for_item(item_name)
        lines = [
            str(data.get("name", item_name)),
            "",
            f"Slot: {slot.title()}",
            f"Effect: {self.combat_equipment_effect_text(slot, item_name)}",
            f"Cost: {self.combat_gear_cost_text(item_name)}",
            f"Status: {self.combat_gear_purchase_status(item_name)}",
            f"Unlock: {self.combat_gear_unlock_hint(item_name)}",
            "",
            str(data.get("description", "No description.")),
        ]
        missing = self.combat_gear_missing_requirements(item_name)
        if missing and not self.owns_combat_gear(item_name):
            lines.extend(["", "Missing:", *[f"- {entry}" for entry in missing]])
        return lines

    def purchase_combat_gear(self, item_name: str, equip_now: bool = False) -> bool:
        item_name = str(item_name)
        if not self.can_purchase_combat_gear(item_name):
            self.set_message(f"Cannot forge {item_name}: {self.combat_gear_purchase_status(item_name)}.")
            return False
        money, items = self.combat_gear_cost(item_name)
        self.state.money -= money
        for item, qty in items.items():
            self.state.inventory[item] = max(0, int(self.state.inventory.get(item, 0) or 0) - qty)
        self.state.inventory[item_name] = max(1, int(self.state.inventory.get(item_name, 0) or 0))

        equip_msg = ""
        if equip_now:
            slot = self.combat_gear_slot_for_item(item_name)
            if slot and self.equip_combat_item(slot, item_name):
                equip_msg = " Equipped it."
        if not equip_msg:
            self.autosave_with_message(f"Forged {item_name}.")
        else:
            self.autosave_with_message(f"Forged {item_name}.{equip_msg}")
        return True

    def blacksmith_combat_gear_names(self) -> List[str]:
        names: List[str] = []
        for slot in ["weapon", "armor", "accessory"]:
            _field_name, data, _default = COMBAT_EQUIPMENT_SLOTS[slot]
            for item_name in data:
                if self.combat_gear_is_starter(item_name):
                    continue
                names.append(item_name)
        return names

    def available_blacksmith_combat_gear_count(self) -> int:
        return sum(1 for item_name in self.blacksmith_combat_gear_names() if self.combat_gear_unlock_available(item_name))

    def blacksmith_combat_gear_menu(self):
        while True:
            gear_items: List[MenuItem] = []
            for item_name in self.blacksmith_combat_gear_names():
                unlocked = self.combat_gear_unlock_available(item_name)
                slot = self.combat_gear_slot_for_item(item_name)
                status = self.combat_gear_purchase_status(item_name) if unlocked else self.combat_gear_unlock_hint(item_name)
                label = f"{item_name}"
                if self.owns_combat_gear(item_name):
                    label += " [owned]"
                gear_items.append(MenuItem(
                    label=label,
                    value=item_name,
                    enabled=unlocked,
                    hint=f"{slot} | {self.combat_equipment_effect_text(slot, item_name)} | {status}",
                ))
            gear_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

            selected = self.vertical_panel_select("Combat Gear", gear_items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if selected is None or selected.value == MENU_BACK:
                return MENU_BACK

            item_name = str(selected.value)
            slot = self.combat_gear_slot_for_item(item_name)
            can_buy = self.can_purchase_combat_gear(item_name)
            owned = self.owns_combat_gear(item_name)
            detail_items = [
                MenuItem(label="Forge", value="forge", enabled=can_buy, hint=self.combat_gear_cost_text(item_name)),
                MenuItem(label="Forge and equip", value="forge_equip", enabled=can_buy and bool(slot), hint=self.combat_gear_cost_text(item_name)),
                MenuItem(label="Equip owned", value="equip", enabled=owned and bool(slot), hint=slot),
                MenuItem(label="Read details", value="details", enabled=True),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select(item_name, detail_items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                continue
            if choice.value == "details":
                self.vertical_panel_view(item_name, self.combat_gear_detail_lines(item_name), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "equip":
                self.equip_combat_item(slot, item_name)
                return "changed"
            if choice.value == "forge":
                self.purchase_combat_gear(item_name, equip_now=False)
                return "changed"
            if choice.value == "forge_equip":
                self.purchase_combat_gear(item_name, equip_now=True)
                return "changed"

    def show_tool_status(self):
        rows = []
        rows.append("Tool rotation:")
        rows.append(", ".join(self.state.available_tools))
        rows.append("")
        for tool_name in ["Hoe", "Watering Can", "Axe", "Pickaxe"]:
            owned = self.owns_tool(tool_name)
            level = self.tool_level(tool_name)
            if not owned:
                rows.append(f"{tool_name[:16]:16} Not owned")
                continue
            rows.append(f"{tool_name[:16]:16} {TOOL_LEVEL_NAMES.get(level, 'Lv'+str(level))}")
            upgrade = self.next_tool_upgrade(tool_name)
            if upgrade:
                rows.append(f"  Next: ${upgrade['price']}")
            else:
                rows.append("  Max upgrade")
        self.vertical_panel_view("Tool Status", rows, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
        return MENU_BACK

    def shippable_unit_price(self, item_name: str) -> int:
        artisan_prices = {
            "Berry Jam": 140,
            "Pickled Turnips": 120,
            "Pickled Carrots": 135,
            "Tomato Preserve": 170,
            "Corn Relish": 180,
            "Mushroom Preserve": 210,
            "Wildflower Honey": 160,
            "Ancient Preserves": 1250,
        }
        if item_name in artisan_prices:
            return artisan_prices[item_name]
        if item_name in FISH_DATA:
            return fish_sell_price(item_name)
        crop_name, quality = parse_quality_item(item_name)
        if crop_name and quality:
            return quality_sell_price(crop_name, quality)
        ordinary_price = int(ITEM_SELL_PRICES.get(item_name, 0))
        return ordinary_price if ordinary_price > 0 else self.container_item_sell_price(item_name)

