    def next_family_home_goal(self) -> Dict[str, object]:
        upgrades = set(getattr(self.state, "house_upgrades", []) or [])
        spouse_id = str(getattr(self.state, "spouse_npc_id", "") or "")
        engaged_id = str(getattr(self.state, "engaged_npc_id", "") or "")
        children = getattr(self.state, "children", []) or []
        progress = f"House upgrades {len(upgrades)}/{len(HOUSE_UPGRADE_DATA)}; spouse {'yes' if spouse_id else 'no'}; engaged {'yes' if engaged_id else 'no'}; children {len(children)}"

        if not spouse_id:
            if engaged_id:
                return self.progression_goal_entry(
                    "Family & Home",
                    "Wedding Day",
                    "Scheduled",
                    progress,
                    (
                        f"Wedding with {self.town_npc_name(engaged_id)}: "
                        f"{self.wedding_date_label()}."
                    ),
                    "Sleep and continue daily life until the ceremony date arrives.",
                    8,
                )
            candidates = [npc for npc in self.active_town_npcs() if self.is_marriageable_npc(npc)]
            candidates.sort(key=lambda npc: self.town_npc_relationship(str(npc.get("id", ""))), reverse=True)
            if candidates:
                npc = candidates[0]
                npc_id = str(npc.get("id", ""))
                name = str(npc.get("name", "a romance candidate"))
                propose_ok, propose_reason = self.can_propose_to_town_npc(npc)
                court_ok, court_reason = self.can_court_town_npc(npc)
                rel = self.town_npc_relationship(npc_id)
                if propose_ok:
                    status = "Ready"
                    step = f"Propose to {name} with a {WEDDING_RING_ITEM}."
                    priority = 10
                elif court_ok:
                    status = "Ready"
                    step = f"Spend courtship time with {name} today."
                    priority = 16
                else:
                    status = "Active"
                    reason = propose_reason if rel >= RELATIONSHIP_COURTSHIP_REQUIRED_FRIENDSHIP else court_reason
                    step = f"Talk, gift, and complete requests for {name}. {reason}"
                    priority = 33
                return self.progression_goal_entry(
                    "Home & Family",
                    f"Relationship with {name}",
                    status,
                    progress,
                    step,
                    "Builds toward marriage, spouse support, and children.",
                    priority,
                )
            return self.progression_goal_entry(
                "Home & Family",
                "Meet romance candidates",
                "Active",
                progress,
                "Restore town buildings and meet more eligible residents.",
                "More residents means more relationship paths.",
                36,
            )

        spouse = self.npc_record_by_id(spouse_id)
        spouse_name = self.town_npc_name(spouse_id)
        if not getattr(self.state, "spouse_moved_to_farm", False):
            return self.progression_goal_entry(
                "Home & Family",
                "Spouse move-in",
                "Ready",
                progress,
                f"Invite {spouse_name} to move into the farmhouse from their talk menu.",
                "Enables spouse support and family planning.",
                12,
            )
        if getattr(self.state, "pregnancy_active", False):
            if spouse and self.pregnancy_checkup_available():
                step = f"Complete pregnancy month {self.pregnancy_month_number()} check-in with {spouse_name}."
                status = "Ready"
                priority = 7
            else:
                step = f"Prepare the home before the due date: {self.pregnancy_due_date_label()}."
                status = "Active"
                priority = 27
            return self.progression_goal_entry(
                "Home & Family",
                "Pregnancy",
                status,
                progress,
                step,
                "Keeps family progression grounded in time and household care.",
                priority,
            )

        for upgrade_name, data in HOUSE_UPGRADE_DATA.items():
            if upgrade_name in upgrades:
                continue
            missing = [req for req in data.get("requires", []) or [] if req not in upgrades]
            if missing:
                return self.progression_goal_entry(
                    "Home & Family",
                    upgrade_name,
                    "Locked",
                    progress,
                    f"Buy {', '.join(missing)} before {upgrade_name}.",
                    str(data.get("description", "Improves the farmhouse.")),
                    34,
                )
            status, step = self.progression_price_step(
                f"Buy {upgrade_name} from the Carpenter",
                int(data.get("price", 0) or 0),
            )
            return self.progression_goal_entry(
                "Home & Family",
                upgrade_name,
                status,
                progress,
                step,
                str(data.get("description", "Improves the farmhouse.")),
                17 if status == "Ready" else 32,
            )

        if not children and spouse:
            family_ok, family_reason = self.can_start_pregnancy_with_spouse(spouse)
            discussed = self.family_planning_discussed_with_spouse(spouse)
            if family_ok:
                status = "Ready"
                step = f"Try for a baby with {spouse_name} from Family Planning."
                priority = 10
            elif not discussed:
                status = "Ready"
                step = f"Talk with {spouse_name} about children from Family Planning."
                priority = 15
            else:
                status = "Active"
                step = f"Deepen spouse romance for family planning. {family_reason}"
                priority = 30
            return self.progression_goal_entry(
                "Home & Family",
                "Family planning",
                status,
                progress,
                step,
                "Opens the long family timeline without rushing it.",
                priority,
            )

        return self.progression_goal_entry(
            "Home & Family",
            "Household rhythm",
            "Stable",
            progress,
            "Use meals, lessons, gifts, and chores to keep the household growing.",
            "Family life is now part of the long-term farm rhythm.",
            74,
        )

    def active_progression_goals(self) -> List[Dict[str, object]]:
        goals = [
            self.next_town_restoration_goal(),
            self.next_land_progression_goal(),
            self.next_tool_and_automation_goal(),
            self.next_combat_progression_goal(),
            self.next_family_home_goal(),
        ]
        return [goal for goal in goals if isinstance(goal, dict)]

    def progression_priority_goals(self, limit: int = 4) -> List[Dict[str, object]]:
        rank = {
            "Ready": 0,
            "Recovery": 1,
            "Active": 2,
            "Needs materials": 3,
            "Needs money": 4,
            "Locked": 5,
            "Stable": 6,
            "Complete": 7,
        }
        active = [goal for goal in self.active_progression_goals() if goal.get("status") not in ("Stable", "Complete")]
        active.sort(key=lambda goal: (rank.get(str(goal.get("status", "")), 9), int(goal.get("priority", 50))))
        return active[:max(0, int(limit))]

    def progression_today_priority_lines(self, limit: int = 3) -> List[str]:
        goals = self.progression_priority_goals(limit)
        if not goals:
            return ["- No urgent progression goals. Tune the farm, visit people, or explore at your own pace."]
        return [f"- {goal['track']}: {goal['next_step']}" for goal in goals]

    def progression_morning_priority_summary(self) -> str:
        goals = self.progression_priority_goals(1)
        if not goals:
            return ""
        text = str(goals[0].get("next_step", "")).strip()
        if len(text) > 110:
            text = text[:107].rstrip() + "..."
        return text.rstrip(".")

    def progression_milestone_ladder_lines(self) -> List[str]:
        return [
            "- Town: restore services -> reopen culture/market spaces -> fund civic projects.",
            "- Land: expand the home farm -> buy a claim -> develop specialized claim networks.",
            "- Tools: secure Axe/Pickaxe -> upgrade core tools -> build machines that reduce chores.",
            "- Combat: first mine victory -> floor 5 -> mission board -> dungeons -> reclaimed strongholds.",
            "- Home: kitchen -> larger farmhouse -> marriage -> spouse move-in -> family planning.",
            "- Rewards: ore, ruin loot, town access, and land claims should feed back into better farms.",
        ]

    def journal_progression_lines(self) -> List[str]:
        goals = self.active_progression_goals()
        lines = [
            "PROGRESSION GOALS",
            "",
            "These are suggested paths, not chores. They point at systems that unlock or support each other.",
            "",
            "Highest-value next steps:",
        ]
        lines.extend(self.progression_today_priority_lines(5))
        lines.extend(["", "Current tracks:"])
        for goal in goals:
            lines.extend([
                f"- {goal.get('track')}: {goal.get('title')}",
                f"  Status: {goal.get('status')} | {goal.get('progress')}",
                f"  Next: {goal.get('next_step')}",
            ])
            payoff = str(goal.get("payoff", "") or "")
            if payoff:
                lines.append(f"  Why: {payoff}")
        lines.extend(["", "Milestone ladder:"])
        lines.extend(self.progression_milestone_ladder_lines())
        return lines

    def journal_overview_lines(self) -> List[str]:
        ready_jobs = sum(1 for job in self.today_bulletin_jobs() if self.can_complete_bulletin_job(job))
        ready_requests = sum(1 for request_id in self.resident_request_data() if self.resident_request_status(request_id) == "Ready")
        claim_count = len(self.state.owned_wilderness_claims) if isinstance(self.state.owned_wilderness_claims, dict) else 0
        seen_count = len(getattr(self.state, "combat_bestiary_seen", []) or [])
        roster_count = len(self.tactical_mission_roster_names())
        lines = [
            "JOURNAL / CODEX",
            "",
            f"Today: {self.state.date_label} ({self.state.weekday})",
            (
                f"Farmstead head: {self.state.player_name}, "
                f"age {self.player_age()} "
                f"(Generation {self.state.player_generation})"
                if self.aging_and_death_active()
                else f"Farmstead head: {self.state.player_name}, "
                f"{self.player_life_stage()} "
                f"(Generation {self.state.player_generation})"
            ),
            f"Weather: {self.state.weather} - {weather_forecast_summary(self.state.weather)}",
            "",
            "Today's notices:",
        ]
        notices = [
            line
            for line in self.selected_calendar_events_text(self.state.month, self.state.day, self.state.year)
            if line != "No events scheduled."
        ]
        lines.extend(f"- {line}" for line in notices[:6])
        if not notices:
            lines.append("- No special notices.")
        lines.extend(["", *self.home_region_journey_lines()])
        lines.extend([
            "",
            "Today's priorities:",
            *self.progression_today_priority_lines(3),
        ])
        lines.extend([
            "",
            "Memory aid:",
            f"- Ready bulletin jobs: {ready_jobs}",
            f"- Ready resident requests: {ready_requests}",
            f"- Owned land claims: {claim_count}",
            f"- Relationships tracked: {len(self.active_town_npcs())} active residents",
            f"- Bestiary: {seen_count}/{roster_count} seen",
            f"- Museum donations: {self.museum_total_donated()}/{self.museum_total_possible()}",
            f"- Party: {self.party_menu_hint()}",
            "",
            "Use Progress Goals for the big-picture path, or the other Journal pages for details.",
        ])
        return lines

    def journal_quest_lines(self) -> List[str]:
        lines = ["QUEST JOURNAL", ""]
        lines.extend(self.resident_requests_overview_lines())
        lines.extend(["", "-" * 18, ""])
        lines.extend(self.companion_quests_overview_lines())
        lines.extend(["", "-" * 18, ""])
        lines.extend(self.bulletin_jobs_overview_lines())
        lines.extend(["", "-" * 18, "", "REGIONAL CONTRACTS", ""])
        active_contracts = self.regional_contracts(("active",))
        if active_contracts:
            for contract in active_contracts:
                ready, reason = self.can_complete_regional_contract(contract)
                lines.extend(
                    [
                        f"- {contract.get('title')}",
                        f"  {contract.get('description')}",
                        f"  {'Ready to complete' if ready else reason}",
                        f"  Reward: {contract.get('reward', 0)}g",
                    ]
                )
        else:
            lines.append("- No active regional contracts.")
        lines.extend(["", "-" * 18, ""])
        lines.extend(self.combat_mission_board_lines())
        return lines

    def journal_land_claim_lines(self) -> List[str]:
        claims = self.state.owned_wilderness_claims if isinstance(self.state.owned_wilderness_claims, dict) else {}
        lines = [
            "LAND CLAIMS",
            "",
            "Home Farm: main farmhouse, shipping bin, spouse/child housing, and farm infrastructure.",
            "",
        ]
        if not claims:
            lines.extend([
                "No wilderness claims owned yet.",
                "",
                "Look for deed markers in rare wilderness chunks. Owned claims keep their raw land, shipping bin, and placed infrastructure.",
            ])
            return lines
        for claim_key, claim in sorted(claims.items()):
            claim = self.ensure_wilderness_claim_identity(claim_key, claim)
            farm_type_id = claim_farm_type_id_for_record(claim)
            farm_type = farm_claim_type_data(farm_type_id)
            stats = self.claim_development_stats(claim_key, claim)
            lines.extend([
                str(claim.get("name", f"Claim {claim_key}")),
                f"- Chunk: {claim_key}",
                f"- Deed: {claim.get('deed_code', 'unrecorded')}",
                f"- Type: {claim.get('farm_type', farm_type.get('name', 'Farm Claim'))}",
                f"- Focus: {farm_type.get('focus', claim.get('traits', 'raw land'))}",
                f"- Development: {self.claim_development_label(claim_key, claim)} ({stats.get('cleared_percent', 0)}% cleared/workable)",
                f"- Landmark: {claim.get('landmark', 'survey marker')}",
                "",
            ])
        lines.append("Open Land Claims from the main menu to travel or read full deed notes.")
        return lines

    def journal_relationship_lines(self) -> List[str]:
        self.normalize_town_npcs()
        active = sorted(self.active_town_npcs(), key=lambda npc: str(npc.get("name", "")))
        inactive = sorted(self.inactive_town_npcs(), key=lambda npc: str(npc.get("name", "")))
        lines = [
            "RELATIONSHIPS",
            "",
            f"Spouse: {self.town_npc_name(self.state.spouse_npc_id) if self.state.spouse_npc_id else 'none'}",
            "Household: spouse lives on farm" if self.state.spouse_moved_to_farm else "Household: no spouse move-in active",
            "",
            "Active residents:",
        ]
        for npc in active:
            npc_id = str(npc.get("id", ""))
            rel = self.town_npc_relationship(npc_id)
            romance = f"; {self.romance_label_for_npc(npc)}" if self.is_romance_candidate_npc(npc) else ""
            lines.append(f"- {npc.get('name')} ({npc.get('role')}): {self.town_npc_friendship_label(rel)} {rel}{romance}")
            lines.append(f"  Birthday: {self.npc_birthday_label(npc)} | {self.town_npc_routine_brief(npc)}")
        if inactive:
            lines.extend(["", "Later arrivals:"])
            for npc in inactive[:12]:
                required_building = TOWN_NPC_REQUIRED_BUILDINGS.get(str(npc.get("id", "")), "")
                arrival = f"{self.town_building_label(required_building)} opens" if required_building else "town development advances"
                lines.append(f"- {npc.get('name')} ({npc.get('role')}): arrives when {arrival}")
        generated_rows: List[Tuple[str, Dict[str, object]]] = []
        for plan in self.discovered_procedural_town_plans():
            population = self.procedural_settlement_population(
                int(plan["chunk_x"]),
                int(plan["chunk_y"]),
            ) or {}
            for resident in population.get("residents", {}).values():
                if not isinstance(resident, dict):
                    continue
                if (
                    resident.get("met")
                    or str(resident.get("id", ""))
                    in set(self.state.dating_npc_ids or [])
                    or str(resident.get("id", ""))
                    == str(self.state.spouse_npc_id)
                ):
                    generated_rows.append((str(plan.get("name", "Wilderness Town")), resident))
        if generated_rows:
            lines.extend(["", "Wilderness-town residents:"])
            for town_name, resident in sorted(
                generated_rows,
                key=lambda row: (row[0], str(row[1].get("name", ""))),
            ):
                resident_id = str(resident.get("id", ""))
                relationship = self.town_npc_relationship(resident_id)
                romance = (
                    f"; {self.romance_label_for_npc(resident)}"
                    if self.is_romance_candidate_npc(resident)
                    else ""
                )
                lines.append(
                    f"- {resident.get('name')} ({town_name}, {resident.get('role')}): "
                    f"{self.town_npc_friendship_label(relationship)} "
                    f"{relationship}{romance}"
                )
                lines.append(
                    f"  Birthday: {self.npc_birthday_label(resident)} | "
                    f"{resident.get('runtime_activity', 'following their routine')}"
                )
        return lines

    def birthday_distance_from_today(self, month: int, day: int) -> int:
        today = day_of_year(self.state.month, self.state.day, self.state.year)
        target = day_of_year(month, day, self.state.year)
        if target < today:
            target += 366 if is_leap_year(self.state.year) else 365
        return max(0, target - today)

    def journal_birthday_lines(self) -> List[str]:
        self.normalize_town_npcs()
        entries: List[Tuple[int, str, str]] = []
        player_month, player_day = self.birthday_tuple_from(self.state.player_birthday_month, self.state.player_birthday_day)
        entries.append((
            self.birthday_distance_from_today(player_month, player_day),
            self.state.player_name,
            (
                f"{self.player_birthday_label()}, born Year "
                f"{self.state.player_birth_year}"
                if self.aging_and_death_active()
                else f"{self.player_birthday_label()}, "
                f"{self.player_life_stage()}"
            ),
        ))
        for npc in self.state.town_npcs:
            month, day = self.npc_birthday(npc)
            entries.append((self.birthday_distance_from_today(month, day), str(npc.get("name", "Villager")), self.npc_birthday_label(npc)))
        seen_generated = set()
        for plan in self.discovered_procedural_town_plans():
            population = self.procedural_settlement_population(
                int(plan["chunk_x"]),
                int(plan["chunk_y"]),
            ) or {}
            for resident in population.get("residents", {}).values():
                resident_id = str(resident.get("id", ""))
                if not resident_id or resident_id in seen_generated:
                    continue
                seen_generated.add(resident_id)
                month, day = self.npc_birthday(resident)
                entries.append(
                    (
                        self.birthday_distance_from_today(month, day),
                        str(resident.get("name", "Resident")),
                        self.npc_birthday_label(resident),
                    )
                )
        for child in self.state.children:
            month, day = self.child_birthday(child)
            entries.append((self.birthday_distance_from_today(month, day), str(child.get("name", "Child")), self.child_birthday_label(child)))
        for relative in [
            *getattr(self.state, "dynasty_elders", []),
            *getattr(self.state, "dynasty_kin", []),
        ]:
            if (
                not isinstance(relative, dict)
                or not relative.get("active", True)
                or relative.get("linked_existing_npc")
            ):
                continue
            month = int(relative.get("birth_month", 3) or 3)
            day = int(relative.get("birth_day", 1) or 1)
            relation = (
                "family elder"
                if relative.get("dynasty_elder")
                else self.dynasty_relation_for_generation(relative).lower()
            )
            entries.append(
                (
                    self.birthday_distance_from_today(month, day),
                    str(relative.get("name", "Relative")),
                    f"{format_birthday(month, day)} ({relation})",
                )
            )
        entries.sort(key=lambda row: (row[0], row[2], row[1]))
        lines = ["BIRTHDAYS", "", "Upcoming:"]
        for distance, name, label in entries[:24]:
            when = "today" if distance == 0 else f"in {distance} day(s)"
            lines.append(f"- {label}: {name} ({when})")
        lines.extend(["", "Birthdays also appear on the wall calendar and town calendar notices."])
        return lines

    def journal_bestiary_lines(self) -> List[str]:
        seen = set(getattr(self.state, "combat_bestiary_seen", []) or [])
        defeated = getattr(self.state, "combat_bestiary_defeated", {}) or {}
        lines = [
            "BESTIARY",
            "",
            f"Seen: {len(seen)}/{len(self.tactical_mission_roster_names())}",
            "",
        ]
        for enemy_name in self.tactical_mission_roster_names():
            marker = "seen" if enemy_name in seen else "unknown"
            count = int(defeated.get(enemy_name, 0) or 0)
            profile = mine_enemy_profile(enemy_name) if enemy_name in MINE_ENEMY_PROFILES else {}
            lines.append(f"- {enemy_name}: {marker}, defeated {count}")
            if profile:
                lines.append(f"  {profile.get('description', '')}")
            sample = self.museum_bestiary_sample_for_enemy(enemy_name)
            sample_id = self.museum_record_id("bestiary", sample, enemy_name)
            specimen = "donated" if sample_id in self.museum_donated_record_ids() else "not donated"
            lines.append(f"  Museum specimen: {sample} ({specimen})")
        return lines

    def journal_combat_report_lines(self) -> List[str]:
        report = list(getattr(self.state, "last_combat_report", []) or [])
        lines = [
            "COMBAT REPORTS",
            "",
            f"Readiness: {' '.join(self.combat_readiness_lines())}",
            f"Party: {self.party_menu_hint()}",
            f"Tactic: {self.party_tactic()}",
            f"Seasonal contract: {self.seasonal_combat_contract_label_for_date(self.state.month, self.state.day, self.state.year)}",
            f"Mine hazard: {self.mine_hazard_label_for_date(self.state.month, self.state.day, self.state.year) or 'none forecast today'}",
            "",
        ]
        lines.extend(self.seasonal_combat_contract_lines()[2:])
        lines.extend(["", "Last battle:"])
        lines.extend(report[:10] if report else ["- No battle report recorded yet."])
        return lines

    def journal_crafting_goal_lines(self) -> List[str]:
        ready: List[str] = []
        blocked: List[str] = []
        for recipe_name, recipe in CRAFTING_RECIPES.items():
            ok, reason = self.can_craft_recipe(recipe_name)
            output_name, output_qty = recipe["output"]
            line = f"- {recipe_name}: {output_qty} {output_name}"
            if ok:
                ready.append(line + " (ready)")
            else:
                blocked.append(line + f" ({reason})")
        lines = [
            "CRAFTING GOALS",
            "",
            f"Crafting Bench placed: {'yes' if self.has_placed_object_named('Crafting Bench') else 'no'}",
            "",
            "Ready now:",
        ]
        lines.extend(ready[:14] if ready else ["- Nothing ready right now."])
        lines.extend(["", "Needs work:"])
        lines.extend(blocked[:20] if blocked else ["- Every known recipe is ready."])
        return lines

    def show_journal_calendar_menu(self):
        while True:
            items = [
                MenuItem(label="Open calendar", value="calendar", enabled=True, hint="festivals, markets, warnings"),
                MenuItem(label="Birthday list", value="birthdays", enabled=True, hint="town and household"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Calendar & Birthdays", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            if choice.value == "calendar":
                self.show_calendar()
            elif choice.value == "birthdays":
                self.vertical_panel_view("Birthdays", self.journal_birthday_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

    def show_journal_records_menu(self):
        while True:
            items = [
                MenuItem(label="Land records", value="claims", enabled=True, hint="owned claims and travel notes"),
                MenuItem(label="Regional journal", value="regional", enabled=True, hint="towns, markets, routes, and caravans"),
                MenuItem(label="Relationship records", value="relationships", enabled=True, hint="friendship overview"),
                MenuItem(label="Family records", value="family", enabled=True, hint="household overview"),
                MenuItem(label="Dynasty records", value="dynasty", enabled=True, hint=f"generation {self.state.player_generation}"),
                MenuItem(label="Bestiary records", value="bestiary", enabled=True, hint="seen and defeated"),
                MenuItem(label="Combat reports", value="combat", enabled=True, hint="recent results"),
                MenuItem(label="Crafting goals", value="crafting", enabled=True, hint="known recipes"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Records & Discoveries", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            if choice.value == "regional":
                self.show_regional_journal_menu()
                continue
            views = {
                "claims": ("Land Records", self.journal_land_claim_lines),
                "relationships": ("Relationship Records", self.journal_relationship_lines),
                "family": ("Family Records", self.family_status_lines),
                "dynasty": ("Dynasty Records", self.dynasty_ledger_lines),
                "bestiary": ("Bestiary Records", self.journal_bestiary_lines),
                "combat": ("Combat Reports", self.journal_combat_report_lines),
                "crafting": ("Crafting Goals", self.journal_crafting_goal_lines),
            }
            title, lines_fn = views[str(choice.value)]
            self.vertical_panel_view(title, lines_fn(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)

    def show_journal_codex_menu(self):
        while True:
            items = [
                MenuItem(label="Today", value="today", enabled=True),
                MenuItem(label="Quests", value="quests", enabled=True),
                MenuItem(label="Calendar & Birthdays", value="calendar", enabled=True),
                MenuItem(label="Progress Goals", value="progress", enabled=True),
                MenuItem(label="Records & Discoveries", value="records", enabled=True),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Journal", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                self.set_message("Closed Journal.")
                return MENU_BACK
            if choice.value == "today":
                self.vertical_panel_view("Today", self.journal_overview_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "progress":
                self.vertical_panel_view("Progress Goals", self.journal_progression_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "quests":
                self.vertical_panel_view("Quest Journal", self.journal_quest_lines(), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if choice.value == "calendar":
                self.show_journal_calendar_menu()
                continue
            if choice.value == "records":
                self.show_journal_records_menu()
                continue

    def item_alias_map(self) -> Dict[str, str]:
        return {
            "Berries": "Wild Berries",
            "Wildflower": "Wildflowers",
            "Honey": "Wild Honey",
        }

    def canonical_item_name(self, item_name: str) -> str:
        return self.item_alias_map().get(item_name, item_name)

    def item_alias_lines(self, item_name: str) -> List[str]:
        canonical = self.canonical_item_name(item_name)
        if canonical != item_name:
            return [f"Alias of: {canonical}"]
        aliases = [alias for alias, target in self.item_alias_map().items() if target == item_name]
        if aliases:
            return [f"Also accepted as: {', '.join(aliases)}"]
        return []

    def item_detail_lines(self, item_name: str) -> List[str]:
        qty = self.state.inventory.get(item_name, 0)
        lines: List[str] = [item_name, "", f"Quantity: {qty}"]
        alias_lines = self.item_alias_lines(item_name)
        if alias_lines:
            lines.extend(alias_lines)

        if is_food_item(item_name):
            lines.append(f"Edible: yes (+{food_stamina_value(item_name)} stamina)")
            buff_lines = self.food_buff_lines(item_name)
            if buff_lines:
                lines.extend([""])
                lines.extend(buff_lines)
        else:
            lines.append("Edible: no")

        unit_price = self.shippable_unit_price(item_name)
        if self.is_shippable_item(item_name):
            lines.append(f"Shipping value: ${unit_price} each")
            lines.append(f"Stack value: ${unit_price * qty}")
        elif unit_price > 0 and self.is_shipping_protected_material(item_name):
            lines.append(f"Shipping value: protected from bin shipping (${unit_price} base value)")
            lines.append("Protected because it is used for crafting, restoration, gear, or unlocks.")
        else:
            lines.append("Shipping value: none")

        seed_crop = self.crop_name_for_seed_item(item_name)
        if seed_crop and seed_crop in CROP_DATA:
            crop = CROP_DATA[seed_crop]
            lines.extend([
                "",
                "Seed info:",
                f"Plants: {seed_crop}",
                f"Season: {crop.get('season')}",
                f"Growth days: {crop.get('growth_days')}",
                f"Base crop value: ${crop.get('sell_price')}",
            ])

        if item_name in FISH_DATA:
            data = FISH_DATA[item_name]
            lines.extend([
                "",
                "Fish info:",
                f"Locations: {', '.join(data.get('locations', []))}",
                f"Seasons: {', '.join(data.get('seasons', []))}",
                f"Weather: {', '.join(data.get('weather', []))}",
                f"Time: {data.get('time', 'Any')}",
            ])
            if not data.get("junk", False):
                lines.extend([""])
                lines.extend(self.fish_pond_item_status_lines(item_name))

        crop_name, quality = parse_quality_item(item_name)
        if crop_name and crop_name in CROP_DATA:
            crop = CROP_DATA[crop_name]
            lines.extend([
                "",
                "Crop info:",
                f"Crop: {crop_name}",
                f"Quality: {quality}",
                f"Season: {crop.get('season')}",
                f"Base sell price: ${crop.get('sell_price')}",
            ])

        if item_name in INFRASTRUCTURE_DATA:
            data = INFRASTRUCTURE_DATA[item_name]
            lines.extend([
                "",
                "Placeable object:",
                f"Category: {data.get('category', 'infrastructure')}",
                f"Footprint: {self.footprint_label(item_name)}",
                data.get("description", "Placeable object."),
            ])
            if item_name == "Fish Pond":
                lines.extend([
                    "",
                    "Fish pond:",
                    "Stock with caught fish from inventory.",
                    "Produces harvests overnight after enough days pass.",
                    "Use Z/Enter on a placed pond to manage it.",
                ])
            if item_name == "Preserves Jar":
                lines.extend([
                    "",
                    "Artisan processor:",
                    "Processes crops and forage into higher-value goods.",
                    "Use Z/Enter on a placed jar to start or collect batches.",
                ])
        elif item_name in FOOD_DATA:
            desc = FOOD_DATA[item_name].get("description")
            if desc:
                lines.extend(["", desc])
        elif item_name in FISH_DATA:
            lines.extend(["", "Can be eaten raw if edible, shipped, or used in Any Fish recipes."])

        combat_item = FARMSTEAD_COMBAT_ITEM_DATA.get(item_name, {})
        if combat_item:
            effect = str(combat_item.get("effect", ""))
            amount = int(combat_item.get("amount", 0) or 0)
            if effect == "heal":
                lines.extend(["", f"Combat recovery: restores {amount} HP."])
            elif effect == "mp":
                lines.extend(["", f"Combat recovery: restores {amount} focus."])
            elif effect:
                lines.extend(["", f"Combat item: {combat_item.get('description', effect)}"])

        artisan_good_lines = self.artisan_good_lines(item_name)
        if artisan_good_lines:
            lines.extend([""])
            lines.extend(artisan_good_lines)

        artisan_recipe = self.artisan_recipe_for_item(item_name)
        if artisan_recipe:
            lines.extend([
                "",
                "Artisan processing:",
                f"Preserves Jar -> {artisan_recipe['qty']} {artisan_recipe['output']} ({artisan_recipe['days']} day(s))",
            ])

        recipe_lines = self.ingredient_usage_lines(item_name)
        if recipe_lines:
            lines.extend(["", "Used in cooking:"])
            lines.extend(recipe_lines)

        craft_lines = self.crafting_usage_lines(item_name)
        if craft_lines:
            lines.extend(["", "Used in crafting:"])
            lines.extend(craft_lines)

        return lines

    def item_hint_for_goods_list(self, item_name: str, qty: int) -> str:
        parts: List[str] = [f"x{qty}"]
        if is_food_item(item_name):
            parts.append(f"+{food_stamina_value(item_name)} stam")
        if self.is_inventory_consumable_item(item_name):
            recovery = self.food_combat_recovery_label(item_name)
            if recovery:
                parts.append(recovery)
        price = self.shippable_unit_price(item_name)
        if self.is_shippable_item(item_name):
            parts.append(f"${price} ea")
        elif price > 0 and self.is_shipping_protected_material(item_name):
            parts.append("protected")
        if self.ingredient_usage_lines(item_name):
            parts.append("ingredient")
        return ", ".join(parts)

    def ship_inventory_item(self, item_name: str) -> bool:
        qty_owned = self.state.inventory.get(item_name, 0)
        if qty_owned <= 0:
            self.set_message(f"You do not have any {item_name}.")
            return False
        if self.shipping_bin_target() is None:
            self.set_message("Face the shipping bin to ship items from inventory.")
            return False

        unit_price = self.shippable_unit_price(item_name)
        if unit_price <= 0 or not self.is_shippable_item(item_name):
            if self.is_shipping_protected_material(item_name):
                self.set_message(f"{item_name} is protected for crafting and unlocks.")
                return False
            self.set_message(f"{item_name} is not shippable.")
            return False

        qty = self.vertical_quantity_select(
            "Ship Item",
            item_name,
            unit_price,
            max_qty=qty_owned,
            start_qty=qty_owned,
            panel_width=LEFT_PANEL_WIDTH,
            panel_height=LEFT_PANEL_HEIGHT,
            return_back=True,
        )
        if qty == MENU_BACK or qty is None or qty <= 0:
            self.set_message("Shipping cancelled.")
            return False

        qty = int(qty)
        total = qty * unit_price
        self.state.inventory[item_name] = qty_owned - qty
        self.add_to_shipping_report(item_name, qty, total)
        self.autosave_with_message(f"Shipped {qty} {item_name} for ${total}. Payment arrives tomorrow.")
        return True

    def show_item_action_menu(self, item_name: str):
        while True:
            qty = self.state.inventory.get(item_name, 0)
            if qty <= 0:
                self.set_message(f"No {item_name} remaining.")
                return "changed"

            action_items: List[MenuItem] = []
            seed_crop = self.crop_name_for_seed_item(item_name)
            if seed_crop:
                action_items.append(MenuItem(label="Select", value="select_seed", enabled=True, hint=seed_crop))
            if self.is_inventory_consumable_item(item_name):
                action_items.append(MenuItem(
                    label="Eat" if is_food_item(item_name) else "Use",
                    value="consume",
                    enabled=self.consumable_can_help_now(item_name),
                    hint=self.consumable_item_hint(item_name),
                ))
            if self.is_shippable_item(item_name):
                near_bin = self.shipping_bin_target() is not None
                action_items.append(MenuItem(label="Ship", value="ship", enabled=near_bin, hint=f"${self.shippable_unit_price(item_name)} each" if near_bin else "face bin"))
            if item_name in FISH_DATA and not FISH_DATA[item_name].get("junk", False):
                action_items.append(MenuItem(label="Fish Pond", value="pond_info", enabled=True, hint="stockable"))
            if self.ingredient_usage_lines(item_name):
                action_items.append(MenuItem(label="Recipes", value="recipes", enabled=True, hint="cooking"))
            action_items.append(MenuItem(label="Inspect", value="inspect", enabled=True))
            action_items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

            choice = self.vertical_panel_select(
                f"{item_name} x{qty}",
                action_items,
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK

            action = choice.value
            if action == "select_seed":
                seed_crop = self.crop_name_for_seed_item(item_name)
                if seed_crop:
                    self.state.selected_seed = seed_crop
                    self.select_tool_by_name("Seeds")
                    self.autosave_with_message(f"Selected {item_name} for planting.")
                    return "changed"
                self.set_message("That item is not a seed.")
                continue
            if action == "consume":
                if self.choose_and_use_consumable_item(item_name):
                    return "changed"
                continue
            if action == "ship":
                if self.ship_inventory_item(item_name):
                    return "changed"
                continue
            if action == "pond_info":
                rows = self.fish_pond_item_status_lines(item_name)
                if not rows:
                    rows = ["This item cannot be stocked in a Fish Pond."]
                self.vertical_panel_view("Fish Pond Info", rows, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if action == "recipes":
                rows = self.ingredient_usage_lines(item_name)
                if not rows:
                    rows = ["No known recipes use this item."]
                self.vertical_panel_view("Recipe Uses", rows, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue
            if action == "inspect":
                self.vertical_panel_view("Item Details", self.item_detail_lines(item_name), LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT)
                continue

    def show_carried_goods_menu(self):
        while True:
            carried_items = [(item, qty) for item, qty in sorted(self.state.inventory.items()) if qty > 0]
            items: List[MenuItem] = [
                MenuItem(
                    label=item,
                    value=item,
                    enabled=True,
                    hint=self.item_hint_for_goods_list(item, qty),
                )
                for item, qty in carried_items
            ]
            items.append(MenuItem(label="Back", value=MENU_BACK, enabled=True))

            choice = self.vertical_panel_select(
                "Carried Goods",
                items,
                LEFT_PANEL_WIDTH,
                LEFT_PANEL_HEIGHT,
                return_back=True,
            )
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK

            result = self.show_item_action_menu(str(choice.value))
            if result == "changed":
                return "changed"

    def tab_build_menu_state(self) -> Tuple[bool, str]:
        infrastructure_count = sum(qty for _name, qty in self.infrastructure_items_in_inventory())
        built_count = len(self.placed_objects_in_current_scope()) if self.can_hold_objects_here() else 0
        enabled = self.can_hold_objects_here() and (infrastructure_count > 0 or built_count > 0)
        bits = []
        if infrastructure_count:
            bits.append(f"{infrastructure_count} carried")
        if built_count:
            bits.append(f"{built_count} placed")
        return enabled, ", ".join(bits) if bits else "owned land/house"

    def show_backpack_menu(self):
        while True:
            carried_items = [(item, qty) for item, qty in sorted(self.state.inventory.items()) if qty > 0]
            non_seed_count = sum(1 for item, _qty in carried_items if not item.endswith(" Seeds"))
            seed_type_count = sum(1 for item, _qty in carried_items if item.endswith(" Seeds"))
            goods_hint = f"{non_seed_count} goods"
            if seed_type_count:
                goods_hint += f", {seed_type_count} seeds"
            storage_records = self.player_storage_records()
            stored_count = sum(
                self.container_used(self.normalize_container_record(record)[0])
                for record in storage_records
            )
            food_count = sum(qty for _name, qty, _stamina in self.edible_items_in_inventory())
            items = [
                MenuItem(
                    label=f"Carried goods ({self.backpack_used()}/{self.backpack_capacity()})",
                    value="goods",
                    enabled=True,
                    hint=goods_hint,
                ),
                MenuItem(label="Food", value="food", enabled=food_count > 0, hint=f"x{food_count}" if food_count else "none"),
                MenuItem(label="Owned storage", value="storage", enabled=bool(storage_records), hint=f"x{stored_count}" if storage_records else "interact with a container"),
                MenuItem(label="Back", value=MENU_BACK, enabled=True),
            ]
            choice = self.vertical_panel_select("Backpack", items, LEFT_PANEL_WIDTH, LEFT_PANEL_HEIGHT, return_back=True)
            if choice is None or choice.value == MENU_BACK:
                return MENU_BACK
            if choice.value == "goods":
                self.show_carried_goods_menu()
            elif choice.value == "food":
                self.show_food_menu()
            elif choice.value == "storage":
                self.show_player_storage_index()

