    def month_first_weekday_index(self, month: int, year: int) -> int:
        """Return Monday-based weekday index for the first day of a month."""
        days_before = day_of_year(month, 1, year) - 1
        return days_before % 7

    def birthday_tuple_from(self, month_value: object, day_value: object, fallback_month: int = 3, fallback_day: int = 1) -> Tuple[int, int]:
        try:
            month = max(1, min(12, int(month_value)))
        except Exception:
            month = fallback_month
        try:
            day = max(1, min(days_in_month(month, 1), int(day_value)))
        except Exception:
            day = fallback_day
        return month, day

    def player_birthday_label(self) -> str:
        month, day = self.birthday_tuple_from(self.state.player_birthday_month, self.state.player_birthday_day)
        return format_birthday(month, day)

    def npc_birthday(self, npc: Dict[str, object]) -> Tuple[int, int]:
        npc_id = str(npc.get("id", ""))
        fallback_month, fallback_day = NPC_BIRTHDAY_BY_ID.get(npc_id, (3, 1))
        return self.birthday_tuple_from(npc.get("birthday_month", fallback_month), npc.get("birthday_day", fallback_day), fallback_month, fallback_day)

    def npc_birthday_label(self, npc: Dict[str, object]) -> str:
        month, day = self.npc_birthday(npc)
        return format_birthday(month, day)

    def is_player_birthday(self, month: Optional[int] = None, day: Optional[int] = None) -> bool:
        month = self.state.month if month is None else int(month)
        day = self.state.day if day is None else int(day)
        birthday_month, birthday_day = self.birthday_tuple_from(self.state.player_birthday_month, self.state.player_birthday_day)
        return month == birthday_month and day == birthday_day

    def is_npc_birthday(self, npc: Dict[str, object], month: Optional[int] = None, day: Optional[int] = None) -> bool:
        month = self.state.month if month is None else int(month)
        day = self.state.day if day is None else int(day)
        birthday_month, birthday_day = self.npc_birthday(npc)
        return month == birthday_month and day == birthday_day

    def child_birthday(self, child: Dict[str, object]) -> Tuple[int, int]:
        return self.birthday_tuple_from(child.get("birth_month", 3), child.get("birth_day", 1))

    def child_birthday_label(self, child: Dict[str, object]) -> str:
        month, day = self.child_birthday(child)
        return format_birthday(month, day)

    def child_has_been_born_by(self, child: Dict[str, object], month: int, day: int, year: int) -> bool:
        try:
            birth_month = int(child.get("birth_month", month))
            birth_day = int(child.get("birth_day", day))
            birth_year = int(child.get("birth_year", year))
        except Exception:
            return True
        return date_reached(month, day, year, birth_month, birth_day, birth_year)

    def market_day_label_for_date(self, month: int, day: int, year: int) -> Optional[str]:
        weekday = weekday_for_date(month, day, year)
        festival_id = self.festival_id_for_date(month, day, year)
        if festival_id:
            festival = self.festival_catalog().get(festival_id, {})
            return f"Festival market: {festival.get('name', 'festival stock')} brings extra foot traffic."
        if weekday in ["Wednesday", "Saturday"]:
            return f"Market Day ({weekday}): Market Row emphasizes limited daily stock."
        if int(day) in [1, 15]:
            return "Supply Market: vendors refresh long-range orders and seed advice."
        return None

    def mine_hazard_label_for_date(self, month: int, day: int, year: int) -> Optional[str]:
        weather = forecast_weather_for_date(month, day, year)
        if weather in ["Stormy", "Blizzard"]:
            return f"Storm echo: {weather.lower()} weather makes the mines more active."
        score = (int(year) * 37 + int(month) * 19 + int(day) * 11) % 29
        if score in [0, 7, 14]:
            return "Deep tremor: one extra enemy can appear on newly generated mine floors."
        if int(day) in [13, 26]:
            return "Loose strata: cave routes are unstable and hostile movement is elevated."
        return None

    def seasonal_combat_contract_label_for_date(self, month: int, day: int, year: int) -> str:
        season = season_for_month(month)
        contracts = {
            "Spring": "Muckroot Sweep",
            "Summer": "Embercap Patrol",
            "Fall": "Hollowcap Hunt",
            "Winter": "Frostfang Watch",
        }
        return contracts.get(season, "Mine Safety Patrol")

    def seasonal_combat_contract_lines(self, month: Optional[int] = None, day: Optional[int] = None, year: Optional[int] = None) -> List[str]:
        month = self.state.month if month is None else int(month)
        day = self.state.day if day is None else int(day)
        year = self.state.year if year is None else int(year)
        season = season_for_month(month)
        contract = self.seasonal_combat_contract_label_for_date(month, day, year)
        themes = {
            "Spring": "Clear early-season slime pressure before it reaches the farm roads.",
            "Summer": "Watch for heat-stirred cave life and bring restorative food.",
            "Fall": "Gather combat salvage while the mines shed more spores and stones.",
            "Winter": "Keep the lower routes safe during severe weather and low visibility.",
        }
        return [
            "SEASONAL COMBAT CONTRACT",
            "",
            f"Active contract: {contract}",
            f"Season: {season}",
            f"Period: all of {season}",
            "",
            themes.get(season, "Keep the mine route safe for the town."),
            "",
            "Check the Combat Mission Board for tactical contracts and bestiary progress.",
        ]

    def weather_warning_label_for_date(self, month: int, day: int, year: int) -> Optional[str]:
        weather = forecast_weather_for_date(month, day, year)
        if weather == "Stormy":
            return "Storm warning: crops are watered, but mine activity is more dangerous."
        if weather == "Blizzard":
            return "Blizzard warning: visibility and mine conditions are poor."
        if weather == "Hot":
            return "Heat advisory: carry food before long field work or travel."
        if weather == "Foggy":
            return "Fog advisory: morning visibility will be poor."
        return None

    def calendar_advisory_events_for_date(self, month: int, day: int, year: int) -> List[str]:
        events: List[str] = []
        if (
            int(month) == int(self.state.player_birthday_month)
            and int(day) == int(self.state.player_birthday_day)
        ):
            age = self.player_age_on_date(month, day, year)
            if self.aging_and_death_active() and age >= 75:
                events.append(
                    f"Succession planning: age {age}. "
                    f"{self.player_health_outlook(age)}"
                )
        weather_warning = self.weather_warning_label_for_date(month, day, year)
        if weather_warning:
            events.append(weather_warning)
        market_day = self.market_day_label_for_date(month, day, year)
        if market_day:
            events.append(market_day)
        public_occasion = self.public_occasion_calendar_label_for_date(month, day, year)
        if public_occasion:
            events.append(public_occasion)
        events.extend(self.regional_circulation_calendar_events_for_date(month, day, year))
        mine_hazard = self.mine_hazard_label_for_date(month, day, year)
        if mine_hazard:
            events.append(f"Mine hazard day: {mine_hazard}")
        if (
            str(getattr(self.state, "engaged_npc_id", "") or "")
            and int(getattr(self.state, "wedding_month", 0) or 0) == int(month)
            and int(getattr(self.state, "wedding_day", 0) or 0) == int(day)
            and int(getattr(self.state, "wedding_year", 0) or 0) == int(year)
        ):
            events.append(
                f"Wedding ceremony with "
                f"{self.town_npc_name(self.state.engaged_npc_id)}"
            )
        if self.state.spouse_npc_id and self.state.marriage_month == int(month) and self.state.marriage_day == int(day):
            spouse_name = self.town_npc_name(self.state.spouse_npc_id)
            if int(year) > int(self.state.marriage_year or 0):
                events.append(f"Wedding anniversary with {spouse_name}")
            else:
                events.append(f"Wedding day with {spouse_name}")
        if self.state.pregnancy_active:
            if (
                int(month) == int(self.state.pregnancy_due_month)
                and int(day) == int(self.state.pregnancy_due_day)
                and int(year) == int(self.state.pregnancy_due_year)
            ):
                events.append(f"Pregnancy due date: {self.pregnancy_gestational_parent_name()}")
            if int(day) == int(self.state.pregnancy_start_day or 0) and date_reached(
                month,
                day,
                year,
                self.state.pregnancy_start_month,
                self.state.pregnancy_start_day,
                self.state.pregnancy_start_year,
            ) and not date_reached(
                month,
                day,
                year,
                self.state.pregnancy_due_month,
                self.state.pregnancy_due_day,
                self.state.pregnancy_due_year,
            ):
                month_no = months_between_dates(
                    self.state.pregnancy_start_month,
                    self.state.pregnancy_start_day,
                    self.state.pregnancy_start_year,
                    month,
                    day,
                    year,
                ) + 1
                if 1 <= month_no <= 9:
                    events.append(f"Pregnancy check-in month {month_no}")
        for child in self.state.children:
            try:
                birth_month = int(child.get("birth_month", 1))
                birth_day = int(child.get("birth_day", 1))
                birth_year = int(child.get("birth_year", 1))
            except Exception:
                continue
            for stage, age_months in self.child_stage_months().items():
                sm, sd, sy = add_months_to_date(birth_month, birth_day, birth_year, age_months)
                if int(month) == sm and int(day) == sd and int(year) == sy:
                    events.append(f"{child.get('name', 'Child')} reaches {stage}")
        weekday = weekday_for_date(month, day, year)
        if int(day) == 1 or weekday == "Monday":
            events.append(f"Seasonal combat contract active: {self.seasonal_combat_contract_label_for_date(month, day, year)}")
        tomorrow_month, tomorrow_day, tomorrow_year = advance_date(month, day, year)
        tomorrow_weather = forecast_weather_for_date(tomorrow_month, tomorrow_day, tomorrow_year)
        if tomorrow_weather in ["Stormy", "Blizzard"]:
            events.append(f"Tomorrow warning: {tomorrow_weather.lower()} weather expected.")
        return events

    def today_calendar_notice_lines(self) -> List[str]:
        today = format_date(self.state.month, self.state.day, self.state.year)
        tomorrow_month, tomorrow_day, tomorrow_year = advance_date(self.state.month, self.state.day, self.state.year)
        tomorrow = format_date(tomorrow_month, tomorrow_day, tomorrow_year)
        today_events = self.selected_calendar_events_text(self.state.month, self.state.day, self.state.year)
        tomorrow_events = self.selected_calendar_events_text(tomorrow_month, tomorrow_day, tomorrow_year)
        lines = [
            "CALENDAR NOTICES",
            "",
            f"Today: {today} ({self.state.weekday})",
            f"Weather: {self.state.weather} - {weather_forecast_summary(self.state.weather)}",
            "",
            "Today:",
        ]
        lines.extend(f"- {line}" for line in today_events[:8])
        lines.extend(["", f"Tomorrow: {tomorrow}", f"Forecast: {forecast_weather_for_date(tomorrow_month, tomorrow_day, tomorrow_year)}", ""])
        lines.append("Tomorrow:")
        lines.extend(f"- {line}" for line in tomorrow_events[:6])
        return lines

    def town_calendar_notice_bullets(self) -> List[str]:
        events = [
            line
            for line in self.selected_calendar_events_text(self.state.month, self.state.day, self.state.year)
            if line != "No events scheduled."
        ]
        if not events:
            return ["- No special notices."]
        return [f"- {line}" for line in events[:6]]

    def daily_calendar_notice_summary(self) -> str:
        events = [
            line
            for line in self.selected_calendar_events_text(self.state.month, self.state.day, self.state.year)
            if line != "No events scheduled."
        ]
        if not events:
            return ""
        summary = "; ".join(events[:2])
        if len(events) > 2:
            summary += f"; +{len(events) - 2} more"
        return f" Calendar: {summary}."

    def is_child_birthday(self, child: Dict[str, object], month: Optional[int] = None, day: Optional[int] = None, year: Optional[int] = None) -> bool:
        month = self.state.month if month is None else int(month)
        day = self.state.day if day is None else int(day)
        year = self.state.year if year is None else int(year)
        birthday_month, birthday_day = self.child_birthday(child)
        return month == birthday_month and day == birthday_day and self.child_has_been_born_by(child, month, day, year)

    def birthday_events_for_date(self, month: int, day: int, year: int) -> List[str]:
        events: List[str] = []
        if self.is_player_birthday(month, day):
            if self.aging_and_death_active():
                events.append(
                    f"{self.state.player_name}'s birthday: turns "
                    f"{self.player_age_on_date(month, day, year)} "
                    f"(born Year {self.state.player_birth_year})"
                )
            else:
                events.append(
                    f"{self.state.player_name}'s birthday "
                    f"({self.player_life_stage()})"
                )
        self.normalize_town_npcs()
        for npc in self.state.town_npcs:
            if self.is_npc_birthday(npc, month, day):
                events.append(f"{npc.get('name', 'Villager')}'s birthday")
        seen_generated = set()
        for plan in self.discovered_procedural_town_plans():
            population = self.procedural_settlement_population(
                int(plan["chunk_x"]),
                int(plan["chunk_y"]),
            ) or {}
            for resident in population.get("residents", {}).values():
                resident_id = str(resident.get("id", ""))
                if resident_id in seen_generated:
                    continue
                seen_generated.add(resident_id)
                if self.is_npc_birthday(resident, month, day):
                    events.append(
                        f"{resident.get('name', 'Resident')}'s birthday "
                        f"({plan.get('name', 'wilderness town')})"
                    )
        for child in self.state.children:
            if self.is_child_birthday(child, month, day, year):
                events.append(f"{child.get('name', 'Child')}'s birthday")
        events.extend(self.dynasty_birthday_events_for_date(month, day, year))
        return events

    def selected_calendar_events_text(self, month: int, day: int, year: int) -> List[str]:
        events = calendar_events_for(month, day, year)
        events.extend(self.birthday_events_for_date(month, day, year))
        events.extend(self.calendar_advisory_events_for_date(month, day, year))
        if events:
            return events
        return ["No events scheduled."]

    def calendar_event_panel_lines(
        self,
        events: List[str],
        width: int = 50,
        max_rows: int = 6,
    ) -> List[str]:
        """Wrap calendar bullets without expanding the fixed calendar panel."""
        width = max(8, int(width))
        max_rows = max(1, int(max_rows))
        display: List[str] = []
        omitted = 0
        for index, event in enumerate(events):
            wrapped = wrap_panel_row(f"- {event}", width)
            if len(display) + len(wrapped) <= max_rows:
                display.extend(wrapped)
                continue
            omitted = len(events) - index
            if not display:
                display.extend(wrapped[:max_rows])
            break
        if omitted:
            more_line = fit_text(
                f"  +{omitted} more event{'s' if omitted != 1 else ''}",
                width,
            )
            if len(display) >= max_rows:
                display = display[:max_rows - 1]
            display.append(more_line)
        return [fit_text(line, width) for line in display[:max_rows]]

    def calendar_previous_month(self, month: int, year: int) -> Tuple[int, int]:
        month -= 1
        if month < 1:
            month = 12
            year -= 1
        return month, year

    def calendar_next_month(self, month: int, year: int) -> Tuple[int, int]:
        month += 1
        if month > 12:
            month = 1
            year += 1
        return month, year

    def calendar_min_month_year(self) -> Tuple[int, int]:
        """Calendar cannot browse before the start of the game."""
        return 3, 1

    def calendar_can_go_previous(self, month: int, year: int) -> bool:
        min_month, min_year = self.calendar_min_month_year()
        return (year, month) > (min_year, min_month)

    def calendar_clamp_month_year(self, month: int, year: int) -> Tuple[int, int]:
        min_month, min_year = self.calendar_min_month_year()
        if (year, month) < (min_year, min_month):
            return min_month, min_year
        return month, year

    def calendar_previous_month_safe(self, month: int, year: int) -> Tuple[int, int]:
        if not self.calendar_can_go_previous(month, year):
            return month, year
        return self.calendar_previous_month(month, year)

    def draw_calendar_panel(self, view_month: int, view_year: int, cursor_day: int):
        s = self.state
        days = days_in_month(view_month, view_year)
        first_weekday = self.month_first_weekday_index(view_month, view_year)
        viewing_current_month = view_month == s.month and view_year == s.year

        self.invalidate_draw_cache()
        clear_screen()
        title = f"{MONTH_NAMES[view_month]}, Year {view_year}"
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to(title.center(50), 50) + "|", 52)
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to(" Mo  Tu  We  Th  Fr  Sa  Su", 50) + "|", 52)

        cells: List[str] = ["    "] * first_weekday
        for day in range(1, days + 1):
            if day == cursor_day:
                cell = colorize(f"[{day:2d}]", C.PLAYER)
            elif viewing_current_month and day == s.day:
                cell = colorize(f" {day:2d} ", C.CROP_READY)
            else:
                cell = f" {day:2d} "
            cells.append(cell)

        while len(cells) % 7 != 0:
            cells.append("    ")

        for i in range(0, len(cells), 7):
            row = "".join(cells[i:i + 7])
            self.centered_print("|" + pad_to(row, 50) + "|", 52)

        self.centered_print("+" + "-" * 50 + "+", 52)

        selected_label = f"Selected: {MONTH_NAMES[view_month]} {cursor_day}, Year {view_year}"
        self.centered_print("|" + pad_to(selected_label, 50) + "|", 52)
        if viewing_current_month:
            self.centered_print("|" + pad_to("Current day is highlighted in the calendar grid.", 50) + "|", 52)
        else:
            self.centered_print("|" + pad_to("Viewing another month.", 50) + "|", 52)
        self.centered_print("|" + pad_to(f"Season: {season_for_month(view_month)}", 50) + "|", 52)
        player_calendar_line = (
            f"{self.state.player_name}'s age: "
            f"{self.player_age_on_date(view_month, cursor_day, view_year)} "
            f"(Generation {self.state.player_generation})"
            if self.aging_and_death_active()
            else f"{self.state.player_name}: {self.player_life_stage()} "
            f"(Generation {self.state.player_generation})"
        )
        self.centered_print("|" + pad_to(player_calendar_line, 50) + "|", 52)
        self.centered_print("|" + pad_to(f"Forecast: {forecast_weather_for_date(view_month, cursor_day, view_year)}", 50) + "|", 52)

        event_lines = self.selected_calendar_events_text(view_month, cursor_day, view_year)
        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to("Events:", 50) + "|", 52)
        for line in self.calendar_event_panel_lines(event_lines, 50, 6):
            self.centered_print("|" + pad_to(line, 50) + "|", 52)

        self.centered_print("+" + "-" * 50 + "+", 52)
        self.centered_print("|" + pad_to("Arrows/WASD move | Q/E month | X/Esc/Tab/K closes", 50) + "|", 52)
        self.centered_print("+" + "-" * 50 + "+", 52)

    def move_calendar_cursor(self, day: int, delta: int, view_month: Optional[int] = None, view_year: Optional[int] = None) -> int:
        month = self.state.month if view_month is None else view_month
        year = self.state.year if view_year is None else view_year
        days = days_in_month(month, year)
        return max(1, min(days, day + delta))

    def show_calendar(self):
        view_month, view_year = self.calendar_clamp_month_year(self.state.month, self.state.year)
        cursor_day = self.state.day

        while True:
            view_month, view_year = self.calendar_clamp_month_year(view_month, view_year)
            month_days = days_in_month(view_month, view_year)
            cursor_day = max(1, min(month_days, cursor_day))
            self.draw_calendar_panel(view_month, view_year, cursor_day)
            key = normalize_key(read_key())

            if key in ["\t", "\x1b", "k", "x"]:
                self.set_message("Closed calendar.")
                return

            if key == "q":
                old_day = cursor_day
                old_month, old_year = view_month, view_year
                view_month, view_year = self.calendar_previous_month_safe(view_month, view_year)
                if (view_month, view_year) == (old_month, old_year):
                    cursor_day = 1
                    self.set_message("Calendar starts at March, Year 1.")
                else:
                    cursor_day = min(old_day, days_in_month(view_month, view_year))
            elif key == "e":
                old_day = cursor_day
                view_month, view_year = self.calendar_next_month(view_month, view_year)
                cursor_day = min(old_day, days_in_month(view_month, view_year))
            elif key in ["a", "LEFT"]:
                if cursor_day <= 1:
                    old_month, old_year = view_month, view_year
                    view_month, view_year = self.calendar_previous_month_safe(view_month, view_year)
                    if (view_month, view_year) == (old_month, old_year):
                        cursor_day = 1
                        self.set_message("Calendar starts at March, Year 1.")
                    else:
                        cursor_day = days_in_month(view_month, view_year)
                else:
                    cursor_day -= 1
            elif key in ["d", "RIGHT"]:
                if cursor_day >= days_in_month(view_month, view_year):
                    view_month, view_year = self.calendar_next_month(view_month, view_year)
                    cursor_day = 1
                else:
                    cursor_day += 1
            elif key in ["w", "UP"]:
                cursor_day = self.move_calendar_cursor(cursor_day, -7, view_month, view_year)
            elif key in ["s", "DOWN"]:
                cursor_day = self.move_calendar_cursor(cursor_day, 7, view_month, view_year)

